window.HADITH_CACHE["ibnu-majah_5"] = {"2501":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ الْجُمَحِيُّ حَدَّثَنَا الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَتَرَ عَوْرَةَ أَخِيهِ الْمُسْلِمِ سَتَرَ اللَّهُ عَوْرَتَهُ يَوْمَ الْقِيَامَةِ وَمَنْ كَشَفَ عَوْرَةَ أَخِيهِ الْمُسْلِمِ كَشَفَ اللَّهُ عَوْرَتَهُ حَتَّى يَفْضَحَهُ بِهَا فِي بَيْتِهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib], telah menceritakan kepada kami [Muhammad bin Utsman Al Jumahi], telah menceritakan kepada kami [Hakam bin Aban] dari [Ikrimah] dari [Ibnu 'Abbas], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang menutupi aib saudaranya muslim, Allah akan menutupi aibnya pada hari kiamat, dan barang siapa mengumbar aib saudaranya muslim, maka Allah akan mengumbar aibnya hingga terbukalah kejelekannya di dalam rumahnya.\""},"2502":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَة��أَنَّ قُرَيْشًا أَهَمَّهُمْ شَأْنُ الْمَرْأَةِ الْمَخْزُومِيَّةِ الَّتِي سَرَقَتْ فَقَالُوا مَنْ يُكَلِّمُ فِيهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَمَنْ يَجْتَرِئُ عَلَيْهِ إِلَّا أُسَامَةُ بْنُ زَيْدٍ حِبُّ رَسُولِ اللَّهِ فَكَلَّمَهُ أُسَامَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْفَعُ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ ثُمَّ قَامَ فَاخْتَطَبَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّمَا هَلَكَ الَّذِينَ مِنْ قَبْلِكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ فِيهِمْ الضَّعِيفُ أَقَامُوا عَلَيْهِ الْحَدَّ وَايْمُ اللَّهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُ يَدَهَاقَالَ مُحَمَّدُ بْنُ رُمْحٍ سَمِعْتُ اللَّيْثَ بْنَ سَعْدٍ يَقُولُ قَدْ أَعَاذَهَا اللَّهُ عَزَّ وَجَلَّ أَنْ تَسْرِقَ وَكُلُّ مُسْلِمٍ يَنْبَغِي لَهُ أَنْ يَقُولَ هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri], telah memberitakan kepada kami [Laits bin Sa'ad] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] sesungguhnya orang-orang Quraisy merasa cemas terhadap apa yang akan ditimpakan kepada seorang wanita bani Makhzumivah yang telah mencuri. Mereka berkata, \"Siapa yang akan berbicara mengenai hal ini kepada Rasulullah?\" Sebagian orang berkata, \"Siapa lagi yang berani, selain Usamah bin Zaid sosok yang dicintai Rasulullah?\" Lalu Usamah membicarakannya kepada Rasulullah shallallahu 'alaihi wasallam. Maka beliau bersabda: \"Apakah engkau akan memberikan syafaat atau pengampunan dalam hal hukum hudud?\" Lalu beliau berdiri sambil berpidato, beliau bersabda: \" Wahai manusia sekalian! Sesungguhnya orang-orang sebelum kalian telah binasa, karena apabila seorang yang mulia diantara mereka mencuri, maka mereka membiarkannya. Tetapi apabila seorang yang lemah diantara mereka mencuri, maka mereka melaksanakan hukum hudud. Demi Allah! Seandainya saja Fatimah putri Muhammad mencuri, niscaya aku sendiri yang memotong tangannya. \" Muhammad bin Rumh berkata, \"Aku mendengar Laits bin Sa'd berkata, 'Sungguh Allah telah melindunginya (Fatimah) dari pencurian.' Maka seyogiayanya setiap Muslim mengucapkannya perkataan seperti ini.\""},"2503":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ طَلْحَةَ بْنِ رُكَانَةَ عَنْ أُمِّهِ عَائِشَةَ بِنْتِ مَسْعُودِ بْنِ الْأَسْوَدِ عَنْ أَبِيهَا قَالَلَمَّا سَرَقَتْ الْمَرْأَةُ تِلْكَ الْقَطِيفَةَ مِنْ بَيْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْظَمْنَا ذَلِكَ وَكَانَتْ امْرَأَةً مِنْ قُرَيْشٍ فَجِئْنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُكَلِّمُهُ وَقُلْنَا نَحْنُ نَفْدِيهَا بِأَرْبَعِينَ أُوقِيَّةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُطَهَّرَ خَيْرٌ لَهَا فَلَمَّا سَمِعْنَا لِينَ قَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَيْنَا أُسَامَةَ فَقُلْنَا كَلِّمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ قَامَ خَطِيبًا فَقَالَ مَا إِكْثَارُكُمْ عَلَيَّ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ عَزَّ وَجَلَّ وَقَعَ عَلَى أَمَةٍ مِنْ إِمَاءِ اللَّهِ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ كَانَتْ فَاطِمَةُ ابْنَةُ رَسُولِ اللَّهِ نَزَلَتْ بِالَّذِي نَزَلَتْ بِهِ لَقَطَعَ مُحَمَّدٌ يَدَهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abdullah bin Numair], telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Thalhah bin Rukanah] dari Ibunya [Aisyah binti Mas'ud bin Al Aswad] dari [Ayahnya] berkata; ketika ada seorang wanita dari kaumnya yang mencuri di rumah Rasulullah shallallahu 'alaihi wasallam, maka kami membesarkannya dan ternyata wanita itu dari Quraisy, kamipun mendatangi Nabi shallallahu 'alaihi wasallam untuk melaporkannya kami berkata; \"Kami menebusnya dengan empat puluh uqiyah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mensucikan diri lebih baik baginya.\" Ketika kami mendengar Rasulullah shallallahu 'alaihi wasallam menolaknya, kami pun mendatangi Usamah, kami berkata; \"Rayulah Rasulullah shallallahu 'alaihi wasallam wahai Usamah!.\" Hingga akhirnya Rasulullah shallallahu 'alaihi wasallam berdiri sambil berpidato, beliau bersabda: \"Apa yang menyebabkan kalian mencegahku dari menegakkan hukum hukum Allah yang terjadi pada seorang budak dari budak-budak Allah? Demi yang jiwa Muhammad berada di tangan-Nya, seandainya saja Fatimah putri Muhammad mencuri, niscaya Muhammad sendiri yang memotong tangannya.\""},"2504":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ وَشِبْلٍ قَالُواكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهُ رَجُلٌ فَقَالَ أَنْشُدُكَ اللَّهَ لَمَّا قَضَيْتَ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَالَ خَصْمُهُ وَكَانَ أَفْقَهَ مِنْهُ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَأْذَنْ لِي حَتَّى أَقُولَ قَالَ قُلْ قَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا وَإِنَّهُ زَنَى بِامْرَأَتِهِ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَخَادِمٍ فَسَأَلْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ فَأُخْبِرْتُ أَنَّ عَلَى ابْنِي جَلْدَ مِائَةٍ وَتَغْرِيبَ عَامٍ وَأَنَّ عَلَى امْرَأَةِ هَذَا الرَّجْمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ الْمِائَةُ الشَّاةُ وَالْخَادِمُ رَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَاغْدُ يَا أُنَيْسُ عَلَى امْرَأَةِ هَذَا فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا قَالَ هِشَامٌ فَغَدَا عَلَيْهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Hisyam bin Ammar] dan [Muhammad bin Shabah], semuanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Abu Hurairah] dan [Zaid bin Khalid] dan [Syibl] berkata; Kami sedang berada di sisi Rasulullah shallallahu 'alaihi wasallam. lalu seseorang datang menemui beliau, ia berkata; \"Aku memohon kepadamu atas nama Allah untuk memutuskan hukuman ini dengan kitabullah. Sahabatnya berkata, \"Ia rupanya lebih pandai, \"Wahai Rasulullah, tetapkanlah bagi kami dengan kitabullah dan izinkanlah aku berbicara.\" Rasulullah bersabda: \"Bicaralah\" Laki-laki tadi berkata; \"Sesungguhnya anakku bekerja pada seseorang, lalu ia berzina dengan orang tersebut. Aku telah menebus perbuatan zina tersebut dengan memberikan kepadanya seratus ekor kambing dan seorang pembantu. Aku bertanya kepada para ahli ilmu, lalu aku diberitahu bahwa hukuman bagi anakku adalah seratus kali dera dan diasingkan satu tahun. Sementara si wanita itu dikenakan hukuman rajam. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah! Aku akan menetapkan bagi kalian berdua dengan kitabullah, Seratus ekor kambing dan seorang pembantu hendaknya dikembalikan kepadamu, anakmu dihukum seratus kali dera dan diasingkan selama tahun. Pergilah wahai Unais! Temuilah wanita itu. apabila ia akui, maka rajamlah\" Hisyam berkata, \"Unais kemudian pergi menemui wanita tersebut dan ia mengakui, hingga kemudian dirajam.\""},"2505":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذُوا عَنِّي قَدْ جَعَلَ اللَّهُ لَهُنَّ سَبِيلًا الْبِكْرُ بِالْبِكْرِ جَلْدُ مِائَةٍ وَتَغْرِيبُ سَنَةٍ وَالثَّيِّبُ بِالثَّيِّبِ جَلْدُ مِائَةٍ وَالرَّجْمُ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyir], telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Yunus bin Jubair] dari [Hithan bin Abdullah] dari [Ubadah bin Shamit], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah (ketetapan hukum) dariku. Allah telah menjadikan jalan bagi mereka, perawan dan perjaka dengan didera seratus kali dan diasingkan selama satu tahun. Sementara seorang janda dan duda dengan didera seratus kali dan dirajam.\""},"2506":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ حَبِيبِ بْنِ سَالِمٍ قَالَأُتِيَ النُّعْمَانُ بْنُ بَشِيرٍ بِرَجُلٍ غَشِيَ جَارِيَةَ امْرَأَتِهِ فَقَالَ لَا أَقْضِي فِيهَا إِلَّا بِقَضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ كَانَتْ أَحَلَّتْهَا لَهُ جَلَدْتُهُ مِائَةً وَإِنْ لَمْ تَكُنْ أَذِنَتْ لَهُ رَجَمْتُهُ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah], telah menceritakan kepada kami [Khalid bin Al Harits], telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Habib bin Salim] berkata; \"Didatangkan pada [Nu'man bin Basyir] seorang yang telah menzinahi budak istrinya, maka ia berkata; \"Aku tidak menghukuminya kecuali dengan hukum Rasulullah shallallahu 'alaihi wasallam, bila istrinya meridlainya maka aku akan menderanya seratus kali dan bila ia tidak rela maka aku akan merajamnya.\""},"2507":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُفِعَ إِلَيْهِ رَجُلٌ وَطِئَ جَارِيَةَ امْرَأَتِهِ فَلَمْ يَحُدَّهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Hisyam bin Hasan] dari [Al Hasan] dari [Salamah bin Al Muhabbiq] bahwa Rasulullah shallallahu 'alaihi wasallam pernah dilapori seseorang yang telah mensetubuhi budak wanita milik istrinya dan beliau tidak merajamnya.\""},"2508":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِلَقَدْ خَشِيتُ أَنْ يَطُولَ بِالنَّاسِ زَمَانٌ حَتَّى يَقُولَ قَائِلٌ مَا أَجِدُ الرَّجْمَ فِي كِتَابِ اللَّهِ فَيَضِلُّوا بِتَرْكِ فَرِيضَةٍ مِنْ فَرَائِضِ اللَّهِ أَلَا وَإِنَّ الرَّجْمَ حَقٌّ إِذَا أُحْصِنَ الرَّجُلُ وَقَامَتْ الْبَيِّنَةُ أَوْ كَانَ حَمْلٌ أَوْ اعْتِرَافٌ وَقَدْ قَرَأْتُهَا الشَّيْخُ وَالشَّيْخَةُ إِذَا زَنَيَا فَارْجُمُوهُمَا الْبَتَّةَ رَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجَمْنَا بَعْدَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Shabah], keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas], ia berkata, [Umar bin Khaththab] berkata; \"Aku khawatir setelah lama masa berlalu, hingga seseorang berkata, \"Tidak aku temukan hukum rajam di dalam kitabullah (Al Qur'an), hingga mereka akan sesat karena meninggalkan salah satu dari syari'at Allah. Ingatlah! Sesungguhnya hukum rajam benar adanya. Apabila terjadi zina lalu ada saksi atau wanita yang bersangkutan hamil, atau ada pengakuan, maka aku membaca, \"Laki-laki dan wanita dewasa apabila keduanya berzina, maka benar-benar rajamlah mereka.\" Rasulullah shallallahu 'alaihi wasallam melakukan hukum rajam dan kami pun melaksanakannya sepeninggal beliau.\""},"2509":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ مَاعِزُ بْنُ مَالِكٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي زَنَيْتُ فَأَعْرَضَ عَنْهُ ثُمَّ قَالَ إِنِّي قَدْ زَنَيْتُ فَأَعْرَضَ عَنْهُ ثُمَّ قَالَ إِنّ��ي زَنَيْتُ فَأَعْرَضَ عَنْهُ ثُمَّ قَالَ قَدْ زَنَيْتُ فَأَعْرَضَ عَنْهُ حَتَّى أَقَرَّ أَرْبَعَ مَرَّاتٍ فَأَمَرَ بِهِ أَنْ يُرْجَمَ فَلَمَّا أَصَابَتْهُ الْحِجَارَةُ أَدْبَرَ يَشْتَدُّ فَلَقِيَهُ رَجُلٌ بِيَدِهِ لَحْيُ جَمَلٍ فَضَرَبَهُ فَصَرَعَهُ فَذُكِرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِرَارُهُ حِينَ مَسَّتْهُ الْحِجَارَةُ فَقَالَ فَهَلَّا تَرَكْتُمُوهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abbad bin Al Awwam] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; \"Maiz bin Malik datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, 'Wahai Rasulullah aku telah berzina.' Akan tetapi Rasulullah shallallahu 'alaihi wasallam mengacuhkannya. Lalu ia berkata kembali, \"Aku telah berzina.\" Dan Rasulullah shallallahu 'alaihi wasallam pun mengacuhkannya. Kemudian ia berkata lagi, \"Aku telah berzina.\" Rasulullah shallallahu 'alaihi wasallam tetap mengacuhkannya. Lalu ia berkata kembali, \"Aku telah berzina.\" Namun Rasulullah shallallahu 'alaihi wasallam tetap tidak memperdulikannya sampai ia mengikrarkan perihal tersebut sebanyak empat kali. Lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan agar ia dihukum rajam. Di saat tubuhnya terkena lemparan batu, ia pun melarikan diri karena kesakitan. Kemudian bertemu dengan seorang yang membawa tulang rahang unta di tangannya, laki-laki ini akhirnya memukul Maiz sampai pingsan. Perihal larinya Maiz saat terkena lemparan batu itu diceritakan kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Tidakkah sebaiknya kalian membiarkannya?\""},"2510":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو عَمْرٍو حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَاجِرِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِأَنَّ امْرَأَةً أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاعْتَرَفَتْ بِالزِّنَا فَأَمَرَ بِهَا فَشُكَّتْ عَلَيْهَا ثِيَابُهَا ثُمَّ رَجَمَهَا ثُمَّ صَلَّى عَلَيْهَا","id":"Telah menceritakan kepada kami [Al Abbas bin Utsman Ad Dimasyqi], telah menceritakan kepada kami [Al Walid bin Muslim], telah menceritakan kepada kami [Abu Amru], telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Qilabah] dari [Abu Al Muhajir] dari [Imran bin Al Hushain] bahwa seorang wanita datang menemui Nabi shallallahu 'alaihi wasallam, lalu mengaku bahwa ia telah berzina. Kemudian Rasulullah memerintahkan untuk mempererat bajunya (agar tidak tersingkap auratnya) dan dirajam lalu menyalatinya.\""},"2511":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَمَ يَهُودِيَّيْنِأَنَا فِيمَنْ رَجَمَهُمَا فَلَقَدْ رَأَيْتُهُ وَإِنَّهُ يَسْتُرُهَا مِنْ الْحِجَارَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar], ia berkata, \"Sesungguhnya Nabi telah menghukum rajam dua orang Yahudi yang berzina, aku termasuk yang menghukum rajam keduanya, aku menyaksikan yang laki-lakinya menutupi tubuh wanita tersebut dari lemparan batu.\""},"2512":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَمَ يَهُودِيًّا وَيَهُودِيَّةً","id":"Telah menceritakan kepada kami [Isma'il bin Musa], telah menceritakan kepada kami [Syarik] dari [Simak bin Harb] dari [Jabir bin Samurah] Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah menghukum rajam seorang laki-laki dan seorang wanita Yahudi."},"2513":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ مُحَمَّمٍ مَجْلُودٍ فَدَعَاهُمْ فَقَالَ هَكَذَا تَجِدُونَ فِي كِتَابِكُمْ حَدَّ الزَّانِي قَالُوا نَعَمْ فَدَعَا رَجُلًا مِنْ عُلَمَائِهِمْ فَقَالَ أَنْشُدُكَ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى أَهَكَذَا تَجِدُونَ حَدَّ الزَّانِي قَالَ لَا وَلَوْلَا أَنَّكَ نَشَدْتَنِي لَمْ أُخْبِرْكَ نَجِدُ حَدَّ الزَّانِي فِي كِتَابِنَا الرَّجْمَ وَلَكِنَّهُ كَثُرَ فِي أَشْرَافِنَا الرَّجْمُ فَكُنَّا إِذَا أَخَذْنَا الشَّرِيفَ تَرَكْنَاهُ وَكُنَّا إِذَا أَخَذْنَا الضَّعِيفَ أَقَمْنَا عَلَيْهِ الْحَدَّ فَقُلْنَا تَعَالَوْا فَلْنَجْتَمِعْ عَلَى شَيْءٍ نُقِيمُهُ عَلَى الشَّرِيفِ وَالْوَضِيعِ فَاجْتَمَعْنَا عَلَى التَّحْمِيمِ وَالْجَلْدِ مَكَانَ الرَّجْمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَوَّلُ مَنْ أَحْيَا أَمْرَكَ إِذْ أَمَاتُوهُ وَأَمَرَ بِهِ فَرُجِمَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al 'A'masy] dari [Abdullah bin Murrah] dari [Al Barra bin Azib], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bertemu dengan seorang laki-laki Yahudi yang berwajah memar dan bekas cambukan di tubuhnya. Lalu Rasulullah shallallahu 'alaihi wasallam memanggil mereka dan berkata, 'Apakah ini yang kalian temukan dalam kitab suci kalian mengenai hukuman bagi pezina?\" Mereka menjawab, \"Ya.\" Lalu Rasulullah memanggil salah seorang ulama dari kalangan mereka dan berkata, \"Aku menyerukan kepadamu atas nama Allah Yang telah menurunkan Taurat kepada Nabi Musa. Apakah demikian kalian menemukan hukuman untuk seorang pezina?\" la menjawab, \"Tidak\" dan seandainya engkau tidak tidak bersumpah padaku, maka aku tidak akan memberitahukan hal ini kepadamu. Di dalam kitab kami, kami temukan bahwa hukuman bagi seorang pezina adalah hukum rajam, tetapi sangat banyak dari kalangan pembesar-pembesar kami yang terkena hukum rajam. Apabila kami menangkap seorang Pembesar, maka kami biarkan dan apabila kami menangkap seorang dari kalangan bawah, maka kami melaksanakan hukum had tersebut kepadanya. Akhirnya kami berkumpul, dari kalangan bangsawan dan rakyat jelata untuk menyepakati bahwa hukuman atas pezina adalah dengan mencoreng wajahnya dengan arang dan hukuman dera sebagai ganti dari rajam. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sunguh aku adalah orang yang pertama kali menghidupkan perintah-Mu, ketika mereka telah meniadakannya. Lalu beliau shallallahu 'alaihi wasallam meminta agar laki-laki tersebut dirajam."},"2514":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا زَيْدُ بْنُ يَحْيَى بْنِ عُبَيْدٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتُ رَاجِمًا أَحَدًا بِغَيْرِ بَيِّنَةٍ لَرَجَمْتُ فُلَانَةَ فَقَدْ ظَهَرَ مِنْهَا الرِّيبَةُ فِي مَنْطِقِهَا وَهَيْئَتِهَا وَمَنْ يَدْخُلُ عَلَيْهَا","id":"Telah menceritakan kepada kami [Abbas bin Al Walid Ad Dimasyqi], telah menceritakan kepada kami [Zaid bin Yahya bin Ubaid], telah menceritakan kepada kami [Laits bin Sa'ad] dari [Ubaidullah bin Abu Ja'far] dari [Abu Al Aswad] dari [Urwah] dari [Ibnu Abbas], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya aku adalah orang yang menghukum rajam seseorang tanpa harus ada saksi, niscaya aku akan menghukum rajam di fulanah sebab dari dirinya tampak keraguan, baik dari ucapan, gerak-gerik dan dari laki-laki yang datang padanya.\""},"2515":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ قَالَذَكَرَ ابْنُ عَبَّاسٍ الْمُتَلَاعِنَيْنِ فَقَالَ لَهُ ابْنُ شَدَّادٍ أَهِيَ الَّتِي قَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتُ رَاجِمًا أَحَدًا بِغَيْرِ بَيِّنَةٍ لَرَجَمْتُهَا فَقَالَ ابْنُ عَبَّاسٍ تِلْكَ امْرَأَةٌ أَعْلَنَتْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Khalad Al Bahili], telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al Qasim bin Muhammad] berkata; [Ibnu Abbas] menyebutkan tentang dua orang yang saling meli'an. Ibnu Syadad berkata kepadanya; \"Apakah wanita itu yang dikatakan Rasulullah shallallahu 'alaihi wasallam? Seandainya aku adalah orang yang menghukum rajam seseorang tanpa harus ada saksi, niscaya aku akan menghukumnya? Ibnu Abbas berkata; \"Wanita tersebut mengikrarkan sendiri perbuatannya.\""},"2516":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَأَبُو بَكْرِ بْنُ خَلَّادٍ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيرِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ وَجَدْتُمُوهُ يَعْمَلُ عَمَلَ قَوْمِ لُوطٍ فَاقْتُلُوا الْفَاعِلَ وَالْمَفْعُولَ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Shabah] dan [Abu Bakar bin Khalad], keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Amru bin Abu Amru] dari [Ikrimah] dari [Ibnu Abbas], sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dari kalian yang menemukan orang yang melakukan perbuatan kaum nabi Luth, maka bunuhlah pelaku dan obyek dari pelaku itu.\""},"2517":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ نَافِعٍ أَخْبَرَنِي عَاصِمُ بْنُ عُمَرَ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يَعْمَلُ عَمَلَ قَوْمِ لُوطٍ قَالَ ارْجُمُوا الْأَعْلَى وَالْأَسْفَلَ ارْجُمُوهُمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Yunus bin Abdul 'A'la], telah mengabarkan kepadaku [Abdullah bin Nafi'], telah mengabarkan kepadaku [Ashim bin Umar] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam tentang orang yang melakukan perbuatan kaum Nabi Luth, Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kalian harus merajamnya, baik sosok yang posisinya di atas atau di bawah secara bersamaan.\""},"2518":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا الْقَاسِمُ بْنُ عَبْدِ الْوَاحِدِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخْوَفَ مَا أَخَافُ عَلَى أُمَّتِي عَمَلُ قَوْمِ لُوطٍ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] Telah menceritakan kepada kami [Abdul Warits bin Sa'id] Telah menceritakan kepada kami [Al Qasim bin Abdul Wahid] dari [Abdullah bin Muhammad bin Uqail] dari [Jabir bin Abdullah], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang paling aku khawatirkan terhadap umatku adalah perbuatan kaum Luth.\""},"2519":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ إِبْرَاهِيمَ بْنِ إِسْمَعِيلَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَقَعَ عَلَى ذَاتِ مَحْرَمٍ فَاقْتُلُوهُ وَمَنْ وَقَعَ عَلَى بَهِيمَةٍ فَاقْتُلُوهُ وَاقْتُلُوا الْبَهِيمَةَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi], telah menceritakan kepada kami [Ibnu Abi Fudaik] dari [Ibrahim bin Isma'il] dari [Dawud bin Hushain] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barang siapa yang berzina dengan mahramnya maka bunuhlah ia. Dan barangsiapa berzina dengan seekor binatang, bunuhlah ia dan bunuhlah binatang tersebut.\""},"2520":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ وَشِبْلٍ قَالُواكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ رَجُلٌ عَنْ الْأَمَةِ تَزْنِي قَبْلَ أَنْ تُحْصَنَ فَقَالَ اجْلِدْهَا فَإِنْ زَنَتْ فَاجْلِدْهَا ثُمَّ قَالَ فِي الثَّال��ثَةِ أَوْ فِي الرَّابِعَةِ فَبِعْهَا وَلَوْ بِحَبْلٍ مِنْ شَعَرٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Shabah], keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Abu Hurairah] dan [Zaid bin Khalid] serta [Syibl] mereka berkata, \"Kami sedang berada di sisi Nabi shallallahu 'alaihi wasallam, lalu seorang laki-laki bertanya kepada beliau mengenai hamba sahaya perempuan yang melakukan zina sebelum ia menikah (perawan), maka Nabi shallallahu 'alaihi wasallam bersabda: \"Deralah ia, apabila ia berzina lagi, deralah kembali.\" Lalu Rasulullah shallallahu 'alaihi wasallam berkata pada ketiga atau kalinya, \"Maka juallah budak perempuan tersebut walaupun senilai seikat rambut.\""},"2521":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ قَالَ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَمَّارِ بْنِ أَبِي فَرْوَةَ أَنَّ مُحَمَّدَ بْنَ مُسْلِمٍ حَدَّثَهُ أَنَّ عُرْوَةَ حَدَّثَهُ أَنَّ عَمْرَةَ بِنْتَ عَبْدِ الرَّحْمَنِ حَدَّثَتْهُ أَنَّ عَائِشَةَ حَدَّثَتْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا زَنَتْ الْأَمَةُ فَاجْلِدُوهَا فَإِنْ زَنَتْ فَاجْلِدُوهَا فَإِنْ زَنَتْ فَاجْلِدُوهَا فَإِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ بِيعُوهَا وَلَوْ بِضَفِيرٍ وَالضَّفِيرُ الْحَبْلُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata; telah memberitakan kepada kami [Laits bin Sa'ad] dari [Yazid bin Abu Habib] dari [Ammar bin Abu Farwah] bahwa [Muhammad bin Muslim] menceritakannya bahwa ['Urwah] menceritakan kepadanya bahwa [Amrah binti Abdurrahman] juga telah menceritakannya dari [Aisyah], sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang hamba sahaya perempuan melakukan zina, maka deralah ia, apabila melakukannya lagi, maka deralah ia, apabila melakukannya lagi, maka deralah ia, apabila melakukannya lagi, maka deralah ia, lalu juallah ia meskipun hanya senilai seutas tali.\""},"2522":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَ عُذْرِي قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَذَكَرَ ذَلِكَ وَتَلَا الْقُرْآنَ فَلَمَّا نَزَلَ أَمَرَ بِرَجُلَيْنِ وَامْرَأَةٍ فَضُرِبُوا حَدَّهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Ibnu Abu Adi] dari [Muhammad bin Ishaq] dari [Abdullah bin Abu Bakar] dari [Amrah] dari [Aisyah]. ia berkata; \"Ketika ayat yang membebaskanku dari tuduhan turun, Rasulullah shallallahu 'alaihi wasallam berdiri di atas mjmbar lalu mengemukakan hal tersebut dengan membaca ayat suci Al Qur'an. Dan Ketika Rasulullah shallallahu 'alaihi wasallam turun dari mimbar, beliau memerintahkan terhadap dua orang laki-laki dan satu orang untuk dilakukan hukuman had atas mereka.\""},"2523":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي ابْنُ أَبِي حَبِيبَةَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الرَّجُلُ لِلرَّجُلِ يَا مُخَنَّثُ فَاجْلِدُوهُ عِشْرِينَ وَإِذَا قَالَ الرَّجُلُ لِلرَّجُلِ يَا لُوطِيُّ فَاجْلِدُوهُ عِشْرِينَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim], telah menceritakan kepada kami [Ibnu Abu Fudaik], telah menceritakan kepadaku [Ibnu Abu Habibah] dari [Dawud bin Al Hushain] dari [Ikrimah] dari [Ibnu 'Abbas], dari Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila seorang lelaki berkata kepada lelaki lain; 'Wahai bencong, maka derahlah dia sebanyak dua puluh kali. Dan apabila seorang lelaki berkata kepada lelaki lain: \"Wahai homosek, maka cambuklah ia dua puluh kali.\""},"2524":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا شَرِيكٌ عَنْ أَبِي حُصَيْنٍ عَنْ عُمَيْرِ بْنِ سَعِيدٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا مُطَرِّفٌ سَمِعْتُهُ عَنْ عُمَيْرِ بْنِ سَعِيدٍ قَالَ قَالَ عَلِيُّ بْنُ أَبِي طَالِبٍمَا كُنْتُ أَدِي مَنْ أَقَمْتُ عَلَيْهِ الْحَدَّ إِلَّا شَارِبَ الْخَمْرِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَسُنَّ فِيهِ شَيْئًا إِنَّمَا هُوَ شَيْءٌ جَعَلْنَاهُ نَحْنُ","id":"Telah menceritakan kepada kami [Isma'il bin Musa], telah menceritakan kepada kami [Syarik] dari [Abu Hushain] dari [Umair bin Sa'id], telah menceritakan kepada kami [Abdullah bin Muhammad Az Zuhri], telah menceritakan kepada kami [Sufyan bin Uyainah], telah menceritakan kepada kami [Mutharrif], aku mendengarnya dari [Umair bin Sa'id], ia berkata; [Ali bin Abi Thalib] berkata, \"Aku tidak pernah menetapkan hukuman diyat (denda) bagi orang yang aku diberi hukuman had, kecuali peminum khamar. Sesungguhnya Rasul shallallahu 'alaihi wasallam tidak pernah memberlakukan hal tersebut sama sekali. Sungguh kamilah yang memberlakukannya.\""},"2525":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ جَمِيعًا عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضْرِبُ فِي الْخَمْرِ بِالنِّعَالِ وَالْجَرِيدِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami], telah menceritakan kepada kami [Yazid bin Zura'i] telah menceritakan kepada kami [Sa'id], Demikian juga diriwayatkan dari jalur lain, telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'] dari [Hisyam Ad Dastuwa'i] semuanya dari [Qatadah] dari [Anas bin Malik], ia berkata, \"Rasulullah menghukum orang yang meminum khamer dengan memukulnya menggunakan sandal dan pelapah kurma.\""},"2526":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ عَبْدِ اللَّهِ بْنِ الدَّانَاجِ سَمِعْتُ حُضَيْنَ بْنَ الْمُنْذِرِ الرَّقَاشِيَّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ فَيْرُوزَ الدَّانَاجُ قَالَ حَدَّثَنِي حُضَيْنُ بْنُ الْمُنْذِرِ قَالَلَمَّا جِيءَ بِالْوَلِيدِ بْنِ عُقْبَةَ إِلَى عُثْمَانَ قَدْ شَهِدُوا عَلَيْهِ قَالَ لِعَلِيٍّ دُونَكَ ابْنَ عَمِّكَ فَأَقِمْ عَلَيْهِ الْحَدَّ فَجَلَدَهُ عَلِيٌّ وَقَالَ جَلَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعِينَ وَجَلَدَ أَبُو بَكْرٍ أَرْبَعِينَ وَجَلَدَ عُمَرُ ثَمَانِينَ وَكُلٌّ سُنَّةٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Ibnu Ulayyah] dari [Sa'id bin Abu Arubah] dari [Abdullah bin Danaj], aku mendengar [Hudlain bin Mundzir Ar Raqasyi], telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Syawarib], telah menceritakan kepada kami [Abdul Aziz bin Mukhtar], telah menceritakan kepada kami [Abdullah bin Fairuz Ad Daanaj], ia berkata; telah menceritakan kepadaku [Hudhain bin Mundzir], ia berkata, \"Ketika Walid bin Uqbah dibawa kepada Utsman karena masyarakat telah menyaksikannya meminum khamer, Hudhain bin Mundzir berkata kepada Ali: Silahkan ini anak pamanmu! laksanakan hukuman had padanya, maka [Ali] pun menderanya dan berkata; \"Rasulullah shallallahu 'alaihi wasallam melakukan empat puluh kali deraan, Abu Bakar empat puluh kali, Umar delapan peluh kali dan semuanya adalah Sunnah.\""},"2527":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْحَارِثِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَكِرَ فَاجْلِدُوهُ فَإِنْ عَادَ فَاجْلِدُوهُ فَإِنْ عَادَ فَاجْلِدُوهُ ثُمَّ قَالَ فِي الرَّابِعَةِ فَإِنْ عَادَ فَاضْرِبُوا عُنُقَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Syababah] dari [Ibnu Abu Dzi'b] dari [Al Harits] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seseorang mabuk, maka kalian harus menghukumnya dengan hukuman dera, Apabila ia mengulanginya, maka kalian harus menghukum dera kembali. Dan apabila mengulangi lagi, maka kalian harus menghukumnya dengan hukuman dera kembali. Rasulullah shallallahu 'alaihi wasallam bersabda pada yang ke empat kalinya: 'Apabila ia mengulanginya lagi, tebaslah lehernya.'"},"2528":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ ذَكْوَانَ أَبِي صَالِحٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَرِبُوا الْخَمْرَ فَاجْلِدُوهُمْ ثُمَّ إِذَا شَرِبُوا فَاجْلِدُوهُمْ ثُمَّ إِذَا شَرِبُوا فَاجْلِدُوهُمْ ثُمَّ إِذَا شَرِبُوا فَاقْتُلُوهُمْ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar], telah menceritakan kepada kami [Syu'aib bin Ishaq], telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Ashim bin Bahdalah] dari [Dzakwan Abu Shalih] dari [Mu'awiiyah bin Abu Sufyan]; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila mereka meminum Khamr maka cambuklah mereka, kemudian meminum lagi maka cambuklah mereka, kemudian minum lagi maka cambuklah mereka, kemudian minum lagi maka bunuhlah mereka.\""},"2529":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ سَعِيدِ بْنِ سَعْدِ بْنِ عُبَادَةَ قَالَكَانَ بَيْنَ أَبْيَاتِنَا رَجُلٌ مُخْدَجٌ ضَعِيفٌ فَلَمْ يُرَعْ إِلَّا وَهُوَ عَلَى أَمَةٍ مِنْ إِمَاءِ الدَّارِ يَخْبُثُ بِهَا فَرَفَعَ شَأْنَهُ سَعْدُ بْنُ عُبَادَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اجْلِدُوهُ ضَرْبَ مِائَةِ سَوْطٍ قَالُوا يَا نَبِيَّ اللَّهِ هُوَ أَضْعَفُ مِنْ ذَلِكَ لَوْ ضَرَبْنَاهُ مِائَةَ سَوْطٍ مَاتَ قَالَ فَخُذُوا لَهُ عِثْكَالًا فِيهِ مِائَةُ شِمْرَاخٍ فَاضْرِبُوهُ ضَرْبَةً وَاحِدَةًحَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ سَعْدِ بْنِ عُبَادَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abdullah bin Numair], telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Ya'qub bin Abdullah bin Al Asyajj] dari [Abu Umamah bin Sahal bin Hunaif] dari [Sa'id bin Sa'd bin Ubadah], ia berkata; \"Di sekitar rumah kami ada seorang laki-laki pendek dan sudah tua, kami tidak memperhatikan dirinya kecuali di saat ia telah melakukan perbuatan zina dengan seorang budak rumahan, peristiwa itu diadukan oleh [Sa'd bin Ubadah] kepada Rasulullah Shalallahu 'alaihi wa salam, lalu beliau bersabda: \"Hukumlah dengan hukuman dera sebanyak seratus kali dera. \" Mereka menjawab, \"Wahai Nabi Allah! Laki-laki itu sangat lemah, seandainya kita mencambuknya seratus kali, niscaya akan mati, Rasulullah shallallahu 'alaihi wasallam menjawab, \"Ambillah oleh kalian satu batang yang terdapat seratus dahan kurma, lalu pukulkanlah ia dengannya sekali saja.\" Telah menceritakan kepada kami [Sufyan bin Waki'], telah menceritakan kepada kami [Al Muharibi] dari [Muhammad bin Ishaq] dari [Ya'qub bin Abdullah] dari [Abu Umamah bin Sahal] dari [Sa'd bin Ubadah] dari Nabi Shalallahu 'alaihi wa salam dengan Hadits yang serupa."},"2530":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ و حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ و حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ أَبِي مَعْشَرٍ عَنْ مُحَمَّدِ بْنِ كَعْبٍ وَمُوسَى بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَمَلَ عَلَيْنَا السِّلَاحَ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib], telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] ia berkata; dan telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Ibnu Ajlan] dari [Bapaknya] dari [Abu Hurairah] dia berkata; Telah menceritakan kepada kami [Anas bin Iyadl] dari [Abu Masy'ar] dari [Muhammad bin Ka'ab] dan [Musa bin Yasar] dari [Abu Hurairah] bahwa sesungguhnya Nabi Muhammad shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menghunuskan pedangnya kepada kami, maka ia bukan dari golongan kami.\""},"2531":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ الْبَرَّادِ بْنِ يُوسُفَ بْنِ بُرَيْدِ بْنِ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَمَلَ عَلَيْنَا السِّلَاحَ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Barrad bin Yusuf bin Buraid bin Abu Burdah bin Abu Musa Al `Asy'ari] berkata; telah menceritakan kepada kami [Abu Usamah] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa yang menghunuskan pedang (untuk menyerang) kami, maka ia bukan dari golongan kami.\""},"2532":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ وَأَبُو كُرَيْبٍ وَيُوسُفُ بْنُ مُوسَى وَعَبْدُ اللَّهِ بْنُ الْبَرَّادِ قَالُوا حَدَّثَنَا أَبُو أُسَامَةُ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ مَنْ شَهَرَ عَلَيْنَا السِّلَاحَ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] dan [Abu Kuraib] dan [Yusuf bin Musa] dan [Abdullah bin Al Barrad], semuanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa Al Asy'ari], ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menghunus pedang kepada kami, maka bukan dari golongan kami.\""},"2533":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ أُنَاسًا مِنْ عُرَيْنَةَ قَدِمُوا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَقَالَ لَوْ خَرَجْتُمْ إِلَى ذَوْدٍ لَنَا فَشَرِبْتُمْ مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَفَعَلُوا فَارْتَدُّوا عَنْ الْإِسْلَامِ وَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا ذَوْدَهُ فَبَعَثَ رَسُولُ اللَّهِ فِي طَلَبِهِمْ فَجِيءَ بِهِمْ فَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَرَ أَعْيُنَهُمْ وَتَرَكَهُمْ بِالْحَرَّةِ حَتَّى مَاتُوا","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami], telah menceritakan kepada kami [Abdul Wahab], telah menceritakan kepada kami [Humaid] dari [Anas bin Malik] bahwa sekelompok manusia dari Urainah datang ke Madinah di zaman Rasulullah Shalallahu 'alaihi wa salam karena sakit perut, Anas bin Malik berkata, \"Alangkah baiknya kalian keluar menuju hewan ternak unta, lalu kalian minum susu dan air seni unta-unta tersebut. Maka mereka melakukan tersebut lalu keluar dari Islam dan membunuh pengembala Rasulullah Shalallahu 'alaihi wa salam dan menyembelih hewan ternak tersebut. Maka Rasulullah Shalallahu 'alaihi wa salam mengirimkan utusan untuk mencari mereka. Kemudian mendatangi mereka dan memotong tangan, kaki serta membutakan mata mereka kemudian membiarkan mereka di kawasan panas bebatuan sampai mereka mati.\""},"2534":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْوَزِيرِ حَدَّثَنَا الدَّرَاوَرْدِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ قَوْمًا أَغَارُوا عَلَى لِقَاحِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَطَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Muhamad bin Al Mutsanna], keduanya berkata; telah menceritakan kepada kami [Ibrahim bin Abu Al Wazir], telah menceritakan kepada kami [Ad Darawardi] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Aisyah]: bahwasanya sebuah kaum mencincang (membunuh dengan kebencian) unta milik Rasulullah shallallahu 'alaihi wasallam yang banyak memiliki susu dan hendak melahirkan, maka beliau shallallahu 'alaihi wasallam memotong tangan dan kaki mereka, serta mencungkil mata mereka (dengan besi panas).\""},"2535":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Thalhah bin Abdullah bin Auf] dari [Sa'id bin Zaid bin Amru bin Nufail] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang terbunuh karena mempertahankan hartanya, maka ia adalah seorang syahid. \""},"2536":{"ar":"حَدَّثَنَا الْخَلِيلُ بْنُ عَمْرٍو حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا يَزِيدُ بْنُ سِنَانٍ الْجَزَرِيُّ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُتِيَ عِنْدَ مَالِهِ فَقُوتِلَ فَقَاتَلَ فَقُتِلَ فَهُوَ شَهِيدٌ","id":"Telah menceritakan kepada kami [Khalil bin Amru], telah menceritakan kepada kami [Marwan bin Mu'awiyah], telah menceritakan kepada kami [Yazid bin Sinan Al Jazari] dari [Maimun bin Mihran] dari [Ibnu Umar], ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang hartanya dirampok lalu ia diserang dan kemudian melawan namun terbunuh, maka ia mati syahid. \""},"2537":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُطَّلِبِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُرِيدَ مَالُهُ ظُلْمًا فَقُتِلَ فَهُوَ شَهِيدٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Abu Amir], telah menceritakan kepada kami [Abdul Aziz bin Al Muthallib] dari [Abdullah bin Al Hasan] dari [Abdurrahman Al `A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang hartanya ingin dimiliki secara zalim oleh orang lain lalu ia terbunuh, maka ia mati syahid.\""},"2538":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ اللَّهُ السَّارِقَ يَسْرِقُ الْبَيْضَةَ فَتُقْطَعُ يَدُهُ وَيَسْرِقُ الْحَبْلَ فَتُقْطَعُ يَدُهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abu Mu'awiyah] dari [`Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah subhanahu wata'ala melaknat seorang pencuri yang mencuri sebutir telur lalu dipotong tangannya dan mencuri seutas tali lalu dipotong.\""},"2539":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَطَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مِجَنٍّ قِيمَتُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Ali bin Mushir] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata, \"Nabi shallallahu 'alaihi wasallam memotong tangan seseorang yang mencuri perisai yang nilainya tiga dirham.\""},"2540":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ عَمْرَةَ أَخْبَرَتْهُ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْطَعُ الْيَدُ إِلَّا فِي رُبُعِ دِينَارٍ فَصَاعِدًا","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani], telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] bahwa [Amrah] mengkabarinya dari [Aisyah], ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dipotong tangan seorang pencuri, kecuali barang yang dicurinya bernilai seperempat dinar atau lebih.\""},"2541":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو هِشَامٍ الْمَخْزُومِيُّ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَبُو وَاقِدٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقْطَعُ يَدُ السَّارِقِ فِي ثَمَنِ الْمِجَنِّ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Abu Hisyam Al Makhzumi], telah menceritakan kepada kami [Wuhaib], telah menceritakan kepada kami [Abu Waqid] dari [Amir bin Sa'd] dari [Ayahnya] dari Nabi Shalallahu 'alaihi wa salam bersabda: \"Tangan seorang pencuri dipotong seharga perisai perang.\""},"2542":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ وَمُحَمَّدُ بْنُ بَشَّارٍ وَأَبُو سَلَمَةَ الْجُوبَارِيُّ يَحْيَى بْنُ خَلَفٍ قَالُوا حَدَّثَنَا عُمَرُ بْنُ عَلِيِّ بْنِ عَطَاءِ بْنِ مُقَدَّمٍ عَنْ حَجَّاجٍ عَنْ مَكْحُولٍ عَنْ ابْنِ مُحَيْرِيزٍ قَالَسَأَلْتُ فَضَالَةَ بْنَ عُبَيْدٍ عَنْ تَعْلِيقِ الْيَدِ فِي الْعُنُقِ فَقَالَ السُّنَّةُ قَطَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ رَجُلٍ ثُمَّ عَلَّقَهَا فِي عُنُقِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Bisyr Bakar bin Khalaf] dan [Muhammad bin Basyar] serta [Abu Salamah Al Jubari Yahya bin Khalaf], semuanya berkata; telah menceritakan kepada kami [Umar bin Ali bin Atha` bin Muqaddam] dari [Hajjaj] dari [Makhul] dari [Ibnu Muhairiz], ia berkata; \"Aku bertanya kepada [Fadlalah bin 'Ubaid] tentang menggantungkan tangan dileher, maka dia menjawab; \"Termasuk Sunnah Rasulullah shallallahu 'alaihi wasallam beliau memotong tangan seorang lelaki kemudian menggantungkannya di lehernya.\""},"2543":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَنْبَأَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ ثَعْلَبَةَ الْأَنْصَارِيِّ عَنْ أَبِيهِأَنَّ عَمْرَو بْنَ سَمُرَةَ بْنِ حَبِيبِ بْنِ عَبْدِ شَمْسٍ جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي سَرَقْتُ جَمَلًا لِبَنِي فُلَانٍ فَطَهِّرْنِي فَأَرْسَلَ إِلَيْهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّا افْتَقَدْنَا جَمَلًا لَنَا فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُطِعَتْ يَدُهُقَالَ ثَعْلَبَةُ أَنَا أَنْظُرُ إِلَيْهِ حِينَ وَقَعَتْ يَدُهُ وَهُوَ يَقُولُ الْحَمْدُ لِلَّهِ الَّذِي طَهَّرَنِي مِنْكِ أَرَدْتِ أَنْ تُدْخِلِي جَسَدِي النَّارَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Ibnu Abu Maryam], telah memberitakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Abdurrahman bin Tsa'labah Al Anshari] dari [Ayahnya]; bahwa Amru bin Samurah bin Habib bin Abdu Syams mendatangi Rasulullah Shalallahu 'alaihi wa salam dan berkata; \"Wahai Rasulullah, aku telah mencuri seekor unta milik bani Fulan, bersihkanlah aku!.\" Maka Nabi shallallahu 'alaihi wasallam mengirim kepada bani Fulan, dan mereka berkata; \" kami telah kehilangan unta kami\". Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk menegakkan hukuman kepadanya, sehingga tangannya dipotong. Berkata Tsa'labah; \"Aku melihatnya tatkala tangannya jatuh dan dia berkata; \" segala puji bagi Allah yang telah mensucikanku dari dirimu (tangan) yang ingin memasukkan jasadku ke neraka.\""},"2544":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ أَبِي عَوَانَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَرَقَ الْعَبْدُ فَبِيعُوهُ وَلَوْ بِنَشٍّ","id":"Telah menceritakan kepada kami [Abu bakar bin Abu Syaibah], telah menceritakan kepada kami [Abu Usamah] dari [Abu 'Awanah] dari [Umar bin Abu Salamah] dari [Ayahnya] dari [Abu Hurairah] berkata; Rasulullah Shalallahu 'alaihi wa salam bersabda: \"Apabila seorang budak mencuri maka juallah walau seharga setengah uqiyah.\""},"2545":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا حَجَّاجُ بْنُ تَمِيمٍ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍأَنَّ عَبْدًا مِنْ رَقِيقِ الْخُمُسِ سَرَقَ مِنْ الْخُمُسِ فَرُفِعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَقْطَعْهُ وَقَالَ مَالُ اللَّهِ عَزَّ وَجَلَّ سَرَقَ بَعْضُهُ بَعْضًا","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallas], telah menceritakan kepada kami [Hajjaj bin Tamim] dari [Maimun bin Mihran] dari [Ibnu 'Abbas]; sesungguhnya seorang budak dari kalangan budak seperlima harta rampasan perang mencuri sesuatu dari seperlima harta rampasan perang, maka dihadapkanlah kepada Nabi shallallahu 'alaihi wasallam dan beliau tidak memotongnya, beliau bersabda: \"Harta Allah Azza wa Jalla, sebagian mencuri sebagian yang lain.\""},"2546":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُقْطَعُ الْخَائِنُ وَلَا الْمُنْتَهِبُ وَلَا الْمُخْتَلِسُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir bin Abdullah], sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang pengkhianat, perampas dan pencopet tidak dipotong tangannya!.\""},"2547":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَاصِمِ بْنِ جَعْفَرٍ الْمِصْرِيُّ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ عَلَى الْمُخْتَلِسِ قَطْعٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Muhammad bin Ashim bin Ja'far Al Mishri], telah menceritakan kepada kami [Al Mufadlal bin Fadlalah] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari [Ibrahim bin Abdurrahman bin 'Auf], dari [Ayahnya] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidak ada hukuman potong tangan bagi seorang pencopet.\""},"2548":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari Pamannya [Wasi' bin Habban] dari [Rafi' bin Khadij] berkata; Rasulullah Shalallahu 'alaihi wa salam bersabda: \"Tidak ada hukum potong tangan atas pencuri buah-buahan dan getah kurma.\""},"2549":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سَعْدُ بْنُ سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَخِيهِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], telah menceritakan kepada kami [Sa'ad bin Sa'id Al Maqburi] dari [Saudaranya] dari [Ayahnya] dari [Abu Hurairah], ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hukum potong tangan atas pencuri buah dan juga getah kurma.\""},"2550":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ صَفْوَانَ عَنْ أَبِيهِأَنَّهُ نَامَ فِي الْمَسْجِدِ وَتَوَسَّدَ رِدَاءَهُ فَأُخِذَ مِنْ تَحْتِ رَأْسِهِ فَجَاءَ بِسَارِقِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْطَعَ فَقَالَ صَفْوَانُ يَا رَسُولَ اللَّهِ لَمْ أُرِدْ هَذَا رِدَائِي عَلَيْهِ صَدَقَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا قَبْلَ أَنْ تَأْتِيَنِي بِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Syababah] dari [Malik bin Anas] dari [Az Zuhri] dari [Abdullah bin Shafwan], dari [Bapaknya] bahwa Ia sedang tidur di sebuah masjid berbantalkan selendangnya, lalu selendang tersebut diambil oleh seseorang dari bawah kepalanya. Kemudian ia datang menemui Nabi shallallahu 'alaihi wasallam dengan membawa pencuri selendangnya itu. Nabi shallallahu 'alaihi wasallam memerintahkan agar tangan si pencuri dipotong, Shafwan berkata; \"Wahai Rasulullah! Aku tidak menginginkan hal ini. Biarlah selendangku sebagai sedekah untuknya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mengapa tidak kau lakukan itu sebelum kau bawa permasalahan ini padaku! \""},"2551":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَجُلًا مِنْ مُزَيْنَةَ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الثِّمَارِ فَقَالَ مَا أُخِذَ فِي أَكْمَامِهِ فَاحْتُمِلَ فَثَمَنُهُ وَمِثْلُهُ مَعَهُ وَمَا كَانَ مِنْ الْجَرِينِ فَفِيهِ الْقَطْعُ إِذَا بَلَغَ ثَمَنَ الْمِجَنِّ وَإِنْ أَكَلَ وَلَمْ يَأْخُذْ فَلَيْسَ عَلَيْهِ قَالَ الشَّاةُ الْحَرِيسَةُ مِنْهُنَّ يَا رَسُولَ اللَّهِ قَالَ ثَمَنُهَا وَمِثْلُهُ مَعَهُ وَالنَّكَالُ وَمَا كَانَ فِي الْمُرَاحِ فَفِيهِ الْقَطْعُ إِذَا كَانَ مَا يَأْخُذُ مِنْ ذَلِكَ ثَمَنَ الْمِجَنِّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa seseorang dari Muzainah bertanya kepada Nabi shallallahu 'alaihi wasallam tentang buah-buahan, maka beliau menjawab: \"Apa yang diambil dari mayangnya, maka dia menanggung harganya dan yang serupa dengannya. Sementara buah-buahan yang berada pada tempat penebahan biji, maka si pencuri harus dipotong tangannya apabila mencapai harga sebuah perisai. Dan apabila ia hanya memakannya saja dan tidak mengambilnya, maka ia tidak terkena potong tangan. \"Lalu ia bertanya, \"Bagaimana dengan kambing yang berkeliaran di gunung-gunung yang ada penjaganya, wahai Rasulullah?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Dihitung nilainya dan yang sejenisnya, dan orang yang mengambilnya dihukum. Sementara kambing yang dikurung dan yang berada di dalam kandang, maka seseorang dipotong tangannya apabila kambing yang diambil sama nilainya dengan sebuah perisai."},"2552":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ إِسْحَقَ بْنِ أَبِي طَلْحَةَ قَالَ سَمِعْتُ أَبَا الْمُنْذِرِ مَوْلَى أَبِي ذَرٍّ يَذْكُرُ أَنَّ أَبَا أُمَيَّةَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلِصٍّ فَاعْتَرَفَ اعْتِرَافًا وَلَمْ يُوجَدْ مَعَهُ الْمَتَاعُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا إِخَالُكَ سَرَقْتَ قَالَ بَلَى ثُمَّ قَالَ مَا إِخَالُكَ سَرَقْتَ قَالَ بَلَى فَأَمَرَ بِهِ فَقُطِعَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ قَالَ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ قَالَ اللَّهُمَّ تُبْ عَلَيْهِ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] Telah menceritakan kepada kami [Sa'id bin Yahya] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Ishaq bin Abu Thalhah] dia berkata; Aku mendengar [Abu Mudzir] -mantan budak- Abu Dzar menyebutkan bahwa [Abu Umayyah] telah menceritakan kepadanya, sesungguhnya seorang pencuri suatu ketika dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam, lalu ia mengakuinya namun barangnya tidak bersamanya. Rasulullah Shallallahu'alaihiWasallam bersabda kepadanya; \"Apakah kau yakin telah mencuri?.\" Orang itu menjawab; Betul, aku telah mencuri. Lalu Rasulullah Shallallahu'alaihiWasallam bertanya lagi; \"Apakah kau yakin telah mencuri?.\" Orang itu menjawab; Betul, aku telah mencuri. kemudian Rasulullah Shallallahu'alaihi Wasallam menyuruh untuk dipotong tangannya.\" kemudian Rasulullah Shallallahu'alaihiWasallam bersabda padanya; \"Ucapkan; Aku meminta ampun pada Allah dan bertaubat pada-Nya.\" Ia berkata; Aku meminta ampun pada Allah dan bertaubat pada-Nya. Rasulullah Shallallahu'alaihi Wasallam bersabda; \"Ya Allah! terimalah taubatnya.\" -beliau ucapkan sebanyak dua kali.-"},"2553":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ وَأَيُّوبُ بْنُ مُحَمَّدٍ الْوَزَّانُ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالُوا حَدَّثَنَا مُعَمَّرُ بْنُ سُلَيْمَانَ أَنْبَأَنَا الْحَجَّاجُ بْنُ أَرْطَاةَ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَاسْتُكْرِهَتْ امْرَأَةٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَرَأَ عَنْهَا الْحَدَّ وَأَقَامَهُ عَلَى الَّذِي أَصَابَهَا وَلَمْ يَذْكُرْ أَنَّهُ جَعَلَ لَهَا مَهْرًا","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] dan [Ayyub bin Muhammad Al Wazzan] dan [Abdullah bin Sa'id], semuanya berkata; telah menceritakan kepada kami [Ma'mar bin Sulaiman], telah memberitakan keapda kami [Al Hajjaj bin Arthah] dari [Abdul Jabbar bin Wail] dari [Ayahnya], ia berkata, \"Seorang wanita dipaksa melakukan hubungan seksual di masa Rasulullah shallallahu 'alaihi wasallam, kemudian hukuman hudud tidak diberlakukan padanya. Akhirnya hukuman hudud tersebut dilaksanakan pada laki-laki yang menodainya, dimana ia tidak mengemukakan bahwa dirinya telah memberikan maskawin kepada wanita tersebut.\""},"2554":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ ح و حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا أَبُو حَفْصٍ الْأَبَّارُ جَمِيعًا عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُقَامُ الْحُدُودُ فِي الْمَسَاجِدِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id], telah menceritakan kepada kami [Ali bin Mushir], telah menceritakan kepada kami [Hasan bin Arafah], telah menceritakan kepada kami [Abu Hafsh Al Abbar] semuanya dari [Isma'il bin Muslim] dari [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas], \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: 'Hukuman hudud tidak boleh dilakukan di masjid-masjid.\""},"2555":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ لَهِيعَةَ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ أَنَّهُ سَمِعَ عَمْرَو بْنَ شُعَيْبٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ جَلْدِ الْحَدِّ فِي الْمَسَاجِدِ","id":"Telah menceritakan kepada kami [Muhamad bin Rumh], telah memberitakan kepada kami [Abdullah bin Lahi'ah] dari [Muhammad bin Ajlan] bahwa ia mendengar [Amru bin Syu'aib] menceritakan dari [Ayahnya] dari [Kakeknya] bahwa sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang melaksanakan hukuman dera (cambuk) di masjid-masjid.\""},"2556":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أَب��ي بُرْدَةَ بْنِ نِيَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَا يُجْلَدُ أَحَدٌ فَوْقَ عَشْرِ جَلَدَاتٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh], telah memberitakan keapda kami [Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Bukair bin Abdullah bin Al Asyajj] dari [Sulaiman bin Yasar] dari [Abdurrahman bin Jabir bin Abdullah] dari [Abu Burdah bin Niyar], Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang tidak boleh didera lebih dari sepuluh kali deraan, kecuali di dalam salah satu hukum hudud.\""},"2557":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا عَبَّادُ بْنُ كَثِيرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُعَزِّرُوا فَوْقَ عَشَرَةِ أَسْوَاطٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar], telah menceritakan kepada kami [Isma'il bin Ayyasy], telah menceritakan kepada kami [Abbad bin Katsir] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam Bersabda: \"Janganlah kalian menta'zir (memberi sangsi) di atas sepuluh cambukan.\""},"2558":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ وَابْنُ أَبِي عَدِيٍّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَصَابَ مِنْكُمْ حَدًّا فَعُجِّلَتْ لَهُ عُقُوبَتُهُ فَهُوَ كَفَّارَتُهُ وَإِلَّا فَأَمْرُهُ إِلَى اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna], telah menceritakan kepada kami [Abdul Wahab] dan [Ibnu Abu Adi] dari [Khalid Al Khadza`] dari [Abu Qilabah] dari [Abul `Asy'ats] dari [Ubadah bin Shamit], ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diantara kalian terkena hukum hudud maka mempercepat hukuman adalah kafaratnya. Sementara apabila tidak dipercepat, maka urusannya dikembalikan kepada Allah.\""},"2559":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي جُحَيْفَةَ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَصَابَ فِي الدُّنْيَا ذَنْبًا فَعُوقِبَ بِهِ فَاللَّهُ أَعْدَلُ مِنْ أَنْ يُثَنِّيَ عُقُوبَتَهُ عَلَى عَبْدِهِ وَمَنْ أَذْنَبَ ذَنْبًا فِي الدُّنْيَا فَسَتَرَهُ اللَّهُ عَلَيْهِ فَاللَّهُ أَكْرَمُ مِنْ أَنْ يَعُودَ فِي شَيْءٍ قَدْ عَفَا عَنْهُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah Hammal], telah menceritakan kepada kami [Hajjaj bin Muhammad], telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Abu Ishaq] dari [Abu Juhaifah] dari [Ali], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa melakukan dosa di dunia kemudian dia dihukum karenanya, Maka hal itu karena Allah lebih adil dari melipatkan siksaan-Nya terhadap hambanya. Dan barang siapa berbuat dosa di dunia kemudian Allah menutupinya, maka hal itu karena Allah lebih mulia dari mengulangi sesuatu yang telah Ia maafkan.\""},"2560":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ وَمُحَمَّدُ بْنُ عُبَيْدٍ الْمَدِينِيُّ أَبُو عُبَيْدٍ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ سَعْدَ بْنَ عُبَادَةَ الْأَنْصَارِيَّ قَالَ يَا رَسُولَ اللَّهِ الرَّجُلُ يَجِدُ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَالَ سَعْدٌ بَلَى وَالَّذِي أَكْرَمَكَ بِالْحَقِّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمَعُوا مَا يَقُولُ سَيِّدُكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] dan [Muhammad bin Ubaid Al Madini Abu Ubaid], keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah], ia berkata, \"Sesungguhnya Sa'd bin Ubadah Al Anshari, ia berkata, \"Wahai Rasulullah! \"Ada seorang suami yang menjumpai isterinya tengah bersama laki-laki lain, apakah ia boleh membunuh lelaki itu? Rasulullah shallallahu 'alaihi wasallam menjawab, \"Tidak.\" Sa'd berkata, \"Tentu, demi Allah yang telah memuliakanmu dengan kebenaran! Rasulullah shallallahu 'alaihi wasallam berkata, \"Dengarkanlah apa yang dikemukakan pemimpin kalian.\""},"2561":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْفَضْلِ بْنِ دَلْهَمٍ عَنْ الْحَسَنِ عَنْ قَبِيصَةَ بْنِ حُرَيْثٍ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِ قَالَقِيلَ لِأَبِي ثَابِتٍ سَعْدِ بْنِ عُبَادَةَ حِينَ نَزَلَتْ آيَةُ الْحُدُودِ وَكَانَ رَجُلًا غَيُورًا أَرَأَيْتَ لَوْ أَنَّكَ وَجَدْتَ مَعَ امْرَأَتِكَ رَجُلًا أَيَّ شَيْءٍ كُنْتَ تَصْنَعُ قَالَ كُنْتُ ضَارِبَهُمَا بِالسَّيْفِ أَنْتَظِرُ حَتَّى أَجِيءَ بِأَرْبَعَةٍ إِلَى مَا ذَاكَ قَدْ قَضَى حَاجَتَهُ وَذَهَبَ أَوْ أَقُولُ رَأَيْتُ كَذَا وَكَذَا فَتَضْرِبُونِي الْحَدَّ وَلَا تَقْبَلُوا لِي شَهَادَةً أَبَدًا قَالَ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَفَى بِالسَّيْفِ شَاهِدًا ثُمَّ قَالَ لَا إِنِّي أَخَافُ أَنْ يَتَتَابَعَ فِي ذَلِكَ السَّكْرَانُ وَالْغَيْرَانُقَالَ أَبُو عَبْدِ اللَّهِ يَعْنِي ابْنَ مَاجَهْ سَمِعْتُ أَبَا زُرْعَةَ يَقُولُ هَذَا حَدِيثُ عَلِيِّ بْنِ مُحَمَّدٍ الطَّنَافِسِيِّ وَفَاتَنِي مِنْهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'] dari [Fadhal bin Dalham] dari [Al Hasan] dari [Qubishah bin Huraits] dari [Salamah bin Al Muhabbiq] berkata; Telah dikatakan kepada Abu Tsabit, Sa'd Bin 'Ubadah, tatkala turun ayat hudud, dan ia adalah seorang lelaki yang pencemburu; \"Apa pandanganmu jika kamu mendapati seorang lelaki bersama istrimu? Apa yang akan kamu lakukan?\" Ia menjawab; \"Aku akan memukul keduanya dengan pedang sampai aku mendatangkan empat orang hingga dia menyelesaikan hajatnya dan pergi atau aku akan berkata; \"aku melihat seperti ini dan seperti ini kemudian kalian melaksanakan had kepadaku dan kalian jangan menerima persaksianku selamanya.\" Ia berkata; maka hal itu disampaikan kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Cukuplah dengan pedang sebagai saksi.\" Kemudian beliau bersabda: \"Tidak, sesungguhnya aku khawatir itu merupakan pengaruh dari mabuk atau cemburu.\" Telah menceritakan kepada kami Abu Abdullah Ibnu Majah; aku mendengar Abu Zur'ah mengatakan hadits ini dari Ali bin Muhammad Ath Thanafisi."},"2562":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا هُشَيْمٌ ح و حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ جَمِيعًا عَنْ أَشْعَثَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَمَرَّ بِي خَالِي سَمَّاهُ هُشَيْمٌ فِي حَدِيثِهِ الْحَارِثَ بْنَ عَمْرٍو وَقَدْ عَقَدَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِوَاءً فَقُلْتُ لَهُ أَيْنَ تُرِيدُ فَقَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَجُلٍ تَزَوَّجَ امْرَأَةَ أَبِيهِ مِنْ بَعْدِهِ فَأَمَرَنِي أَنْ أَضْرِبَ عُنُقَهُ","id":"Telah menceritakan kepada kami [Isma'il bin Musa], telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Sahal bin Abu Sahal], telah menceritakan kepada kami [Hafsh bin Ghiyats] semuanya dari [`Asy'ats] dari [Adi bin Tsabit] dari [Al Barra` bin 'Azib], ia berkata, \"Aku bertemu dengan [Pamanku] yang disebut oleh Husyaim dalam haditsnya dengan nama Al Harits bin Amru, dan dia telah ditetapkan oleh Nabi sebagai pemegang bendera. Aku bertanya kepadanya, \"Anda hendak kemana?\" la menjawab, \"Rasulullah shallallahu 'alaihi wasallam mengutusku untuk menemui seorang laki-laki yang menikahi isteri ayahnya, lalu memerintahkanku untuk memenggal lehernya.\""},"2563":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ ابْنُ أَخِي الْحُسَيْنِ الْجُعْفِيِّ حَدَّثَنَا يُوسُفُ بْنُ مَنَازِلَ التَّيْمِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ خَالِدِ بْنِ أَبِي كَرِيمَةَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَجُلٍ تَزَوَّجَ امْرَأَةَ أَبِيهِ أَنْ أَضْرِبَ عُنُقَهُ وَأُصَفِّيَ مَالَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahman bin Akhi Al Husain Al Ju'fi], telah menceritakan kepada kami [Yusuf bin Manazil At Ataimi], telah menceritakan kepada kami [Abdullah bin Idris] dari [Khalid bin Abu Karimah] dari [Mu'awiyah bin Qurrah], dari [Bapaknya] ia berkata, \"Aku diutus oleh Rasululllah shallallahu 'alaihi wasallam untuk menjumpai seorang laki-laki yang menikah dengan isteri ayahnya, agar aku memenggal lehernya dan menyita hartanya.\""},"2564":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا ابْنُ أَبِي الضَّيْفِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ انْتَسَبَ إِلَى غَيْرِ أَبِيهِ أَوْ تَوَلَّى غَيْرَ مَوَالِيهِ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakar bin Khalaf], telah menceritakan kepada kami [Ibnu Abu Dlaif], telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menghubungkan nasabnya kepada selain ayahnya atau seorang budak mengaku sebagai budak kepada selain majikannya, maka laknat dari Allah, para malaikat dan manusia secara keseluruhan ditimpakan kepadanya'.\""},"2565":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ قَالَ سَمِعْتُ سَعْدًا وَأَبَا بَكْرَةَ وَكُلُّ وَاحِدٍ مِنْهُمَا يَقُولُسَمِعَتْ أُذُنَايَ وَوَعَى قَلْبِي مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ وَهُوَ يَعْلَمُ أَنَّهُ غَيْرُ أَبِيهِ فَالْجَنَّةُ عَلَيْهِ حَرَامٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Ashim Al Ahwal] dari [Abu Utsman An Nahdi] berkata; Aku mendengar [Sa'd] dan [Abu Bakrah], masing-masing dari keduanya berkata, \"Kedua telingaku mendengar dan hatiku memperhatikan Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mengaku-ngaku memiliki hubungan nasab kepada selain ayahnya, padahal ia tahu bahwa orang tersebut memang bukan ayahnya, maka surga menjadi haram baginya.\""},"2566":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ عَنْ عَبْدِ الْكَرِيمِ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ لَمْ يَرَحْ رَائِحَةَ الْجَنَّةِ وَإِنَّ رِيحَهَا لَيُوجَدُ مِنْ مَسِيرَةِ خَمْسِ مِائَةِ عَامٍ","id":"Telah menceritakan kepada kami [Muhammad bin Shabah], telah memberitakan kepada kami [Sufyan] dari [Abdul Karim] dari [Mujahid] dari [Abdullah bin Amru] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mengaku-ngaku memiliki hubungan nasab kepada selain ayahnya, maka surga menjadi haram baginya, padahal bau surga dapat dicium sepanjang jarak perjalanan lima ratus tahun.\""},"2567":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ ح و حَدَّثَنَا هَارُونُ بْنُ حَيَّانَ أَنْبَأَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُغِيرَةِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَقِيلِ بْنِ طَلْحَةَ السُّلَمِيِّ عَنْ مُسْلِمِ بْنِ هَيْضَمٍ عَنْ الْأَشْعَثِ بْنِ قَيْسٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى ال��َّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدِ كِنْدَةَ وَلَا يَرَوْنِي إِلَّا أَفْضَلَهُمْ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَسْتُمْ مِنَّا فَقَالَ نَحْنُ بَنُو النَّضْرِ بْنِ كِنَانَةَ لَا نَقْفُو أُمَّنَا وَلَا نَنْتَفِي مِنْ أَبِينَاقَالَ فَكَانَ الْأَشْعَثُ بْنُ قَيْسٍ يَقُولُ لَا أُوتِي بِرَجُلٍ نَفَى رَجُلًا مِنْ قُرَيْشٍ مِنْ النَّضْرِ بْنِ كِنَانَةَ إِلَّا جَلَدْتُهُ الْحَدَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Yazid bin Harun], telah menceritakan kepada kami [Hamad bin Salamah], telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Harun bin Hayyan], telah memberitakan kepada kami [Abdul Aziz bin Al Mughirah], keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Aqil bin Thalhah As Sulami] dari [Muslim bin Haidlam] dari [Al Asy'ats bin Qais], ia berkata; \"Aku datang menemui Rasulullah bersama delegasi bani Kindah. Mereka tidak mengenaliku kecuali aku sebagai seorang pembesar mereka. Aku tanyakan kepadanya, wahai Rasulullah, bukankah Anda termasuk golongan kami? Rasulullah shallallahu 'alaihi wasallam menjawab, \"Kami adalah bani Nadlr bin Kinanah. Kami tidak menghilangkan jejak ibunda kami, dan tidak mengabaikan ayahanda kami.\" Perawi berkata; \"Lalu Asy'ats berkata; \"Aku tidak akan mendatangkan orang yang telah meniadakan orang lain dari suku Quraisy, dari kabilah Nadhr bin Kinanah kecuali aku akan mencambuknya sebagai hukuman hudud.\""},"2568":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ أَبِي الرَّبِيعِ الْجُرْجَانِيُّ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنِي يَحْيَى بْنُ الْعَلَاءِ أَنَّهُ سَمِعَ بِشْرَ بْنَ نُمَيْرٍ أَنَّهُ سَمِعَ مَكْحُولًا يَقُولُ إِنَّهُ سَمِعَ يَزِيدَ بْنَ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ صَفْوَانَ بْنَ أُمَيَّةَ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ عَمْرُو بْنُ مُرَّةَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ قَدْ كَتَبَ عَلَيَّ الشِّقْوَةَ فَمَا أُرَانِي أُرْزَقُ إِلَّا مِنْ دُفِّي بِكَفِّي فَأْذَنْ لِي فِي الْغِنَاءِ فِي غَيْرِ فَاحِشَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا آذَنُ لَكَ وَلَا كَرَامَةَ وَلَا نُعْمَةَ عَيْنٍ كَذَبْتَ أَيْ عَدُوَّ اللَّهِ لَقَدْ رَزَقَكَ اللَّهُ طَيِّبًا حَلَالًا فَاخْتَرْتَ مَا حَرَّمَ اللَّهُ عَلَيْكَ مِنْ رِزْقِهِ مَكَانَ مَا أَحَلَّ اللَّهُ عَزَّ وَجَلَّ لَكَ مِنْ حَلَالِهِ وَلَوْ كُنْتُ تَقَدَّمْتُ إِلَيْكَ لَفَعَلْتُ بِكَ وَفَعَلْتُ قُمْ عَنِّي وَتُبْ إِلَى اللَّهِ أَمَا إِنَّكَ إِنْ فَعَلْتَ بَعْدَ التَّقْدِمَةِ إِلَيْكَ ضَرَبْتُكَ ضَرْبًا وَجِيعًا وَحَلَقْتُ رَأْسَكَ مُثْلَةً وَنَفَيْتُكَ مِنْ أَهْلِكَ وَأَحْلَلْتُ سَلَبَكَ نُهْبَةً لِفِتْيَانِ أَهْلِ الْمَدِينَةِ فَقَامَ عَمْرٌو وَبِهِ مِنْ الشَّرِّ وَالْخِزْيِ مَا لَا يَعْلَمُهُ إِلَّا اللَّهُ فَلَمَّا وَلَّى قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَؤُلَاءِ الْعُصَاةُ مَنْ مَاتَ مِنْهُمْ بِغَيْرِ تَوْبَةٍ حَشَرَهُ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ كَمَا كَانَ فِي الدُّنْيَا مُخَنَّثًا عُرْيَانًا لَا يَسْتَتِرُ مِنْ النَّاسِ بِهُدْبَةٍ كُلَّمَا قَامَ صُرِعَ","id":"Telah menceritakan kepada kami [Hasan bin Abu Rabi'Al Jurhani], telah memberitakan kepada kami [Abdurrazak], telah mengkabarkan kepadaku [Yahya bin 'Ala'] bahwa ia mendengar [Bisyr bin Numair], ia mendengar dari [Makhul], ia berkata; bahwa ia mendengar [Yazid bin Abdullah], ia mendengar dari [Shafwan bin Umaiyah], ia berkata; \"Ketika kami sedang bersama Rasulullah shallallahu 'alaihi wasallam, datanglah 'Amru bin Murrah dan berkata; \"Wahai Rasulullah, sesungguhnya Allah telah menentukan kemalangan kepada diriku, dan aku menganggap tidak akan mendapat rizki kecuali dari menabuh rebana dengan telapak tanganku, maka izinkanlah aku bernyanyi bukan di dalam hal yang keji\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak akan mengizinkanmu, dan tidak ada kemuliaan, serta kesejukan mata, engkau telah berdusta wahai musuh Allah. Sungguh Allah telah memberimu rizki yang baik dan halal, kemudian kamu memilih rizki yang diharamkan Allah kepadamu untuk mengganti sesuatu yang halal yang telah dihalalkan Allah untukmu, kalau saja aku mendekati dirimu, sungguh aku akan memukulmu dan memukulmu, bangun, pergi dariku dan bertaubatlah kepada Allah, dan jika kamu masih melakukan setelah kedatanganmu ini kepadaku, aku akan memukulmu dengan pukulan yang menyakitkan, aku akan mencukur rambutmu sebagai hukuman, aku akan mengusirmu dari keluargamu, dan aku halalkan merampas hartamu sebagai harta rampasan untuk pemuda-pemuda penduduk Madinah.\" Maka bangunlah 'Amru, keburukan dan hinaan, meskipun tidak ada yang mengetahuinya kecuali Allah Azza wa Jalla. Tatkala dia pergi, Nabi shallallahu 'alaihi wasallam bersabda: \"Mereka itu adalah orang-orang yang durhaka, jika di antara mereka mati sebelum bertaubah, Allah akan merugikannya di hari kiamat kelak sebagaimana dia ketika di dunianya menjadi bencong yang telanjang tidak dapat menutupi diri dari manusia meski dengan bulu mata pun, setiap kali dia bangun dia akan terbanting, \""},"2569":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَسَمِعَ مُخَنَّثًا وَهُوَ يَقُولُ لِعَبْدِ اللَّهِ بْنِ أَبِي أُمَيَّةَ إِنْ يَفْتَحْ اللَّهُ الطَّائِفَ غَدًا دَلَلْتُكَ عَلَى امْرَأَةٍ تُقْبِلُ بِأَرْبَعٍ وَتُدْبِرُ بِثَمَانٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْرِجُوهُمْ مِنْ بُيُوتِكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Zainab binti Ummu Salamah] dari [Ummi Salamah]; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam masuk untuk menemuinya, lalu ia mendengar seorang waria sedang berbicara kepada Abdullah bin Abu Umayyah dengan perkataannya; \"Apabila Allah subhanahu wata'ala membuka kota Thaif besok hari (menaklukkannya), maka akan aku tunjukkan kepadamu seorang wanita yang nampak dari depan memiliki empat lipatan (di perut) dan dari belakang nampak delapan lipatan.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keluarkanlah mereka dari rumah kalian.\""},"2570":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالُوا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَا يُقْضَى بَيْنَ النَّاسِ يَوْمَ الْقِيَامَةِ فِي الدِّمَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] dan [Muhammad bin Basyar], semuanya berkata; telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Al'A'masy] dari [Syaqiq] dari [Abdullah], Ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perkara yang pertama kali diadili pada manusia di hari Kiamat kelak adalah masalah pembunuhan.\""},"2571":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْتَلُ نَفْسٌ ظُلْمًا إِلَّا كَانَ عَلَى ابْنِ آدَمَ الْأَوَّلِ كِفْلٌ مِنْ دَمِهَا لِأَنَّهُ أَوَّلُ مَنْ سَنَّ الْقَتْلَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar], telah menceritakan kepada kami [Isa bin Yunus], telah menceritakan kepada kami [Al 'A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang dibunuh secara keji, melainkan dosa pembunuh tersebut juga akan ditimpakan kepada anak laki-laki pertama dari Nabi Adam, karena dialah yang pertama kali mencontohkan pembunuhan tersebut.\""},"2572":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ الْأَزْهَرِ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ شَرِيكٍ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَا يُقْضَى بَيْنَ النَّاسِ يَوْمَ الْقِيَامَةِ فِي الدِّمَاءِ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Azhar Al Wasithi], telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] dari [Syarik] dari [Ashim] dari [Abu Wa'il] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perkara pertama yang diadili pada manusia di hari Kiamat adalah masalah pembunuhan.\""},"2573":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَائِذٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَقِيَ اللَّهَ لَا يُشْرِكُ بِهِ شَيْئًا لَمْ يَتَنَدَّ بِدَمٍ حَرَامٍ دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Abdurrahman bin 'A'idz] dari [Uqbah bin Amir Al Juhani], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bertemu dengan Allah subhanahu wata'ala dalam keadaan tidak menyekutukan-Nya dengan sesuatu apapun, serta tidak pernah melakukan pembunuhan, maka ia pasti masuk surga.\""},"2574":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مَرْوَانُ بْنُ جَنَاحٍ عَنْ أَبِي الْجَهْمِ الْجُوْزَجَانِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَزَوَالُ الدُّنْيَا أَهْوَنُ عَلَى اللَّهِ مِنْ قَتْلِ مُؤْمِنٍ بِغَيْرِ حَقٍّ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar], telah menceritakan kepada kami [Walid bin Muslim], telah menceritakan kepada kami [Marwan bin Janah] dari [Abu Jahm Al Juzajani] dari [Al Bara bin Azib], sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kehancuran dunia (nilainya) lebih ringan di sisi Allah subhanahu wata'ala dari pada seseorang membunuh seorang mukmin tanpa hak.\""},"2575":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا يَزِيدُ بْنُ زِيَادٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعَانَ عَلَى قَتْلِ مُؤْمِنٍ بِشَطْرِ كَلِمَةٍ لَقِيَ اللَّهَ عَزَّ وَجَلَّ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ آيِسٌ مِنْ رَحْمَةِ اللَّهِ","id":"Telah menceritakan kepada kami [Amru bin Rafi'], telah menceritakan kepada kami [Marwan bin Mu'awiyah], telah menceritakan kepada kami [Yazid bin Ziyad] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa menolong untuk membunuh seorang mu'min meski dengan setengah kalimat, maka dia akan berjumpa dengan Allah dalam keadaan tertulis diantara kedua matanya; putus asa dari rahmat Allah.\""},"2576":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمَّارٍ الدُّهْنِيِّ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ قَالَسُئِلَ ابْنُ عَبَّاسٍ عَمَّنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا ثُمَّ تَابَ وَآمَنَ وَعَمِلَ صَالِحًا ثُمَّ اهْتَدَى قَالَ وَيْحَهُ وَأَنَّى لَهُ الْهُدَى سَمِعْتُ نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَجِيءُ الْقَاتِلُ وَالْمَقْتُولُ يَوْمَ الْقِيَامَةِ مُتَعَلِّقٌ بِرَأْسِ صَاحِبِهِ يَقُولُ رَبِّ سَلْ هَذَا لِمَ قَتَلَنِي وَاللَّهِ لَقَدْ أَنْزَلَهَا اللَّهُ عَزَّ وَجَلَّ عَلَى نَبِيِّكُمْ ثُمَّ مَا نَسَخَهَا بَعْدَمَا أَنْزَلَهَا","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ammar Ad Duhni] dari [Salim bin Abu Al Ja'd], ia berkata; \" [Ibnu Abbas] ditanya tentang seseorang yang membunuh seorang mukmin secara sengaja, lalu bertaubat, beriman dan beramal shalih kemudian ia mendapat hidayah?\" ia menjawab; Aku mendengar Nabi shallallahu 'alaihi wasallam kalian bersabda: \"Orang yang membunuh dan yang dibunuh akan datang di hari kiamat dalam keadaan bergantungan dengan kepala sahabatnya, lalu ia bertanya, 'Wahai Tuhanku! Tanyalah dia mengapa ia membunuhku? ' Demi Allah! Allah subhanahu wata'ala telah menurunkan ayat yang melarang pembunuhan kepada nabi kalian di mana Dia tidak menasakhnya setelah ayat tersebut diturunkan.\""},"2577":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا هَمَّامُ بْنُ يَحْيَى عَنْ قَتَادَةَ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأَلَا أُخْبِرُكُمْ بِمَا سَمِعْتُ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي إِنَّ عَبْدًا قَتَلَ تِسْعَةً وَتِسْعِينَ نَفْسًا ثُمَّ عَرَضَتْ لَهُ التَّوْبَةُ فَسَأَلَ عَنْ أَعْلَمِ أَهْلِ الْأَرْضِ فَدُلَّ عَلَى رَجُلٍ فَأَتَاهُ فَقَالَ إِنِّي قَتَلْتُ تِسْعَةً وَتِسْعِينَ نَفْسًا فَهَلْ لِي مِنْ تَوْبَةٍ قَالَ بَعْدَ تِسْعَةٍ وَتِسْعِينَ نَفْسًا قَالَ فَانْتَضَى سَيْفَهُ فَقَتَلَهُ فَأَكْمَلَ بِهِ الْمِائَةَ ثُمَّ عَرَضَتْ لَهُ التَّوْبَةُ فَسَأَلَ عَنْ أَعْلَمِ أَهْلِ الْأَرْضِ فَدُلَّ عَلَى رَجُلٍ فَأَتَاهُ فَقَالَ إِنِّي قَتَلْتُ مِائَةَ نَفْسٍ فَهَلْ لِي مِنْ تَوْبَةٍ فَقَالَ وَيْحَكَ وَمَنْ يَحُولُ بَيْنَكَ وَبَيْنَ التَّوْبَةِ اخْرُجْ مِنْ الْقَرْيَةِ الْخَبِيثَةِ الَّتِي أَنْتَ فِيهَا إِلَى الْقَرْيَةِ الصَّالِحَةِ قَرْيَةِ كَذَا وَكَذَا فَاعْبُدْ رَبَّكَ فِيهَا فَخَرَجَ يُرِيدُ الْقَرْيَةَ الصَّالِحَةَ فَعَرَضَ لَهُ أَجَلُهُ فِي الطَّرِيقِ فَاخْتَصَمَتْ فِيهِ مَلَائِكَةُ الرَّحْمَةِ وَمَلَائِكَةُ الْعَذَابِ قَالَ إِبْلِيسُ أَنَا أَوْلَى بِهِ إِنَّهُ لَمْ يَعْصِنِي سَاعَةً قَطُّ قَالَ فَقَالَتْ مَلَائِكَةُ الرَّحْمَةِ إِنَّهُ خَرَجَ تَائِبًاقَالَ هَمَّامٌ فَحَدَّثَنِي حُمَيْدٌ الطَّوِيلُ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي رَافِعٍ قَالَ فَبَعَثَ اللَّهُ عَزَّ وَجَلَّ مَلَكًا فَاخْتَصَمُوا إِلَيْهِ ثُمَّ رَجَعُوا فَقَالَ انْظُرُوا أَيَّ الْقَرْيَتَيْنِ كَانَتْ أَقْرَبَ فَأَلْحِقُوهُ بِأَهْلِهَا قَالَ قَتَادَةُ فَحَدَّثَنَا الْحَسَنُ قَالَ لَمَّا حَضَرَهُ الْمَوْتُ احْتَفَزَ بِنَفْسِهِ فَقَرُبَ مِنْ الْقَرْيَةِ الصَّالِحَةِ وَبَاعَدَ مِنْهُ الْقَرْيَةَ الْخَبِيثَةَ فَأَلْحَقُوهُ بِأَهْلِ الْقَرْيَةِ الصَّالِحَةِ حَدَّثَنَا أَبُو الْعَبَّاسِ بْنُ عَبْدِ اللَّهِ بْنِ إِسْمَعِيلَ الْبَغْدَادِيُّ حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Yazid bin Harun], telah memberitakan kepada kami [Hammam bin Yahya] dari [Qatadah] dari [Abu Shiddiq An Naji] dari [Abu Sa'id Al Khudri], ia berkata; \"Tidakkah ingin aku beritahukan kepada kalian sesuatu yang keluar dari mulut Rasulullah shallallahu 'alaihi wasallam? Aku mendengar dengan kedua telingaku dan hatiku menyimaknya, beliau bersabda: \"Sesungguhnya terdapat seseorang yang telah membunuh sembilan puluh sembilan orang, kemudian ia ingin bertaubat, lalu ia bertanya tentang seseorang yang paling alim di muka bumi ini. Kemudian ia ditunjukkan kepada seseorang. Ia pun mendatanginya dan berkata; \"Aku telah membunuh sembilan puluh sembilan orang, apakah masih ada taubat untukku? Orang tersebut berkata dengan nada terkejut, \"Apa? Telah membunuh sembilan puluh sembilan orang?\" Beliau melanjutkan; \"Akhimya pembunuh itu mengeluarkan pedangnya dan membunuh orang tersebut. Dengan demikian genaplah seratus orang yang dia bunuh. Dia pun masih berkeinginan taubat dan bertanya tentang orang paling alim di muka bumi. Kemudian ia ditunjukkan kepada seseorang dan ia pun mendatanginya. la bertanya; \"Aku telah membunuh seratus orang, maka apakah masih ada taubat untukku?\" Orang alim itu menjawab; \"Celakalah kau! Siapakah yang dapat menghalangimu untuk bertaubat? Keluarlah dari perkampungan yang buruk yang engkau telah diami dan pindahlah ke perkampungan yang baik, yaitu di kampung ini dan ini. Beribadahlah kepada Tuhanmu di sana. \" Lalu pembunuh itu pun keluar menuju perkampungan yang baik tersebut, namun ajal menjeputnya di tengah perjalanan. Kemudian malaikat rahmat dan malaikat azab saling berselisih. Iblis berkata; \"Akulah yang lebih berhak terhadap orang ini, ia tidak pernah menentang perintahku sama sekali. Malaikat rahmat menjawab, \"la telah keluar dalam rangka taubat.\" [Hammam] berkata; telah menceritakan kepadaku [Humaid At Thawil], telah menceritakan kepadaku dari [Bakar bin Abdullah] dari [Abu Rafi'], ia meriwayatkan; \"Allah subhanahu wata'ala mengutus para malaikat, mereka berseteru mengenai hal ini lalu mereka kembali. Allah subhanahu wata'ala lalu berfirman, \"Lihatlah, mana dintara dua perkampungan itu yang lebih dekat padanya (kampung maksiat atau kampung yang baik)?\" lalu golongkanlah ia pada penghuni kampung tersebut.\" [Qatadah] berkata; telah menceritakan kepada kami [Al Hasan], ia berkata, \"Saat ajal menjemputnya, ia melompat hingga lebih dekat kepada perkampungan yang baik, dan perkampungan yang buruk lebih jauh, Kemudian ia dianggap sebagai penduduk kampung yang baik.\" Telah menceritakan kepada kami Abu Al Abbas bin Abdullah bin Isma'il Al Baghdadi, telah menceritakan kepada kami 'Affan, telah menceritakan kepada kami Hammam, ia menyebutkan yang semisalnya."},"2578":{"ar":"حَدَّثَنَا عُثْمَانُ وَأَبُو بَكْرٍ ابْنَا أَبِي شَيْبَةَ قَالَا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ ح و حَدَّثَنَا أبُو بَكْرٍ وَعُثْمَانُ ابْنَا أَبِي شَيْبَةَ قَالَا حَدَّثَنَا جَرِيرٌ وَعَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ جَمِيعًا عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الْحَارِثِ بْنِ فُضَيْلٍ أَظُنُّهُ عَنْ ابْنِ أَبِي الْعَوْجَاءِ وَاسْمُهُ سُفْيَانُ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُصِيبَ بِدَمٍ أَوْ خَبْلٍ وَالْخَبْلُ الْجُرْحُ فَهُوَ بِالْخِيَارِ بَيْنَ إِحْدَى ثَلَاثٍ فَإِنْ أَرَادَ الرَّابِعَةَ فَخُذُوا عَلَى يَدَيْهِ أَنْ يَقْتُلَ أَوْ يَعْفُوَ أَوْ يَأْخُذَ الدِّيَةَ فَمَنْ فَعَلَ شَيْئًا مِنْ ذَلِكَ فَعَادَ فَإِنَّ لَهُ نَارَ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا","id":"Telah menceritakan kepada kami [Utsman] dan [Abu Bakar] keduanya anak Ibnu Syaibah, keduanya berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] (dari jalur lain) telah menceritakan kepada kami [Abu Bakr] dan [Utsman] keduanya putra Abu Syaibah, keduanya berkata; telah menceritakan kepada kami [Jarir] dan [Abdurrahim bin Sulaiman] semuanya dari [Muhammad bin Ishaq] dari [Harits bin Fudhail], aku menyangka dari [Ibnu Abu 'Auja'] yang namanya adalah Sufyan, dari [Abu Syuraih Al Khuza'i] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa terkena darah (terbunuh) ataupun terluka, maka baginya untuk memilih diantara tiga pilihan: Meminta qishos ataupun meminta diyat (ganti materi) ataupun memaafkan, maka barang siapa yang memilih yang keempat (selain dari tiga pilihan, pent) maka cegahlah dia, dan apabila dia telah memilih 'memaafkan atau diat' diantara tiga hal tersebut kemudian dia masih membunuh maka baginya balasan api neraka yang kekal di dalamnya.\""},"2579":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ لَهُ قَتِيلٌ فَهُوَ بِخَيْرِ النَّظَرَيْنِ إِمَّا أَنْ يَقْتُلَ وَإِمَّا أَنْ يُفْدَى","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi], telah menceritakan kepada kami [Al Walid], telah menceritakan kepada kami [Al 'Auza'i], telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah bersabda: \"Barangsiapa memiliki saudara yang dibunuh, maka hendaklah memilih yang terbaik di antara dua pilihan: membunuh (qisas) atau menerima diyat.\""},"2580":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ زَيْدِ بْنِ ضُمَيْرَةَ حَدَّثَنِي أَبِي وَعَمِّي وَكَانَا شَهِدَا حُنَيْنًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَاصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ ثُمَّ جَلَسَ تَحْتَ شَجَرَةٍ فَقَامَ إِلَيْهِ الْأَقْرَعُ بْنُ حَابِسٍ وَهُوَ سَيِّدُ خِنْدِفٍ يَرُدُّ عَنْ دَمِ مُحَلِّمِ بْنِ جَثَّامَةَ وَقَامَ عُيَيْنَةُ بْنُ حِصْنٍ يَطْلُبُ بِدَمِ عَامِرِ بْنِ الْأَضْبَطِ وَكَانَ أَشْجَعِيًّا فَقَالَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقْبَلُونَ الدِّيَةَ فَأَبَوْا فَقَامَ رَجُلٌ مِنْ بَنِي لَيْثٍ يُقَالُ لَهُ مُكَيْتِلٌ فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا شَبَّهْتُ هَذَا الْقَتِيلَ فِي غُرَّةِ الْإِسْلَامِ إِلَّا كَغَنَمٍ رُمِيَ أَوَّلُهَا فَنَفَرَ آخِرُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكُمْ خَمْسُونَ فِي سَفَرِنَا وَخَمْسُونَ إِذَا رَجَعْنَا فَقَبِلُوا الدِّيَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Muhammad bin Ishaq], telah menceritakan kepadaku [Muhammad bin Ja'far] dari [Zaid bin Dlumairah], telah menceritakan kepadaku [Ayah] dan [Pamanku] keduanya telah menyaksikan peperangan Hunain bersama Rasulullah shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam shalat zhuhur lalu duduk dibawah pohon, kemudian berdirilah Aqra'bin Habis, pemimpin Khindif yang menuntut darah Muhallim bin Jatsamah, lalu berdirilah Uyainah bin Hishin menuntut darah Amir bin Adhbath seorang pemberani, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah kalian menerima diyat?.\" Tapi mereka semua menolak, lalu berdirilah seorang pemuda dari bani Laits, ia biasa disebut dengan Mukaitil, ia berkata; Ya Rasulullah, demi Allah, aku tidak menyamakan pembunuhan di dalam Islam, kecuali seperti sekelompok kambing yang dilempar yang pertamanya lalu lari yang selainnya. Nabi shallallahu 'alaihi wasallam bersabda: \"Untuk kalian lima puluh dalam safar ini dan lima puluh lagi kalau sudah kembali.\" Maka mereka menerima diyat tersebut."},"2581":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ عَمْدًا دُفِعَ إِلَى أَوْلِيَاءِ الْقَتِيلِ فَإِنْ شَاءُوا قَتَلُوا وَإِنْ شَاءُوا أَخَذُوا الدِّيَةَ وَذَلِكَ ثَلَاثُونَ حِقَّةً وَثَلَاثُونَ جَذَعَةً وَأَرْبَعُونَ خَلِفَةً وَذَلِكَ عَقْلُ الْعَمْدِ مَا صُولِحُوا عَلَيْهِ فَهُوَ لَهُمْ وَذَلِكَ تَشْدِيدُ الْعَقْلِ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid Ad Dimasyqi], telah menceritakan kepada kami [Ayahku], telah menceritakan kepada kami [Muhammad bin Rasyid] dari [Sulaiman bin Musa] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] ia berkata; Rasulullah Shallallahu Alaihi Wasallam bersabda: \"Barangsiapa membunuh secara sengaja, maka urusannya diserahkan kepada keluarga orang yang terbunuh. Apabila menginginkan, maka mereka bisa membunuh atau mengambil sejumlah tiga puluh unta hiqqah (unta betina yang berusia pada tahun ke empat), tiga puluh unta jad'ah (unta berusia lima tahun), dan empat unta khalifah (unta yang sedang mengandung). Itu adalah diyat karena sengaja apabila mereka mau berdamai kepadanya, dan itu adalah diyat yang paling berat.\""},"2582":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَيُّوبَ سَمِعْتُ الْقَاسِمَ بْنَ رَبِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَتِيلُ الْخَطَإِ شِبْهِ الْعَمْدِ قَتِيلُ السَّوْطِ وَالْعَصَا مِائَةٌ مِنْ الْإِبِلِ أَرْبَعُونَ مِنْهَا خَلِفَةً فِي بُطُونِهَا أَوْلَادُهَاحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ خَالِدٍ الْح��ذَّاءِ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عُقْبَةَ بْنِ أَوْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Muhammad bin Ja'far], keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Ayyub] Aku mendengar [Qasim bin Rabi'ah] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Pembunuhan karena kesalahan, menyerupai kesengajaan. Sedangkan pembunuhan karena cambuk dan pukulan cemeti. Maka dendanya seratus ekor unta dan empat puluh diantaranya adalah unta khalifah yang di dalam perutnya terdapat janin.\" Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hammad bin Zaid] dari [Khalid Al Hadza'] dari [Qasim bin Rabi'ah] dari [Uqbah bin Aus] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"2583":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ جُدْعَانَ سَمِعَهُ مِنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ يَوْمَ فَتْحِ مَكَّةَ وَهُوَ عَلَى دَرَجِ الْكَعْبَةِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي صَدَقَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ أَلَا إِنَّ قَتِيلَ الْخَطَإِ قَتِيلَ السَّوْطِ وَالْعَصَا فِيهِ مِائَةٌ مِنْ الْإِبِلِ مِنْهَا أَرْبَعُونَ خَلِفَةً فِي بُطُونِهَا أَوْلَادُهَا أَلَا إِنَّ كُلَّ مَأْثُرَةٍ كَانَتْ فِي الْجَاهِلِيَّةِ وَدَمٍ تَحْتَ قَدَمَيَّ هَاتَيْنِ إِلَّا مَا كَانَ مِنْ سِدَانَةِ الْبَيْتِ وَسِقَايَةِ الْحَاجِّ أَلَا إِنِّي قَدْ أَمْضَيْتُهُمَا لِأَهْلِهِمَا كَمَا كَانَا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammmad Az Zuhri], telah menceritakan kepada kami [Sufyan bin Uiyainah] dari [Ibnu Jud'an] ia mendengar dari [Al Qasim bin Rabi'ah] dari [Ibnu Umar], sesungguhnya Rasulullah shallallahu 'alaihi wasallam berdiri di tangga Ka'bah pada saat penakukan kota Makkah dengan memuji Allah, beliau bersabda: \"Segala puji bagi Allah yang Maha menepati janji, menolong hamba-Nya dan mengalahkan musuh sendirian. Ingatlah sesungguhnya orang yang terbunuh karena salah adalah terbunuhnya ia oleh cambuk dan tongkat. Maka baginya diyat dengan seratus ekor diantaranya empat puluh ekor khalifah yang di dalam perutnya terdapat janin. Ketahuilah bahwa setiap kebanggaan yang berlaku dimasa jahiliyyah akan berada di kedua kakiku ini (dihapus) kecuali kebiasaan menjaga Ka'bah dan memberi minum orang haji. Ketahuilah sesungguhnya aku telah membiarkan kepada keduanya sebagaimana adanya.\""},"2584":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ جَعَلَ الدِّيَةَ اثْنَيْ عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Mu'adz bin Hani], telah menceritakan kepada kami [Muhammad bin Muslim] dari [Amru bin Dinar] dari [Ikrimah] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam; sesungguhnya ia menjadikan diyat dengan dua belas ribu.\""},"2585":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ الْمَرْوَزِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قُتِلَ خَطَأً فَدِيَتُهُ مِنْ الْإِبِلِ ثَلَاثُونَ بِنْتَ مَخَاضٍ وَثَلَاثُونَ بِنْتَ لَبُونٍ وَثَلَاثُونَ حِقَّةً وَعَشَرَةٌ بَنِي لَبُونٍ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَوِّمُهَا عَلَى أَهْلِ الْقُرَى أَرْبَعَ مِائَةِ دِينَارٍ أَوْ عَدْلَهَا مِنْ الْوَرِقِ وَيُقَوِّمُهَا عَلَى أَزْمَانِ الْإِبِلِ إِذَا غَلَتْ رَفَعَ ثَمَنَهَا وَإِذَا هَانَتْ نَقَصَ مِنْ ثَمَنِهَا عَلَى نَحْوِ الزَّمَانِ مَا كَانَ فَبَلَغَ قِيمَتُهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ الْأَرْبَعِ مِائَةِ دِينَارٍ إِلَى ثَمَانِ مِائَةِ دِينَارٍ أَوْ عَدْلَهَا مِنْ الْوَرِقِ ثَمَانِيَةُ آلَافِ دِرْهَمٍ وَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مَنْ كَانَ عَقْلُهُ فِي الْبَقَرِ عَلَى أَهْلِ الْبَقَرِ مِائَتَيْ بَقَرَةٍ وَمَنْ كَانَ عَقْلُهُ فِي الشَّاءِ عَلَى أَهْلِ الشَّاءِ أَلْفَيْ شَاةٍ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur Al Mawarzi], telah menceritakan kepada kami [Yazid bin Harun], telah memberitakan kepada kami [Muhammad bin Rasyid] dari [Sulaiman bin Musa] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membunuh seseorang karena kesalahan, dendanya adalah tiga puluh ekor unta binta makhad (unta betina yang berusia satu tahun), tiga puluh ekor unta binta labun (unta betina yang berusia dua tahun), tiga puluh unta hiqqah dan sepuluh unta bani labun (unta jantan yang berusia dua tahun) Rasulullah menilai harga unta tersebut kepada masyarakat kampung dengan nilai empat ratus Dinar atau senilai dengan uang perak. Beliau menilainya dengan kondisi harga unta, apabila harganya sedang tinggi, maka ia menaikkan nilainya dan apabila sedang rendah, maka ia menurunkan nilainya sesuai dengan kondisi yang ada. Oleh karena itu nilai harga unta pada masa Rasulullah berada di antara empat ratus sampai delapan ratus dinar atau sebanding dengan uang perak sejumlah delapan ribu Dirham. Rasulullah shallallahu 'alaihi wasallam menetapkan bahwa barangsiapa dendanya berupa sapi, maka ia harus membayar dengan dua ratus ekor sapi, barangsiapa dendanya berupa kambing, maka ia harus membayar dengan dua ribu ekor kambing.\""},"2586":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ عَاصِمٍ حَدَّثَنَا الصَّبَّاحُ بْنُ مُحَارِبٍ حَدَّثَنَا حَجَّاجُ بْنُ أَرْطَاةَ حَدَّثَنَا زَيْدُ بْنُ جُبَيْرٍ عَنْ خِشْفِ بْنِ مَالِكٍ الطَّائِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي دِيَةِ الْخَطَإِ عِشْرُونَ حِقَّةً وَعِشْرُونَ جَذَعَةً وَعِشْرُونَ بِنْتَ مَخَاضٍ وَعِشْرُونَ بِنْتَ لَبُونٍ وَعِشْرُونَ بَنِي مَخَاضٍ ذُكُورٌ","id":"Telah menceritakan kepada kami [Abdussalam bin Ashim], telah menceritakan kepada kami [Shabah bin Muharib], telah menceritakan kepada kami [Hajjaj bin Arthah], telah menceritakan kepada kami [Zaid bin Jubair] dari [Khisyaf bin Malik Ath Tha'i] dari [Abdullah bin Mas'ud] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Untuk diyat pembunuhan karena salah adalah dua puluh unta hiqqah, dua puluh unta jadz'ah, dua puluh bintu makhad (unta betina yang berusia satu tahun), tiga puluh ekor unta bintu labun (unta betina yang berusia dua tahun) dan dua puluh unta bani makhad yang jantan.\""},"2587":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ جَعْفَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ الدِّيَةَ اثْنَيْ عَشَرَ أَلْفًا قَالَ وَذَلِكَ قَوْلُهُ{ وَمَا نَقَمُوا إِلَّا أَنْ أَغْنَاهُمْ اللَّهُ وَرَسُولُهُ مِنْ فَضْلِهِ }قَالَ بِأَخْذِهِمْ الدِّيَةَ","id":"Telah menceritakan kepada kami [Al Abbas bin Ja'far], telah menceritakan kepada kami [Muhammad bin Sinan], telah menceritakan kepada kami [Muhammad bin Muslim] dari [Amru bin Dinar] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau menjadikan diyat dengan dua belas ribu, sebagaimana firman Allah: 'Wamaa naqamu illa an aghnahumullahu wa rasuluhu min fadhlihi' tidaklah pembalasan itu kecuali agar Allah dan Rasulnya mengkayakan mereka.\" Beliau bersabda: 'Yaitu dengan diyat.\""},"2588":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبِي عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نَضْلَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالدِّيَةِ عَلَى الْعَاقِلَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ayahku] dari [Manshur] dari [Ibrahim] dari [Ubaid bin Nadhlah] dari [Al Mughirah bin Syu'bah], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menetapkan diyat atas kerabat atau keluarga pembunuh.\""},"2589":{"ar":"حَدَّثَنَا يَحْيَى بْنُ دُرُسْتَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ عَلِيِّ بْنِ أَبِي طَلْحَةَ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ أَبِي عَامِرٍ الْهَوْزَنِيِّ عَنْ الْمِقْدَامِ الشَّامِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَارِثُ مَنْ لَا وَارِثَ لَهُ أَعْقِلُ عَنْهُ وَأَرِثُهُ وَالْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُ يَعْقِلُ عَنْهُ وَيَرِثُهُ","id":"Telah menceritakan kepada kami [Yahya bin Durusta], telah menceritakan kepada kami [Hammad bin Zaid] dari [Budail bin Maisarah] dari [Ali bin Abu Thalhah] dari [Rasyid bin Sa'ad] dari [Abu Amir Al Hauzani] dari [Al Miqdam Asy-Syami], ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: 'Aku adalah ahli waris bagi orang yang tidak memiliki ahli waris. Aku yang akan menanggung diyat dan mewarisinya. Seorang paman menjadi ahli waris bagi orang yang tidak memiliki ahli waris, ia yang akan menanggung diyat dan yang mewarisinya.\""},"2590":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ فِي عِمِّيَّةٍ أَوْ عَصَبِيَّةٍ بِحَجَرٍ أَوْ سَوْطٍ أَوْ عَصًا فَعَلَيْهِ عَقْلُ الْخَطَإِ وَمَنْ قَتَلَ عَمْدًا فَهُوَ قَوَدٌ وَمَنْ حَالَ بَيْنَهُ وَبَيْنَهُ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar], telah menceritakan kepada kami [Muhammad bin Katsir], telah menceritakan kepada kami [Sulaiman bin Katsir] dari [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas], la meriwayatkannya dari Nabi shallallahu 'alaihi wasallam secara marfu', beliau bersabda: \"Barangsiapa yang membunuh seseorang secara serampangan (membabi buta) atau karena menahan batu atau tongkat, atau cambuk maka ia dikenakan hukuman diyat membunuh karena kesalahan. Dan barangsiapa yang membunuh secara segaja, maka ia dikenakan hukum qishash. Dan Barangsiapa yang menghalang-halangi antara diyat dan hukum qishash, maka laknat Allah, para malaikat dan seluruh manusia atasnya, serta tidak diterima darinya pertaubatan dan fidyah.\""},"2591":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَعَمَّارُ بْنُ خَالِدٍ الْوَاسِطِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ دَهْثَمِ بْنِ قُرَّانَ حَدَّثَنِي نِمْرَانُ بْنُ جَارِيَةَ عَنْ أَبِيهِأَنَّ رَجُلًا ضَرَبَ رَجُلًا عَلَى سَاعِدِهِ بِالسَّيْفِ فَقَطَعَهَا مِنْ غَيْرِ مَفْصِلٍ فَاسْتَعْدَى عَلَيْهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ لَهُ بِالدِّيَةِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ الْقِصَاصَ قَالَ خُذْ الدِّيَةَ بَارَكَ اللَّهُ لَكَ فِيهَا وَلَمْ يَقْضِ لَهُ بِالْقِصَاصِ","id":"Telah menceritakan kepada kami [Muhammad bin Shabah], telah menceritakan kepada kami [Ammar bin Khalid Al Wasithi], telah menceritakan kepada kami [Abu Bakar bin Ayyasy] dari [Dahtsam bin Qurran], telah menceritakan kepadaku [Nimran bin Jariyah], dari [ayahnya]; bahwa seorang lelaki memukul lelaki pada bagian lengannya dengan pedang sehingga putus tanpa persendian, maka dia meminta tolong kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau memerintahkan kepadanya untuk membayar diyat, tetapi dia berkata; \" wahai Rasulullah, aku menginginkan qishas.\" Maka Nabi bersabda: \"Ambillah diyat, semoga Allah memberkatimu\". Dan tidak memutuskan baginya dengan qishas.\""},"2592":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ مُعَاذِ بْن�� مُحَمَّدٍ الْأَنْصَارِيِّ عَنْ ابْنِ صُهْبَانَ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَوَدَ فِي الْمَأْمُومَةِ وَلَا الْجَائِفَةِ وَلَا الْمُنَقِّلَةِ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Risydin bin Sa'ad] dari [Mu'awiyah bin Shalih] dari [Mu'adz bin Muhammad Al Anshari] dari [Ibnu Shuhban] dari [Al Abbas bin Abdul Muthalib], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hukum qishash pada ma'mumah (luka yang tidak berhubungan secara langsung pada perut), pada ja`ifah (luka yang berlubang dan harus dijahit) dan pada munaqqilah (luka yang memindahkan posisi tulang). \""},"2593":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا جَهْمِ بْنَ حُذَيْفَةَ مُصَدِّقًا فَلَاجَّهُ رَجُلٌ فِي صَدَقَتِهِ فَضَرَبَهُ أَبُو جَهْمٍ فَشَجَّهُ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا الْقَوَدَ يَا رَسُولَ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكُمْ كَذَا وَكَذَا فَلَمْ يَرْضَوْا فَقَالَ لَكُمْ كَذَا وَكَذَا فَرَضُوا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي خَاطِبٌ عَلَى النَّاسِ وَمُخْبِرُهُمْ بِرِضَاكُمْ قَالُوا نَعَمْ فَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ هَؤُلَاءِ اللَّيْثِيِّينَ أَتَوْنِي يُرِيدُونَ الْقَوَدَ فَعَرَضْتُ عَلَيْهِمْ كَذَا وَكَذَا أَرَضِيتُمْ قَالُوا لَا فَهَمَّ بِهِمْ الْمُهَاجِرُونَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكُفُّوا فَكَفُّوا ثُمَّ دَعَاهُمْ فَزَادَهُمْ فَقَالَ أَرَضِيتُمْ قَالُوا نَعَمْ قَالَ إِنِّي خَاطِبٌ عَلَى النَّاسِ وَمُخْبِرُهُمْ بِرِضَاكُمْ قَالُوا نَعَمْ فَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ أَرَضِيتُمْ قَالُوا نَعَمْقَالَ ابْن مَاجَةَ سَمِعْت مُحَمَّدَ بْنَ يَحْيَى يَقُولُ تَفَرَّدَ بِهَذَا مَعْمَرٌ لَا أَعْلَمُ رَوَاهُ غَيْرُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Abdurrazak], telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari ['Aisyah]; sesungguhnya Rasulullah shallallahu 'alaihi wasallam mengutus Abu Jahm bin Khudzaifah untuk mengambil zakat, tetapi seseorang menolaknya untuk membayarkan zakatnya, maka Abu Jahm memukulnya hingga melukai bagian kepalanya. Lalu datanglah mereka kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Qishaslah wahai Rasulullah\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kalian mendapatkan seperti ini dan seperti ini.\" Tetapi mereka tidak mau menerima. Kemudian beliau bersabda kembali: \"Bagi kalian seperti ini dan seperti ini.\" Maka mereka menerimanya. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku akan berbicara kepada orang-orang dan memberitahukan kepada mereka dengan kerelaan kalian.\" Mereka berkata: \"Silahkan.\" Maka Nabi shallallahu 'alaihi wasallam berkhutbah dan bersabda: \"Sesungguhnya mereka orang-orang suku Laits telah mendatangiku dan menginginkan qishas, kemudian aku tawarkan kepada mereka seperti ini dan seperti ini, apakah kalian rela?\". Mereka menjawab; \" Tidak.\" Maka para sahabat Muhajirin pun gerang kepada mereka, sehingga Nabi shallallahu 'alaihi wasallam memerintahkan untuk menahan, dan mereka pun menahan. Kemudian beliau memanggil mereka dan menambahnya, serta bersabda: \"Apakah kalian telah rela?\" mereka menjawab; \"Iya\". Nabi bersabda: \"Aku akan berkhutbah dihadapan orang-orang dan memberitahukan kepada mereka tentang kerelaan kalian\". Mereka menjawab; \"Silahkan\". Maka Nabi shallallahu 'alaihi wasallam berkhutbah kemudian bersabda: \"Apakah kalian rela?.\" Mereka menjawab; \"Ya.\" Ibnu Majah berkata; Aku mendengar Muhammad bin Yahya berkata; Ma'mar meriwayatkan Hadits ini secara sendirian, aku tidak mengetahui ada riwayat dari yang lainnya."},"2594":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنِينِ بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ فَقَالَ الَّذِي قُضِيَ عَلَيْهِ أَنَعْقِلُ مَنْ لَا شَرِبَ وَلَا أَكَلَ وَلَا صَاحَ وَلَا اسْتَهَلَّ وَمِثْلُ ذَلِكَ يُطَلُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا لَيَقُولُ بِقَوْلِ شَاعِرٍ فِيهِ غُرَّةٌ عَبْدٌ أَوْ أَمَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Muhammad bin Bisyir] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menetapkan hukuman di dalam membunuh janin dengan diyat, yaitu memerdekakan seorang hamba sahaya laki-laki atau perempuan. Lalu orang yang menerima hukuman tersebut berkata; \"Apakah kami harus membayar diyat untuk sosok manusia yang belum dapat minum dan makan, tidak berteriak dan tidak menangis dan hal semacam itu?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang ini berbicara dengan ucapan penyair, maka ia dikenakan memerdekakan seorang budak, laki-laki atau perempuan.'\""},"2595":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَاسْتَشَارَ عُمَرُ بْنُ الْخَطَّابِ النَّاسَ فِي إِمْلَاصِ الْمَرْأَةِ يَعْنِي سِقْطَهَا فَقَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِيهِ بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ فَقَالَ عُمَرُ ائْتِنِي بِمَنْ يَشْهَدُ مَعَكَ فَشَهِدَ مَعَهُ مُحَمَّدُ بْنُ مَسْلَمَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin Abu Urwah] dari [Ayahnya] dari [Miswar bin Makhramah], ia berkata; Umar bin Khaththab bermusyawarah kepada para sahabat mengenai seorang wanita yang menggugurkan kandungannya, [Al Mughirah bin Syu'bah] berkata; \"Aku menyaksikan Rasulullah shallallahu 'alaihi wasallam menetapkan hukumannya dengan memerdekakan seorang hamba sahaya laki-laki atau perempuan.\" Umar berkata; \"Datanglah kepadaku bersama orang yang menyaksikan peristiwa tersebut bersamamu. Kemudian [Muhammad bin Maslamah] bersedia menjadi saksi bersamanya.\""},"2596":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنِي ابْنُ جُرَيْجٍ حَدَّثَنِي عَمْرُو بْنُ دِينَارٍ أَنَّهُ سَمِعَ طَاوُسًا عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّهُ نَشَدَ النَّاسَ قَضَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ يَعْنِي فِي الْجَنِينِ فَقَامَ حَمَلُ بْنُ مَالِكِ بْنِ النَّابِغَةِ فَقَالَ كُنْتُ بَيْنَ امْرَأَتَيْنِ لِي فَضَرَبَتْ إِحْدَاهُمَا الْأُخْرَى بِمِسْطَحٍ فَقَتَلَتْهَا وَقَتَلَتْ جَنِينَهَا فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنِينِ بِغُرَّةٍ عَبْدٍ وَأَنْ تُقْتَلَ بِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi], telah menceritakan kepada kami [Abu Ashim], telah mengkabarkan kepadaku [Ibnu Juraij], telah menceritakan kepadaku [Amru bin Dinar] bahwa ia mendengar [Thawus] dari [Ibnu Abbas] dari [Umar bin Khaththab], ia berkata; Sesungguhnya ia meminta kepada masyarakat memberitahukan tentang keputusan hukum telah dibuat oleh Rasulullah, mengenai janin. Maka [Hamal bin Malik bin Nabighah] berdiri dan berkata; \"Aku berada diantara kedua isteriku, lalu salah seorang dari isteriku memukul isteriku lainnya dengan kayu hingga ia wafat berikut janin yang kandungnya.\" kemudian Rasulullah shallallahu 'alaihi wasallam menetapkan hukum di dalam membunuh janin dengan memerdekakan seorang hamba sahaya dan isteriku yang memukul itu pun dibunuh.\""},"2597":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بِنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ عُمَرَكَانَ يَقُولُ الدِّيَةُ لِلْعَاقِلَةِ وَلَا تَرِثُ الْمَرْأَةُ مِنْ دِيَةِ زَوْجِهَا شَيْئًا حَتَّى كَتَبَ إِلَيْهِ الضَّحَّاكُ بْنُ سُفْيَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَّثَ امْرَأَةَ أَشْيَمَ الضِّبَابِيِّ مِنْ دِيَةِ زَوْجِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id bin Musayyab] bahwa Umar berkata; \"Diyat diberikan kepada keluarga terbunuh. Namun istrinya tidak mendapatkan warisan sama sekali dari diyat suaminya, hingga [Dhahhak bin Sufyan] menulis sesuatu kepadanya dengan mengatakan; 'Sesungguhnya Nabi shallallahu 'alaihi wasallam memberikan warisan kepada isteri dari Asyyam Adh-Dhababi dari diyat suaminya'.\""},"2598":{"ar":"حَدَّثَنَا عَبْدُ رَبِّهِ بْنُ خَالِدٍ النُّمَيْرِيُّ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ إِسْحَقَ بْنِ يَحْيَى بْنِ الْوَلِيدِ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى لِحَمَلِ بْنِ مَالِكٍ الْهُذَلِيِّ اللِّحْيَانِيِّ بِمِيرَاثِهِ مِنْ امْرَأَتِهِ الَّتِي قَتَلَتْهَا امْرَأَتُهُ الْأُخْرَى","id":"Telah menceritakan kepada kami [Abdu Rabbih bin Khalid An Numairi], telah menceritakan kepada kami [Fudhail bin Sulaiman], telah menceritakan kepada kami [Musa bin Uqbah] dari [Ishaq bin Yahya bin Al Walid] dari [Ubadah bin As Shamit], ia berkata; Sesungguhnya Nabi shallallahu 'alaihi wasallam menetapkan hukum bagi Hamal bin Malik Al Hudzali Al Lihyani dengan memberikan warisan kepadanya dari isterinya yang telah dibunuh oleh isterinya yang lain.\""},"2599":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَيَّاشٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ عَقْلَ أَهْلِ الْكِتَابَيْنِ نِصْفُ عَقْلِ الْمُسْلِمِينَ وَهُمْ الْيَهُودُ وَالنَّصَارَى","id":"Telah menceritakan kepada kami [Hisyam bin Ammar], telah menceritakan kepada kami [Hatim bin Isma'il] dari [Abdurrahman bin Ayyasy] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya], ia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam menetapkan hukum bahwa diyat membunuh dua kalangan ahli kitab adalah separuh dari diyat kaum muslimin. Mereka adalah orang-orang Yahudi dan Nasrani."},"2600":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ إِسْحَقَ بْنِ أَبِي فَرْوَةَ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْقَاتِلُ لَا يَرِثُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri], telah memberitakan kepada kami [Al Laits bin Sa'ad] dari [Ishaq bin Abu Farwah] dari [Ibnu Syihab] dari [Humaid] dari [Abu Hurairah], sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pembunuh tidak berhak mendapatkan harta warisan. \""},"2601":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ قَالَا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍأَنَّ أَبَا قَتَادَةَ رَجُلٌ مِنْ بَنِي مُدْلِجٍ قَتَلَ ابْنَهُ فَأَخَذَ مِنْهُ عُمَرُ مِائَةً مِنْ الْإِبِلِ ثَلَاثِينَ حِقَّةً وَثَلَاثِينَ جَذَعَةً وَأَرْبَعِينَ خَلِفَةً فَقَالَ ابْنُ أَخِي الْمَقْتُولِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ لِقَاتِلٍ مِيرَاثٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] dan [Abdullah bin Sa'id Al Kindi], keduanya berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Yahya bin Sa'id] dari [Amru bin Syu'aib] bahwa Qatadah, seseorang lelaki dari Bani Mudlij telah membunuh anaknya. Maka [Umar] mengambil darinya seratus ekor unta, yaitu tiga puluh unta hiqqah (unta betina yang umurnya masuk tahun ke empat), tiga puluh unta jad'ah (unta betina yang umurnya masuk tahun ke lima), dan empat puluh unta khalifah (unta yang sedang hamil).\" Keponakan korban berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hak waris bagi seorang pembunuh.\""},"2602":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَعْقِلَ الْمَرْأَةَ عَصَبَتُهَا مَنْ كَانُوا وَلَا يَرِثُوا مِنْهَا شَيْئًا إِلَّا مَا فَضَلَ عَنْ وَرَثَتِهَا وَإِنْ قُتِلَتْ فَعَقْلُهَا بَيْنَ وَرَثَتِهَا فَهُمْ يَقْتُلُونَ قَاتِلَهَا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur], telah memberitakan kepada kami [Yazid bin Harun], telah memberitakan kepada kami [Muhammad bin Rasyid] dari [Sulaiman bin Musa] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] berkata; \"Rasulullah shallallahu 'alaihi wasallam menetapkan hukum bahwa pihak istri keluarga, siapa saja dibebankan pembayaran diyat terhadap seorang wanita pembunuh. Dan keluarga ini tidak berhak mendapatkan warisan sama sekali, kecuali apabila terdapat kelebihan dari harta warisannya. Jika si wanita yang terbunuh, maka diyat baginya diberikan kepada ahli warisnya dan hendaklah mereka membunuh pembunuhnya.\""},"2603":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا مُجَالِدٌ عَنْ الشَّعْبِيِّ عَنْ جَابِرٍ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدِّيَةَ عَلَى عَاقِلَةِ الْقَاتِلَةِ فَقَالَتْ عَاقِلَةُ الْمَقْتُولَةِ يَا رَسُولَ اللَّهِ مِيرَاثُهَا لَنَا قَالَ لَا مِيرَاثُهَا لِزَوْجِهَا وَوَلَدِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Al Mu'alla bin Asad], telah menceritakan kepada kami [Abdul Wahid bin Ziyad], telah menceritakan kepada kami [Mujalid] dari [Asy Sya'bi] dari [Jabir], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam membebankan diyat kepada keluarga si pembunuh. Lalu keluarga si terbunuh berkata; \"Wahai Rasulullah! Apakah harta warisannnya untuk kami.\" Beliau menjawab, \"Tidak, harta warisannya untuk suami dan anaknya.\""},"2604":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى أَبُو مُوسَى حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ وَابْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَسَرَتْ الرُّبَيِّعُ عَمَّةُ أَنَسٍ ثَنِيَّةَ جَارِيَةٍ فَطَلَبُوا الْعَفْوَ فَأَبَوْا فَعَرَضُوا عَلَيْهِمْ الْأَرْشَ فَأَبَوْا فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِالْقِصَاصِ فَقَالَ أَنَسُ بْنُ النَّضْرِ يَا رَسُولَ اللَّهِ تُكْسَرُ ثَنِيَّةُ الرُّبَيِّعِ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَا تُكْسَرُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَنَسُ كِتَابُ اللَّهِ الْقِصَاصُ قَالَ فَرَضِيَ الْقَوْمُ فَعَفَوْا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ عِبَادِ اللَّهِ مَنْ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّةُ","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna Abu Musa], telah menceritakan kepada kami [Khalid bin Al Harits] dan [Ibnu Abu Adi] dari [Humaid] dari [Anas], ia berkata; \"Ar-Rubayyi, bibi Anas mematahkan gigi depan seorang budak perempuan lalu ia meminta maaf, kemudian mereka menolak. Mereka mengajukan diyat, tetapi keluarga pihak perempuan tidak menerima. Lalu mereka mendatangi Nabi shallallahu 'alaihi wasallam dan beliau memerintahkan untuk melakukan qishash. Anas bin An-Nadhr berkata; \"Wahai Rasulullah, Apakah gigi Ar-Rubayyi' harus dipatahkan juga? Demi Allah! Tidak, jangan dipatahkan!, \" Nabi shallallahu 'alaihi wasallam bersabda: 'Wahai Anas! Di dalam Al Qur`an hukumnya adalah qishas.\" Anas berkata; \"kaumnya pun akhirnya merelakannya dan mereka memberi pengampunan. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara hamba-hamba Allah terdapat seseorang, yang apabila bersumpah, maka Allah akan mengabulkannya.\""},"2605":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنِي شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَسْنَانُ سَوَاءٌ الثَّنِيَّةُ وَالضِّرْسُ سَوَاءٌ","id":"Telah menceritakan kepada kami [Abbas bin Abdul 'Azhim Al'Anbari], telah menceritakan kepada kami [Abdus Shamad bin Abdul Warits] Telah menceritakan kepadaku [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas], sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gigi-gigi sama saja diyatnya, gigi bagian depan dan gigi geraham sama saja.\""},"2606":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ الْبَالِسِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ حَدَّثَنَا أَبُو حَمْزَةَ الْمَرْوَزِيُّ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَضَى فِي السِّنِّ خَمْسًا مِنْ الْإِبِلِ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim Al Balisi], telah menceritakan kepada kami [Ali bin Al Hasan bin Syaqiq], telah menceritakan kepada kami [Abu Hamzah Al Marwazi], telah menceritakan kepada kami [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas], dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau shallallahu 'alaihi wasallam menetapkan hukum diyat bagi gigi yang patah dengan lima ekor unta."},"2607":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ وَابْنُ أَبِي عَدِيٍّ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذِهِ وَهَذِهِ سَوَاءٌ يَعْنِي الْخِنْصَرَ وَالْإِبْهَامَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far] dan [Ibnu Abu Adi], semuanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas], sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Yang ini dan itu sama saja, maksudnya adalah, jari kelingking dan jempol.\""},"2608":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ الْعَتَكِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ مَطَرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَصَابِعُ سَوَاءٌ كُلُّهُنَّ فِيهِنَّ عَشْرٌ عَشْرٌ مِنْ الْإِبِلِ","id":"Telah menceritakan kepada kami [Jamil bin Al Hasan Al 'Ataki], telah menceritakan kepada kami [Abdul `A'la], telah menceritakan kepada kami [Sa'id] dari [Mathar] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: Jari-jemari itu semuanya sama, masing-masing diyatnya sepuluh ekor unta. \""},"2609":{"ar":"حَدَّثَنَا رَجَاءُ بْنُ الْمُرَجَّى السَّمَرْقَنْدِيُّ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ غَالِبٍ التَّمَّارِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ مَسْرُوقِ بْنِ أَوْسٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَصَابِعُ سَوَاءٌ","id":"Telah menceritakan kepada kami [Raja` bin Al Muraja` As Samarqandi], telah menceritakan kepada kami [Nadhar bin Syumail], telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Ghalib At Tammar] dari [Humaid bin Hilal] dari [Masruq bin Aus] dari [Abu Musa Al Asy'ari], dari Nabi shallallahu 'alaihi wasallam bersabda: \"Semua jari hukumnya sama.\""},"2610":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ مَطَرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْمَوَاضِحِ خَمْسٌ خَمْسٌ مِنْ الْإِبِلِ","id":"Telah menceritakan kepada kami [Jamil bin Hasan], telah menceritakan kepada kami [Abdul `A'la], telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Mathar] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Pada luka yang menimbulkan tulang kelihatan diyatnya lima, yaitu lima ekor unta\""},"2611":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ عَنْ عَمَّيْهِ يَعْلَى وَسَلَمَةَ ابْنَيْ أُمَيَّةَ قَالَاخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ وَمَعَنَا صَاحِبٌ لَنَا فَاقْتَتَلَ هُوَ وَرَجُلٌ آخَرُ وَنَحْنُ بِالطَّرِيقِ قَالَ فَعَضَّ الرَّجُلُ يَدَ صَاحِبِهِ فَجَذَبَ صَاحِبُهُ يَدَهُ مِنْ فِيهِ فَطَرَحَ ثَنِيَّتَهُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْتَمِسُ عَقْلَ ثَنِيَّتِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْمِدُ أَحَدُكُمْ إِلَى أَخِيهِ فَيَعَضُّهُ كَعِضَاضِ الْفَحْلِ ثُمَّ يَأْتِي يَلْتَمِسُ الْعَقْلَ لَا عَقْلَ لَهَا قَالَ فَأَبْطَلَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Muhammad bin Ishaq] dari ['Atha`] dari [Shafwan bin Abdullah] dari kedua pamannya [Ya'la] dan [Salamah bin Umayah], keduanya berkata; \"Kami keluar rumah bersama Rasulullah shallallahu 'alaihi wasallam untuk perang Tabuk, satu teman kami ikut bersama kami. Lalu dia dan seorang laki-laki lain bertengkar ketika kami sedang diperjalanan. Perawi berkata; \"Laki-laki tadi menggigit tangan temannya lalu temannya menarik tangannya dari mulutnya, hingga gigi depannya terjatuh, lalu ia datang menemui Rasulullah shallallahu 'alaihi wasallam meminta diyat gigi depannya yang patah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang dari kalian meminta tanggung jawab kepada saudaranya, karena ia telah menggigitnya sebagaimana gigitan hewan jantan. Setelah itu ia datang meminta diyat! Tidak ada diyat baginya. Perawi berkata; \"Maka Rasulullah shallallahu 'alaihi wasallam membatalkan hal tersebut.\""},"2612":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا عَضَّ رَجُلًا عَلَى ذِرَاعِهِ فَنَزَعَ يَدَهُ فَوَقَعَتْ ثَنِيَّتُهُ فَرُفِعَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبْطَلَهَا وَقَالَ يَقْضَمُ أَحَدُكُمْ كَمَا يَقْضَمُ الْفَحْلُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Abdullah bin Numair] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Zurarah bin `Aufa] dari [Imran bin Hushain], sesungguhnya ada seseorang menggigit lengan orang lain, kemudian ia menarik lengannya, maka gigi depan orang tersebut tanggal dan ia mengadukannya kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam membatalkannya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salah seorang dari kalian menggigit orang lain layaknya hewan jantan yang saling menggigit.\""},"2613":{"ar":"حَدَّثَنَا عَلْقَمَةُ بْنُ عَمْرٍو الدَّارِمِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي جُحَيْفَةَ قَالَقُلْتُ لِعَلِيِّ بْنِ أَبِي طَالِبٍ هَلْ عِنْدَكُمْ شَيْءٌ مِنْ الْعِلْمِ لَيْسَ عِنْدَ النَّاسِ قَالَ لَا وَاللَّهِ مَا عِنْدَنَا إِلَّا مَا عِنْدَ النَّاسِ إِلَّا أَنْ يَرْزُقَ اللَّهُ رَجُلًا فَهْمًا فِي الْقُرْآنِ أَوْ مَا فِي هَذِهِ الصَّحِيفَةِ فِيهَا الدِّيَاتُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْ لَا يُقْتَلَ مُسْلِمٌ بِكَافِرٍ","id":"Telah menceritakan kepada kami ['Alqamah bin Amru Ad Darimi], telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Mutharrif] dari [Asy Sya'bi] dari [Abu Juhaifah] berkata; \"Aku berkata kepada [Ali bin Abu Thalib], 'Apakah Anda memiliki ilmu pengetahuan yang tidak dimiliki oleh masyarakat umum?\" Ia menjawab, \"Tidak, demi Allah! Kami tidak memiliki ilmu pengetahuan apa-apa kecuali apa yang telah ada pada masyarakat, kecuali apabila Allah subhanahu wata'ala memberikan rezeki kepada seseorang berupa pemahaman mengenai Al Qur'an atau apa yang ada di dalam lembaran ini, dimana di dalamnya terdapat hukuman diyat dari Rasulullah shallallahu 'alaihi wasallam dan seorang Muslim tidak dibunuh karena membunuh seorang yang kafir.\""},"2614":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَيَّاشٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُقْتَلُ مُسْلِمٌ بِكَافِرٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar], telah menceritakan kepada kami [Hatim bin Isma'il], telah menceritakan kepada kami [Abdurrahman bin Ayyasy] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim tidak dibunuh lantaran membunuh seorang kafir. \""},"2615":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ حَنَشٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُقْتَلُ مُؤْمِنٌ بِكَافِرٍ وَلَا ذُو عَهْدٍ فِي عَهْدِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul `A'la Ashan'ani], telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Ayahnya] dari [Hanasy] dari [Ikrimah] dari [Ibnu Abbas], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang mukmin tidak dibunuh karena membunuh seorang yang kafir, demikian pula dengan membunuh seorang kafir (mu'ahad) yang berada dalam perlidungannya.\""},"2616":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُقْتَلُ بِالْوَلَدِ الْوَالِدُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id], telah menceritakan kepada kami [Ali bin Mushir] dari [Isma'il bin Muslim] dari [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas], sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang tua tidak dibunuh lantaran membunuh anaknya.\""},"2617":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَجَّاجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُقْتَلُ الْوَالِدُ بِالْوَلَدِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abu Khalid Al `Ahmar] dari [Hajjaj] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] dari [Umar bin Khaththab], ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang tua tidak dibunuh karena pembunuhannya terhadap anaknya.\""},"2618":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ عَبْدَهُ قَتَلْنَاهُ وَمَنْ جَدَعَهُ جَدَعْنَاهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Hasan] dari [Samurah bin Jundub] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang membunuh budaknya, aku akan membunuhnya dan siapa yang mencincangnya maka akan aku cincang.\""},"2619":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ الطَّبَّاعِ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي فَرْوَةَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ عَلِيٍّ و عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَتَلَ رَجُلٌ عَبْدَهُ عَمْدًا مُتَعَمِّدًا فَجَلَدَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِائَةً وَنَفَاهُ سَنَةً وَمَحَا سَهْمَهُ مِنْ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Ibnu At Thuba'], telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Ishaq bin Abdullah bin Abu Farwah] dari [Ibrahim bin Abdullah bin Hunain] dari [Ali] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] ia berkata; \"Seorang lelaki membunuh budaknya dengan cara sengaja, maka Rasulullah shallallahu 'alaihi wasallam mencambuknya sebanyak seratus kali dan mengasingkannya selama setahun dan dihapus bagiannya dari kaum muslimin.\""},"2620":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هَمَّامِ بْنِ يَحْيَى عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ يَهُودِيًّا رَضَخَ رَأْسَ امْرَأَةٍ بَيْنَ حَجَرَيْنِ فَقَتَلَهَا فَرَضَخَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ بَيْنَ حَجَرَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'] dari [Hammam bin Yahya] dari [Qatadah] dari [Anas bin Malik] bahwa seorang Yahudi telah membenturkan seorang wanita diantara dua batu hinggga ia terbunuh, maka Nabi Shallalahu 'Alaihi Wasallam membenturkannya diantara dua batu pula.\""},"2621":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ يَهُودِيًّا قَتَلَ جَارِيَةً عَلَى أَوْضَاحٍ لَهَا فَقَالَ لَهَا أَقَتَلَكِ فُلَانٌ فَأَشَارَتْ بِرَأْسِهَا أَنْ لَا ثُمَّ سَأَلَهَا الثَّانِيَةَ فَأَشَارَتْ بِرَأْسِهَا أَنْ لَا ثُمَّ سَأَلَهَا الثَّالِثَةَ فَأَشَارَتْ بِرَأْسِهَا أَنْ نَعَمْ فَقَتَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ حَجَرَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Muhammad bin Ja'far], Demikan juga diriwayatkan dari jalur lain; telah menceritakan kepada kami [Ishaq bin Manshur], telah menceritakan kepada kami [Nadhar bin Syumail], keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid] dari [Anas bin Malik] bahwa seorang Yahudi telah membunuh budak perempuan dengan kalung dari perak miliknya, maka ia berkata kepadanya; \"Apakah fulan membunuhmu?\" ia memberikan isyarat dengan kepalanya dengan mengatakan 'tidak'. Lalu ia bertanya untuk yang kedua kalinya. Ia pun menggelengkan kepalanya yang mengisyaratkan tidak. Lalu ia kembali untuk yang ketiga kalinya kemudian memberi isyarat dengan kepalanya mengatakan; \"Ya.\" Lalu Rasulullah shallallahu 'alaihi wasallam membunuh orang Yahudi tersebut dengan memposisikannya di antara dua batu.\""},"2622":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُسْتَمِرِّ الْعُرُوقِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ سُفْيَانَ عَنْ جَابِرٍ عَنْ أَبِي عَازِبٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا قَوَدَ إِلَّا بِالسَّيْفِ","id":"Telah menceritakan kepada kami [Ibrahim bin Mustamir Al 'Uruqi], telah menceritakan kepada kami [Abu Ashim] dari [Sufyan] dari [Jabir] dari [Abu 'Azib] dari [An Nu'man bin Basyir]; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada qishas kecuali dengan pedang.\""},"2623":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُسْتَمِرِّ حَدَّثَنَا الْحُرُّ بْنُ مَالِكٍ الْعَنْبَرِيُّ حَدَّثَنَا مُبَارَكُ بْنُ فَضَالَةَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَوَدَ إِلَّا بِالسَّيْفِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mustamir], telah menceritakan kepada kami [Al Hurr bin Malik Al 'Anbari], telah menceritakan kepada kami [Mubarak bin Fadhalah] dari [Al Hasan] dari [Abu Bakrah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada qishas kecuali dengan pedang.\""},"2624":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي حَجَّةِ الْوَدَاعِ أَلَا لَا يَجْنِي جَانٍ إِلَّا عَلَى نَفْسِهِ لَا يَجْنِي وَالِدٌ عَلَى وَلَدِهِ وَلَا مَوْلُودٌ عَلَى وَالِدِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abul Ahwas] dari [Syabib bin Gharqadah] dari [Sulaiman bin Amru bin Al Ahwasy], dari [Ayahnya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada saat haji wada; \"Ketahuilah! Pelaku kejahatan tidak menuai balasan, kecuali atas dirinya sendiri orang tua tidak menanggung hukuman perbuatan anaknya, dan anak tidak menuai hukum akibat orang tua.\""},"2625":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ حَدَّثَنَا جَامِعُ بْنُ شَدَّادٍ عَنْ طَارِقٍ الْمُحَارِبِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ حَتَّى رَأَيْتُ بَيَاضَ إِبْطَيْهِ يَقُولُ أَلَا لَا تَجْنِي أُمٌّ عَلَى وَلَدٍ أَلَا لَا تَجْنِي أُمٌّ عَلَى وَلَدٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abdullah bin Numair] dari [Yazid bin Abu Ziyad], telah menceritakan kepada kami [Jami' bin Syadad] dari [Thariq Al Muharabi], ia berkata; Aku melihat Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya sampai aku melihat warna putih ketiaknya, beliau bersabda: \"Ketahuilah! Seorang ibu tidak menanggung (hukuman) akibat perbuatan jahat anaknya. Ketahuilah! Seorang ibu tidak menanggung (hukuman) akibat perbuatan jahat anaknya.\""},"2626":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا هُشَيْمٌ عَنْ يُونُسَ عَنْ حُصَيْنِ بْنِ أَبِي الْحُرِّ عَنْ الْخَشْخَاشِ الْعَنْبَرِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِيَ ابْنِي فَقَالَ لَا تَجْنِي عَلَيْهِ وَلَا يَجْنِي عَلَيْكَ","id":"Telah menceritakan kepada kami [Amru bin Rafi'], telah menceritakan kepada kami [Husyaim] dari [Yunus] dari [Hushain bin Abu Al Hurr] dari [Al Khasykhasy Al 'Anbari], ia berkata; Aku mendatangi Nabi shallallahu 'alaihi wasallam bersama anakku, beliau bersabda: \"Kau tidak menanggung hukuman akibat kejahatannya, dan ia tidak menanggung hukuman akibat kejahatanmu.\""},"2627":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عَقِيلٍ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا أَبُو الْعَوَّامِ الْقَطَّانُ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْنِي نَفْسٌ عَلَى أُخْرَى","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Ubaid bin 'Aqil], telah menceritakan kepada kami [Amru bin'Ashim], telah menceritakan kepada kami [Abu Al 'Awwam Al Qaththan] dari [Muhammad bin Juhadah] dari [Ziyad bin 'Ilaqah] dari [Usamah bin Syarik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap jiwa manusia tidak menanggung hukuman akibat kejahatan orang lain.\""},"2628":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَجْمَاءُ جَرْحُهَا جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَالْبِئْرُ جُبَارٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Luka yang diakibatkan binatang buas adalah sia-sia (tidak ada jaminan), dan kematian akibat kecelakaan di sebuah tambang adalah sia-sia, kematian karena jatuh ke sumur adalah sia-sia (tidak ada jaminan).\""},"2629":{"ar":"حَدَّثَنَا أَبو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا ��َثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَجْمَاءُ جَرْحُهَا جُبَارٌ وَالْمَعْدِنُ جُبَارٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Khalid bin Makhlad], telah menceritakan kepada kami [Katsir bin Abdullah bin Amru bin 'Auf] dari [Ayahnya] dari [Kakeknya] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Luka yang diakibatkan binatang liar adalah sia-sia (tidak ada jaminan) dan kematian (kecelakaan) dalam tambang adalah sia-sia.\""},"2630":{"ar":"حَدَّثَنَا عَبْدُ رَبِّهِ بْنُ خَالِدٍ النُّمَيْرِيُّ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنِي مُوسَى بْنُ عُقْبَةَ حَدَّثَنِي إِسْحَقُ بْنُ يَحْيَى بْنِ الْوَلِيدِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْمَعْدِنَ جُبَارٌ وَالْبِئْرَ جُبَارٌ وَالْعَجْمَاءَ جَرْحُهَا جُبَارٌ وَالْعَجْمَاءُ الْبَهِيمَةُ مِنْ الْأَنْعَامِ وَغَيْرِهَا وَالْجُبَارُ هُوَ الْهَدْرُ الَّذِي لَا يُغَرَّمُ","id":"Telah menceritakan kepada kami [Abdurrabih bin Khalid An Numairi], telah menceritakan kepada kami [Fudhail bin Sulaiman], telah menceritakan kepadaku [Musa bin Uqbah], telah menceritakan kepadaku [Ishaq bin Yahya bin Al Walid] dari [Ubadah bin As Shamit], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menetapkan hukum bahwa kematian dalam pertambangan adalah sia-sia (tidak ada jaminan diyat atau qishash), kematian karena jatuh ke sumur adalah sia-sia, dan luka/kematian yang diakibatkan hewan lain adalah sia-sia.\""},"2631":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّارُ جُبَارٌ","id":"Telah menceritakan kepada kami [Ahmad bin Azhar], telah menceritakan kepada kami [Abdurrazak] dari [Ma'mar] dari [Hammam] dari [Abu hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kecelakaan (kematian) yang diakibatkan merembaknya api tanpa disengaja adalah sia-sia.\""},"2632":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ سَمِعْتُ مَالِكَ بْنَ أَنَسٍ حَدَّثَنِي أَبُو لَيْلَى بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَهْلٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ أَنَّهُ أَخْبَرَهُ عَنْ رِجَالٍ مِنْ كُبَرَاءِ قَوْمِهِأَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ وَمُحَيِّصَةَ خَرَجَا إِلَى خَيْبَرَ مِنْ جَهْدٍ أَصَابَهُمْ فَأُتِيَ مُحَيِّصَةُ فَأُخْبِرَ أَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ قَدْ قُتِلَ وَأُلْقِيَ فِي فَقِيرٍ أَوْ عَيْنٍ بِخَيْبَرَ فَأَتَى يَهُودَ فَقَالَ أَنْتُمْ وَاللَّهِ قَتَلْتُمُوهُ قَالُوا وَاللَّهِ مَا قَتَلْنَاهُ ثُمَّ أَقْبَلَ حَتَّى قَدِمَ عَلَى قَوْمِهِ فَذَكَرَ ذَلِكَ لَهُمْ ثُمَّ أَقْبَلَ هُوَ وَأَخُوهُ حُوَيِّصَةُ وَهُوَ أَكْبَرُ مِنْهُ وَعَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ فَذَهَبَ مُحَيِّصَةُ يَتَكَلَّمُ وَهُوَ الَّذِي كَانَ بِخَيْبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمُحَيِّصَةَ كَبِّرْ كَبِّرْ يُرِيدُ السِّنَّ فَتَكَلَّمَ حُوَيِّصَةُ ثُمَّ تَكَلَّمَ مُحَيِّصَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِمَّا أَنْ يَدُوا صَاحِبَكُمْ وَإِمَّا أَنْ يُؤْذَنُوا بِحَرْبٍ فَكَتَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِمْ فِي ذَلِكَ فَكَتَبُوا إِنَّا وَاللَّهِ مَا قَتَلْنَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحُوَيِّصَةَ وَمُحَيِّصَةَ وَعَبْدِ الرَّحْمَنِ تَحْلِفُونَ وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ قَالُوا لَا قَالَ فَتَحْلِفُ لَكُمْ يَهُودُ قَالُوا لَيْسُوا بِمُسْلِمِينَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ فَبَعَثَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِائَةَ نَاقَةٍ حَتَّى أُدْخِلَتْ عَلَيْهِمْ الدَّارَفَقَالَ سَهْلٌ فَلَقَدْ رَكَضَتْنِي مِنْهَا نَاقَةٌ حَمْرَاءُ","id":"Telah menceritakan kepada kami [Yahya bin Hakim], telah menceritakan kepada kami [Bisyr bin Umar], aku mendengar [Malik bin Anas], telah menceritakan kepadaku [Abu Laila bin Abdullah bin Abdurrahman bin Sahal] dari [Sahl bin Abu Hatsmah], dari [para pembesar] kaum mereka, \"Sesungguhnya Abdullah bin Sahl dan Muhayishah, keduanya keluar dari kediamannya menuju kawasan Khaibar karena kesulitan yang menimpa mereka. Lalu Muhayishah didatangi dan diberitahu bahwa Abdullah bin Sahl telah terbunuh dan dilemparkan di sebuah sumur yang biasa disebut Faqir atau Ain di kawasan Khaibar. Orang-orang Yahudi datang lalu Muhayishah berkata kepada mereka, \"Sungguh kalian telah membunuhnya! Demi Allah! Kalian telah membunuhnya.\" Mereka menjawab, \"Demi Allah! kami tidak membunuhnya.\" Lalu ia kembali dan datang menemui kaumnya. Ia mengemukakan hal yang terjadi kepada mereka. Kemudian Muhayishah dan saudara laki-lakinya Huwayishah yang lebih besar darinya serta Abdurrahman bin Sahl berangkat kembali. Muhayishah pergi lalu berbicara, sebab dialah yang ada di kawasan Khaibar, namun Rasulullah shallallahu 'alaihi wasallam berkata kepada Muhayishah, \"Yang besar, yang besar.\" Maksudkan yang paling dewasa usianya. Maka Huwayishah berbicara kemudian diikuti oleh Muhayishah. Rasulullah shallallahu 'alaihi wasallam berkata; \"Mereka akan membayar diyat pada teman kalian atau mereka memberi isyarat untuk berperang.\" Lalu Rasulullah shallallahu 'alaihi wasallam menulis surat dalam hal ini. kemudian mereka membalas dengan pernyataan: \"Sungguh Demi Allah! Kami tidak membunuhnya.\" lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepada Huwayishah, Muhayishah dan Abdurrahman: \"Apakah kalian bersedia bersumpah dengan benar hingga kalian mendapat hak darah saudara kalian?\" Mereka menjawab, \"Tidak.\" Rasulullah bersabda; \"Jika demikian berarti orang-orang Yahudi yang akan bersumpah pada kalian.\" Mereka menjawab; \"Mereka bukan kaum Muslimin.\" Rasulullah pun membayar diyat dari pribadinya. Rasulullah mengirimkan seratus ekor unta kepada mereka sampai dimasukan ke dalam rumah. Sahl berkata; \"Sungguh seekor unta merah darinya telah menyepakku.\""},"2633":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَجَّاجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ حُوَيِّصَةَ وَمُحَيِّصَةَ ابْنَيْ مَسْعُودٍ وَعَبْدَ اللَّهِ وَعَبْدَ الرَّحْمَنِ ابْنَيْ سَهْلٍ خَرَجُوا يَمْتَارُونَ بِخَيْبَرَ فَعُدِيَ عَلَى عَبْدِ اللَّهِ فَقُتِلَ فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تُقْسِمُونَ وَتَسْتَحِقُّونَ فَقَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نُقْسِمُ وَلَمْ نَشْهَدْ قَالَ فَتُبْرِئُكُمْ يَهُودُ قَالُوا يَا رَسُولَ اللَّهِ إِذًا تَقْتُلَنَا قَالَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id], telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Hajjaj] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Huwayishah dan Muhayishah, dua orang anak Mas'ud dan Abdullah serta Abdurrahman dua orang anak laki-laki dari Sahl keluar dari kediamannya dalam rangka mencari makanan dikawasan Khaibar. lalu Abdullah dilukai dan terbunuh. Hal tersebut dikemukakan kepada Rasulullah. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian bersedia bersumpah dan mendapatkan hak kalian?\" Mereka menjawab, \"Wahai Rasulullah! Bagaimana kami dapat bersumpah sementara kami tidak menyaksikannya?\" beliau bersabda: \"Orang-orang Yahudi akan membebaskan kalian.\" Mereka berkata; \"Wahai Rasulullah! Jika demikian mereka akan membunuh kami.\" Perawi berkata; \"Maka Rasulullah shallallahu 'alaihi wasallam membayar diyat dari harta milik beliau.\""},"2634":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ السَّلَامِ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي فَرْوَةَ عَنْ سَلَمَةَ بْنِ رَوْحِ بْنِ زِنْبَاعٍ عَنْ جَدِّهِأَنَّهُ قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَخْصَى غُلَامًا لَهُ فَأَعْتَقَهُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمُثْلَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Abdus Salam] dari [Ishaq bin Abdullah bin Abu Farwah] dari [Salamah bin Rauh bin Zinba'] dari [kakeknya]; bahwasanya ia datang menemui Nabi shallallahu 'alaihi wasallam, dimana telah mengebiri seorang hamba sahaya. Lalu Nabi shallallahu 'alaihi wasallam memerdekakan budak itu sebagai hukumannya tersebut.\""},"2635":{"ar":"حَدَّثَنَا رَجَاءُ بْنُ الْمُرَجَّى السَّمَرْقَنْدِيُّ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا أَبُو حَمْزَةَ الصَّيْرَفِيُّ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَارِخًا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكَ قَالَ سَيِّدِي رَآنِي أُقَبِّلُ جَارِيَةً لَهُ فَجَبَّ مَذَاكِيرِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيَّ بِالرَّجُلِ فَطُلِبَ فَلَمْ يُقْدَرْ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَأَنْتَ حُرٌّ قَالَ عَلَى مَنْ نُصْرَتِي يَا رَسُولَ اللَّهِ قَالَ يَقُولُ أَرَأَيْتَ إِنْ اسْتَرَقَّنِي مَوْلَايَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كُلِّ مُؤْمِنٍ أَوْ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Raja`bin Muraja` As Samarqandi], telah menceritakan kepada kami [Nadlar bin Syumail], telah menceritakan kepada kami [Abu Hamzah Ash Shairafi], telah menceritakan kepadaku [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] berkata; \"Seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam sambil berteriak, maka Rasulullah shallallahu 'alaihi wasallam berkata kepadanya, \"Ada apa denganmu?\" Ia menjawab, \"Tuanku telah melihatku mencium hamba sahaya perempuannya, maka ia memotong kemaluanku.\" Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Datangkanlah padaku tuanmu itu!.\" Lalu dicarinya, tetapi ia tidak kuasa untuk membawanya, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergilah, kamu telah bebas.\" Ia bertanya; \"Siapakah yang akan menolongku, wahai Rasulullah?\" Ia berkata; \"Bagaimana jika ia mencariku dan mengembalikanku padanya?\"Rasulullah shallallahu 'alaihi wasallam menjawab: \"Yang bertanggung jawab kepadamu adalah setiap orang mukmin atau muslim.\" "},"2636":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا هُشَيْمٌ عَنْ مُغِيرَةَ عَنْ شِبَاكٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ قَالَ عَبْدُ اللَّهِقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَعَفِّ النَّاسِ قِتْلَةً أَهْلَ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi], telah menceritakan kepada kami [Husyaim] dari [Mughirah] dari [Syibak] dari [Ibrahim] dari [Al Qamah] berkata; [Abdullah] berkata; \"Sungguh orang yang paling dijaga dari suatu pembunuhan adalah ahli iman.\""},"2637":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ مُغِيرَةَ عَنْ شِبَاكٍ عَنْ إِبْرَاهِيمَ عَنْ هُنَيِّ بْنِ نُوَيْرَةَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَعَفَّ النَّاسِ قِتْلَةً أَهْلُ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Mughirah] dari [Syibak] dari [Ibrahim] dari [Hunaiy bin Nuwairah] dari ['Alqamah] dari [Abdullah] berkata; \"Sungguh yang paling diutamakan untuk dijaga dari suatu pembunuhan adalah ahli iman.\""},"2638":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ حَنَشٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُس��لِمُونَ تَتَكَافَأُ دِمَاؤُهُمْ وَهُمْ يَدٌ عَلَى مَنْ سِوَاهُمْ يَسْعَى بِذِمَّتِهِمْ أَدْنَاهُمْ وَيُرَدُّ عَلَى أَقْصَاهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul `A'la Ashan'ani], telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Ayahnya] dari [Hanasy] dari [Ikrimah] dari [Ibnu Abbas], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Nyawa umat Islam sepadan. seorang muslim harus saling membantu sesama mereka, yang lemah dan yang jauh mempunyai hak yang sama dalah perihal ghanimah.\""},"2639":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ أَبُو ضَمْرَةَ عَنْ عَبْدِ السَّلَامِ بْنِ أَبِي الْجَنُوبِ عَنْ الْحَسَنِ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمُونَ يَدٌ عَلَى مَنْ سِوَاهُمْ وَتَتَكَافَأُ دِمَاؤُهُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari], telah menceritakan kepada kami [Anas bin Iyadh Abu Dhamrah] dari [Abdussalam bin Abu Janub] dari [Al Hasan] dari [Ma'qil bin Yasar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kaum muslimin saling menolong dengan sesama mereka dan nyawa mereka mempunyai kedudukan setingkat (dalam hal qishas dan diyat).\""},"2640":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَيَّاشٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدُ الْمُسْلِمِينَ عَلَى مَنْ سِوَاهُمْ تَتَكَافَأُ دِمَاؤُهُمْ وَأَمْوَالُهُمْ وَيُجِيرُ عَلَى الْمُسْلِمِينَ أَدْنَاهُمْ وَيَرُدُّ عَلَى الْمُسْلِمِينَ أَقْصَاهُمْ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar], telah menceritakan kepada kami [Hatim bin Isma'il] dari [Abdurrhaman bin Ayyasy] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kaum muslimin saling menolong dengan sesama mereka dan nyawa dan harta mereka mempunyai kedudukan setingkat (dalam hal qishas dan diyat), yang lemah dan yang jauh mempunyai hak yang sama dalah perihal ghanimah.\""},"2641":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْحَسَنِ بْنِ عَمْرٍو عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ مُعَاهَدًا لَمْ يَرَحْ رَائِحَةَ الْجَنَّةِ وَإِنَّ رِيحَهَا لَيُوجَدُ مِنْ مَسِيرَةِ أَرْبَعِينَ عَامًا","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al Hasan bin Amru] dari [Mujahid] dari [Abdullah bin Amru] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membunuh seorang kafir mu'ahad, maka ia tidak dapat mencium aroma surga. Dan sesungguhnya aroma surga dapat dirasakan dari jarak per jalanan selama empat puluh tahun.\""},"2642":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مَعْدِيُّ بْنُ سُلَيْمَانَ أَنْبَأَنَا ابْنُ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ مُعَاهَدًا لَهُ ذِمَّةُ اللَّهِ وَذِمَّةُ رَسُولِهِ لَمْ يَرَحْ رَائِحَةَ الْجَنَّةِ وَإِنَّ رِيحَهَا لَيُوجَدُ مِنْ مَسِيرَةِ سَبْعِينَ عَامًا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Ma'di bin Sulaiman], telah memberitakan kepada kami [Ibnu 'Ajalan] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa membunuh orang kafir mu'ahad yang berada dalam perlindungan Allah dan perlindungan RasulNya, maka dia tidak dapat mencium harumnya surga, sedangkan harumnya dapat di cium dari perjalanan tujuh puluh tahun.\""},"2643":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِفَاعَةَ بْنِ شَدَّادٍ الْقِتْبَانِيِّ قَالَلَوْلَا كَلِمَةٌ سَمِعْتُهَا مِنْ عَمْرِو بْنِ الْحَمِقِ الْخُزَاعِيِّ لَمَشَيْتُ فِيمَا بَيْنَ رَأْسِ الْمُخْتَارِ وَجَسَدِهِ سَمِعْتُهُ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَمِنَ رَجُلًا عَلَى دَمِهِ فَقَتَلَهُ فَإِنَّهُ يَحْمِلُ لِوَاءَ غَدْرٍ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Syawarib], telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik bin Umair] dari [Rifa'ah bin Syaddad Al Qitbani] berkata; Kalaulah bukan satu kalimat yang pernah aku dengar dari [Amru bin Hamiq Al Khuza'i], maka niscaya aku telah berjalan diantara kepala Al Mukhtar dan tubuhnya, aku mendengarnya berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mengamankan nyawa seseorang lalu ia membunuhnya, maka di hari Kiamat kelak ia akan membawa bendera pengkhianatan.\""},"2644":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو لَيْلَى عَنْ أَبِي عُكَّاشَةَ عَنْ رِفَاعَةَ قَالَدَخَلْتُ عَلَى الْمُخْتَارِ فِي قَصْرِهِ فَقَالَ قَامَ جِبْرَائِيلُ مِنْ عِنْدِيَ السَّاعَةَ فَمَا مَنَعَنِي مِنْ ضَرْبِ عُنُقِهِ إِلَّا حَدِيثٌ سَمِعْتُهُ مِنْ سُلَيْمَانَ بْنِ صُرَدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا أَمِنَكَ الرَّجُلُ عَلَى دَمِهِ فَلَا تَقْتُلْهُ فَذَاكَ الَّذِي مَنَعَنِي مِنْهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Abu Laila], dari [Abu Ukasyah] dari [Rifa'ah] berkata; \"Aku mendatangi Mukhtar di rumahnya lalu ia berkata; Pada saat itu Jibril berdiri di sisiku, tidak ada yang menghalangiku untuk memenggal lehernya kecuali sebuah Hadits yang pernah aku dengar dari [Sulaiman bin Shard] dari Nabi Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Jika kamu merasa aman dari kejahatan seseorang, maka janganlah kamu membunuhnya.\" Itulah yang menahan aku dari memenggalnya."},"2645":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَتَلَ رَجُلٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُفِعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَفَعَهُ إِلَى وَلِيِّ الْمَقْتُولِ فَقَالَ الْقَاتِلُ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا أَرَدْتُ قَتْلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْوَلِيِّ أَمَا إِنَّهُ إِنْ كَانَ صَادِقًا ثُمَّ قَتَلْتَهُ دَخَلْتَ النَّارَ قَالَ فَخَلَّى سَبِيلَهُ قَالَ فَكَانَ مَكْتُوفًا بِنِسْعَةٍ فَخَرَجَ يَجُرُّ نِسْعَتَهُ فَسُمِّيَ ذَا النِّسْعَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al `A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; \"Seorang laki-laki di masa Rasulullah shallallahu 'alaihi wasallam telah melakukan pembunuhan, hal ini diadukan kepada Nabi shallallahu 'alaihi wasallam, lalu diserahkan kepada keluarga terbunuh. Si pembunuh berkata; \"Wahai Rasulullah! Demi Allah! Aku sebenarnya tidak bermaksud membunuhnya.\" Rasulullah shallallahu 'alaihi wasallam bersabda kepada wali korban, \"Jika ia (pembunuh) benar lalu kamu membunuhnya, maka kamu akan masuk neraka. \" Maka ia pun berkata; \"Sudah, lepaskanlah ia.\" perawi berkata; \"Terdakwa diikat dengan tali yang terbuat dari kulit lalu ia keluar menariknya dengan tali tersebut hingga ia dijuluki dengan panggilan si pemilik tali kulit.\""},"2646":{"ar":"حَدَّثَنَا أَبُو عُمَيْرٍ عِيسَى بْنُ مُحَمَّدِ بْنِ النَّحَّاسِ وَعِيسَى بْنُ يُونُسَ وَالْحُسَيْنُ بْنُ أَبِي السَّرِىِّ الْعَسْقَلَانِيُّ قَالُوا حَدَّثَنَا ضَمْرَةُ بْنُ رَبِيعَةَ عَنْ ابْنِ شَوْذَبٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَتَى رَجُلٌ بِقَاتِلِ وَلِيِّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْفُ فَأَبَى فَقَالَ خُذْ أَرْشَكَ فَأَبَى قَالَ اذْهَبْ فَاقْتُلْهُ فَإِنَّكَ مِثْلُهُ قَالَ فَلُحِقَ بِهِ فَقِيلَ لَهُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ اقْتُلْهُ فَإِنَّكَ مِثْلُهُ فَخَلَّى سَبِيلَهُ قَالَ فَرُئِيَ يَجُرُّ نِسْعَتَهُ ذَاهِبًا إِلَى أَهْلِهِ قَالَ كَأَنَّهُ قَدْ كَانَ أَوْثَقَهُقَالَ أَبُو عُمَيْرٍ فِي حَدِيثِهِ قَالَ ابْنُ شَوْذَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ فَلَيْسَ لِأَحَدٍ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقُولُ اقْتُلْهُ فَإِنَّكَ مِثْلُهُ قَالَ ابْن مَاجَةَ هَذَا حَدِيثُ الرَّمْلِيِّينَ لَيْسَ إِلَّا عِنْدَهُمْ","id":"Telah menceritakan kepada kami [Abu Umair Isa bin Muhammd bin Nahas] dan [Isa bin Yunus] serta [Husain bin Abu Sari Al 'Asqalani], semuanya berkata; telah menceritakan kepada kami [Dlamrah bin Rabi'ah] dari [Ibnu Syaudzab] dari [Tsabit Al Bunani] dari [Anas bin Malik], ia berkata; \"Seseorang membawa pembunuh salah satu keluarganya dan menemui Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Maafkanlah. \" Lalu ia menolak. Rasulullah bersabda kembali; \"Ambillah diyat untukmu.\" ia tetap menolak. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergilah dan bunuhlah, sesungguhnya kamu seperti dirinya.\" perawi berkata; \"Lalu diikuti olehnya.\" Kemudian dikatakan kepadanya, Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Bunuhlah sesungguhnya kamu seperti dirinya.\" Lalu Rasulullah shallallahu 'alaihi wasallam membiarkannya. perawi berkata; \"Kemudian ia menarik pembunuh tersebut dan mengikatnya dengan tali hingga menemui keluarganya.\" Perawi berkata; \"Seakan-akan Nabi shallallahu 'alaihi wasallam telah percaya kepadanya.\" Abu Umair berkata di dalam Haditsnya, Ibnu Syaudzab berkata; dari Abdurrahman bin Al Qasim, ia berkata; \"Tidak ada seorang pun yang layak berbicara setelah Nabi shallallahu 'alaihi wasallam bersabda: \"Bunuhlah karena sesungguhnya kamu sepertinya.\" Ibnu Majah berkata; Hadits ini adalah dari suku Ramli, tiada yang lain kecuali dari mereka.\""},"2647":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ الْمُزَنِيُّ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ قَالَ لَا أَعْلَمُهُ إِلَّا عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا رُفِعَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ فِيهِ الْقِصَاصُ إِلَّا أَمَرَ فِيهِ بِالْعَفْوِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur], telah memberitakan kepada kami [Habban bin Hilal], telah menceritakan kepada kami [Abdullah bin Bukair Al Muzanni] dari ['Atha`bin Abu Maimunah] berkata; Aku tidak mengetahuinya kecuali dari jalur [Anas bin Malik], ia berkata; \"Tidak pernah suatu perkara diajukan kepada Rasulullah yang di dalamnya terdapat masalah qishash kecuali beliau memerintahkan untuk memberi pengampunan.\""},"2648":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ أَبِي السَّفَرِ قَالَ قَالَ أَبُو الدَّرْدَاءِسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ رَجُلٍ يُصَابُ بِشَيْءٍ مِنْ جَسَدِهِ فَيَتَصَدَّقُ بِهِ إِلَّا رَفَعَهُ اللَّهُ بِهِ دَرَجَةً أَوْ حَطَّ عَنْهُ بِهِ خَطِيئَةً سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'] dari [Yunus bin Abu Ishaq] dari [Abu Safar] berkata; [Abu Darda`] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang lelaki yang tertimpa sesuatu di tubuhnya lalu ia meninggalkan untuk mengqishasnya kecuali Allah akan mengangkat derajatnya atau dihapus kesalahan darinya.\" Aku mendengarnya dengan kedua telingaku dan hatiku dapat memahaminya.\""},"2649":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو صَالِحٍ عَنْ ابْنِ لَهِيعَةَ عَنْ ابْنِ أَنْعُمَ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ حَدَّثَنَا مُعَاذُ بْنُ جَبَلٍ وَأَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ وَعُبَادَةُ بْنُ الصَّامِتِ وَشَدَّادُ بْنُ أَوْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَرْأَةُ إِذَا قَتَلَتْ عَمْدًا لَا تُقْتَلُ حَتَّى تَضَعَ مَا فِي بَطْنِهَا إِنْ كَانَتْ حَامِلًا وَحَتَّى تُكَفِّلَ وَلَدَهَا وَإِنْ زَنَتْ لَمْ تُرْجَمْ حَتَّى تَضَعَ مَا فِي بَطْنِهَا وَحَتَّى تُكَفِّلَ وَلَدَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Abu Shalih] dari [Ibnu Lahi'ah] dari [Ibnu `An'um] dari [Ubadah bin Nusai] dari [Abdurrahman bin Ghanam], telah menceritakan kepada kami [Mu'adz bin Jabal], [Abu 'Ubaidah bin Al-Jarrah], ['Ubadah bin As-Shamit] dan [Syaddad bin Aus]; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang perempuan apabila membunuh dengan sengaja, maka janganlah dibunuh sehingga dia melahirkan anak yang ada di perutnya jika dia dalam keadaan hamil dan sampai dia dapat memelihara anaknya. Dan jika dia berzina jangan dirajam sampai dia melahirkan anak yang ada di perutnya dan sampai dapat memelihara anaknya.\""},"2650":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ أَبُو بَكْرٍ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِينَارًا وَلَا دِرْهَمًا وَلَا شَاةً وَلَا بَعِيرًا وَلَا أَوْصَى بِشَيْءٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair], telah menceritakan kepada kami [Ayahku] dan [Abu Mu'awiyah], (demikian juga diriwayatkan dari jalur lain), telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduannya berkata; telah menceritakan kepada kami [Abu Mu'awiyah]; Abu Bakar dan Abdullah bin Numair dari [Al `A'masy] dari [Syaqiq] dari [Masruq] dari [Aisyah], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan uang satu dinar atau satu dirham pun, demikian pula dengan seekor kambing dan unta. Juga Beliau tidak memberikan wasiat dengan sesuatu sama sekali.\""},"2651":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ قَالَقُلْتُ لِعَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى أَوْصَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ قَالَ لَا قُلْتُ فَكَيْفَ أَمَرَ الْمُسْلِمِينَ بِالْوَصِيَّةِ قَالَ أَوْصَى بِكِتَابِ اللَّهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'] dari [Malik bin Mighwal] dari [Thalhah bin Musharrif] berkata; \"Aku katakan kepada [Abdullah bin Abu Aufa], ia berkata; 'Apakah Rasulullah shallallahu 'alaihi wasallam mewasiatkan sesuatu? ' la menjawab, \"Tidak.\" Aku katakan, \"Lalu bagaimana beliau memerintahkan umat Islam untuk berwasiat?.\" Thalhah berkata; \"Beliau telah berwasiat dengan Al Qur'an.\""},"2652":{"ar":"قَالَ مَالِكٌ وَقَالَ طَلْحَةُ بْنُ مُصَرِّفٍ قَالَ الْهُزَيْلُ بْنُ شُرَحْبِيلَأَبُو بَكْرٍ كَانَ يَتَأَمَّرُ عَلَى وَصِيِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَّ أَبُو بَكْرٍ أَنَّهُ وَجَدَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدًا فَخَزَمَ أَنْفَهُ بِخِزَامٍ","id":"[Malik] berkata; [Thalhah bin Musharrif] berkata, [Al Huzail bin Syurhabil] berkata; \"Apakah [Abu Bakar] pernah berkonspirasi mengenai wasiat Rasulullah?\" Abu Bakar menginginkan bahwa dirinya menemukan dari Rasulullah shallallahu 'alaihi wasallam sebuah janji, lalu ia mengikat hidungnya dengan seutas tali."},"2653":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْمِقْدَامِ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَتْ عَامَّةُ وَصِيَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ حَضَرَتْهُ الْوَفَاةُ وَهُوَ يُغَرْغِرُ بِنَفْسِهِ الصَّلَاةَ وَمَا مَلَكَتْ أَيْمَانُكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Miqdam], telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman]; aku mendengar [Ayahku] menceritakan dari [Qatadah] dari [Anas bin Malik], ia berkata; \"Wasiat umum Rasulullah shallallahu 'alaihi wasallam menjelang wafat, ketika sakaratul maut yaitu: \"Jagalah shalat dan zakat serta perhatikanlah hamba sahaya kalian.\""},"2654":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ مُغِيرَةَ عَنْ أُمِّ مُوسَى عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكَانَ آخِرُ كَلَامِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ وَمَا مَلَكَتْ أَيْمَانُكُمْ","id":"Telah menceritakan kepada kami [Sahal bin Abu Sahal], telah menceritakan kepada kami [Muhammad bin Fudhail] dari [Mughirah] dari [Ummu Musa] dari [Ali bin Abu Thalib] berkata; \"Akhir ucapan Nabi shallallahu 'alaihi wasallam adalah: \"Jagalah shalat dan zakat serta perhatikanlah hamba sahaya kalian.\""},"2655":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَقُّ امْرِئٍ مُسْلِمٍ أَنْ يَبِيتَ لَيْلَتَيْنِ وَلَهُ شَيْءٌ يُوصِي فِيهِ إِلَّا وَوَصِيَّتُهُ مَكْتُوبَةٌ عِنْدَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hak dari seorang muslim yang bermalam selama dua malam dan ia memiliki sesuatu yang diwasiatkan, kecuali wasiatnya ditulis di sisinya.\""},"2656":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا دُرُسْتُ بْنُ زِيَادٍ حَدَّثَنَا يَزِيدُ الرَّقَاشِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَحْرُومُ مَنْ حُرِمَ وَصِيَّتَهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdhami], telah menceritakan kepada kami [Durustu bin Ziyad], telah menceritakan kepada kami [Yazid Ar Raqasyi] dari [Anas Bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang bernasib buruk adalah orang yang terhalangi untuk membuat wasiat.\""},"2657":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ يَزِيدَ بْنِ عَوْفٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَاتَ عَلَى وَصِيَّةٍ مَاتَ عَلَى سَبِيلٍ وَسُنَّةٍ وَمَاتَ عَلَى تُقًى وَشَهَادَةٍ وَمَاتَ مَغْفُورًا لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Mushaffa Al Himshi], telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Yazid bin 'Auf] dari [Abu Zubair] dari [Jabir bin Abdullah], ia berkata; bersabda Rasulullah shallallahu 'alaihi wasallam: \"Barang siapa yang meninggal dalam keadaan berwasiat maka dia meninggal diatas jalan yang benar dan sunnah, dia meninggal diatas ketaqwaan dan syahadah, dan dia meninggal dalam keadaan diampuni.\""},"2658":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا رَوْحُ بْنُ عَوْفٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَقُّ امْرِئٍ مُسْلِمٍ يَبِيتُ لَيْلَتَيْنِ وَلَهُ شَيْءٌ يُوصِي بِهِ إِلَّا وَوَصِيَّتُهُ مَكْتُوبَةٌ عِنْدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar], telah menceritakan kepada kami [Rauh bin 'Auf] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada hak seorang muslim yang bermalam selama dua malam dan ia memiliki sesuatu yang diwasiatkan, kecuali wasiatnya ditulis di sisinya.\""},"2659":{"ar":"حَ��َّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ زَيْدٍ الْعَمِّيُّ عَنْ أَبِيهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَرَّ مِنْ مِيرَاثِ وَارِثِهِ قَطَعَ اللَّهُ مِيرَاثَهُ مِنْ الْجَنَّةِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id], telah menceritakan kepada kami [Abdurrahim bin Zaid Al 'Ammi] dari [Ayahnya] dari [Anas bin Malik], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang lari dengan membawa warisan ahli warisnya, Allah akan memutus warisannya dari surga pada hari kiamat.\""},"2660":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ بْنُ هَمَّامٍ أَنْبَأَنَا مَعْمَرٌ عَنْ أَشْعَثَ بْنِ عَبْدِ اللَّهِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرَّجُلَ لَيَعْمَلُ بِعَمَلِ أَهْلِ الْخَيْرِ سَبْعِينَ سَنَةً فَإِذَا أَوْصَى حَافَ فِي وَصِيَّتِهِ فَيُخْتَمُ لَهُ بِشَرِّ عَمَلِهِ فَيَدْخُلُ النَّارَ وَإِنَّ الرَّجُلَ لَيَعْمَلُ بِعَمَلِ أَهْلِ الشَّرِّ سَبْعِينَ سَنَةً فَيَعْدِلُ فِي وَصِيَّتِهِ فَيُخْتَمُ لَهُ بِخَيْرِ عَمَلِهِ فَيَدْخُلُ الْجَنَّةَقَالَ أَبُو هُرَيْرَةَ وَاقْرَءُوا إِنْ شِئْتُمْ{ تِلْكَ حُدُودُ اللَّهِ إِلَى قَوْلِهِ عَذَابٌ مُهِينٌ }","id":"Telah menceritakan kepada kami [Ahmad bin Azhar], telah menceritakan kepada kami [Abdurrazak bin Hammam], telah memberitakan kepada kami [Ma'mar] dari [`Asy'ats bin Abdullah] dari [Syahr bin Hausyab] dari [Abu Hurairah], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang lelaki beramal dengan amalan ahlul khair (kebaikan) selama tujuh puluh tahun kemudian apabila dia berwasiat dan dia bertindak lalim di dalam wasiatnya, maka dia diakhiri dengan perbuatannya yang buruk sehingga dia masuk neraka. Dan sesungguhnya seorang lelaki beramal dengan amalan pelaku keburukan selama tujuh puluh tahun kemudian dia bersikap adil di dalam wasiatnya maka dia diakhiri dengan perbuatan yang baik sehingga dia masuk syurga.\" Abu Hurairah Berkata; Bacalah jika kalian kehendaki: \" Itulah ketentuan-ketentuan dari Allah sampai firmanNya adzab yang hina.\" An Nisa: 13-14."},"2661":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ أَبِي حَلْبَسٍ عَنْ خُلَيْدِ بْنِ أَبِي خُلَيْدٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَضَرَتْهُ الْوَفَاةُ فَأَوْصَى وَكَانَتْ وَصِيَّتُهُ عَلَى كِتَابِ اللَّهِ كَانَتْ كَفَّارَةً لِمَا تَرَكَ مِنْ زَكَاتِهِ فِي حَيَاتِهِ","id":"Telah menceritakan kepada kami [Yahya bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi], telah menceritakan kepada kami [Baqiyyah] dari [Abu Halbas] dari [Khulaid bin Abu Khulaid] dari [Mu'awiyah bin Qurrah], dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa ketika diambang kematian berwasiat dengan wasiat yang dibenarkan oleh kitabullah maka wasiatnya akan menjadi pelebur bagi apa yang dia tinggalkan dari zakatnya pada masa hidupnya.\""},"2662":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ بْنِ شُبْرُمَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ نَبِّئْنِي مَا حَقُّ النَّاسِ مِنِّي بِحُسْنِ الصُّحْبَةِ فَقَالَ نَعَمْ وَأَبِيكَ لَتُنَبَّأَنَّ أُمُّكَ قَالَ ثُمَّ مَنْ قَالَ ثُمَّ أُمُّكَ قَالَ ثُمَّ مَنْ قَالَ ثُمَّ أُمُّكَ قَالَ ثُمَّ مَنْ قَالَ ثُمَّ أَبُوكَ قَالَ نَبِّئْنِي يَا رَسُولَ اللَّهِ عَنْ مَالِي كَيْفَ أَتَصَدَّقُ فِيهِ قَالَ نَعَمْ وَاللَّهِ لَتُنَبَّأَنَّ أَنْ تَصَدَّقَ وَأَنْتَ صَحِيحٌ شَحِيحٌ تَأْمُلُ الْعَيْشَ وَتَخَافُ الْفَقْرَ وَلَا تُمْهِلْ حَتَّى إِذَا بَلَغَتْ نَفْسُكَ هَا هُنَا قُلْتَ مَالِي لِفُلَانٍ وَمَالِي لِفُلَانٍ وَهُوَ لَهُمْ وَإِنْ كَرِهْتَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Syarik] dari [Umarah bin Qa'qa bin Syubrumah] dari [Abu Zur'ah] dari [Abu Hurairah], ia berkata; \"Seseorang datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; 'Wahai Rasulullah! Beritahukanlah kepadaku, siapakah orang yang paling berhak aku temani?\" Beliau menjawab: \"Baiklah, demi Allah aku akan memberitahu kepadamu, (ia adalah) ibumu. \" Orang tersebut berkata; \"Kemudian siapa?\" beliau menjawab, \"Ibumu.\" Orang tersebut berkata; \"Kemudian siapa?\" beliau menjawab, \"Ibumu. \" Orang tersebut berkata lagi, \"Kemudian siapa?\" Rasulullah shallallahu 'alaihi wasallam menjawab, \"Kemudian ayahmu.\"Orang tersebut berkata lagi, \"Wahai Rasulullah, beritahukanlah kepadaku, bagaimana sebaiknya aku menyedekahkan hartaku.\" Beliau bersabda: \"Baiklah, demi Allah, aku akan memberitahu kepadamu, hendaklah kau bersedekah pada saat kau sehat dan kikir, mengharapkan kebaikan kehidupan dunia dan takut akan kemiskinan, dan janganlah kau menundanya hingga nafasmu sampai di sini, dan kau akan mengatakan, \"Sungguh hartaku untuk si fulan, hartaku untuk si fulan, padahal ia pasti menjadi milik mereka sekalipun kau tidak menyukainya.\""},"2663":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا حَرِيزُ بْنُ عُثْمَانَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ مَيْسَرَةَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ بُسْرِ بْنِ جَحَّاشٍ الْقُرَشِيِّ قَالَبَزَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كَفِّهِ ثُمَّ وَضَعَ أُصْبُعَهُ السَّبَّابَةَ وَقَالَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَنَّى تُعْجِزُنِي ابْنَ آدَمَ وَقَدْ خَلَقْتُكَ مِنْ مِثْلِ هَذِهِ فَإِذَا بَلَغَتْ نَفْسُكَ هَذِهِ وَأَشَارَ إِلَى حَلْقِهِ قُلْتَ أَتَصَدَّقُ وَأَنَّى أَوَانُ الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Yazid bin Harun], telah memberitakan kepada kami [Hariz bin Utsman], telah menceritakan kepadaku [Abdurrahman bin Maisarah] dari [Jubair bin Nufair] dari [Busr bin Jahasy Al Qurasyi], ia berkata; Rasulullah shallallahu 'alaihi wasallam meludah di telapak tangannya lalu ia menegakkan jari telunjuknya dan berkata; \"Allah subhanahu wata'ala berfirman: 'Bagaimana kau dapat memperdayaku wahai anak Adam! Padahal Aku telah menciptakanmu dari sesuatu seperti ini. Apabila nyawamu telah sampai disini -beliau memberi isyarat pada tenggorokkannya- engkau mengatakan; 'Aku akan bersedekah! \" Lalu apakah masih ada waktu untuk bersedekah?.\""},"2664":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَالْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ وَسَهْلٌ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَمَرِضْتُ عَامَ الْفَتْحِ حَتَّى أَشْفَيْتُ عَلَى الْمَوْتِ فَعَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَيْ رَسُولَ اللَّهِ إِنَّ لِي مَالًا كَثِيرًا وَلَيْسَ يَرِثُنِي إِلَّا ابْنَةٌ لِي أَفَأَتَصَدَّقُ بِثُلُثَيْ مَالِي قَالَ لَا قُلْتُ فَالشَّطْرُ قَالَ لَا قُلْتُ فَالثُّلُثُ قَالَ الثُّلُثُ وَالثُّلُثُ كَثِيرٌ أَنْ تَذَرَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَذَرَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Husain bin Hasan Al Marwazi] serta [Sahal], semuanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Amir bin Sa'd] dari [Ayahnya], ia berkata; \"Pada saat penaklukan kota Makkah, aku menderita sakit, sampai aku hampir mati, kemudian Rasulullah shallallahu 'alaihi wasallam mengunjungiku. Aku katakan kepada beliau, wahai Rasulullah shallallahu 'alaihi wasallam! Sesungguhnya aku memiliki harta yang banyak dan tidak ada yang akan mewarisiku, kecuali seorang anak perempuanku saja. Apakah aku bersedekah dengan dua pertiga hartaku? Rasulullah menjawab: 'Tidak.' Aku bertanya; \"Setengah?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak. \" Aku tanya lagi, \"Sepertiga?\" Rasulullah menjawab, \"(Boleh) sepertiga, sepertiga itu banyak. Engkau meninggalkan ahli warismu dalam keadaan kaya lebih baik daripada meninggalkan mereka dalam keadaan miskin dan meminta-minta kepada manusia.\""},"2665":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ طَلْحَةَ بْنِ عَمْرٍو عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَصَدَّقَ عَلَيْكُمْ عِنْدَ وَفَاتِكُمْ بِثُلُثِ أَمْوَالِكُمْ زِيَادَةً لَكُمْ فِي أَعْمَالِكُمْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Waki'] dari [Thalhah bin Amru] dari ['Atha`] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah bersedekah pada kalian ketika kalian wafat dengan sepertiga harta kalian sebagai tambahan terhadap amal perbuatan kalian.\""},"2666":{"ar":"حَدَّثَنَا صَالِحُ بْنُ مُحَمَّدِ بنِ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا مُبَارَكُ بْنُ حَسَّانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا ابْنَ آدَمَ اثْنَتَانِ لَمْ تَكُنْ لَكَ وَاحِدَةٌ مِنْهُمَا جَعَلْتُ لَكَ نَصِيبًا مِنْ مَالِكَ حِينَ أَخَذْتُ بِكَظَمِكَ لِأُطَهِّرَكَ بِهِ وَأُزَكِّيَكَ وَصَلَاةُ عِبَادِي عَلَيْكَ بَعْدَ انْقِضَاءِ أَجَلِكَ","id":"Telah menceritakan kepada kami [Shalih bin Muhammad bin Yahya bin Sa'id Al Qaththan]; telah menceritakan kepada kami ['Ubaidullah bin Musa]; telah memberitakan kepada kami [Mubarak bin Hassan] dari [Nafi'] dari [Ibnu 'Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai anak Adam, dua perkara yang salah satunya tidak akan menjadi milikmu, aku telah menjadikan bagian dari hartamu untukmu tatkala aku mengambil dengan kemarahanmu supaya aku mensucikanmu dan membersihkanmu dan shalatnya hamba-hamba-Ku kepadamu setelah datangnya ajalmu.\""},"2667":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَوَدِدْتُ أَنَّ النَّاسَ غَضُّوا مِنْ الثُّلُثِ إِلَى الرُّبُعِ لِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الثُّلُثُ كَبِيرٌ أَوْ كَثِيرٌ","id":"Telah menceritakan kepada kami ['Ali bin Muhamad]; telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Ibnu Abbas], ia berkata; \"Aku menginginkan manusia agar mereka mengurangi dari sepertiga menjadi seperempat karena Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sepertiga itu besar -atau banyak-.'"},"2668":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ عَمْرِو بْنِ خَارِجَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَهُمْ وَهُوَ عَلَى رَاحِلَتِهِ وَإِنَّ رَاحِلَتَهُ لَتَقْصَعُ بِجِرَّتِهَا وَإِنَّ لُغَامَهَا لَيَسِيلُ بَيْنَ كَتِفَيَّ قَالَ إِنَّ اللَّهَ قَسَمَ لِكُلِّ وَارِثٍ نَصِيبَهُ مِنْ الْمِيرَاثِ فَلَا يَجُوزُ لِوَارِثٍ وَصِيَّةٌ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ وَمَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ أَوْ تَوَلَّى غَيْرَ مَوَالِيهِ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌ أَوْ قَالَ عَدْلٌ وَلَا صَرْفٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Yazid bin Harun]; telah memberitakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Syahr bin Hausyab] dari [Abdurrahman bin Ghanam] dari ['Amru bin Kharijah], sesungguhnya Nabi shallallahu 'alaihi wasallam berpidato kepada masyarakat, dan beliau tengah berada di atas kendaraannya. Dan pada waktu itu kendaraannya (yang berupa unta) sedang mengunyah makanan, sementara air liurnya mengalir di antara kedua bahuku. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Subhanahu Wa Ta'ala telah membagi harta warisan dengan bagian masing-masing kepada ahli waris tersebut. Seorang ahli waris tidak boleh mendapatkan harta wasiat. Anak adalah hak pemilik tempat tidur (suami), sedangkan bagi pezina adalah lemparan batu (hukuman rajam), barangsiapa menisbatkan keturunannya kepada orang lain atau budak kepada selain majikannya, maka atasnya laknat Allah Subhanahu Wa Ta'ala, para malaikat dan seluruh manusia, Allah Subhanahu Wa Ta'ala tidak menerima taubat dan tebusan.\" Atau Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tebusan atau taubat.'"},"2669":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا شُرَحْبِيلُ بْنُ مُسْلِمٍ الْخَوْلَانِيُّ سَمِعْتُ أَبَا أُمَامَةَ الْبَاهِلِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي خُطْبَتِهِ عَامَ حِجَّةِ الْوَدَاعِ إِنَّ اللَّهَ قَدْ أَعْطَى كُلَّ ذِي حَقٍّ حَقَّهُ فَلَا وَصِيَّةَ لِوَارِثٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Isma'il bin 'Ayyasy]; telah menceritakan kepada kami [Syurahbil bin Muslim Al Khaulani], aku mendengar [Abu Umamah Al Bahili], ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada saat khutbah haji wada': 'Sesungguhnya Allah Subhanahu Wa Ta'ala telah memberi masing-masing orang haknya, maka tidak ada harta wasiat bagi ahli waris.'\""},"2670":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبِ بْنِ شَابُورَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ أَنَّهُ حَدَّثَهُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَإِنِّي لَتَحْتَ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِيلُ عَلَيَّ لُعَابُهَا فَسَمِعْتُهُ يَقُولُ إِنَّ اللَّهَ قَدْ أَعْطَى كُلَّ ذِي حَقٍّ حَقَّهُ أَلَا لَا وَصِيَّةَ لِوَارِثٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Muhammad bin Syu'aib bin Syabur]; telah menceritakan kepada kami [Abdurrahman bin Yazid bin Jabir] dari [Sa'id bin Abu Sa'id] bahwa ia menceritakan dari [Anas bin Malik], ia berkata; \"Sesungguhnya aku sedang berada di bawah unta Rasulullah shallallahu 'alaihi wasallam dimana air liurnya mengalir mengenaiku. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya Allah Subhanahu Wa Ta'ala telah memberi masing-masing orang akan haknya, ingatlah tidak ada harta wasiat bagi ahli waris.'\""},"2671":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالدَّيْنِ قَبْلَ الْوَصِيَّةِ وَأَنْتُمْ تَقْرَءُونَهَا{ مِنْ بَعْدِ وَصِيَّةٍ يُوصِي بِهَا أَوْ دَيْنٍ }وَإِنَّ أَعْيَانَ بَنِي الْأُمِّ لَيَتَوَارَثُونَ دُونَ بَنِي الْعَلَّاتِ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan] dari [Ibnu Ishaq] dari [Al Harits] dari ['Ali] berkata; \"Rasulullah shallallahu 'alaihi wasallam telah menetapkan hukum agar melunasi hutang sebelum memberikan harta warisan. Kalian dapat membaca ayat Al Qur'an yang berbunyi; sesudah dipenuhi wasiat yang ia buat atau (dan) sesudah dibayar hutangnya.' (An Nisaa: 11) Dan sesungguhnya saudara kandung (dari satu bapak dan satu ibu) yang mendapatkan warisan, dan bukan saudara sebapak dari banyak ibu.\""},"2672":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَبِي مَاتَ وَتَرَكَ مَالًا وَلَمْ يُوصِ فَهَلْ يُكَفِّرُ عَنْهُ أَنْ تَصَدَّقْتُ عَنْهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin 'Utsman Al Utsmani]; telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al A'la bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah], ia berkata; \"Sesungguhnya seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata; 'Sesungguhnya ayahku telah meninggal dunia dan meninggalkan sejumlah harta, sementara ia tidak melakukan wasiat, apakah hartanya dapat menjadi kifarat apabila aku menyedekahkannya? Rasulullah shallallahu 'alaihi wasallam menjawab: 'Ya.'"},"2673":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُمِّي افْتُلِتَتْ نَفْسُهَا وَلَمْ تُوصِ وَإِنِّي أَظُنُّهَا لَوْ تَكَلَّمَتْ لَتَصَدَّقَتْ فَلَهَا أَجْرٌ إِنْ تَصَدَّقْتُ عَنْهَا وَلِيَ أَجْرٌ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur]; telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah], ia berkata; \"Sesungguhnya seorang laki-laki datang menemui Nabi Muhammad shallallahu 'alaihi wasallam, ia berkata; 'Sesungguhnya ibuku meninggal dunia secara mendadak dan ia tidak memberikan wasiat. Aku perkirakan apabila ia dapat berbicara, maka niscaya ia melakukan sedekah, apakah ibuku dan diriku mendapat pahala apabila aku menyedekahkan hartanya? ' Rasulullah shallallahu 'alaihi wasallam menjawab: 'Ya.'\""},"2674":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا أَجِدُ شَيْئًا وَلَيْسَ لِي مَالٌ وَلِي يَتِيمٌ لَهُ مَالٌ قَالَ كُلْ مِنْ مَالِ يَتِيمِكَ غَيْرَ مُسْرِفٍ وَلَا مُتَأَثِّلٍ مَالًا قَالَ وَأَحْسِبُهُ قَالَ وَلَا تَقِي مَالَكَ بِمَالِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Al Azhar]; telah menceritakan kepada kami [Rauh bin 'Ubadah]; telah menceritakan kepada kami [Husain Al Mu'allim] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya], ia berkata; \"Seseorang datang menemui Nabi shallallahu 'alaihi wasallam dan berkata; 'Aku tidak memiliki apa-apa, aku tidak memiliki harta, tetapi aku memiliki seorang anak yatim dan ia memiliki harta.' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Makanlah dari sebagian harta anak yatimmu tanpa berlebihan dan tidak menguasainya.\" Perawi berkata; 'Aku mengira beliau shallallahu 'alaihi wasallam bersabda: 'Dan janganlah engkau campur hartamu dengan hartanya.'"},"2675":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا حَفْصُ بْنُ عُمَرَ بْنِ أَبِي الْعِطَافِ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ تَعَلَّمُوا الْفَرَائِضَ وَعَلِّمُوهَا فَإِنَّهُ نِصْفُ الْعِلْمِ وَهُوَ يُنْسَى وَهُوَ أَوَّلُ شَيْءٍ يُنْزَعُ مِنْ أُمَّتِي","id":"Telah menceritakan kepada kami [Ibrahim bin Mundzir Al Hizami]; telah menceritakan kepada kami [Hafsh bin 'Umar bin Abu Al 'Ithaf]; telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Hurairah, belajarlah faraidl dan ajarkanlah, karena sesungguhnya ia adalah setengah dari ilmu, dan ilmu itu akan dilupakan dan ia adalah yang pertama kali dicabut dari umatku.\""},"2676":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَتْ امْرَأَةُ سَعْدِ بْنِ الرَّبِيعِ بِابْنَتَيْ سَعْدٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ هَاتَانِ ابْنَتَا سَعْدٍ قُتِلَ مَعَكَ يَوْمَ أُحُدٍ وَإِنَّ عَمَّهُمَا أَخَذَ جَمِيعَ مَا تَرَكَ أَبُوهُمَا وَإِنَّ الْمَرْأَةَ لَا تُنْكَحُ إِلَّا عَلَى مَالِهَا فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أُنْزِلَتْ آيَةُ الْمِيرَاثِ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَا سَعْدِ بْنِ الرَّبِيعِ فَقَالَ أَعْطِ ابْنَتَيْ سَعْدٍ ثُلُثَيْ مَالِهِ وَأَعْطِ امْرَأَتَهُ الثُّمُنَ وَخُذْ أَنْتَ مَا بَقِيَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdullah bin Muhammad bin 'Aqil] dari [Jabir bin Abdullah], ia berkata; \"Isteri Sa'd bin Rabi' datang menemui Nabi shallallahu 'alaihi wasallam dengan membawa kedua anak perempuannnya, lalu berkata; 'Wahai Rasulullah! Ini dua anak perempuan dari Sa'd. la terbunuh di saat perang Uhud bersamamu. Sesungguhnya pamannya telah mengambil seluruh peninggalan ayah mereka. Padahal seorang wanita yang menikah pasti memiliki harta. Rasulullah terdiam sampai ayat tentang warisan diturunkan. Lalu Rasulullah shallallahu 'alaihi wasallam memanggil saudara laki-laki dari Sa'd bin Rabi', lalu berkata; 'Berikanlah dua pertiga dari harta Sa'd untuk kedua anak perempuannya, seperdelapan untuk isterinya dan sisanya untukmu.'\""},"2677":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي قَيْسٍ الْأَوْدِيِّ عَنْ الْهُزَيْلِ بْنِ شُرَحْبِيلَ قَالَجَاءَ رَجُلٌ إِلَى أَبِي مُوسَى الْأَشْعَرِيِّ وَسَلْمَانَ بْنِ رَبِيعَةَ الْبَاهِلِيِّ فَسَأَلَهُمَا عَنْ ابْنَةٍ وَابْنَةِ ابْنٍ وَأُخْتٍ لِأَبٍ وَأُمٍّ فَقَالَا لِلِابْنَةِ النِّصْفُ وَمَا بَقِيَ فَلِلْأُخْتِ وَائْتِ ابْنَ مَسْعُودٍ فَسَيُتَابِعُنَا فَأَتَى الرَّجُلُ ابْنَ مَسْعُودٍ فَسَأَلَهُ وَأَخْبَرَهُ بِمَا قَالَا فَقَالَ عَبْدُ اللَّهِ قَدْ ضَلَلْتُ إِذًا وَمَا أَنَا مِنْ الْمُهْتَدِينَ وَلَكِنِّي سَأَقْضِي بِمَا قَضَى بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلِابْنَةِ النِّصْفُ وَلِابْنَةِ الِابْنِ السُّدُسُ تَكْمِلَةَ الثُّلُثَيْنِ وَمَا بَقِيَ فَلِلْأُخْتِ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan] dari [Abu Qais Al Audi] dari [Al Huzail bin Syurahbil], ia berkata; \"Seorang laki-laki datang menemui Abu Musa AI Asy'ari dan Salman bin Rabi'ah Al Bahili lalu ia bertanya pada keduanya mengenai harta warisan untuk seorang anak perempuan, cucu perempuan dan saudara perempuan sekandung?\" Keduanya menjawab; 'Anak perempuan mendapat setengah dan sisanya untuk saudara perempuan si mayit. Temuilah Ibnu Mas'ud, maka ia pasti mengikuti fatwa kita.' Laki-laki tadi datang menemui [Ibnu Mas'ud] lalu bertanya dan memberitahukan apa yang dikatakan oleh kedua orang tersebut. Abdullah berkata; 'Aku telah sesat jika demikian, aku bukan termasuk orang-orang yang mendapat petunjuk, tetapi aku menetapkan hukum sesuai dengan yang ditetapkan oleh Rasulullah shallallahu 'alaihi wasallam yaitu: Anak perempuan mendapat setengah, cucu perempuan mendapat seperenam menyempurnakan pembagian dua pertiga dan sisanya untuk saudara perempuan si mayit.'"},"2678":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ مَعْقِلِ بْنِ يَسَارٍ الْمُزَنِيِّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِفَرِيضَةٍ فِيهَا جَدٌّ فَأَعْطَاهُ ثُلُثًا أَوْ سُدُسًاحَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا ابْنُ الطَّبَّاعِ حَدَّثَنَا هُشَيْمٌ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَ قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَدٍّ كَانَ فِينَا بِالسُّدُسِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Syababah]; telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Abu Ishaq] dari ['Amru bin Maimun] dari [Ma'qil bin Yasar Al Muzani], ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam didatangi oleh seseorang yang menanyakan pembagian harta warisan yang di dalamnya terdapat seorang kakek dimana ia memberi sepertiga atau seperenam.\" Telah menceritakan kepada kami [Abu Hatim]; telah menceritakan kepada kami [Ibnu Ath Thabba']; telah menceritakan kepada kami [Husyaim] dari [Yunus] dari [Al Hasan] dari [Ma'qil bin Yasar], ia berkata; 'Rasulullah shallallahu 'alaihi wasallam menetapkan hukum harta warisan bagi seorang kakek yang ada pada kita sebesar seperenam.'"},"2679":{"ar":"حَدَّثَ��َا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَهُ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ ح و حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ عُثْمَانَ بْنِ إِسْحَقَ بْنِ خَرَشَةَ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ قَالَجَاءَتْ الْجَدَّةُ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ تَسْأَلُهُ مِيرَاثَهَا فَقَالَ لَهَا أَبُو بَكْرٍ مَا لَكِ فِي كِتَابِ اللَّهِ شَيْءٌ وَمَا عَلِمْتُ لَكِ فِي سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَارْجِعِي حَتَّى أَسْأَلَ النَّاسَ فَسَأَلَ النَّاسَ فَقَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ حَضَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهَا السُّدُسَ فَقَالَ أَبُو بَكْرٍ هَلْ مَعَكَ غَيْرُكَ فَقَامَ مُحَمَّدُ بْنُ مَسْلَمَةَ الْأَنْصَارِيُّ فَقَالَ مِثْلَ مَا قَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَأَنْفَذَهُ لَهَا أَبُو بَكْرٍ ثُمَّ جَاءَتْ الْجَدَّةُ الْأُخْرَى مِنْ قِبَلِ الْأَبِ إِلَى عُمَرَ تَسْأَلُهُ مِيرَاثَهَا فَقَالَ مَا لَكِ فِي كِتَابِ اللَّهِ شَيْءٌ وَمَا كَانَ الْقَضَاءُ الَّذِي قُضِيَ بِهِ إِلَّا لِغَيْرِكِ وَمَا أَنَا بِزَائِدٍ فِي الْفَرَائِضِ شَيْئًا وَلَكِنْ هُوَ ذَاكِ السُّدُسُ فَإِنْ اجْتَمَعْتُمَا فِيهِ فَهُوَ بَيْنَكُمَا وَأَيَّتُكُمَا خَلَتْ بِهِ فَهُوَ لَهَا","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh Al Mishri]; telah memberitakan kepada kami [Abdullah bin Wahab]; telah memberitakan kepada kami [Yunus] dari [Ibnu Syihab]; telah menceritakan kepadanya dari [Qabishah bin Dzu`aib]; Demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Suwaid bin Sa'id]; telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari ['Utsman bin Ishaq bin Kharasy] dari [Qabishah bin Dzuaib] ia berkata; \"Datang seorang nenek kepada Abu Bakar dan bertanya kepadanya tentang bagian warisannya, maka Abu Bakar berkata kepadanya; \"Aku tidak mendapatkan sesuatupun untukmu di dalam Kitabullah dan aku tidak mengetahui sesuatupun bagimu di dalam Sunnah Rasulullah shallallahu 'alaihi wasallam, maka kembalilah sehingga aku bertanya kepada orang-orang. Maka bertanyalah ia kepada orang-orang, dan [Al Mughirah bin Syu'bah] berkata; 'Aku hadir dihadapan Rasulullah shallallahu 'alaihi wasallam, beliau memberinya seperenam.' Bertanyalah Abu Bakar; 'Apakah selainmu ada yang bersamamu? ' Maka bangunlah [Muhammad bin Maslamah Al Anshariy], dan dia berkata seperti yang dikatakan Al Mughirah bin Syu'bah, kemudian Abu Bakar memberikan seperenam kepadanya. Lalu datanglah nenek yang lain dari pihak ayah kepada 'Umar menanyakan bagian warisnya, maka dia menjawab; 'Aku tidak mendapatkan sesuatu bagimu di dalam kitabullah dan tidak ada ketetapan yang ditetapkan kecuali untuk selain dirimu, dan aku tidak menambah sesuatupun di dalam Faraidl, akan tetapi dia adalah seperenam, dan jika kalian berdua berkumpul di dalam warisan maka bagiannya diantara kalian berdua, siapa saja diantara kalian bersendirian dengannya, maka dia adalah miliknya.' "},"2680":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ عَنْ شَرِيكٍ عَنْ لَيْثٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَّثَ جَدَّةً سُدُسًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Abdul Wahhab]; telah menceritakan kepada kami [Salam bin Qutaibah] dari [Syarik] dari [Laits] dari [Thawus] dari [Ibnu 'Abbas]; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memberi bagian warisan kepada nenek seperenam.\""},"2681":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمُرِيِّأَنَّ عُمَرَ بْنَ الْخَطَّابِ قَامَ خَطِيبًا يَوْمَ الْجُمُعَةِ أَوْ خَطَبَهُمْ يَوْمَ الْجُمُعَةِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ إِنِّي وَاللَّهِ مَا أَدَعُ بَعْدِي شَيْئًا هُوَ أَهَمُّ إِلَيَّ مِنْ أَمْرِ الْكَلَالَةِ وَقَدْ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا أَغْلَظَ لِي فِي شَيْءٍ مَا أَغْلَظَ لِي فِيهَا حَتَّى طَعَنَ بِإِصْبَعِهِ فِي جَنْبِي أَوْ فِي صَدْرِي ثُمَّ قَالَ يَا عُمَرُ تَكْفِيكَ آيَةُ الصَّيْفِ الَّتِي نَزَلَتْ فِي آخِرِ سُورَةِ النِّسَاءِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Sa'id] dari [Qatadah] dari [Salim bin Abu Ja'ad] dari [Ma'dan bin Abu Thalhah Al Ya'muri]; \"Sesungguhnya ['Umar bin Khaththab] berdiri sambil berpidato di hari jum'at atau ia menyampaikan khutbah kepada Masyarakat di hari jum'at. la memuji kepada Allah lalu berkata; 'Sesungguhnya aku Demi Allah! Tidak ada hal sama sekali yang aku tinggalkan yang sangat penting, yang aku perhatikan daripada masalah kalalah, aku telah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, seperti halnya dalam masalah ini, hingga Rasulullah shallallahu 'alaihi wasallam menusuk jarinya di pinggangku atau di dadaku, lalu bersabda: 'Wahai 'Umar! Cukup bagimu ayat shaif yang diturunkan di akhir surat An-Nisa.'\""},"2682":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَأَبُو بَكْرِ بْنُ أَبِى شَيْبَةَ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ عَنْ مُرَّةَ بْنِ شَرَاحِيلَ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِثَلَاثٌ لَأَنْ يَكُونَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيَّنَهُنَّ أَحَبُّ إِلَيَّ مِنْ الدُّنْيَا وَمَا فِيهَا الْكَلَالَةُ وَالرِّبَا وَالْخِلَافَةُ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad] dan [Abu Bakar bin Abu Syaibah], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan], telah menceritakan kepada kami [Amru bin Murrah] dari [Murrah bin Syarahil] berkata; ' [Umar bin Al Khatthab] berkata; \"Tiga perkara, jika Rasulullah shallallahu 'alaihi wasallam menerangkannya lebih aku sukai ketimbang dunia dan seisinya; kalalah, riba dan khilafah.\""},"2683":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي هُوَ وَأَبُو بَكْرٍ مَعَهُ وَهُمَا مَاشِيَانِ وَقَدْ أُغْمِيَ عَلَيَّ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَبَّ عَلَيَّ مِنْ وَضُوئ��هِ فَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَصْنَعُ كَيْفَ أَقْضِي فِي مَالِي حَتَّى نَزَلَتْ آيَةُ الْمِيرَاثِ فِي آخِرِ النِّسَاءِ{ وَإِنْ كَانَ رَجُلٌ يُورَثُ كَلَالَةً }وَ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }الْآيَةَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir], ia mendengar [Jabir bin 'Abdullah] berkata; \"Aku sedang sakit lalu Rasulullah shallallahu 'alaihi wasallam bersama Abu bakar datang menjengukku, keduanya datang dengan berjalan kaki. Saat itu aku sedang dalam keadaan pingsan. Rasulullah shallallahu 'alaihi wasallam kemudian berwudlu lalu ia menyiramkan bekas air wudlunya kepadaku dan aku katakan; 'Wahai Rasulullah! Apa yang harus aku perbuat? Apa yang harus aku putuskan pada hartaku? Sampai turun ayat mengenai harta warisan di akhir surat An-Nisa yang berbunyi: 'Apabila seorang laki-laki mewariskan kalalah.' Dan ayat: 'Mereka meminta fatwa kepadamu (wahai Muhammad), katakanlah: 'Allah Subhanahu Wa Ta'ala memberi fatwa kepada kalian mengenai kalalah'.\""},"2684":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَرِثُ الْمُسْلِمُ الْكَافِرَ وَلَا الْكَافِرُ الْمُسْلِمَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Amar] dan [Muhammad bin Ash Shabah], keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ali bin Al Husain] dari ['Amru bin 'Utsman] dari [Usamah bin Zaid], ia berkata; -secara marfu- Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim tidak berhak memberikan harta warisannya kepada orang kafir, demikian pula seorang kafir tidak diperkenankan memberikan harta warisannya kepada seorang muslim.\""},"2685":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ أَنَّهُ حَدَّثَهُ أَنَّ عَمْرَو بْنَ عُثْمَانَ أَخْبَرَهُ عَنْ أُسَامَةَ بْنِ زَيْدٍأَنَّهُ قَالَ يَا رَسُولَ اللَّهِ أَتَنْزِلُ فِي دَارِكَ بِمَكَّةَ قَالَ وَهَلْ تَرَكَ لَنَا عَقِيلٌ مِنْ رِبَاعٍ أَوْ دُورٍ وَكَانَ عَقِيلٌ وَرِثَ أَبَا طَالِبٍ هُوَ وَطَالِبٌ وَلَمْ يَرِثْ جَعْفَرٌ وَلَا عَلِيٌّ شَيْئًا لِأَنَّهُمَا كَانَا مُسْلِمَيْنِ وَكَانَ عَقِيلٌ وَطَالِبٌ كَافِرَيْنِ فَكَانَ عُمَرُ مِنْ أَجْلِ ذَلِكَ يَقُولُ لَا يَرِثُ الْمُؤْمِنُ الْكَافِرَ قَالَ أُسَامَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرِثُ الْمُسْلِمُ الْكَافِرَ وَلَا الْكَافِرُ الْمُسْلِمَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh]; telah menceritakan kepada kami [Abdullah bin Wahab]; telah memberitakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Ali bin Al Hushain] bahwa ia menceritakannya bahwa ['Amru bin 'Utsman] mengabarinya dari [Usamah bin Zaid], sesungguhnya ia berkata; \"Wahai Rasulullah apakah engkau akan mampir di rumahmu di Makkah?\" Ia berkata; 'Apakah Aqil meninggalkan bagian dari harta warisan untuk kami berupa rumah? ' Aqil adalah ahli waris dari Abu Thalib, yaitu ia dan Thalib. Sedangkan Ja'far dan Ali tidak mendapatkan harta warisan sama sekali karena keduanya orang Islam. Sementara Aqil dan Thalib adalah orang kafir. Oleh karena hal ini Umar berkata; 'Seorang mukmin tidak boleh memberikan warisan kepada orang kafir.' Usamah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim tidak boleh memberikan harta warisan kepada orang kafir, demikian pula orang kafir tidak boleh memberikan harta warisannya kepada orang muslim.\""},"2686":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا ابْنُ لَهِيعَةَ عَنْ خَالِدِ بْنِ يَزِيدَ أَنَّ الْمُثَنَّى بْنَ الصَّبَّاحِ أَخْبَرَهُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَوَارَثُ أَهْلُ مِلَّتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Ibnu Lahi'ah] dari [Khalid bin Yazid] bahwa [Mutsanna bin Ash Shabbah]; mengabarinya dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya]; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemeluk dua agama (yang berlainan) tidak boleh saling mewarisi. \""},"2687":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَتَزَوَّجَ رَبَابُ بْنُ حُذَيْفَةَ بْنِ سَعِيدِ بْنِ سَهْمٍ أُمَّ وَائِلٍ بِنْتَ مَعْمَرٍ الْجُمَحِيَّةَ فَوَلَدَتْ لَهُ ثَلَاثَةً فَتُوُفِّيَتْ أُمُّهُمْ فَوَرِثَهَا بَنُوهَا رِبَاعًا وَوَلَاءَ مَوَالِيهَا فَخَرَجَ بِهِمْ عَمْرُو بْنُ الْعَاصِ إِلَى الشَّامِ فَمَاتُوا فِي طَاعُونِ عَمْوَاسٍ فَوَرِثَهُمْ عَمْرُو وَكَانَ عَصَبَتَهُمْ فَلَمَّا رَجَعَ عَمْرُو بْنُ الْعَاصِ جَاءَ بَنُو مَعْمَرٍ يُخَاصِمُونَهُ فِي وَلَاءِ أُخْتِهِمْ إِلَى عُمَرَ فَقَالَ عُمَرُ أَقْضِي بَيْنَكُمْ بِمَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُهُ يَقُولُ مَا أَحْرَزَ الْوَلَدُ وَالْوَالِدُ فَهُوَ لِعَصَبَتِهِ مَنْ كَانَ قَالَ فَقَضَى لَنَا بِهِ وَكَتَبَ لَنَا بِهِ كِتَابًا فِيهِ شَهَادَةُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَزَيْدِ بْنِ ثَابِتٍ وَآخَرَ حَتَّى إِذَا اسْتُخْلِفَ عَبْدُ الْمَلِكِ بْنُ مَرْوَانَ تُوُفِّيَ مَوْلًى لَهَا وَتَرَكَ أَلْفَيْ دِينَارٍ فَبَلَغَنِي أَنَّ ذَلِكَ الْقَضَاءَ قَدْ غُيِّرَ فَخَاصَمُوا إِلَى هِشَامِ بْنِ إِسْمَعِيلَ فَرَفَعَنَا إِلَى عَبْدِ الْمَلِكِ فَأَتَيْنَاهُ بِكِتَابِ عُمَرَ فَقَالَ إِنْ كُنْتُ لَأَرَى أَنَّ هَذَا مِنْ الْقَضَاءِ الَّذِي لَا يُشَكُّ فِيهِ وَمَا كُنْتُ أَرَى أَنَّ أَمْرَ أَهْلِ الْمَدِينَةِ بَلَغَ هَذَا أَنْ يَشُكُّوا فِي هَذَا الْقَضَاءِ فَقَضَى لَنَا فِيهِ فَلَمْ نَزَلْ فِيهِ بَعْدُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abu Usamah]; telah menceritakan kepada kami [Husain Al Mua'llim] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] berkata; \"Rabab bin Hudzaifah bin Sa'id bin Sahm, ibu dari Wail binti Ma'mar Al Jumahiyah menikah. Rubab melahirkan tiga orang anak, kemudian ibu mereka meninggal dunia. Anak-anaknya menjadi ahli waris dari ibunya, berupa rumah dan hamba sahaya. Amru bin Ash lalu keluar bersama mereka menuju Syam, tetapi mereka meninggal dunia terkena penyakit kusta di kawasan Amwas. Maka Amru menjadi ahli waris mereka karena Amru termasuk keluarga mereka, ketika Amru bin Ash kembali, Bani Ma'mar datang memprotes mengenai keberadaan hamba sahaya saudara perempuan mereka kepada Umar.\" [Umar] berkata; 'Aku menetapkan hukum dengan sesuatu yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Harta yang diperoleh dari seorang anak dan seorang ayah, maka ia untuk keturunannya, siapa saja. (Umar) menetapkan hukum tersebut kepada kami. Umar juga menulis kepada kami suatu tulisan yang di dalamnya terdapat kesaksian Abdurrahman bin Auf dan Zaid bin Tsabit dan yang lainnya sehingga ketika Abdul Malik bin Marwan menjadi khalifah, seorang hamba sahaya meninggal dunia. Hamba sahaya tersebut meninggalkan dua ribu dinar. Lalu aku mendengar bahwa keputusan hukum tersebut telah diubah. Mereka lalu mengadu kepada Hisyam bin Ismail kemudian kami adukan kepada Abdul Malik, kami mendatanginya dengan membawa tulisan Umar. Abdul Malik berkata; 'Aku memandang bahwa ini adalah keputusan hukum yang tidak diragukan lagi, aku tidak melihat penduduk kota Madinah yang telah sampai kepada mereka hukum ini kemudian akan meragukannya, lalu ia menetapkan hukum ini kepada kami dan setelahnya terus seperti itu.'"},"2688":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ مُجَاهِدِ بْنِ وَرْدَانَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ مَوْلًى لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَعَ مِنْ نَخْلَةٍ فَمَاتَ وَتَرَكَ مَالًا وَلَمْ يَتْرُكْ وَلَدًا وَلَا حَمِيمًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطُوا مِيرَاثَهُ رَجُلًا مِنْ أَهْلِ قَرْيَتِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin Al `Asbahani] dari [Mujahid bin Wardan] dari [Urwah bin Zubair] dari [Aisyah], sesungguhnya seorang budak Nabi shallallahu 'alaihi wasallam terjatuh dari pohon kurma lalu meninggal dunia, ia tidak meninggalkan harta, tidak meninggalkan anak dan isteri. Nabi shallallahu 'alaihi wasallam bersabda: 'Berikanlah harta warisan kepada seorang laki-laki dari penduduk kampungnya.\""},"2689":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْحَكَمِ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ بِنْتِ حَمْزَةَ قَالَ مُحَمَّدٌ يَعْنِي ابْنَ أَبِي لَيْلَى وَهِيَ أُخْتُ ابْنِ شَدَّادٍ لِأُمِّهِ قَالَتْمَاتَ مَوْلَايَ وَتَرَكَ ابْنَةً فَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَالَهُ بَيْنِي وَبَيْنَ ابْنَتِهِ فَجَعَلَ لِي النِّصْفَ وَلَهَا النِّصْفَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Husain bin Ali] dari [Za`idah] dari [Muhammad bin Abdurrahman bin Abu Laila] dari [Al Hakam] dari [Abdullah bin Syaddad] dari [Anak perempuan Hamzah], ia berkata; \"Majikanku meninggal dunia dan meninggalkan seorang anak perempuan. Lalu Rasulullah shallallahu 'alaihi wasallam membagi hartanya diantara diriku dan anak perempuannya. Rasulullah menjadikan untukku separuh dan untuk anak perempuannya separuh.\""},"2690":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ إِسْحَقَ بْنِ أَبِي فَرْوَةَ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْقَاتِلُ لَا يَرِثُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh], telah memberitakan kepada kami [Al Laits bin Sa'ad] dari [Ishaq bin Abu Farwah] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman bin 'Auf] dari [Abu Hurairah], dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang pembunuh tidak mewarisi.\""},"2691":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ مُحَمَّدِ بْنِ سَعِيدٍ وَقَالَ مُحَمَّدُ بْنُ يَحْيَى عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ حَدَّثَنِي أَبِي عَنْ جَدِّي عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ يَوْمَ فَتْحِ مَكَّةَ فَقَالَ الْمَرْأَةُ تَرِثُ مِنْ دِيَةِ زَوْجِهَا وَمَالِهِ وَهُوَ يَرِثُ مِنْ دِيَتِهَا وَمَالِهَا مَا لَمْ يَقْتُلْ أَحَدُهُمَا صَاحِبَهُ فَإِذَا قَتَلَ أَحَدُهُمَا صَاحِبَهُ عَمْدًا لَمْ يَرِثْ مِنْ دِيَتِهِ وَمَالِهِ شَيْئًا وَإِنْ قَتَلَ أَحَدُهُمَا صَاحِبَهُ خَطَأً وَرِثَ مِنْ مَالِهِ وَلَمْ يَرِثْ مِنْ دِيَتِهِ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad] dan [Muhammad bin Yahya], keduanya berkata; telah menceritakan kepada kami ['Ubaidulllah bin Musa] dari [Al Hasan bin Shalih] dari [Muhammad bin Sa'id] dan [Muhammad bin Yahya] berkata dari ['Umar bin Sa'id] dari [Amru bin Syu'aib]; telah menceritakan kepadaku [Ayahku] dari [Kakekku, Abdullah bin Amru] sesungguhnya Rasulullah shallallahu 'alaihi wasallam berdiri pada hari penaklukan kota Makkkah, dan beliau bersabda: \"Seorang perempuan mewarisi dari diyat suaminya dan hartanya, dan suaminya mewarisi diyatnya dan hartanya selagi salah satu dari keduanya tidak membunuh pasangannya. Apabila salah seorang membunuh pasangannya dengan sengaja, maka tidak dapat mewarisi dari diyatnya dan hartanya sedikitpun, dan jika salah seorang dari keduanya membunuh pasangan dengan tidak disengaja, maka dia mewarisi hartanya dan tidak mewarisi dari diyatnya.\""},"2692":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ عَيَّاشِ بْنِ أَبِي رَبِيعَةَ الزُّرَقِيِّ عَنْ حَكِيمِ بْنِ حَكِيمِ بْنِ عَبَّادِ بْنِ حُنَيْفٍ الْأَنْصَارِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍأَنَّ رَجُلًا رَمَى رَجُلًا بِسَهْمٍ فَقَتَلَهُ وَلَيْسَ لَهُ وَارِثٌ إِلَّا خَالٌ فَكَتَبَ فِي ذَلِكَ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ إِلَى عُمَرَ فَكَتَبَ إِلَيْهِ عُمَرُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ وَرَسُولُهُ مَوْلَى مَنْ لَا مَوْلَى لَهُ وَالْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdurrahman bin Harits bin Ayyasy bin Abu Rabi'ah Az Zuraqqi] dari [Hakim bin Hakim bin 'Abbad bin Hunaif Al Anshari] dari [Abu Umamah bin Sahl bin Hunaif], sesunguhnya seorang laki-laki melempar laki-laki lainnya dengan sebuah anak panah hingga membunuhnya. Laki-laki ini tidak memiliki ahli waris, kecuali hanya seorang paman. Kemudian Abu Ubadah bin Al Jarrah menulis surat kepada Umar, dan Umar membalasnya bahwa Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Allah Subhanahu Wa Ta'ala dan Rasul-Nya adalah wali bagi orang yang tidak memiliki wali dan seorang paman dapat menjadi ahli waris bagi orang yang tidak memiliki ahli waris.\""},"2693":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ حَدَّثَنِي بُدَيْلُ بْنُ مَيْسَرَةَ الْعُقَيْلِيُّ عَنْ عَلِيِّ بْنِ أَبِي طَلْحَةَ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ أَبِي عَامِرٍ الْهَوْزَنِيِّ عَنْ الْمِقْدَامِ أَبِي كَرِيمَةَ رَجُلٌ مِنْ أَهْلِ الشَّامِ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ وَمَنْ تَرَكَ كَلًّا فَإِلَيْنَا وَرُبَّمَا قَالَ فَإِلَى اللَّهِ وَإِلَى رَسُولِهِ وَأَنَا وَارِثُ مَنْ لَا وَارِثَ لَهُ أَعْقِلُ عَنْهُ وَأَرِثُهُ وَالْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُ يَعْقِلُ عَنْهُ وَيَرِثُهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Syababah]; Demikian juga diriwayatkan dari jalur yang lainnya, telah menceritakan kepada kami [Muhammad bin Al Walid]; telah menceritakan kepada kami [Muhammad bin Ja'far], keduanya berkata; telah menceritakan kepada kami [Syu'bah], telah menceritakan kepadaku [Budail bin Maisarah Al 'Uqaili] dari [Ali bin Abu Thalhah] dari [Rasyid bin Sa'ad] dari [Abu Amir Al Hauzani] dari [Al Miqdam Abu Karimah], ia adalah seorang laki-laki penduduk Syam yang merupakan salah satu sahabat Rasulullah shallallahu 'alaihi wasallam. Ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meninggalkan harta, maka hal tersebut untuk ahli warisnya. Dan Barangsiapa yang meninggalkan keluarga dan hutang yang memberatkan dirinya, maka diserahkan kepada kami.\" Dan barang kali Rasulullah shallallahu 'alaihi wasallam bersabda: 'Maka serahkanlah kepada Allah dan Rasul-Nya. Dan aku adalah ahli waris bagi orang yang tidak memiliki ahli waris. Aku adalah orang yang memmbayarkan diyat dan mewarisinya. Dan paman adalah ahli waris bagi orang yang tidak memiliki ahli waris. Dialah yang membayarkan diyat dan yang mendapatkan harta warisan.\""},"2694":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو بَحْرٍ الْبَكْرَاوِيُّ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ أَعْيَانَ بَنِي الْأُمِّ يَتَوَارَثُونَ دُونَ بَنِي الْعَلَّاتِ يَرِثُ الرَّجُلُ أَخَاهُ لِأَبِيهِ وَأُمِّهِ دُونَ إِخْوَتِهِ لِأَبِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim], telah menceritakan kepada kami [Abu Bahr Al Bakrawi]; telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Al Harits] dari [Ali bin Abu Thalib], ia berkata; Rasulullah shallallahu 'alaihi wasallam menetapkan hukum bahwa saudara seibu saling mendapatkan warisan bukan saudara sebapak, seorang laki-laki dapat memberikan warisan kepada saudara kandungnya bukan saudara sebapak saja."},"2695":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْسِمُوا الْمَالَ بَيْنَ أَهْلِ الْفَرَائِضِ عَلَى كِتَابِ اللَّهِ فَمَا تَرَكَتْ الْفَرَائِضُ فَلِأَوْلَى رَجُلٍ ذَكَرٍ","id":"Telah menceritakan kepada kami [Abbas bin Abdul Azhim Al 'Anbari]; telah menceritakan kepada kami [Abdurrazaq]; telah memberitakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [Ayahnya] dari [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagilah harta diantara para ahli waris berdasarkan Al Qur'an. Apa yang ditinggalkan, maka yang lebih utama diberikan kepada keturunan laki-laki.\""},"2696":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَوْسَجَةَ عَنْ ابْنِ عَبَّاسٍ قَالَمَاتَ رَجُلٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَدَعْ لَهُ وَارِثًا إِلَّا عَبْدًا هُوَ أَعْتَقَهُ فَدَفَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِيرَاثَهُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Isma'il bin Abu Musa]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Amru bin Dinar] dari ['Ausajah] dari [Ibnu Abbas] berkata; \"Seseorang meninggal di zaman Nabi shallallahu 'alaihi wasallam dan ia tidak meninggalkan sesuatupun kecuali seorang budak yang ia merdekakan, lalu Nabi shallallahu 'alaihi wasallam membayarkan pewarisannya tersebut kepadanya.\""},"2697":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا عُمَرُ بْنُ رُؤْبَةَ التَّغْلِبِيُّ عَنْ عَبْدِ الْوَاحِدِ بْنِ عَبْدِ اللَّهِ النَّصْرِيِّ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَرْأَةُ تَحُوزُ ثَلَاثَ مَوَارِيثَ عَتِيقِهَا وَلَقِيطِهَا وَوَلَدِهَا الَّذِي لَاعَنَتْ عَلَيْهِقَالَ مُحَمَّدُ بْنُ يَزِيدَ مَا رَوَى هَذَا الْحَدِيثَ غَيْرُ هِشَامٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Muhammad bin Harb]; telah menceritakan kepada kami [Umar bin Ru`bah At Taghlibi] dari [Abdul Wahid bin Abdullah An Nashri] dari [Watsilah bin Asqa'] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Wanita itu mendapat tiga pewarisan; hamba yang ia merdekakan, anak temuannya (hasil zina), dan dari anak yang ia menjadi dili'an karena anak itu.\" Muhammad bin Yazid berkata; tidak ada yang meriwayatkan Hadits ini selain Hisyam."},"2698":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مُوسَى بْنِ عُبَيْدَةَ حَدَّثَنِي يَحْيَى بْنُ حَرْبٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ آيَةُ اللِّعَانِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ أَلْحَقَتْ بِقَوْمٍ مَنْ لَيْسَ مِنْهُمْ فَلَيْسَتْ مِنْ اللَّهِ فِي شَيْءٍ وَلَنْ يُدْخِلَهَا جَنَّتَهُ وَأَيُّمَا رَجُلٍ أَنْكَرَ وَلَدَهُ وَقَدْ عَرَفَهُ احْتَجَبَ اللَّهُ مِنْهُ يَوْمَ الْقِيَامَةِ وَفَضَحَهُ عَلَى رُءُوسِ الْأَشْهَادِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Zaid bin Al Hubab] dari [Musa bin Ubaidah]; telah menceritakan kepadaku [Yahya bin Harb] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah], ia berkata; \"Tatkala turun ayat Li'an, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perempuan mana saja yang menggabungkan diri dengan suatu kaum yang bukan dari kalangannya, maka Allah tidak membutuhkannya sama sekali, dan sekali-kali tidak akan memasukkannya ke dalam surganya. Dan lelaki manapun yang tidak mengakui anaknya sedang dia telah mengetahuinya, Allah akan menghalanginya pada hari kiamat dan akan membuatnya malu dihadapan orang-orang banyak.\""},"2699":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُفْرٌ بِامْرِئٍ ادِّعَاءُ نَسَبٍ لَا يَعْرِفُهُ أَوْ جَحْدُهُ وَإِنْ دَقَّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdul Aziz bin Abdullah]; telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seseorang menjadi kufur, lantaran mengaku bernasab pada seseorang yang tidak ia kenal, atau mengingkari nasab yang sebenarnya, sekalipun ia telah menelitinya. \""},"2700":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يَحْيَى بْنُ الْيَمَانِ عَنْ الْمُثَنَّى بْنِ الصَّبَّاحِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَاهَرَ أَمَةً أَوْ حُرَّةً فَوَلَدُهُ وَلَدُ زِنًا لَا يَرِثُ وَلَا يُورَثُ","id":"Telah menceritakan kepada kami [Abu Kuraib]; telah menceritakan kepada kami [Yahya bin Al Yaman] dari [Al Mutsanna bin Ash Shabbah] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa menzinahi seorang budak perempuan atau perempuan merdeka, maka anaknya adalah anak zina, tidak mewarisi dan juga tidak diwarisi.\""},"2701":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارِ بْنِ بِلَالٍ الدِّمَشْقِيُّ أَنْبَأَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مُسْتَلْحَقٍ اسْتُلْحِقَ بَعْدَ أَبِيهِ الَّذِي يُدْعَى لَهُ ادَّعَاهُ وَرَثَتُهُ مِنْ بَعْدِهِ فَقَضَى أَنَّ مَنْ كَانَ مِنْ أَمَةٍ يَمْلِكُهَا يَوْمَ أَصَابَهَا فَقَدْ لَحِقَ بِمَنْ اسْتَلْحَقَهُ وَلَيْسَ لَهُ فِيمَا قُسِمَ قَبْلَهُ مِنْ الْمِيرَاثِ شَيْءٌ وَمَا أَدْرَكَ مِنْ مِيرَاثٍ لَمْ يُقْسَمْ فَلَهُ نَصِيبُهُ وَلَا يَلْحَقُ إِذَا كَانَ أَبُوهُ الَّذِي يُدْعَى لَهُ أَنْكَرَهُ وَإِنْ كَانَ مِنْ أَمَةٍ لَا يَمْلِكُهَا أَوْ مِنْ حُرَّةٍ عَاهَرَ بِهَا فَإِنَّهُ لَا يَلْحَقُ وَلَا يُورَثُ وَإِنْ كَانَ الَّذِي يُدْعَى لَهُ هُوَ ادَّعَاهُ فَهُوَ وَلَدُ زِنًا لِأَهْلِ أُمِّهِ مَنْ كَانُوا حُرَّةً أَوْ أَمَةً قَالَ مُحَمَّدُ بْنُ رَاشِدٍ يَعْنِي بِذَلِكَ مَا قُسِمَ فِي الْجَاهِلِيَّةِ قَبْلَ الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Muhammad bin Bakkar bin Bilal Ad Dimasyqi]; telah memberitakan kepada kami [Muhammad bin Rasyid] dari [Sulaiman bin Musa] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap orang yang dikaitkan kepada orang lain setelah bapaknya, maka ahli warispun hendaklah mengakuinya setelahnya. \"Rasulullah shallallahu 'alaihi wasallam menetapkan bahwa wanita yang telah menjadi hamba sahaya pada saat melakukan hubungan intim dengannya, maka nasabnya dikaitkan dengan orang yang mengaitkan sebelumnya, dan ia tidak mendapatkan harta warisan sama sekali dari yang telah dibagi sebelumnya. Adapun harta warisan yang belum dibagikan, maka ia mendapatkan bagiannya. Nasabnya tidak dapat dikaitkan kepada seorang bapak, apabila ia mengingkarinya. Akan tetapi apabila dari budak wanita yang tidak dimiliki, atau perempuan merdeka yang telah berzina, maka nasabnya tidak dapat dikaitkan (kepadanya) dan ia tidak diwarisi. Apabila nasab dikaitkan kepada seorang bapak dan ia mengakuinya, maka ia adalah anak hasil zina, ia (nasabnya) dikaitkan kepada ibunya, baik ia seorang wanita merdeka atau seorang budak. \" Muhammad bin Rasyid berkata; 'Yang dimaksud di sini adalah apa yang telah dibagi pada masa Jahiliyah sebelum Islam.\""},"2702":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ وَسُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Syu'bah] dan [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang menjual pewalian dan menghibahkannya.\""},"2703":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Syawarib], telah menceritakan kepada kami [Yahya bin Sulaim Ath Tha`ifi] dari [Ubaidillah bin Umar] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang menjual perwalian dan menghibahkannya.\""},"2704":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ لَهِيعَةَ عَنْ عُقَيْلٍ أَنَّهُ سَمِعَ نَافِعًا يُخْبِرُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا كَانَ مِنْ مِيرَاثٍ قُسِمَ فِي الْجَاهِلِيَّةِ فَهُوَ عَلَى قِسْمَةِ الْجَاهِلِيَّةِ وَمَا كَانَ مِنْ مِيرَاثٍ أَدْرَكَهُ الْإِسْلَامُ فَهُوَ عَلَى قِسْمَةِ الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Abdullah bin Lahi'ah] dari ['Uqail] bahwa ia mendengar [Nafi'] mengabari dari [Abdullah bin Umar]; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Harta warisan yang telah dibagikan di masa Jahiliyah, maka ia sesuai dengan pembagian di masa Jahiliyah itu sendiri. Sementara harta warisan yang ada di masa Islam, maka ia sesuai dengan pembagian cara Islam.\""},"2705":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الرَّبِيعُ بْنُ بَدْرٍ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَهَلَّ الصَّبِيُّ صُلِّيَ عَلَيْهِ وَوَرِثَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Amar]; telah menceritakan kepada kami [Ar Rabi' bin Badar]; telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Apabila seorang Jabang bayi telah dapat berteriak, maka ia harus dishalatkan dan berhak mendapatkan hak warisan.\""},"2706":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَالْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرِثُ الصَّبِيُّ حَتَّى يَسْتَهِلَّ صَارِخًا قَالَ وَاسْتِهْلَالُهُ أَنْ يَبْكِيَ وَيَصِيحَ أَوْ يَعْطِسَ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Ad Dimasyqi]; telah menceritakan kepada kami [Marwan bin Muhammad]; telah menceritakan kepada kami [Sulaiman bin Bilal]; telah menceritakan kepadaku [Yahya bin Sa'id] dari [Sa'id bin Al Musayyab] dari [Jabir bin 'Abdullah] dan [Al Miswar bin Makhramah], keduanva berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Seorang jabang bayi tidak berhak mendapatkan harta warisan sampai ia dapat berteriak.' Yang dimaksud berteriak, yaitu: menangis, berteriak atau bersin.\""},"2707":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ قَالَ سَمِعْتُ تَمِيمًا الدَّارِيَّ يَقُولُقُلْتُ يَا رَسُولَ اللَّهِ مَا السُّنَّةُ فِي الرَّجُلِ مِنْ أَهْلِ الْكِتَابِ يُسْلِمُ عَلَى يَدَيْ الرَّجُلِ قَالَ هُوَ أَوْلَى النَّاسِ بِمَحْيَاهُ وَمَمَاتِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki'] dari [Abdul Aziz bin Umar] dari [Abdullah bin Mauhab] berkata; Aku mendengar [Tamim Ad-Dari], ia berkata; \"Aku berkata; 'Wahai Rasulullah! Perbuatan sunnah apa yang ada pada laki-laki dari ahli kitab yang bersalaman mencium tangan orang lain? ' Rasulullah menjawab: 'Ia adalah orang yang paling utama, di saat hidup dan matinya'.\""},"2708":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعَدَّ اللَّهُ لِمَنْ خَرَجَ فِي سَبِيلِهِ لَا يُخْرِجُهُ إِلَّا جِهَادٌ فِي سَبِيلِي وَإِيمَانٌ بِي وَتَصْدِيقٌ بِرُسُلِي فَهُوَ عَلَيَّ ضَامِنٌ أَنْ أُدْخِلَهُ الْجَنَّةَ أَوْ أَرْجِعَهُ إِلَى مَسْكَنِهِ الَّذِي خَرَجَ مِنْهُ نَائِلًا مَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْلَا أَنْ أَشُقَّ عَلَى الْمُسْلِمِينَ مَا قَعَدْتُ خِلَافَ سَرِيَّةٍ تَخْرُجُ فِي سَبِيلِ اللَّهِ أَبَدًا وَلَكِنْ لَا أَجِدُ سَعَةً فَأَحْمِلَهُمْ وَلَا يَجِدُونَ سَعَةً فَيَتَّبِعُونِي وَلَا تَطِيبُ أَنْفُسُهُمْ فَيَتَخَلَّفُونَ بَعْدِي وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوَدِدْتُ أَنْ أَغْزُوَ فِي سَبِيلِ اللَّهِ فَأُقْتَلَ ثُمَّ أَغْزُوَ فَأُقْتَلَ ثُمَّ أَغْزُوَ فَأُقْتَلَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Umarah bin Al Qa'qa] dari [Abu Zur'ah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Subhanahu Wa Ta'ala telah menyiapkan bagi orang yang keluar di jalan-Nya dimana tidak ada yang mengeluarkannya kecuali tujuan jihad di jalan-Ku, beriman dengan-Ku dan mempercayai para rasul-Ku. maka ia Aku jamin akan Aku masukkan ke dalam surga atau Aku kembalikan dirinya menuju kediamannya dimana ia telah keluar darinya dengan memperoleh pahala atau ghanimah.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Demi Allah! Seandainya aku tidak memberatkan umat Islam, maka niscaya aku senantiasa akan duduk dibalik pasukan militer yang keluar di jalan Allah untuk selamanya.-Tetapi aku tidak memiliki keluasan waktu untuk membawa mereka dan mereka tidak memiliki keluasan untuk mengikutiku dan diri mereka tidak akan mampu untuk selalu berada dibelakangku. Demi Dzat yang jiwa Muhammad di tangan-Nya! Aku ingin berperang di jalan Allah kemudian aku terbunuh lalu aku berperang kemudian terbunuh lagi dan berperang lalu terbunuh lagi.'"},"2709":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ فِرَاسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُجَاهِدُ فِي سَبِيلِ اللَّهِ مَضْمُونٌ عَلَى اللَّهِ إِمَّا أَنْ يَكْفِتَهُ إِلَى مَغْفِرَتِهِ وَرَحْمَتِهِ وَإِمَّا أَنْ يَرْجِعَهُ بِأَجْرٍ وَغَنِيمَةٍ وَمَثَلُ الْمُجَاهِدِ فِي سَبِيلِ اللَّهِ كَمَثَلِ الصَّائِمِ الْقَائِمِ الَّذِي لَا يَفْتُرُ حَتَّى يَرْجِعَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib], keduanya berkata; telah menceritakan kepada kami [Ubaidillah bin Musa] dari [Syaiban] dari [Firas] dari ['Athiyyah] dari [Abu Said Al Khudri], dari Nabi Muhammad shallallahu 'alaihi wasallam, ia bersabda: \"Seorang yang berjihad di jalan Allah sudah dijamin oleh Allah, baik Allah Subhanahu Wa Ta'ala memberikan kepadanya ampunan dan rahmat-Nya atau mengembalikannya menuju kekediamannya dengan membawa upah dan harta ghanimah. Perumpamaan orang yang berjihad di jalan Allah bagaikan orang yang berpuasa sambil melaksanakan shalat malam yang tidak pernah bosan, sampai ia kembali ke rumahnya.\""},"2710":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدْوَةٌ أَوْ رَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abdullah bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abu Khalid Al `Ahmar] dari [Ibnu 'Ajlan] dari [Abu Hazim] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergi dan kembali di jalan Allah (berjihad) lebih baik daripada dunia dan seisinya.\""},"2711":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا زَكَرِيَّا بْنُ مَنْظُورٍ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدْوَةٌ أَوْ رَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Zakaria bin Manzhur]; telah menceritakan kepada kami [Abu Hazim] dari [Sahal bin Sa'ad As Sa'idi], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergi dan kembali di jalan Allah lebih baik dari dunia dan seisinya.\""},"2712":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَغَدْوَةٌ أَوْ رَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Nashar bin Ali Al Jahdhami] dan [Muhammad bin Al Mutsanna], keduanya berkata; telah menceritakan kepada kami [Abdul Wahab Ats Tsaqafi]; telah menceritakan kepada kami [Humaid] dari [Anas bin Malik], sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergi dan kembali di jalan Allah lebih baik dari dunia dan seisinya.\""},"2713":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ الْوَلِيدِ بْنِ أَبِي الْوَلِيدِ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ سُرَاقَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ حَتَّى يَسْتَقِلَّ كَانَ لَهُ مِثْلُ أَجْرِهِ حَتَّى يَمُوتَ أَوْ يَرْجِعَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Yunus bin Muhammad]; telah menceritakan kepada kami [Laits bin Sa'ad] dari [Yazid bin Abdullah bin Al Had] dari [Al Walid bin Abu Al Walid] dari ['Utsman bin Abdullah bin Suraqah] dari [Umar bin Al Khaththab] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mempersiapkan perbekalan orang yang berperang maka ia mendapatkan pahala sepertinya hingga ia syahid atau menang.\""},"2714":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ كَانَ لَهُ مِثْلُ أَجْرِهِ مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أَجْرِ الْغَازِي شَيْئًا","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id]; telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Abdul Malik bin Abu Sulaiman] dari [Atha`] dari [Zaid bin Khalid Al Juhani], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyiapkan segala sesuatu bagi orang yang berperang di jalan Allah, maka baginya seperti pahala orang yang berperang itu sendiri, tanpa ada pengurangan dari pahalanya (pejuang) sedikitpun.\""},"2715":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ دِينَارٍ يُنْفِقُهُ الرَّجُلُ دِينَارٌ يُنْفِقُهُ عَلَى عِيَالِهِ وَدِينَارٌ يُنْفِقُهُ عَلَى فَرَسٍ فِي سَبِيلِ اللَّهِ وَدِينَارٌ يُنْفِقُهُ الرَّجُلُ عَلَى أَصْحَابِهِ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Imran bin Musa Al Laitsi]; telah menceritakan kepada kami [Hammad bin Zaid]; telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Abu `Asma`] dari [Tsauban] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dinar yang paling utama diinfakkan oleh seseorang adalah sebagai berikut: dinar yang dinafkahkan untuk istrinya (keluarganya), dinar yang diinfakkan untuk pengurusan kuda di jalan Allah dan dinar yang diinfakkan oleh seseorang untuk para sahabatnya yang berjuang di jalan Allah. \""},"2716":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الْخَلِيلِ بْنِ عَبْدِ اللَّهِ عَنْ الْحَسَنِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ وَأَبِي الدَّرْدَاءِ وَأَبِي هُرَيْرَةَ وَأَبِي أُمَامَةَ الْبَاهِلِيِّ وَعَبْدِ اللَّهِ بْنِ عُمَرَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَجَابِرِ بْنِ عَبْدِ اللَّهِ وَعِمْرَانَ بْنِ الْحُصَيْنِ كُلُّهُمْ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ أَرْسَلَ بِنَفَقَةٍ فِي سَبِيلِ اللَّهِ وَأَقَامَ فِي بَيْتِهِ فَلَهُ بِكُلِّ دِرْهَمٍ سَبْعُ مِائَةِ دِرْهَمٍ وَمَنْ غَزَا بِنَفْسِهِ فِي سَبِيلِ اللَّهِ وَأَنْفَقَ فِي وَجْهِ ذَلِكَ فَلَهُ بِكُلِّ دِرْهَمٍ سَبْعُ مِائَةِ أَلْفِ دِرْهَمٍ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَاللَّهُ يُضَاعِفُ لِمَنْ يَشَاءُ }","id":"Telah menceritakan kepada kami [Harun bin Abdullah Al Hammal]; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Khalil bin 'Abdullah] dari [Al Hassan] dari [Ali bin Abu Thalib] dan [Abu Darda`], [Abu Hurairah] dan [Abu UmamahAl Bahili], [Abdullah bin Umar], [Abdullah bin Amru], juga dari [Jabir bin Abdullah] dan [Imran bin Husain] semuanya menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang membekali seseorang dalam peperangan sedang ia berada di rumahnya saja, maka pada setiap dirhamnya dilipat gandakan tujuh ratus dirham. Sedang bagi yang ikut berperang di jalan Allah dan ia berinfak karena itu maka baginya untuk satu dirham dilipat gandakan menjadi tujuh ratus ribu.\" Kemudian beliau membaca ayat: ' WALLAHU YUDHA'IFU LIMAN YASYAA` '(Dan Allah melipat gandakan pahala bagi siapa saja yang dikehendaki-Nya).\""},"2717":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا يَحْيَى بْنُ الْحَارِثِ الذِّمَارِيُّ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَغْزُ أَوْ يُجَهِّزْ غَازِيًا أَوْ يَخْلُفْ غَازِيًا فِي أَهْلِهِ بِخَيْرٍ أَصَابَهُ اللَّهُ سُبْحَانَهُ بِقَارِعَةٍ قَبْلَ يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Amar]; telah menceritakan kepada kami [Al Walid bin Muslim]; telah menceritakan kepada kami [Yahya bin Al Harits Adz Dzamari] dari [Al Qasim] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang tidak berperang dan tidak membekali orang yang berperang atau membantu orang yang berperang karena mengurusi keluarganya dengan baik, maka Allah akan menimpakannya malapetaka sebelum hari kiamat.\""},"2718":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا أَبُو رَافِعٍ هُوَ إِسْمَعِيلُ بْنُ رَافِعٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَقِيَ اللَّهَ وَلَيْسَ لَهُ أَثَرٌ فِي سَبِيلِ اللَّهِ لَقِيَ اللَّهَ وَفِيهِ ثُلْمَةٌ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Al Walid]; telah menceritakan kepada kami [Abu Rafi'] yaitu Isma'il bin Rafi' dari [Sumay] -mantan budak- 'Abu Bakar dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berjumpa dengan Allah dan tidak ada tanda bekas berjuang jalan Allah, dia akan bertemu dengan Allah dalam kondisi cacat.\""},"2719":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَةِ تَبُوكَ فَدَنَا مِنْ الْمَدِينَةِ قَالَ إِنَّ بِالْمَدِينَةِ لَقَوْمًا مَا سِرْتُمْ مِنْ مَسِيرٍ وَلَا قَطَعْتُمْ وَادِيًا إِلَّا كَانُوا مَعَكُمْ فِيهِ قَالُوا يَا رَسُولَ اللَّهِ وَهُمْ بِالْمَدِينَةِ قَالَ وَهُمْ بِالْمَدِينَةِ حَبَسَهُمْ الْعُذْرُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna]; telah menceritakan kepada kami [Ibnu Abi Adi] dari [Humaid] dari [Anas bin Malik], ia berkata; ketika Rasulullah shallallahu 'alaihi wasallam kembali dari perang Tabuk lalu ia mendekati kota Madinah dan bersabda: \"Sesungguhnya di kota Madinah sekelompok kaum, apa yang telah kalian lalui dari perjalanan dan lembah yang telah kalian tembus, maka mereka senantiasa bersama kalian.\" Mereka bertanya; 'Wahai Rasulullah! Apakah mereka berada di Madinah? ' Rasulullah menjawab: 'Ya, mereka berada di Madinah, karena mereka terhalang oleh udzur.'"},"2720":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بِالْمَدِينَةِ رِجَالًا مَا قَطَعْتُمْ وَادِيًا وَلَا سَلَكْتُمْ طَرِيقًا إِلَّا شَرِكُوكُمْ فِي الْأَجْرِ حَبَسَهُمْ الْعُذْرُقَالَ أَبُو عَبْد اللَّهِ أَوْ كَمَا قَالَ كَتَبْتُهُ لَفْظًا","id":"Telah menceritakan kepada kami [Ahmad bin Sinan]; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di kota Madinah terdapat sekelompok laki-laki, tidak ada lembah yang kalian tembus dan perjalanan yang kalian tempuh, kecuali mereka bersama kalian di dalam mendapatkan pahalanya karena udzur telah menghalangi mereka.\" Abu Abdullah berkata; Atau sebagaimana yang beliau sabdakan, aku menulisnya secara lafadz."},"2721":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ مُصْعَبِ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَخَطَبَ عُثْمَانُ بْنُ عَفَّانَ النَّاسَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنِّي سَمِعْتُ حَدِيثًا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَمْنَعْنِي أَنْ أُحَدِّثَكُمْ بِهِ إِلَّا الضِّنُّ بِكَمْ وَبِصَحَابَتِكُمْ فَلْيَخْتَرْ مُخْتَارٌ لِنَفْسِهِ أَوْ لِيَدَعْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَابَطَ لَيْلَةً فِي سَبِيلِ اللَّهِ سُبْحَانَهُ كَانَتْ كَأَلْفِ لَيْلَةٍ صِيَامِهَا وَقِيَامِهَا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Abdurrahman bin Zaid bin Aslam] dari [Ayahnya] dari [Mush'ab bin Tsabit] dari [Abdullah bin Az Zubair] berkata; \" [Utsman bin Affan] berpidato di hadapan manusia, ia mengatakan; 'Wahai manusia, aku mendengar sebuah hadits dari Rasulullah shallallahu 'alaihi wasallam yang tidak ada sesuatu pun menghalangiku untuk menyampaikannya kepada kalian kecuali jika aku rakus terhadap Hadits itu. Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barang siapa yang melakukan ribath (berjaga di perbatasan musuh) di jalan Allah satu malam lebih baik maka ia seperti mengerjakan puasa dan shalat seribu malam.\""},"2722":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي اللَّيْثُ عَنْ زُهْرَةَ بْنِ مَعْبَدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَاتَ مُرَابِطًا فِي سَبِيلِ اللَّهِ أَجْرَى عَلَيْهِ أَجْرَ عَمَلِهِ الصَّالِحِ الَّذِي كَانَ يَعْمَلُ وَأَجْرَى عَلَيْهِ رِزْقَهُ وَأَمِنَ مِنْ الْفَتَّانِ وَبَعَثَهُ اللَّهُ يَوْمَ الْقِيَامَةِ آمِنًا مِنْ الْفَزَعِ","id":"Telah menceritakan kepada kami [Yunus bin Abdul Al Al'a]; telah menceritakan kepada kami [Abdullah bin Wahab]; telah menceritakan kepadaku [Al Laits] dari [Zuhrah bin Ma'bad] dari [Ayahnya] dari [Abu Hurairah], dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggal dunia dalam keadaan ribath (berjaga) di jalan Allah, maka ia akan diberikan pahala sesuai dengan pahala amal saleh yang ia lakukan, diberikan kepadanya rezeki dan diamankan dari orang yang memfitnah dan Allah Subhanahu Wa Ta'ala akan mengutusnya di hari kiamat dalam keadaan aman dari rasa takut.\""},"2723":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ حَدَّثَنَا مُحَمَّدُ بْنُ يَعْلَى السُّلَمِيُّ حَدَّثَنَا عُمَرُ بْنُ صُبْحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو عَنْ مَكْحُولٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَرِبَاطُ يَوْمٍ فِي سَبِيلِ اللَّهِ مِنْ وَرَاءِ عَوْرَةِ الْمُسْلِمِينَ مُحْتَسِبًا مِنْ غَيْرِ شَهْرِ رَمَضَانَ أَعْظَمُ أَجْرًا مِنْ عِبَادَةِ مِائَةِ سَنَةٍ صِيَامِهَا وَقِيَامِهَا وَرِبَاطُ يَوْمٍ فِي سَبِيلِ اللَّهِ مِنْ وَرَاءِ عَوْرَةِ الْمُسْلِمِينَ مُحْتَسِبًا مِنْ شَهْرِ رَمَضَانَ أَفْضَلُ عِنْدَ اللَّهِ وَأَعْظَمُ أَجْرًا أُرَاهُ قَالَ مِنْ عِبَادَةِ أَلْفِ سَنَةٍ صِيَامِهَا وَقِيَامِهَا فَإِنْ رَدَّهُ اللَّهُ إِلَى أَهْلِهِ سَالِمًا لَمْ تُكْتَبْ عَلَيْهِ سَيِّئَةٌ أَلْفَ سَنَةٍ وَتُكْتَبُ لَهُ الْحَسَنَاتُ وَيُجْرَى لَهُ أَجْرُ الرِّبَاطِ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah]; telah menceritakan kepada kami [Muhammad bin Ya'la bin As Sulami]; telah menceritakan kepada kami [Umar bin Shubh] dari [Abdurrahman bin Amru] dari [Makhul] dari [Ubay bin Ka'b] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh ribath (menjaga perbatasan) satu hari di jalan Allah dari perbatasan kaum muslimin karena semata-mata mengharap ridla dari Allah, bukan pada bulan Ramadlan, maka pahalanya lebih besar ketimbang ibadah selama seratus tahun, baik puasanya maupun qiyamul lailnya. Dan ribath sehari di jalan Allah pada perbatasan kaum muslimin karena semata-mata mengharap ridla dari Allah pada bulan Ramadlan itu lebih utama di sisi Allah dan lebih besar pahalanya.\" Aku melihat beliau bersabda: 'Dari ibadah selama seribu tahun, baik puasanya maupun shalat malamnya, jika Allah mengembalikannya kepada keluarganya dalam keadaan selamat, tidak akan ditulis kejelekannya selama seribu tahun dan akan ditulis kebaikannya dan dialirkan pahala ribathnya sampai hari kiamat.\""},"2724":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ صَالِحِ بْنِ مُحَمَّدِ بْنِ زَائِدَةَ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ حَارِسَ الْحَرَسِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah]; telah memberitakan kepada kami [Abdul Aziz bin Muhammad] dari [Shalih bin Muhammad bin Za`idah] dari [Umar bin Abdul Aziz] dari [Uqbah bin Amir Al Juhani] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah merahmati orang yang melindungi perbatasan.\" "},"2725":{"ar":"حَدَّثَنَا عِيسَى بْنُ يُونُسَ الرَّمْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبِ بْنِ شَابُورَ عَنْ سَعِيدِ بْنِ خَالِدِ بْنِ أَبِي الطَّوِيلِ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حَرَسُ لَيْلَةٍ فِي سَبِيلِ اللَّهِ أَفْضَلُ مِنْ صِيَامِ رَجُلٍ وَقِيَامِهِ فِي أَهْلِهِ أَلْفَ سَنَةٍ السَّنَةُ ثَلَاثُ مِائَةٍ وَسِتُّونَ يَوْمًا وَالْيَوْمُ كَأَلْفِ سَنَةٍ","id":"Telah memberitakan kepada kami [Isa bin Yunus Ar Ramli]; telah memberitakan kepada kami [Muhammad bin Syu'aib bin Syabur] dari [Sa'id bin Khalid bin Abu Ath Thawil] berkata; Aku mendengar [Anas bin Malik], ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang berjaga di malam hari di jalan Allah itu lebih utama ketimbang puasa seorang lelaki dan shalat malamnya bersama keluarganya selama seribu tahun. Sedang setahun itu adalah tiga ratus enam puluh hari, sedangkan ia pahalanya sehari seperti seribu tahun.\""},"2726":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ أُوصِيكَ بِتَقْوَى اللَّهِ وَالتَّكْبِيرِ عَلَى كُلِّ شَرَفٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki'] dari [Usamah bin Zaid] dari [Sa'id Al Maqburi] dari [Abu Hurairah]; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda kepada seorang laki-Iaki: \"Aku berwasiat kepadamu agar bertakwa kepada Allah dan bertakbir pada saat berada di tempat yang tinggi.\""},"2727":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَذُكِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ أَحْسَنَ النَّاسِ وَكَانَ أَجْوَدَ النَّاسِ وَكَانَ أَشْجَعَ النَّاسِ وَلَقَدْ فَزِعَ أَهْلُ الْمَدِينَةِ لَيْلَةً فَانْطَلَقُوا قِبَلَ الصَّوْتِ فَتَلَقَّاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ سَبَقَهُمْ إِلَى الصَّوْتِ وَهُوَ عَلَى فَرَسٍ لِأَبِي طَلْحَةَ عُرْيٍ مَا عَلَيْهِ سَرْجٌ فِي عُنُقِهِ السَّيْفُ وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ لَنْ تُرَاعُوا يَرُدُّهُمْ ثُمَّ قَالَ لِلْفَرَسِ وَجَدْنَاهُ بَحْرًا أَوْ إِنَّهُ لَبَحْرٌ قَالَ حَمَّادٌ وَحَدَّثَنِي ثَابِتٌ أَوْ غَيْرُهُ قَالَ كَانَ فَرَسًا لِأَبِي طَلْحَةَ يُبَطَّأُ فَمَا سُبِقَ بَعْدَ ذَلِكَ الْيَوْمِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah]; telah memberitakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas bin Malik], ia berkata; Disebutkan tentang Nabi shallallahu 'alaihi wasallam. Anas bin Malik berkata; \"Beliau adalah manusia terbaik, manusia paling dermawan dan manusia paling berani. Di suatu malam penduduk kota Madinah dikejutkan oleh suara sebuah suara, lalu mereka pergi mencari asal usul suara tersebut. Rasulullah menjumpai mereka dan beliau lebih dahulu daripada mereka dalam mencari asal suara tersebut, saat itu Rasulullah berada di atas kuda milik Abu Thalhah yang polos, tidak menggunakan pelana sedang di lehernya terdapat pedang. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai manusia! Janganlah kalian cemas, -beliau menyuruh mereka kembali.- kemudian beliau bersabda kepada kuda: 'Kami mendapatkan kuda ini cepat sekali. atau sesungguhnya kuda ini sangat cepat.' Hammad berkata; Tsabit dan lainnya menceritakan kepadaku, ia berkata; 'Kuda milik Abu Thalhah adalah kuda yang lambat, namun setelah hari itu ia tidak pernah terkalahkan lagi.'"},"2728":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ بَكَّارِ بْنِ عَبْدِ الْمَلِكِ بْنِ الْوَلِيدِ بْنِ بُسْرِ بْنِ أَبِي أَرْطَاةَ حَدَّثَنَا الْوَلِيدُ حَدَّثَنِي شَيْبَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَ��ْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتُنْفِرْتُمْ فَانْفِرُوا","id":"Telah menceritakan kepada kami [Ahmad bin Abdurrahman bin Bakkar bin Abdul Malik bin Al Walid bin Busr bin Abu Arthah]; telah menceritakan kepada kami [Al Walid]; telah menceritakan kepadaku [Syaiban] dari [Al A'masy] dari [Abu Shalih] dari [Ibnu Abbas], dan Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila kalian diperintah untuk memerangi musuh, maka perangilah.\""},"2729":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طَلْحَةَ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَجْتَمِعُ غُبَارٌ فِي سَبِيلِ اللَّهِ وَدُخَانُ جَهَنَّمَ فِي جَوْفِ عَبْدٍ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin Abdurrahman] -mantan budak- keluarga Thalhah dari ['Isa bin Thalhah] dari [Abu Hurairah], Nabi shallallahu 'alaihi wasallam bersabda: \"Debu di jalan Allah dan asap neraka jahannam tidak akan menyatu di dalam perut seorang hamba yang muslim. \""},"2730":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدِ بْنِ يَزِيدَ بْنِ إِبْرَاهِيمَ التُّسْتَرِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ شَبِيبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَاحَ رَوْحَةً فِي سَبِيلِ اللَّهِ كَانَ لَهُ بِمِثْلِ مَا أَصَابَهُ مِنْ الْغُبَارِ مِسْكًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id bin Yazid bin Ibrahim At Tustari]; telah menceritakan kepada kami [Abu 'Ashim] dari [Syabib] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang pergi satu kali di jalan Allah, maka debu yang didapatkannya akan menjadi minyak misik di hari kiamat. \""},"2731":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ ابْنِ حَبَّانَ هُوَ مُحَمَّدُ بْنُ يَحْيَى بْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ خَالَتِهِ أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ أَنَّهَا قَالَتْنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا قَرِيبًا مِنِّي ثُمَّ اسْتَيْقَظَ يَبْتَسِمُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَضْحَكَكَ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ يَرْكَبُونَ ظَهْرَ هَذَا الْبَحْرِ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ قَالَتْ فَادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ فَدَعَا لَهَا ثُمَّ نَامَ الثَّانِيَةَ فَفَعَلَ مِثْلَهَا ثُمَّ قَالَتْ مِثْلَ قَوْلِهَا فَأَجَابَهَا مِثْلَ جَوَابِهِ الْأَوَّلِ قَالَتْ فَادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَقَالَ فَخَرَجَتْ مَعَ زَوْجِهَا عُبَادَةَ بْنِ الصَّامِتِ غَازِيَةً أَوَّلَ مَا رَكِبَ الْمُسْلِمُونَ الْبَحْرَ مَعَ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ فَلَمَّا انْصَرَفُوا مِنْ غَزَاتِهِمْ قَافِلِينَ فَنَزَلُوا الشَّامَ فَقُرِّبَتْ إِلَيْهَا دَابَّةٌ لِتَرْكَبَ فَصَرَعَتْهَا فَمَاتَتْ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari [Ibnu Hibban] yaitu Muhammad bin Yahya bin Habban dari [Anas bin Malik] dari bibinya [Ummi Haram binti Milhan], ia berkata; pada suatu hari Rasulullah shallallahu 'alaihi wasallam tertidur di dekatku, kemudian beliau bangun dan tersenyum, maka aku bertanya; \"Wahai Rasulullah, apa yang membuatmu tertawa?\" Rasulullah shallallahu 'alaihi wasallam menjawab: 'Sekelompok umatku telah diperlihatkan kepadaku dimana mereka menaiki bahtera lautan ini seperti para raja yang berada di atas singgasana.' Ummi Haram berkata; 'Berdoalah kepada Allah agar menjadikanku bagian dari mereka.' Rasulullah shallallahu 'alaihi wasallam lalu berdo'a, dan kemudian beliau tidur kembali. Kemudian terjadi kembali hal itu untuk kedua kalinya. Rasulullah melakukan hal serupa dan Ummi Haram berkata kembali seperti ucapannya tadi. Rasulullah pun menjawab seperti jawaban yang pertama. Ummi Haram berkata; 'Berdoalah kepada Allah agar menjadikanku bagian dari mereka.' Rasulullah menjawab: 'Engkau termasuk para pemula.' (perawi berkata) menuturkan; 'Ummi Haram keluar dari kediamannya bersama suaminya 'Ubadah bin Shamit untuk berperang, peristiwa pertama kali umat Islam menaiki kapal adalah dengan Muawiyah bin Abu Sufyan. Setelah mereka kembali dari peperangan secara berkelompok, mereka singgah di kota Syam. Namun ketika hewan tunggangannya telah di hadapkan kepada Ummu Haram untuk ia naiki, ia terjatuh hingga kemudian ia meninggal.\""},"2732":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا بَقِيَّةُ عَنْ مُعَاوِيَةَ بْنِ يَحْيَى عَنْ لَيْثِ بْنِ أَبِي سُلَيْمٍ عَنْ يَحْيَى بْنِ عَبَّادٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غَزْوَةٌ فِي الْبَحْرِ مِثْلُ عَشْرِ غَزَوَاتٍ فِي الْبَرِّ وَالَّذِي يَسْدَرُ فِي الْبَحْرِ كَالْمُتَشَحِّطِ فِي دَمِهِ فِي سَبِيلِ اللَّهِ سُبْحَانَهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Baqiyyah] dari [Mua'awiyyah bin Yahya] dari [Laits bin Abu Sulaim] dari [Yahya bin 'Abbad] dari [Ummu Darda`] dari [Abu Darda`], ia berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: 'Peperangan di lautan itu seperti sepuluh kali peperangan di daratan, dan orang yang pusing di tengah laut seperti orang yang berlumuran dengan darahnya di jalan Allah Subhaanahu wa ta'ala.\""},"2733":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ يُوسُفَ الْجُبَيْرِيُّ حَدَّثَنَا قَيْسُ بْنُ مُحَمَّدٍ الْكِنْدِيُّ حَدَّثَنَا عُفَيْرُ بْنُ مَعْدَانَ الشَّامِيُّ عَنْ سُلَيْمِ بْنِ عَامِرٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ شَهِيدُ الْبَحْرِ مِثْلُ شَهِيدَيْ الْبَرِّ وَالْمَائِدُ فِي الْبَحْرِ كَالْمُتَشَحِّطِ فِي دَمِهِ فِي الْبَرِّ وَمَا بَيْنَ الْمَوْجَتَيْنِ كَقَاطِعِ الدُّنْيَا فِي طَاعَةِ اللَّهِ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ وَكَلَ مَلَكَ الْمَوْتِ بِقَبْضِ الْأَرْوَاحِ إِلَّا شَهِيدَ الْبَحْرِ فَإِنَّهُ يَتَوَلَّى قَبْضَ أَرْوَاحِهِمْ وَيَغْفِرُ لِشَهِيدِ الْبَرِّ الذُّنُوبَ كُلَّهَا إِلَّا الدَّيْنَ وَلِشَهِيدِ الْبَحْرِ الذُّنُوبَ وَالدَّيْنَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Yusuf Al Jubairi]; telah menceritakan kepada kami [Qais bin Muhammad Al Kindi]; telah menceritakan kepada kami ['Ufair bin Ma'dan Asy Syami] dari [Sulaim bin 'Amir] berkata; Aku mendengar [Abu Umamah], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang syahid di lautan seperti dua orang syahid di daratan, dan pejuang yang pusing di tengah laut seperti orang yang berlumuran dengan darahnya di daratan, dan diantara dua gelombang seperti orang yang melepas dunia untuk ketaatan kepada Allah. Sesungguhnya Allah 'azza wajalla menugaskan kepada Malaikat maut untuk mencabut arwah-arwah, kecuali orang yang syahid di lautan, sesungguhnya Dia Sendiri yang berkepentingan untuk mencabut arwah-arwah mereka. Dan Dia mengampuni semua dosa-dosa orang yang syahid di daratan kecuali hutang, sedangkan dilaut Allah mengampuni dosa-dosa dan hutangnya.\""},"2734":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو دَاوُدَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ الْوَاسِطِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ ح و حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ كُلُّهُمْ عَنْ قَيْسٍ عَنْ أَبِي حُصَيْنٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ لَمْ يَبْقَ مِنْ الدُّنْيَا إِلَّا يَوْمٌ لَطَوَّلَهُ اللَّهُ عَزَّ وَجَلَّ حَتَّى يَمْلِكَ رَجُلٌ مِنْ أَهْلِ بَيْتِي يَمْلِكُ جَبَلَ الدَّيْلَمِ وَالْقُسْطَنْطِينِيَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abu Dawud]; Demikian juga diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Muhammad bin Abdul Malik Al Wasithi]; telah menceritakan kepada kami [Yazid bin Harun]; Demikian juga diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami ['Ali bin Al Mundzir]; telah menceritakan kepada kami [Ishaq bin Manshur] semuanya dari [Qais] dari [Abu Hushain] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau seandainya tidak tersisa di dunia kecuali satu hari, sungguh Allah 'azza wajalla akan memanjangkannya sampai seorang lelaki dari Ahlul baitku menguasai gunung Dailam dan Qusthanthiniyyah.\""},"2735":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ أَسَدٍ حَدَّثَنَا دَاوُدُ بْنُ الْمُحَبَّرِ أَنْبَأَنَا الرَّبِيعُ بْنُ صَبِيحٍ عَنْ يَزِيدَ بْنِ أَبَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتُفْتَحُ عَلَيْكُمْ الْآفَاقُ وَسَتُفْتَحُ عَلَيْكُمْ مَدِينَةٌ يُقَالُ لَهَا قَزْوِينُ مَنْ رَابَطَ فِيهَا أَرْبَعِينَ يَوْمًا أَوْ أَرْبَعِينَ لَيْلَةً كَانَ لَهُ فِي الْجَنَّةِ عَمُودٌ مِنْ ذَهَبٍ عَلَيْهِ زَبَرْجَدَةٌ خَضْرَاءُ عَلَيْهَا قُبَّةٌ مِنْ يَاقُوتَةٍ حَمْرَاءَ لَهَا سَبْعُونَ أَلْفَ مِصْرَاعٍ مِنْ ذَهَبٍ عَلَى كُلِّ مِصْرَاعٍ زَوْجَةٌ مِنْ الْحُورِ الْعِينِ","id":"Telah menceritakan kepada kami [Isma'il bin Asad]; telah menceritakan kepada kami [Dawud bin Al Muhabbar]; telah memberitakan kepada kami [Rabi' bin Shabih] dari [Yazid bin Aban] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh akan ditaklukkan bagi kalian wilayah-wilayah, dan akan ditaklukkan untuk kalian kota yang disebut dengan Qazwin. Barang siapa yang ribath di sana selama empat puluh hari atau empat puluh malam, maka dia akan mendapatkan tiang-tiang dari emas di surga yang dihiasi dengan batu-batu permata hijau, yang diatasnya ada kubah terbuat dari yaqut merah, dia memiliki tujuh puluh ribu pintu yang terbuat dari emas, di setiap pintu ada seorang isteri dari bidadari.\""},"2736":{"ar":"حَدَّثَنَا أَبُو يُوسُفَ مُحَمَّدُ بْنُ أَحْمَدَ الرَّقِّيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْحَرَّانِيُّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ طَلْحَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ مُعَاوِيَةَ بْنِ جَاهِمَةَ السُّلَمِيِّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ أَرَدْتُ الْجِهَادَ مَعَكَ أَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ وَالدَّارَ الْآخِرَةَ قَالَ وَيْحَكَ أَحَيَّةٌ أُمُّكَ قُلْتُ نَعَمْ قَالَ ارْجِعْ فَبَرَّهَا ثُمَّ أَتَيْتُهُ مِنْ الْجَانِبِ الْآخَرِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ أَرَدْتُ الْجِهَادَ مَعَكَ أَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ وَالدَّارَ الْآخِرَةَ قَالَ وَيْحَكَ أَحَيَّةٌ أُمُّكَ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ فَارْجِعْ إِلَيْهَا فَبَرَّهَا ثُمَّ أَتَيْتُهُ مِنْ أَمَامِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ أَرَدْتُ الْجِهَادَ مَعَكَ أَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ وَالدَّارَ الْآخِرَةَ قَالَ وَيْحَكَ أَحَيَّةٌ أُمُّكَ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ وَيْحَكَ الْزَمْ رِجْلَهَا فَثَمَّ الْجَنَّةُحَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُحَمَّدُ بْنُ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ أَبِيهِ طَلْحَةَ عَنْ مُعَاوِيَةَ بْنِ جَاهِمَةَ السُّلَمِيِّ أَنَّ جَاهِمَةَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ قَالَ أَبُو عَبْد اللَّهِ بْن مَاجَةَ هَذَا جَاهِمَةُ بْنُ عَبَّاسِ بْنِ مِرْدَاسٍ السُّلَمِيُّ الَّذِي عَاتَبَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ","id":"Telah menceritakan kepada kami [Abu Yusuf Muhammad bin Ahmad Ar Raqqi]; telah menceritakan kepada kami [Muhammad bin Salamah Al Harrani] dari [Muhammad bin Ishaq] dari [Muhammad bin Thalhah bin Abdurrahman bin Abu Bakar Ash Shiddiq] dari [Muawiyah bin Jahimah As Sulami], ia berkata; \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam, aku katakan kepada beliau; 'Sesungguhnya aku ingin berjihad bersamamu dalam rangka mencari ridla Allah dan kehidupan Akhirat.' Rasulullah shallallahu 'alaihi wasallam menjawab: 'Celakalah kau! Apakah ibumu masih hidup? ' la menjawab; 'Ya.' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kembalilah dan berbaktilah kepadanya.' Kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam kembali dari sisi yang lain. Aku katakan' 'Wahai Rasulullah! Aku ingin berjihad bersamamu dalam rangka mencari ridla Allah dan kehidupan akhirat? Rasulullah shallallahu 'alaihi wasallam menjawab: 'Celakalah kau! Apakah ibumu masih hidup? ' la menjawab; 'Ya.' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kembalilah dan berbaktilah kepadanya.' Kemudian aku mendatanginya dari sisi depan, aku katakan; 'Wahai Rasulullah! Sesungguhnya aku ingin berjihad bersamamu dalam rangka mencari ridla Allah dan kehidupan akhirat.' Rasulullah shallallahu 'alaihi wasallam menjawab: 'Celakalah kau! Apakah ibumu masih hidup? ' la menjawab; 'Ya! Wahai Rasulullah! ' Rasulullah bersabda: 'Celakalah kau! Tetaplah berada pada kedua kakinya dan di situlah terdapat surga.' Telah menceritakan kepada kami [Harun bin Abdullah Al Hammal] Telah menceritakan kepada kami [Hajjaj bin Muhammad] Telah menceritakan kepada kami [Ibnu Juraij] Telah mengabarkan kepadaku [Muhammad bin Thalhah bin Abdullah bin Abdurrahman bin Abu Bakr bin Shiddiq] dari bapaknya, [Thalhah] dari [Mu'awiyah bin Jahimah As Sulami] bahwa Jahimah mendatangi Nabi Shallallahu alaihi wa sallam lalu ia menyebutkan Hadits yang serupa. Abu Abdilah Ibnu Majah berkata; 'Ini adalah Jahimah bin Abbas bin Mardas As-Sulami yang mencerca Nabi shallallahu 'alaihi wasallam pada saat perang Hunain.\""},"2737":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَأَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي جِئْتُ أُرِيدُ الْجِهَادَ مَعَكَ أَبْتَغِي وَجْهَ اللَّهِ وَالدَّارَ الْآخِرَةَ وَلَقَدْ أَتَيْتُ وَإِنَّ وَالِدَيَّ لَيَبْكِيَانِ قَالَ فَارْجِعْ إِلَيْهِمَا فَأَضْحِكْهُمَا كَمَا أَبْكَيْتَهُمَا","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Ala`], telah menceritakan kepada kami [Al Muharibi] dari [Atha` bin Sa`ib] dari [Ayahnya] dari [Abdullah bin Amru] berkata; \"Seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam, ia berkata; 'Wahai Rasulullah! Sesungguhnya aku datang ingin berjihad bersamamu dalam rangka mencari ridha Allah Subhanahu Wa Ta'ala dan kehidupan akhirat. Dan sungguh aku telah datang sedangkan kedua orang tuaku menangis.' Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kembalilah kepada keduanya, buatlah keduanya tertawa sebagaimana engkau membuat keduanya menangis.\""},"2738":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ أَبِي مُوسَى قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُقَاتِلُ شَجَاعَةً وَيُقَاتِلُ حَمِيَّةً وَيُقَاتِلُ رِيَاءً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَاتَلَ لِتَكُونَ كَلِمَةُ اللَّهِ هِيَ الْعُلْيَا فَهُوَ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair], telah menceritakan kepada kami [Abu Mu'awiyah] dari [A`masy] dari [Syaqiq] dari [Abu Musa], ia berkata; Nabi shallallahu 'alaihi wasallam ditanya tentang seorang laki-laki yang berperang karena berani, berperang demi membela fanatisme suku, dan berperang karena riya. Rasulullah shallallahu 'alaihi wasallam menjawab, \"Barangsiapa yang berperang demi kalimat Allah yang tertinggi, maka ia berada dijalan Allah Subhanahu Wa Ta'ala. \""},"2739":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عُقْبَةَ عَنْ أَبِي عُقْبَةَ وَكَانَ مَوْلًى لِأَهْلِ فَارِسَ قَالَشَهِدْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فَضَرَبْتُ رَجُلًا مِنْ الْمُشْرِكِينَ فَقُلْتُ خُذْهَا مِنِّي وَأَنَا الْغُلَامُ الْفَارِسِيُّ فَبَلَغَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا قُلْتَ خُذْهَا وَأَنَا الْغُلَامُ الْأَنْصَارِيُّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Husain bin Muhammad], telah menceritakan kepada kami [Jarir bin Hazim bin Ishaq] dari [Muhammad bin Ishaq] dari [Dawud bin Hushain] dari [Abdurrahman bin Abu Uqbah] dari [Abu Uqbah] seorang budak Persi berkata; \"Aku menyeksikan perang Uhud bersama Nabi shallallahu 'alaihi wasallam, aku pernah membunuh seorang musyrik dan aku berkata; 'Ambilah ia, padahal aku hanyalah seorang anak Persia.' Hingga sampailah berita ini kepada Nabi shallallahu 'alaihi wasallam lalu beliau bersabda: 'Bukankah engkau yang mengatakan; 'Ambilah, karena saya hanya seorang anak Anshar.\""},"2740":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ أَخْبَرَنِي أَبُو هَانِئٍ أَنَّهُ سَمِعَ أَبَا عَبْدِ الرَّحْمَنِ الْحُبُلِيَّ يَقُولُ إِنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ غَازِيَةٍ تَغْزُو فِي سَبِيلِ اللَّهِ فَيُصِيبُوا غَنِيمَةً إِلَّا تَعَجَّلُوا ثُلُثَيْ أَجْرِهِمْ فَإِنْ لَمْ يُصِيبُوا غَنِيمَةً تَمَّ لَهُمْ أَجْرُهُمْ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim], telah menceritakan kepada kami [Abdullah bin Yazid], telah menceritakan kepada kami [Haiwah], telah mengkabarkan kepadaku [Abu Hani`] bahwa ia mendengar [Abu Abdurrahman Al Hubulli] berkata; ia mendengar [Abdullah bin Amru], ia berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada sekelompok pasukan perang yang berperang di jalan Allah lalu mendapatkan harta ghanimah kecuali kalian telah mempercepat dua pertiga pahala mereka, tetapi apabila mereka tidak mendapatkan harta ghanimah, maka pahala pun telah sempurna bagi mereka.\""},"2741":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ عَنْ عُرْوَةَ الْبَارِقِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْرُ مَعْقُودٌ بِنَوَاصِي الْخَيْلِ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syabah], telah menceritakan kepada kami [Abul `Ahwash] dari [Syabib bin Gharqadah] dari [Urwah Al Bariqi], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kebaikan terikat di ubun-ubun kuda sampai hari kiamat.\""},"2742":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْخَيْلُ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh], telah memberitakan kepada kami [Laits bin Sa'ad] dari [Nafi'] dari [Abdullah bin Umar], dari Rasulullah shallallahu 'alaihi wasallam, sesungguhnya ia bersabda: \"Pada ubun-ubun kuda terdapat kebaikan (surga) hingga hari kiamat.\""},"2743":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلُ فِي نَوَاصِيهَا الْخَيْرُ أَوْ قَالَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ قَالَ سُهَيْلٌ أَنَا أَشُكُّ الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْخَيْلُ ثَلَاثَةٌ فَهِيَ لِرَجُلٍ أَجْرٌ وَلِرَجُلٍ سِتْرٌ وَعَلَى رَجُلٍ وِزْرٌ فَأَمَّا الَّذِي هِيَ لَهُ أَجْرٌ فَالرَّجُلُ يَتَّخِذُهَا فِي سَبِيلِ اللَّهِ وَيُعِدُّهَا فَلَا تُغَيِّبُ شَيْئًا فِي بُطُونِهَا إِلَّا كُتِبَ لَهُ أَجْرٌ وَلَوْ رَعَاهَا فِي مَرْجٍ مَا أَكَلَتْ شَيْئًا إِلَّا كُتِبَ لَهُ بِهَا أَجْرٌ وَلَوْ سَقَاهَا مِنْ نَهَرٍ جَارٍ كَانَ لَهُ بِكُلِّ قَطْرَةٍ تُغَيِّبُهَا فِي بُطُونِهَا أَجْرٌ حَتَّى ذَكَرَ الْأَجْرَ فِي أَبْوَالِهَا وَأَرْوَاثِهَا وَلَوْ اسْتَنَّتْ شَرَفًا أَوْ شَرَفَيْنِ كُتِبَ لَهُ بِكُلِّ خُطْوَةٍ تَخْطُوهَا أَجْرٌ وَأَمَّا الَّذِي هِيَ لَهُ سِتْرٌ فَالرَّجُلُ يَتَّخِذُهَا تَكَرُّمًا وَتَجَمُّلًا وَلَا يَنْسَى حَقَّ ظُهُورِهَا وَبُطُونِهَا فِي عُسْرِهَا وَيُسْرِهَا وَأَمَّا الَّذِي هِيَ عَلَيْهِ وِزْرٌ فَالَّذِي يَتَّخِذُهَا أَشَرًا وَبَطَرًا وَبَذَخًا وَرِيَاءً لِلنَّاسِ فَذَلِكَ الَّذِي هِيَ عَلَيْهِ وِزْرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Syawarib], telah menceritakan kepada kami [Abdul Aziz Al Mukhtar], telah menceritakan kepada kami [Suhail] dari [Ayahnya] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda terdapat kebaikan (surga).\" atau Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kuda diikat pada ubun-ubunnya dengan kebaikan (surga). \" Suhail berkata; Aku ragu: kebaikan (surga) -sampai hari kiamat-. Kuda terbagi tiga kategori: kuda memberikan pahala kepada pemiliknya, kuda yang menjaga perbuatan dosa pemiliknya dan kuda yang mengakibatkan dosa pada pemiliknya. Adapun kuda yang memberikan pahala, yaitu seseorang yang membawa serta menyiapkannya di jalan Allah. Hal yang demikian tidak ada yang hilang sama sekali dari perutnya kecuali ditulis bagi pemiliknya pahala. Seandainya ia menggembalakannya di tempat penggembalaan, maka tidak ada yang ia makan kecuali ditulis baginya pahala. Seandainya ia memberikannya minum dari air sungai yang mengalir, maka pahala baginya untuk setiap tetes air yang hilang dari perutnya hingga ia menyebutkan pahala juga ada pada air seni dan kotorannya. Dan apabila ia bergerak satu atau dua langkah, maka ditulis baginya pahala bagi setiap langkahnya. Adapun kuda yang bagi pemiliknya dapat menutupinya dari perbuatan dosa, yaitu seseorang yang membawa seekor kuda untuk dimuliakan dan dipercantik. la tidak melupakan hak punggung dan perutnya, baik di saat sulit atau di saat mendapatkan kemudahan. Adapun kuda yang bagi pemiliknya memberikan dosa, yaitu seseorang yang memiliki kuda untuk kesombongan, berbangga-bangga, kecongkakan dan riya kepada manusia, maka hal seperti itu membuat pemiliknya berdosa.\""},"2744":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ يَحْيَى بْنَ أَيُّوبَ يُحَدِّثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عُلَيِّ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الْخَيْلِ الْأَدْهَمُ الْأَقْرَحُ الْمُحَجَّلُ الْأَرْثَمُ طَلْقُ الْيَدِ الْيُمْنَى فَإِنْ لَمْ يَكُنْ أَدْهَمَ فَكُمَيْتٌ عَلَى هَذِهِ الشِّيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Wahab bin Jarir], telah menceritakan kepada kami [Ayahku], ia berkata; Aku mendengar [Yahya bin Ayyub] menceritakan dari [Yazid bin Abu Habib] dari [Ali bin Rabah] dari [Abu Qatadah Al Anshari], sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baiknya kuda adalah kuda yang berwarna hitam pekat, dikeningnya terdapat warna putih sedikit, hidungnya putih, sisi bagian kanannya terbuka. Apabila ia berwarna tidak hitam, maka ia berwarna hitam kemerah-merahan, dengan ciri-ciri yang serupa.\""},"2745":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَلْمِ بْنِ عَبْدِ الرَّحْمَنِ النَّخَعِيِّ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ الشِّكَالَ مِنْ الْخَيْلِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Salam bin Abdurrahman An Anakha'i] dari [Abu Zur'ah bin Amru bin Jarir] dari [Abu Hurairah], ia berkata; \"Nabi shallallahu 'alaihi wasallam tidak menyukai kuda yang memiliki kalung.\""},"2746":{"ar":"حَدَّثَنَا أَبُو عُمَيْرٍ عِيسَى بْنُ مُحَمَّدٍ الرَّمْلِيُّ حَدَّثَنَا أَحْمَدُ بْنُ يَزِيدَ بْنِ رَوْحٍ الدَّارِيُّ عَنْ مُحَمَّدِ بْنِ عُقْبَةَ الْقَاضِي عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ تَمِيمٍ الدَّارِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ارْتَبَطَ فَرَسًا فِي سَبِيلِ اللَّهِ ثُمَّ عَالَجَ عَلَفَهُ بِيَدِهِ كَانَ لَهُ بِكُلِّ حَبَّةٍ حَسَنَةٌ","id":"Telah menceritakan kepada kami [Abu Umair Isa bin Muhammmad Ar Ramli], telah menceritakan kepada kami [Ahmad bin Yazid bin Rauh Ad Dari] dari [Muhammad bin Uqbah Al Qadhi] dari [Ayahnya] dari [Kakeknya] dari [Tamim Ad Dari], ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mengikatkan kudanya dijalan Allah, lalu ia memberikan makan dengan tangannya, maka bagi setiap butir makanannya bernilai satu kebajikan.\""},"2747":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنَا سُلَيْمَانُ بْنُ مُوسَى حَدَّثَنَا مَالِكُ بْنُ يُخَامِرَ حَدَّثَنَا مُعَاذُ بْنُ جَبَلٍأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَاتَلَ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ مِنْ رَجُلٍ مُسْلِمٍ فُوَاقَ نَاقَةٍ وَجَبَتْ لَهُ الْجَنَّةُ","id":"Telah menceritakan kepada kami [Bisyr bin Adam], telah menceritakan kepada kami [Adh Dhahak bin Makhlad], telah menceritakan kepada kami [Ibnu Juraij], telah menceritakan kepada kami [Sulaiman bin Musa], telah menceritakan kepada kami [Malik bin Yukhamir], telah menceritakan kepada kami [Mu'adz bin Jabal], sesungguhnya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"seorang laki-laki muslim yang berperang dijalan Allah dengan mengendarai untanya, maka wajib baginya surga.\""},"2748":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا دَيْلَمُ بْنُ غَزْوَانَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَحَضَرْتُ حَرْبًا فَقَالَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ يَا نَفْسِأَلَا أَرَاكِ تَكْرَهِينَ الْجَنَّهْأَحْلِفُ بِاللَّهِ لَتَنْزِلِنَّهْطَائِعَةً أَوْ لَتُكْرَهِنَّهْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syabah], telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Dailam bin Ghazwan], telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik], ia berkata; \"Aku ikut berperang lalu Abdullah bin Rawahah berkata; \"Wahai Jiwa! Ingatlah aku melihat dirimu membenci surga, aku bersumpah demi Allah engkau pasti akan turun ke dalam peperangan secara sukarela atau dipaksakan.\" "},"2749":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا حَجَّاجُ بْنُ دِينَارٍ عَنْ مُحَمَّدِ بْنِ ذَكْوَانَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الْجِهَادِ أَفْضَلُ قَالَ مَنْ أُهَرِيقَ دَمُهُ وَعُقِرَ جَوَادُهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Ya'la bin Ubaid], telah menceritakan kepada kami [Hajjaj bin Dinar] dari [Muhammad bin Dzakwan] dari [Syahr bin Hausyab] dari [Amru bin Abasah], ia berkata; \"Aku mendatangi Nabi shallallahu 'alaihi wasallam, aku katakan, \"Wahai Rasulullah! Jihad apakah yang paling utama?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Barangsiapa yang darahnya dialirkan dan kudanya dilukai.\""},"2750":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ وَأَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ قَالَا حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مَجْرُوحٍ يُجْرَحُ فِي سَبِيلِ اللَّهِ وَاللَّهُ أَعْلَمُ بِمَنْ يُجْرَحُ فِي سَبِيلِهِ إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ وَجُرْحُهُ كَهَيْئَتِهِ يَوْمَ جُرِحَ اللَّوْنُ لَوْنُ دَمٍ وَالرِّيحُ رِيحُ مِسْكٍ","id":"Telah menceritakan kepada kami [Bisyr bin Adam] dan [Ahmad bin Tsabit Al Jahdari], keduanya berkata; telah menceritakan kepada kami [Shafwan bin Isa], telah menceritakan kepada kami [Muhammad bin 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada luka yang terdapat di jalan Allah. Allah Subhanahu Wa Ta'ala lebih mengetahui orang yang terluka dijalan-Nya (dan tidak ada yang lain) kecuali ia akan datang di hari kiamat sementara lukanya seperti luka aslinya, darahnya berwarna merah sedang baunya adalah bau misik kesturi.\""},"2751":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنِي إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يَقُولُدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْأَحْزَابِ فَقَالَ اللَّهُمَّ مُنْزِلَ الْكِتَابِ سَرِيعَ الْحِسَابِ اهْزِمْ الْأَحْزَابَ اللَّهُمَّ اهْزِمْهُمْ وَزَلْزِلْهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair], telah menceritakan kepada kami [Ya'la bin Ubaid], telah menceritakan kepadaku [Isma'il bin Abu Khalid], aku mendengar [Abdullah bin Abu Aufa], ia berkata; Rasulullah shallallahu 'alaihi wasallam berdoa untuk golongan orang-orang kafir, Rasulullah bersabda: \"Ya Allah, Dzat yang menurunkan kitab suci, Dzat yang mempercepat perhitungan kalahkanlah golongan kafir tersebut. Ya Allah kalahkan dan goncanglah mereka.\""},"2752":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى وَأَحْمَدُ بْنُ عِيسَى الْمِصْرِيَّانِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي أَبُو شُرَيْحٍ عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ أَنَّ سَهْلَ بْنَ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ حَدَّثَهُ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَأَلَ اللَّهَ الشَّهَادَةَ بِصِدْقٍ مِنْ قَلْبِهِ بَلَّغَهُ اللَّهُ مَنَازِلَ الشُّهَدَاءِ وَإِنْ مَاتَ عَلَى فِرَاشِهِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] dan [Ahmad bin Isa Al Mishriyyan], keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahab], telah menceritakan kepadaku [Abu Syuraih Abdurrahman bin Syuraih] bahwa [Sahal bin Abu Umamah bin Sahal bin Hunaif] menceritakannya dari [Ayahnya] dari [Kakeknya] sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda, \"Barangsiapa yang memohon kepada Allah agar mati syahid dengan kebenaran dalam hatinya, maka Allah Subhanahu Wa Ta'ala akan mengumpulkannya dengan kedudukan orang-orang yang mati syahid, walaupun ia meninggal dunia di atas tempat tidurnya.\""},"2753":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ هِلَالِ بْنِ أَبِي زَيْنَبَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذُكِرَ الشُّهَدَاءُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَجِفُّ الْأَرْضُ مِنْ دَمِ الشَّهِيدِ حَتَّى تَبْتَدِرَهُ زَوْجَتَاهُ كَأَنَّهُمَا ظِئْرَانِ أَضَلَّتَا فَصِيلَيْهِمَا فِي بَرَاحٍ مِنْ الْأَرْضِ وَفِي يَدِ كُلِّ وَاحِدَةٍ مِنْهُمَا حُلَّةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Ibnu Abu Adi] dari [Ibnu Aun] dari [Hilal bin Abu Zainab] dari [Syahr bin Hausyab] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak akan kering bumi dengan darah seorang syahid sehingga kedua istrinya berlomba-lomba menjemputnya, keduanya seakan-akan perempuan yang menyusui yang kehilangan kedua anak penyusuannya di tanah yang sangat lapang. Dan disetiap tangannya ada pakaian yang lebih baik dari dunia dan seisinya.\""},"2754":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ بْنِ مَعْدِيكَرِبَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلشَّهِيدِ عِنْدَ اللَّهِ سِتُّ خِصَالٍ يَغْفِرُ لَهُ فِي أَوَّلِ دُفْعَةٍ مِنْ دَمِهِ وَيُرَى مَقْعَدَهُ مِنْ الْجَنَّةِ وَيُجَارُ مِنْ عَذَابِ الْقَبْرِ وَيَأْمَنُ مِنْ الْفَزَعِ الْأَكْبَرِ وَيُحَلَّى حُلَّةَ الْإِيمَانِ وَيُزَوَّجُ مِنْ الْحُورِ الْعِينِ وَيُشَفَّعُ فِي سَبْعِينَ إِنْسَانًا مِنْ أَقَارِبِهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], telah menceritakan kepada kami [Isma'il bin 'Ayyasy], telah menceritakan kepadaku [Bakhir bin Sa'd] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'dikarib] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang mati syahid mendapatkan enam hal di sisi Allah: Diampuni dosa-dosanya sejak pertama kali darahnya mengalir, diperlihatkan kedudukannya di surga, diselamatkan dari siksa kubur, dibebaskan dari ketakutan yang besar, dihiasi dengan perhiasan iman, dikawinkan dengan bidadari dan dapat memberikan syafaat kepada tujuh puluh orang kerabatnya.\""},"2755":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا مُوسَى بْنُ إِبْرَاهِيمَ الْحَرَامِيُّ الْأَنْصَارِيُّ سَمِعْتُ طَلْحَةَ بْنَ خِرَاشٍ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُلَمَّا قُتِلَ عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ حَرَامٍ يَوْمَ أُحُدٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا جَابِرُ أَلَا أُخْبِرُكَ مَا قَالَ اللَّهُ عَزَّ وَجَلَّ لِأَبِيكَ قُلْتُ بَلَى قَالَ مَا كَلَّمَ اللَّهُ أَحَدًا إِلَّا مِنْ وَرَاءِ حِجَابٍ وَكَلَّمَ أَبَاكَ كِفَاحًا فَقَالَ يَا عَبْدِي تَمَنَّ عَلَيَّ أُعْطِكَ قَالَ يَا رَبِّ تُحْيِينِي فَأُقْتَلُ فِيكَ ثَانِيَةً قَالَ إِنَّهُ سَبَقَ مِنِّي أَنَّهُمْ إِلَيْهَا لَا يُرْجَعُونَ قَالَ يَا رَبِّ فَأَبْلِغْ مَنْ وَرَائِي فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ هَذِهِ الْآيَةَ{ وَلَا تَحْسَبَنَّ الَّذِينَ قُتِلُوا فِي سَبِيلِ اللَّهِ أَمْوَاتًا }الْآيَةَ كُلَّهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Mundzir Al Hizami], telah menceritakan kepada kami [Musa bin Ibrahim Al Harami Al Anshari], aku mendengar [Thalhah bin Khirasy], aku mendengar dari [Jabir bin Abdullah], ia berkata; ketika Abdullah bin Amru bin Haram terbunuh pada perang Uhud, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Jabir!, Maukah engkau aku beritahu tentang apa yang dikatakan oleh Allah Subhanahu Wa Ta'ala kepada ayahmu?\" Aku katakan: \"Tentu.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Subhanahu Wa Ta'ala tidak pernah berbicara kepada seorang pun kecuali dari balik hijab, tetapi Allah Subhanahu Wa Ta'ala berbicara kepada Ayahmu berhadap-hadapan. Allah Subhanahu Wa Ta'ala berfirman: 'Wahai hambaku, mintalah sesuatu dari-Ku, niscaya Aku memberikannya kepadamu, ' ia berkata; 'Wahai Tuhan! Hidupkanlah aku kembali, hingga aku terbunuh kembali demi untuk-Mu yang kedua kalinya.' Allah Subhanahu Wa Ta'ala berfirman, 'Hal itu telah berlalu dari-Ku, sesungguhnya mereka tidak dikembalikan.\" la berkata wahai Tuhan! Sampaikanlah kepada orang-orang setelahku, Allah Subhanahu Wa Ta'ala menurunkana ayat: \" Janganlah kamu mengira bahwa orang-orang yang gugur di jalan Allah itu mati. \""},"2756":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِفِي قَوْلِهِ{ وَلَا تَحْسَبَنَّ الَّذِينَ قُتِلُوا فِي سَبِيلِ اللَّهِ أَمْوَاتًا بَلْ أَحْيَاءٌ عِنْدَ رَبِّهِمْ يُرْزَقُونَ }قَالَ أَمَا إِنَّا سَأَلْنَا عَنْ ذَلِكَ فَقَالَ أَرْوَاحُهُمْ كَطَيْرٍ خُضْرٍ تَسْرَحُ فِي الْجَنَّةِ فِي أَيِّهَا شَاءَتْ ثُمَّ تَأْوِي إِلَى قَنَادِيلَ مُعَلَّقَةٍ بِالْعَرْشِ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ اطَّلَعَ عَلَيْهِمْ رَبُّكَ اطِّلَاعَةً فَيَقُولُ سَلُونِي مَا شِئْتُمْ قَالُوا رَبَّنَا مَاذَا نَسْأَلُكَ وَنَحْنُ نَسْرَحُ فِي الْجَنَّةِ فِي أَيِّهَا شِئْنَا فَلَمَّا رَأَوْا أَنَّهُمْ لَا يُتْرَكُونَ مِنْ أَنْ يَسْأَلُوا قَالُوا نَسْأَلُكَ أَنْ تَرُدَّ أَرْوَاحَنَا فِي أَجْسَادِنَا إِلَى الدُّنْيَا حَتَّى نُقْتَلَ فِي سَبِيلِكَ فَلَمَّا رَأَى أَنَّهُمْ لَا يَسْأَلُونَ إِلَّا ذَلِكَ تُرِكُوا","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah] mengenai firman Allah Subhanahu Wa Ta'ala: \" Janganlah kamu mengira bahwa orang-orang yang gugur di jalan Allah itu mati, bahkan mereka itu hidup di sisi Tuhannya dengan mendapat rezeki.\" la berkata; \"Dapatkah kita bertanya tentang hal itu? Nabi shallallahu 'alaihi wasallam bersabda: \"Ruh-ruh mereka seperti burung hijau yang melebarkan sayapnya di surga mana saja yang ia kehendaki, kemudian ia bernaung di atas lentera yang tergantung di Arasy. Di saat mereka seperti itu, Tuhanmu muncul kepada mereka, Allah Subhanahu Wa Ta'ala berfirman: Mintalah kepadaku apa yang kalian inginkan! Mereka berkata; Tuhan kami! apa yang akan kami minta kepada-Mu, sementara kami sedang melebarkan sayap di surga sesuka hati kami? Ketika mereka melihat bahwa mereka tidak dibiarkan untuk tidak meminta, maka mereka berkata; 'Kami meminta agar ruh kami dikembalikan kepada jasad kami di dunia, kemudian kami terbunuh kembali di jalan-Mu. Ketika Allah Subhanahu Wa Ta'ala melihat bahwa mereka tidak meminta hal lainnya kecuali hal itu, maka mereka ditinggalkan.\""},"2757":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَحْمَدُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَبِشْرُ بْنُ آدَمَ قَالُوا حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى أَنْبَأَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَجِدُ الشَّهِيدُ مِنْ الْقَتْلِ إِلَّا كَمَا يَجِدُ أَحَدُكُمْ مِنْ الْقَرْصَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Ahmad bin Ibrahim Ad Dauraqi] dan [Bisyr bin Adam], semuanya berkata; telah menceritakan kepada kami [Shafwan bin Isa], telah memberitakan kepada kami [Muhammad bin 'Ajlan] dari [Al Qa'qa bin Hakim] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang yang mati syahid tidak merasakan kesakitan, melainkan layaknya salah seorang dari kalian dicubit.\""},"2758":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أَبِي الْعُمَيْسِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ جَبْرِ بْنِ عَتِيكٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ مَرِضَ فَأَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَقَالَ قَائِلٌ مِنْ أَهْلِهِ إِنْ كُنَّا لَنَرْجُو أَنْ تَكُونَ وَفَاتُهُ قَتْلَ شَهَادَةٍ فِي سَبِيلِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ شُهَدَاءَ أُمَّتِي إِذًا لَقَلِيلٌ الْقَتْلُ فِي سَبِيلِ اللَّهِ شَهَادَةٌ وَالْمَطْعُونُ شَهَادَةٌ وَالْمَرْأَةُ تَمُوتُ بِجُمْعٍ شَهَادَةٌ يَعْنِي الْحَامِلَ وَالْغَرِقُ وَالْحَرِقُ وَالْمَجْنُوبُ يَعْنِي ذَاتَ الْجَنْبِ شَهَادَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Waki'] dari [Abu Al Umais] dari [Abdullah bin Abdullah bin Jabri bin 'Atik] dari [Ayahnya] dari [Kakeknya] bahwa ia sedang sakit, lalu Nabi shallallahu 'alaihi wasallam datang untuk menjenguknya, seseorang dari keluarganya berkata; \"Kami mengharapkan agar kematiannya dengan terbunuh secara syahid di jalan Allah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika demikian umatku yang mati syahid hanya sedikit, seseorang yang terbunuh di jalan Allah adalah orang yang mati syahid, penderita lepra mati syahid, wanita yang meninggal dunia karena melahirkan juga syahid, orang yang mati tenggelam, kebakaran dan orang yang menderita selaput dada juga adalah syahid.\""},"2759":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا تَقُولُونَ فِي الشَّهِيدِ فِيكُمْ قَالُوا الْقَتْلُ فِي سَبِيلِ اللَّهِ قَالَ إِنَّ شُهَدَاءَ أُمَّتِي إِذًا لَقَلِيلٌ مَنْ قُتِلَ فِي سَبِيلِ اللَّهِ فَهُوَ شَهِيدٌ وَمَنْ مَاتَ فِي سَبِيلِ اللَّهِ فَهُوَ شَهِيدٌ وَالْمَبْطُونُ شَهِيدٌ وَالْمَطْعُونُ شَهِيدٌقَالَ سُهَيْلٌ وَأَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ مِقْسَمٍ عَنْ أَبِي صَالِحٍ وَزَادَ فِيهِ وَالْغَرِقُ شَهِيدٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Syawarib], telah menceritakan kepada kami [Abdul Aziz bin Mukhtar], telah menceritakan kepada kami [Suhail] dari [Ayahnya] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam beliau bersabda; \"Apa yang kalian katakan tentang seseorang yang mati syahid yang ada pada kalian?\" Mereka menjawab, \"Orang yang terbunuh di jalan Allah. Rasulullah shallallahu 'alaihi wasallam menjawab, \"Jika demikian orang yang mati syahid dari umatku hanya sedikit; Barangsiapa terbunuh di jalan Allah, maka ia syahid. Barangsiapa meninggal dunia di jalan Allah, maka ia syahid, orang yang meninggal dunia karena sakit perut adalah syahid dan orang yang menderita lepra juga syahid\" [Suhail] berkata; \" [Ubaidilah bin Miqsam] memberitahuku dari [Abu Shalih] dan di dalamnya ia menambahkan: \"Orang yang tenggelam juga syahid.\""},"2760":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ يَوْمَ الْفَتْحِ وَعَلَى رَأْسِهِ الْمِغْفَرُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Suwaid bin Sa'id], keduanya berkata; telah menceritakan kepada kami [Malik bin Anas], telah menceritakan kepadaku [Az Zuhri] dari [Anas bin Malik], ia berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam masuk ke kota Mekkah pada saat penaklukan kota Makkah, dan di atas kepala beliau terdapat pelindung kepala.\""},"2761":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ السَّائِبِ بْنِ يَزِيدَ إِنْ شَاءَ اللَّهُ تَعَالَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ أَخَذَ دِرْعَيْنِ كَأَنَّهُ ظَاهَرَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Yazid bin Khushaifah] dari [As-Sa'ib bin Yazid]; \"Dengan izin Allah, pada saat perang Uhud, Nabi shallallahu 'alaihi wasallam mengambil (mengenakan) dua tameng, seolah beliau memakainya untuk saling melengkapi satu dengan yang lainnya (satu di bagian bawah dan satu lagi di bagian atas)."},"2762":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي سُلَيْمَانُ بْنُ حَبِيبٍ قَالَدَخَلْنَا عَلَى أَبِي أُمَامَةَ فَرَأَى فِي سُيُوفِنَا شَيْئًا مِنْ حِلْيَةِ فِضَّةٍ فَغَضِبَ وَقَالَ لَقَدْ فَتَحَ الْفُتُوحَ قَوْمٌ مَا كَانَ حِلْيَةُ سُيُوفِهِمْ مِنْ الذَّهَبِ وَالْفِضَّةِ وَلَكِنْ الْآنُكُ وَالْحَدِيدُ وَالْعَلَابِيُّقَالَ أَبُو الْحَسَنِ الْقَطَّانُ الْعَلَابِيُّ الْعَصَبُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi], telah menceritakan kepada kami [Walid bin Muslim], telah menceritakan kepada kami [Al `Auza'i], telah menceritakan kepadaku [Sulaiman bin Habib], ia berkata; \"Kami masuk untuk menemui [Abu Umamah], kemudian ia melihat pada pedang kami terdapat hiasan yang terbuat dari perak. Maka ia pun lantas marah dan berseru, 'Kaum ini telah banyak melakukan penaklukan-penaklukan, namun tidak ada hiasan pada pedang-pedang mereka yang terbuat dari emas dan perak, melainkan terdiri dari timah yang dilelehkan, besi dan 'Alabi'\" Abu Hasan Al Qathani berkata; \"Alabi adalah sejenis kain pengikat.\""},"2763":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ الصَّلْتِ عَنْ ابْنِ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَنَفَّلَ سَيْفَهُ ذَا الْفَقَارِ يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Ibnu Shalt] dari [Ibnu Abu Zinad] dari [Ayahnya] dari [Ubaidillah bin Abdullah] dari [Ibnu Abbas], ia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memberikan pedangnya yang bernama Dzal Faqar di saat perang Badar.\" "},"2764":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ أَنْبَأَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْخَلِيلِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكَانَ الْمُغِيرَةُ بْنُ شُعْبَةَ إِذَا غَزَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمَلَ مَعَهُ رُمْحًا فَإِذَا رَجَعَ طَرَحَ رُمْحَهُ حَتَّى يُحْمَلَ لَهُ فَقَالَ لَهُ عَلِيٌّ لَأَذْكُرَنَّ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَفْعَلْ فَإِنَّكَ إِنْ فَعَلْتَ لَمْ تُرْفَعْ ضَالَّةً","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah], telah memberitakan kepada kami [Waki'] dari [Sufyan] dari [Abu Ishaq] dari [Abu Khalil] dari [Ali bin Abu Thalib], ia berkata; \"Mughirah bin Syu'bah, apabila ia berperang bersama Nabi shallallahu 'alaihi wasallam, ia selalu membawa tombak bila ia pulang maka ia lemparkan agar ada yang mengembalikan kepadanya.\" Ali berkata kepadanya; \"Aku akan sampaikan hal ini kepada Rasulullah shallallahu 'alaihi wasallam.\" maka beliau menjawab; \"Jangan kamu lakukan hal itu, karena kalau engkau melakukannya maka barang yang hilang itu tidak akan dikembalikan lagi.\""},"2765":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ أَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ أَشْعَثَ بْنِ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ عَنْ أَبِي رَاشِدٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَتْ بِيَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْسٌ عَرَبِيَّةٌ فَرَأَى رَجُلًا بِيَدِهِ قَوْسٌ فَارِسِيَّةٌ فَقَالَ مَا هَذِهِ أَلْقِهَا وَعَلَيْكُمْ بِهَذِهِ وَأَشْبَاهِهَا وَرِمَاحِ الْقَنَا فَإِنَّهُمَا يَزِيدُ اللَّهُ لَكُمْ بِهِمَا فِي الدِّينِ وَيُمَكِّنُ لَكُمْ فِي الْبِلَادِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah], telah memberitakan kepada kami [Ubaidullah bin Musa] dari [`Asy'ats bin Sa'id] dari [Abdullah bin Busr] dari [Abu Rasyid] dari ['Ali], ia berkata; \"Di tangan Rasulullah shallallahu 'alaihi wasallam tergenggam busur panah buatan orang Arab, kemudian beliau melihat seorang lelaki ditangannya busur panah buatan orang Persia, maka beliau bersabda: \"Apa ini, lemparkanlah, dan kalian harus dengan yang ini dan yang serupa dengannya dan tombak-tombak yang bertangkai, karena dengan keduanya Allah akan menambah kekuatan kalian didalam menegakan agama dan menguasakan kepada kalian negeri-negeri.\""},"2766":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَّامٍ عَنْ عَبْدِ اللَّهِ بْنِ الْأَزْرَقِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيُدْخِلُ بِالسَّهْمِ الْوَاحِدِ الثَّلَاثَةَ الْجَنَّةَ صَانِعَهُ يَحْتَسِبُ فِي صَنْعَتِهِ الْخَيْرَ وَالرَّامِيَ بِهِ وَالْمُمِدَّ بِهِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْمُوا وَارْكَبُوا وَأَنْ تَرْمُوا أَحَبُّ إِلَيَّ مِنْ أَنْ تَرْكَبُوا وَكُلُّ مَا يَلْهُو بِهِ الْمَرْءُ الْمُسْلِمُ بَاطِلٌ إِلَّا رَمْيَهُ بِقَوْسِهِ وَتَأْدِيبَهُ فَرَسَهُ وَمُلَاعَبَتَهُ امْرَأَتَهُ فَإِنَّهُنَّ مِنْ الْحَقِّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Yazid bin Harun]; telah memberitakan kepada kami [Hisyam bin Ad Dastuwa`i] dari [Yahya bin Abu Katsir] dari [Abu Sallam] dari [Abdullah bin Azraq] dari [Uqbah bin Amir Al Juhani] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah akan memasukkan tiga orang ke dalam surga dengan satu anak panah; pertama; pembuatnya, yang mana ia membuatnya dengan berharap kebaikan, kedua; yang membidikkannya, dan ketiga; yang membentangkannya\". Dan Rasulullah shallallahu 'alaihi wasallam bersabda: 'Lemparlah dan kendarailah tunggangan, sesungguhnya melemparnya kalian itu lebih aku sukai dari pada mengendarai tunggangan, dan segala mainan apapun yang dilakukan oleh seorang muslim adalah bathil kecuali melempar anak panah, merawat kuda dan canda dengan isterinya, sungguh semuanya adalah hak.'"},"2767":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ سُلَيْمَانَ بْنِ عَبْدِ الرَّحْمَنِ الْقُرَشِيِّ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَمَى الْعَدُوَّ بِسَهْمٍ فَبَلَغَ سَهْمُهُ الْعَدُوَّ أَصَابَ أَوْ أَخْطَأَ فَعَدْلُ رَقَبَةٍ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la]; telah menceritakan kepada kami [Abdullah bin Wahab]; telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Sulaiman bin Abdurrahman Al Qurasyi] dari [Al Qasim bin Abdurrahman] dari ['Amru bin 'Abasah], ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang melepas anak panah pada musuh, lalu anak panah tersebut sampai pada musuh, baik mengenai sasaran atau tidak, maka ia sama dengan memerdekakan seorang budak.\""},"2768":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ أَبِي عَلِيٍّ الْهَمْدَانِيِّ أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَى الْمِنْبَرِ{ وَأَعِدُّوا لَهُمْ مَا اسْتَطَعْتُمْ مِنْ قُوَّةٍ }أَلَا وَإِنَّ الْقُوَّةَ الرَّمْيُ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la]; telah memberitakan kepada kami [Abdullah bin Wahab]; telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Abu 'Ali Al Hamdani] bahwa ia mendengar ['Uqbah bin Amir Al Juhani], ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca ayat suci Al Qur'an di atas mimbar yang berbunyi: \" Dan kalian persiapkan bagi mereka kekuatan yang dapat kalian lakukan. Ingatlah sesungguhnya kekuatan ada pada melepas anak panah -sampai tiga kali-.\""},"2769":{"ar":"حَدَّثَنَا حَرْمَلَهُ بْنُ يَحْيَى الْمِصْرِيُّ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابنُ لَهِيعَةَ عَنْ عُثْمَانَ بْنِ نُعَيْمٍ الرُّعَيْنِيِّ عَنْ الْمُغِيرَةِ بْنِ نَهِيكٍ أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَعَلَّمَ الرَّمْيَ ثُمَّ تَرَكَهُ فَقَدْ عَصَانِي","id":"Telah menceritakan kepada kami [Harmalah bin Yahya Al Mishri]; telah memberitakan kepada kami [Abdullah bin Wahab]; telah mengabarkan kepadaku [Ibnu Lahi'ah] dari ['Utsman bin Nu'aim Ar Ru'aini] dari [Al Mughirah bin Nahiik] bahwa ia mendengar ['Uqbah bin 'Amir Al Juhanni] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mempelajari panah lalu ia melupakannya maka ia telah membangkang kepadaku.\""},"2770":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ زِيَادِ بْنِ الْحُصَيْنِ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَفَرٍ يَرْمُونَ فَقَالَ رَمْيًا بَنِي إِسْمَعِيلَ فَإِنَّ أَبَاكُمْ كَانَ رَامِيًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazaq]; telah memberitakan kepada kami [Sufyan] dari [Al A'masy] dari [Ziyad bin Hushain] dari [Abu Al 'Aliyah] dari [Ibnu 'Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam berpesan kepada sekelompok orang yang sedang melepas anak panah, beliau bersabda: \"Melepas anak panah (adalah budaya) bani Ismail, sesungguhnya ayah kalian adalah seorang pemanah.\""},"2771":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ الْحَارِثِ بْنِ حَسَّانَ قَالَقَدِمْتُ الْمَدِينَةَ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا عَلَى الْمِنْبَرِ وَبِلَالٌ قَائِمٌ بَيْنَ يَدَيْهِ مُتَقَلِّدٌ سَيْفًا وَإِذَا رَايَةٌ سَوْدَاءُ فَقُلْتُ مَنْ هَذَا قَالُوا هَذَا عَمْرُو بْنُ الْعَاصِ قَدِمَ مِنْ غَزَاةٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari ['Ashim] dari [Al Harits bin Hassan] berkata; \"Aku tiba di kota Madinah, aku menyaksikan Nabi shallallahu 'alaihi wasallam sedang berdiri di atas mimbar, sementara Bilal sedang berdiri di hadapan beliau dengan posisi mengikat pedang dan tiba-tiba ada bendera hitam. Aku tanyakan; 'Siapa ini? ' Mereka berkata; 'Ini adalah 'Amru bin Ash yang datang dari peperangan.'"},"2772":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَعَبْدَةُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا شَرِيكٌ عَنْ عَمَّارٍ الدُّهْنِيِّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ يَوْمَ الْفَتْحِ وَلِوَاؤُهُ أَبْيَضُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] dan ['Abdah bin Abdullah], berkata; telah menceritakan kepada kami [Yahya bin Adam]; telah menceritakan kepada kami [Syarik] dari ['Ammar Ad Duhni] dari [Abu Az Zubair] dari [Jabir bin Abdullah], ia berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam memasuki kota Makkah di saat penaklukan kota Makkah dan benderanya berwarna putih.\""},"2773":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِسْحَقَ الْوَاسِطِيُّ النَّاقِدُ حَدَّثَنَا يَحْيَى بْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ حَيَّانَ سَمِعْتُ أَبَا مِجْلَزٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍأَنَّ رَايَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتْ سَوْدَاءَ وَلِوَاؤُهُ أَبْيَضُ","id":"Telah menceritakan kepada kami [Abdullah bin Ishaq Al Washithi An Naqid]; telah menceritakan kepada kami [Yahya bin Ishaq] dari [Yazid bin Hayyan]; aku mendengar [Abu Mijlaz] menceritakan dari [Ibnu Abbas], ia berkata; \"Sesungguhnya panji Rasulullah shallallahu 'alaihi wasallam berwarna hitam dan benderanya berwarna putih.\""},"2774":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ حَجَّاجٍ عَنْ أَبِي عُمَرَ مَوْلَى أَسْمَاءَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍأَنَّهَا أَخْرَجَتْ جُبَّةً مُزَرَّرَةً بِالدِّيبَاجِ فَقَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُ هَذِهِ إِذَا لَقِيَ الْعَدُوَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Hajjaj] dari [Abu 'Umar] -mantan budak Asma` dari [Asma` binti Abu Bakar] bahwa ia mengeluarkan jubah khusus yang semisal sutera, lalu ia mengatakan; \"Nabi shallallahu 'alaihi wasallam memakai ini apabila beliau bertemu dengan musuh (perang).\""},"2775":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ عَنْ عُمَرَأَنَّهُ كَانَ يَنْهَى عَنْ الْحَرِيرِ وَالدِّيبَاجِ إِلَّا مَا كَانَ هَكَذَا ثُمَّ أَشَارَ بِإِصْبَعِهِ ثُمَّ الثَّانِيَةِ ثُمَّ الثَّالِثَةِ ثُمَّ الرَّابِعَةِ وَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا عَنْهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Hafsh bin Ghiyats] dari ['Ashim Al Ahwal] dari [Abu Utsman] dari [Umar]; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang mengenakan pakaian sutera dan dibaj (jenis sutera), kecuali seperti ini, lalu ia memberi isyarat dengan jarinya kemudian untuk kedua, ketiga sampai keempat dan Umar berkata; 'Rasulullah melarang kita dari hal ini.'\""},"2776":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُسَاوِرٍ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِ قَالَكَأَنِّي أَنْظُرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ قَدْ أَرْخَى طَرَفَيْهَا بَيْنَ كَتِفَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abu Usamah] dari [Musawir]; telah menceritakan kepadaku [Ja'far bin Amru bin Huraits] dari [Ayahnya], ia berkata; seakan-akan aku melihat Rasulullah shallallahu 'alaihi wasallam dan di atas kepala beliau ada sorban hitam yang kedua ujungnya menjulur diantara pundaknya."},"2777":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Az Zubair] dari [Jabir], ia berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam memasuki kota Makkah sementara di atas kepalanya terdapat surban hitam.\""},"2778":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْكَرِيمِ حَدَّثَنَا سُنَيْدُ بْنُ دَاوُدَ عَنْ خَالِدِ بْنِ حَيَّانَ الرَّقِّيِّ أَنْبَأَنَا عَلِيُّ بْنُ عُرْوَةَ الْبَارِقِيُّ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ عَنْ أَبِي الزِّنَادِ عَنْ خَارِجَةَ بْنِ زَيْدٍ قَالَرَأَيْتُ رَجُلًا يَسْأَلُ أَبِي عَنْ الرَّجُلِ يَغْزُو فَيَشْتَرِي وَيَبِيعُ وَيَتَّجِرُ فِي غَزْوَتِهِ فَقَالَ لَهُ أَبِي كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَبُوكَ نَشْتَرِي وَنَبِيعُ وَهُوَ يَرَانَا وَلَا يَنْهَانَا","id":"Telah menceritakan kepada kami [Ubaidillah bin Abdul Karim]; telah menceritakan kepada kami [Sunaid bin Dawud] dari [Khalid bin Hayyan Ar Riqqi]; telah memberitakan kepada kami ['Ali bin 'Urwah Al Bariqi]; telah menceritakan kepada kami [Yunus bin Yazid] dari [Abu Az Zinad] dari [Kharijah bin Zaid] berkata; \"Aku melihat seorang lelaki bertanya kepada ayahku tentang seorang lelaki yang berperang sambil membeli dan menjual serta berniaga di dalam peperangan. Maka [ayahku] berkata kepadanya; 'Kami bersama Rasulullah shallallahu 'alaihi wasallam di Tabuk, kami membeli dan menjual sedang beliau melihat kami dan beliau tidak melarang kami.\""},"2779":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا أَبُو الْأَسْوَدِ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ زَبَّانَ بْنِ فَائِدٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ أُشَيِّعَ مُجَاهِدًا فِي سَبِيلِ اللَّهِ فَأَكُفَّهُ عَلَى رَحْلِهِ غَدْوَةً أَوْ رَوْحَةً أَحَبُّ إِلَيَّ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Ja'far bin Musafir]; telah menceritakan kepada kami [Abul Aswad]; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Zabban bin Fa`id] dari [Sahal bin Mu'adz bin Anas] dari [Ayahnya] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku mempersiapkan seorang mujahid di jalan Allah, dipenuhi seluruh kebutuhan dan kendaraannya di pagi atau sorenya lebih aku sukai dari pada dunia dan seisinya.\""},"2780":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ الْحَسَنِ بْنِ ثَوْبَانَ عَنْ مُوسَى بْنِ وَرْدَانَ عَنْ أَبِي هُرَيْرَةَ قَالَوَدَّعَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَسْتَوْدِعُكَ اللَّهَ الَّذِي لَا تَضِيعُ وَدَائِعُهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Al Walid bin Muslim]; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Al Hasan bin Tsauban] dari [Musa bin Wardan] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melepaskan kepergianku, beliau bersabda: \"Aku menitipkan dirimu kepada Allah yang tidak akan menyia-nyiakan barang titipan-Nya.\""},"2781":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ الْوَلِيدِ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا أَبُو مِحْصَنٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَشْخَصَ السَّرَايَا يَقُولُ لِلشَّاخِصِ أَسْتَوْدِعُ اللَّهَ دِينَكَ وَأَمَانَتَكَ وَخَوَاتِيمَ عَمَلِكَ","id":"Telah menceritakan kepada kami ['Abbad bin Al Walid]; telah menceritakan kepada kami [Habban bin Hilal]; telah menceritakan kepada kami [Abu Mihshan] dari [Ibnu Abi Laila] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila mengantar pasukan, beliau berkata: \"Aku menitipkan kepada Allah atas nama agama, amanat dan akhir dari amal perbuatanmu.\""},"2782":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْمَلِكِ مُحَمَّدٌ الصَّنْعَانِيُّ حَدَّثَنَا أَبُو سَلَمَةَ الْعَامِلِيُّ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَكْثَمَ بْنِ الْجَوْنِ الْخُزَاعِيِّ يَا أَكْثَمُ اغْزُ مَعَ غَيْرِ قَوْمِكَ يَحْسُنْ خُلُقُكَ وَتَكْرُمْ عَلَى رُفَقَائِكَ يَا أَكْثَمُ خَيْرُ الرُّفَقَاءِ أَرْبَعَةٌ وَخَيْرُ السَّرَايَا أَرْبَعُ مِائَةٍ وَخَيْرُ الْجُيُوشِ أَرْبَعَةُ آلَافٍ وَلَنْ يُغْلَبَ اثْنَا عَشَرَ أَلْفًا مِنْ قِلَّةٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Abdul Malik Muhammad Ash Shan'ani]; telah menceritakan kepada kami [Abu Salamah Al 'Amili] dari [Ibnu Syihab] dari [Anas bin Malik]; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda kepada Aktsam bin Al Jaun Al Khuza'i: \"Wahai Aktsam, berperanglah bersama selain kaummu maka perangaimu akan menjadi baik, dan kamu akan memuliakan sahabat-sahabatmu, wahai Aktsam, sebaik-baik sahabat adalah empat orang, Sebaik-baik detasemen terdiri dari empat ratus orang, sebaik-baiknya pasukan perang terdiri dari empat ribu orang, sekali-kali dua belas ribu pasukan (yang tidak sedikit) tidak dapat dikalahkan.\""},"2783":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكُنَّا نَتَحَدَّثُ أَنَّ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانُوا يَوْمَ بَدْرٍ ثَلَاثَ مِائَةٍ وَبِضْعَةَ عَشَرَ عَلَى عِدَّةِ أَصْحَابِ طَالُوتَ مَنْ جَازَ مَعَهُ النَّهَرَ وَمَا جَازَ مَعَهُ إِلَّا مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Abu Amir]; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Bara` bin 'Azib], ia berkata; \"Kami sedang berbincang-bincang bahwa para sahabat Rasulullah di saat perang Badar berjumlah tiga ratus orang lebih, sama dengan jumlah pasukan Thalut yang dapat melewati sungai. Tak ada orang yang melewati sungai tersebut kecuali seorang mukmin.\""},"2784":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ ابْنِ لَهِيعَةَ أَخْبَرَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ لَهِيعَةَ بْنِ عُقْبَةَ قَالَ سَمِعْتُ أَبَا الْوَرْدِ صَاحِبَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُإِيَّاكُمْ وَالسَّرِيَّةَ الَّتِي إِنْ لَقِيَتْ فَرَّتْ وَإِنْ غَنِمَتْ غَلَّتْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Zaid bin Al Huban] dari [Ibnu Lahi'ah]; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Lahi'ah bin 'Uqbah], ia berkata; aku mendengar [Abul Ward] sahabat Rasulullah shallallahu 'alaihi wasallam berkata; \"Jangan sampai kalian bergabung dengan pasukan yang apabila bertemu musuh mereka lari, dan jika mendapat ghanimah mereka mencuri.\""},"2785":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ طَعَامِ النَّصَارَى فَقَالَ لَا يَخْتَلِجَنَّ فِي صَدْرِكَ طَعَامٌ ضَارَعْتَ فِيهِ نَصْرَانِيَّةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Simak bin Harb] dari [Qabishah bin Hulb] dari [Bapaknya], ia berkata; \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang makanan orang-orang Nasrani? Rasulullah shallallahu 'alaihi wasallam bersabda: 'Janganlah makanan di dadamu disibukkan oleh sesuatu yang berdekatan dengan orang-orang Nasrani.'\""},"2786":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي أَبُو فَرْوَةَ يَزِيدُ بْنُ سِنَانٍ حَدَّثَنِي عُرْوَةُ بْنُ رُوَيْمٍ اللَّخْمِيُّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ قَالَ وَلَقِيَهُ وَكَلَّمَهُ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ قُدُورُ الْمُشْرِكِينَ نَطْبُخُ فِيهَا قَالَ لَا تَطْبُخُوا فِيهَا قُلْتُ فَإِنْ احْتَجْنَا إِلَيْهَا فَلَمْ نَجِدْ مِنْهَا بُدًّا قَالَ فَارْحَضُوهَا رَحْضًا حَسَنًا ثُمَّ اطْبُخُوا وَكُلُوا","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Usamah]; telah menceritakan kepadaku [Abu Farwah Yazid bin Sinan]; telah menceritakan kepadaku ['Urwah bin Ruwaim Al Lakhmi] dari [Abu Tsa'labah Al Khusyani], ia berkata; \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya kepada beliau. Aku katakan: \"Wahai Rasulullah shallallahu 'alaihi wasallam! Periuk orang-orang musyrik, bolehkah kita memasak di dalamnya? ' Rasulullah menjawab: 'Janganlah kalian memasak di dalamnya.' Lalu aku tanyakan; 'Apabila kita membutuhkannya dan kita tidak menjumpai yang lainnya? ' Rasulullah shallallahu 'alaihi wasallam menjawab: 'Basuhlah dengan baik, lalu masak dan makanlah.'"},"2787":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ نِيَارٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائ��شَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا لَا نَسْتَعِينُ بِمُشْرِكٍ قَالَ عَلِيٌّ فِي حَدِيثِهِ عَبْدُ اللَّهِ بْنُ يَزِيدَ أَوْ زَيْدٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Malik bin Anas] dari [Abdullah bin Yazid] dari Niyardari ['Urwah bin Az Zubair] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya kami tidak meminta tolong kepada orang musyrik.' [Ali] berkata dalam haditsnya; 'Abdullah bin Yazid atau Zaid.'"},"2788":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَرْبُ خَدْعَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Yunus bin Bukair] dari [Muhammad bin Ishaq] dari [Yazid bin Ruman] dari ['Urwah] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Peperangan adalah tipu daya.\""},"2789":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مَطَرِ بْنِ مَيْمُونٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَرْبُ خَدْعَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Yunus bin Bukair] dari [Mathar bin Maimun] dari ['Ikrimah] dari [Ibnu 'Abbas]; sesungguhnya Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Peperangan adalah tipu daya.\""},"2790":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ وَحَفْصُ بْنُ عَمْرٍو قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ أَنْبَأَنَا وَكِيعٌ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ أَبِي هَاشِمٍ الرُّمَّانِيِّ قَالَ أَبُو عَبْد اللَّهِ هُوَ يَحْيَى بْنُ الْأَسْوَدِ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَسَمِعْتُ أَبَا ذَرٍّ يُقْسِمُ لَنَزَلَتْ هَذِهِ الْآيَةُ فِي هَؤُلَاءِ الرَّهْطِ السِّتَّةِ يَوْمَ بَدْرٍ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ فَالَّذِينَ كَفَرُوا قُطِّعَتْ لَهُمْ ثِيَابٌ مِنْ نَارٍ }إِلَى قَوْلِهِ{ الْحَرِيقِ }فِي حَمْزَةَ بْنِ عَبْدِ الْمُطَّلِبِ وَعَلِيِّ بْنِ أَبِي طَالِبٍ وَعُبَيْدَةَ بْنِ الْحَارِثِ وَعُتْبَةَ بْنِ رَبِيعَةَ وَشَيْبَةَ بْنِ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُتْبَةَ اخْتَصَمُوا فِي الْحُجَجِ يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] dan [Hafsh bin 'Amru], keduanya berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi]; telah menceritakan kepada kami [Muhammad bin Isma'il]; telah memberitakan kepada kami [Waki'], keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Hasyim Ar Rumani] berkata Abu Abdullah yaitu Yahya bin Aswad dari [Abu Mijlaz] dari [Qais bin 'Ubad], ia berkata; \"Aku mendengar [Abu Dzar] membagi harta rampasan perang: lalu ayat ini turun kepada suatu kelompok yang terdiri dari enam orang, di saat perang Badar yang berbunyi: \"Inilah dua orang yang bertikai mengenai Tuhan mereka, maka orang-orang kafir dipakaikan pakaian dari neraka.' Sampai kepada firman-Nya: 'terbakar.' pada Hamzah bin Abdul Muththalib, Ali bin Abu Thalib, 'Ubaidah bin Al Harits, 'Utbah bin Rabiah, Syaibah bin Rabiah Walid bin Utbah. Mereka bertikai dengan menggunakan argumentasi-argumentasi di saat perang Badar.'"},"2791":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو الْعُمَيْسِ وَعِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَبَارَزْتُ رَجُلًا فَقَتَلْتُهُ فَنَفَّلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَبَهُ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Abul 'Umais] dan [Ikrimah bin Ammar] dari [Iyas bin Salamah bin Akwa] dari [Ayahnya], ia berkata; \"Aku bertarung dengan seorang laki-laki lalu aku membunuhnya, kemudian Rasulullah shallallahu 'alaihi wasallam memberikan harta rampasan perangnya kepadaku.\""},"2792":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَّلَهُ سَلَبَ قَتِيلٍ قَتَلَهُ يَوْمَ حُنَيْنٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah]; telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Yahya bin Sa'id] dari ['Umar bin Katsir bin Aflah] dari [Abu Muhammad] maula Abu Qatadah, dari [Abu Qatadah]; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memberikan harta rampasan seseorang yang terbunuh di saat perang Hunain kepada yang membunuhnya.\""},"2793":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ عَنْ نُعَيْمِ بْنِ أَبِي هِنْدٍ عَنْ ابْنِ سَمُرَةَ بْنِ جُنْدَبٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ فَلَهُ السَّلَبُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Mu'awiyah]; telah menceritakan kepada kami [Abu Malik Al Asyja'i] dari [Nu'aim bin Abu Hindin] dari [Ibnu Samurah bin Jundab] dari [Bapaknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membunuh, maka harta rampasan perangnya untuknya.\""},"2794":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَنَا الصَّعْبُ بْنُ جَثَّامَةَ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَهْلِ الدَّارِ مِنْ الْمُشْرِكِينَ يُبَيَّتُونَ فَيُصَابُ النِّسَاءُ وَالصِّبْيَانُ قَالَ هُمْ مِنْهُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] berkata; telah menceritakan kepada kami [Ash Sha'b bin Jatstsamah], ia berkata; Nabi shallallahu 'alaihi wasallam ditanya tentang orang-orang musyrik yang sedang bermalam di rumah mereka lalu (diserang) dan terkena kaum wanita serta anak-anak? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka (wanita dan anak-anak) adalah bagian dari mereka (orang-orang musyrik itu).\""},"2795":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ أَنْبَأَنَا وَكِيعٌ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَغَزَوْنَا مَعَ أَبِي بَكْرٍ هَوَازِنَ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْنَا مَاءً لِبَنِي فَزَارَةَ فَعَرَّسْنَا حَتَّى إِذَا كَانَ عِنْدَ الصُّبْحِ شَنَنَّاهَا عَلَيْهِمْ غَارَةً فَأَتَيْنَا أَهْلَ مَاءٍ فَبَيَّتْنَاهُمْ فَقَتَلْنَاهُمْ تِسْعَةً أَوْ سَبْعَةَ أَبْيَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il]; telah memberitakan kepada kami [Waki'] dari ['Ikrimah bin 'Ammar] dari [Iyas bin Salamah bin Al Akwa'] dari [Ayahnya], ia berkata; \"Kami berperang bersama Abu Bakar melawan suku Hawazin pada masa Rasulullah shallallahu 'alaihi wasallam. Lalu kami mendatangi sumber air milik Bani Fazarah, kemudian kami berhenti sebentar, sehingga ketika waktu pagi tiba, maka kami mengadakan serangan terhadap mereka. Kami mendatangi pemilik mata air lalu kami mengepungnya pada malam hari dan kami bunuh sembilan atau tujuh (penghuni) rumah mereka.\""},"2796":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَنْبَأَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى امْرَأَةً مَقْتُولَةً فِي بَعْضِ الطَّرِيقِ فَنَهَى عَنْ قَتْلِ النِّسَاءِ وَالصِّبْيَانِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim]; telah menceritakan kepada kami ['Utsman bin 'Umar]; telah memberitakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu 'Umar]; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam melihat seorang wanita yang terbunuh di jalan, lalu beliau melarang untuk membunuh kaum wanita dan anak-anak.\""},"2797":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْمُرَقَّعِ بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ حَنْظَلَةَ الْكَاتِبِ قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَرْنَا عَلَى امْرَأَةٍ مَقْتُولَةٍ قَدْ اجْتَمَعَ عَلَيْهَا النَّاسُ فَأَفْرَجُوا لَهُ فَقَالَ مَا كَانَتْ هَذِهِ تُقَاتِلُ فِيمَنْ يُقَاتِلُ ثُمَّ قَالَ لِرَجُلٍ انْطَلِقْ إِلَى خَالِدِ بْنِ الْوَلِيدِ فَقُلْ لَهُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكَ يَقُولُ لَا تَقْتُلَنَّ ذُرِّيَّةً وَلَا عَسِيفًاحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ عَنْ الْمُرَقَّعِ عَنْ جَدِّهِ رَبَاحِ بْنِ الرَّبِيعِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ يُخْطِئُ الثَّوْرِيُّ فِيهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Az Zinad] dari [Al Muraqqi' bin Abdullah bin Shaifi] dari [Hanzhalah] seorang penulis, ia berkata; \"Kami telah berperang bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba kami menjumpai seorang wanita yang terbunuh dan telah dikerumuni masyarakat kemudian mereka memberi jalan untuk beliau. Rasulullah shallallahu 'alaihi wasallam bersabda: 'Wanita ini tidak ikut berperang dengan mereka yang perang.' Lalu Rasulullah bersabda kepada seorang laki-laki: 'Berangkatlah menuju Khalid bin Walid dan katakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkanmu seraya bersabda: 'Janganlah engkau bunuh keturunan-keturunannya dan para buruh kerja (tukang).' Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Abu Az Zinad] dari [Al Muraqqi'] dari [Kakeknya, Rabah bin Ar Rabi'] dari Nabi shallallahu 'alaihi wasallam seperti itu. [Abu Bakar bin Abu Syaibah] berkata; 'Ats Tsauri menyalahkannya.'"},"2798":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ حَدَّثَنَا وَكِيعٌ عَنْ صَالِحِ بْنِ أَبِي الْأَخْضَرِ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَرْيَةٍ يُقَالُ لَهَا أُبْنَى فَقَالَ ائْتِ أُبْنَى صَبَاحًا ثُمَّ حَرِّقْ","id":"Telah menceritakan kepada kami [Muhammad bin Ismail bin Samurah]; telah menceritakan kepada kami [Waki'] dari [Shalih bin Abu Al Akhdlar] dari [Az Zuhri] dari [Urwah bin Az Zubair] dari [Usamah bin Zaid], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke suatu perkampungan disebut dengan 'Abnaa', dan bersabda: 'Datangilah Abnaa di waktu pagi, kemudian bakarlah.'\""},"2799":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً }الْآيَةَ الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah menberitakan kepada kami [Al Laits bin Sa'ad] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam membakar pohon kurma bani Nadlir dan menebasnya, yaitu kawasan Buwairah, kemudian Allah Subhanahu Wa Ta'ala menurunkan ayat: 'Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya (Qs. Al Hasyr 99: 5).'\""},"2800":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَفِيهِ يَقُولُ شَاعِرُهُمْ فَهَانَ عَلَى سَرَاةِ بَنِي لُؤَيٍّحَرِيقٌ بِالْبُوَيْرَةِ مُسْتَطِيرُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id]; telah menceritakan kepada kami ['Uqbah bin Khalid] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam membakar pohon kurma bani Nadlir dan menebasnya. Di dalam hal ini seorang penyair berkata; 'Maka mudah bagi seorang majikan bani Luay membakar kawasan Buwairah sehingga bercerai-berai.'\""},"2801":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَغَزَوْنَا مَعَ أَبِي بَكْرٍ هَوَازِنَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَفَّلَنِي جَارِيَةً مِنْ بَنِي فَزَارَةَ مِنْ أَجْمَلِ الْعَرَبِ عَلَيْهَا قَشْعٌ لَهَا فَمَا كَشَفْتُ لَهَا عَنْ ثَوْبٍ حَتَّى أَتَيْتُ الْمَدِينَةَ فَلَقِيَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السُّوقِ فَقَالَ لِلَّهِ أَبُوكَ هَبْهَا لِي فَوَهَبْتُهَا لَهُ فَبَعَثَ بِهَا فَفَادَى بِهَا أُسَارَى مِنْ أُسَارَى الْمُسْلِمِينَ كَانُوا بِمَكَّةَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Ikrimah bin Ammar] dari [Iyas bin Salamah bin Al Akwa] dari [Ayahnya] ia berkata; \"Kami melakukan penyerangan terhadap Hawazin bersama Abu Bakar pada masa Rasulullah shallallahu 'alaihi wasallam. Beliau shallallahu 'alaihi wasallam memberiku seorang budak perempuan dari bani Fazarah yang termasuk perempuan paling cantik di kalangan Arab, ia mengenakan kain penutup (di atas kepalanya). Aku tidak pernah menyingkap pakaiannya hingga tiba di Madinah, kemudian Nabi shallallahu 'alaihi wasallam menemuiku di pasar dan bersabda: 'Demi Allah, karena ayahmu berikanlah ia untukku.' Maka aku pun memberikannya kepada beliau. Lalu Rasulullah shallallahu 'alaihi wasallam mengirim wanita tersebut dan ia ditebus dengan beberapa tawanan dari tawanan kaum muslimin yang ada di Makkah.\""},"2802":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَذَهَبَتْ فَرَسٌ لَهُ فَأَخَذَهَا الْعَدُوُّ فَظَهَرَ عَلَيْهِمْ الْمُسْلِمُونَ فَرُدَّ عَلَيْهِ فِي زَمَنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَأَبَقَ عَبْدٌ لَهُ فَلَحِقَ بِالرُّومِ فَظَهَرَ عَلَيْهِمْ الْمُسْلِمُونَ فَرَدَّهُ عَلَيْهِ خَالِدُ بْنُ الْوَلِيدِ بَعْدَ وَفَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Seekor kuda miliknya terlepas pada masa Rasulullah shallallahu 'alaihi wasallam lalu diambil oleh seorang musuh kemudian diketahui oleh umat Islam, lalu kuda itu dikembalikan kepadanya. Ibnu Umar berkata; 'Seorang budak miliknya melarikan diri lalu ditemukan di Romawi dan diketahui oleh umat Islam. Kemudian dikembalikan oleh Khalid bin Walid kepadanya setelah Rasulullah shallallahu 'alaihi wasallam wafat.'"},"2803":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَبِي عَمْرَةَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَتُوُفِّيَ رَجُلٌ مِنْ أَشْجَعَ بِخَيْبَرَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا عَلَى صَاحِبِكُمْ فَأَنْكَرَ النَّاسُ ذَلِكَ وَتَغَيَّرَتْ لَهُ وُجُوهُهُمْ فَلَمَّا رَأَى ذَلِكَ قَالَ إِنَّ صَاحِبَكُمْ غَلَّ فِي سَبِيلِ اللَّهِقَالَ زَيْدٌ فَالْتَمَسُوا فِي مَتَاعِهِ فَإِذَا خَرَزَاتٌ مِنْ خَرَزِ يَهُودَ مَا تُسَاوِي دِرْهَمَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Al Laits bin Sa'ad] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Hibban] dari [Abu 'Amrah] dari [Zaid bin Khalid Al Juhani] berkata; \"Telah meninggal dunia seorang pemberani Khaibar.\" Nabi shallallahu 'alaihi wasallam bersabda: 'Shalatilah sahabat kalian! ' namun para sahabat mengabaikannya, dan wajah mereka semuanya berubah. ketika beliau melihat hal itu beliau bersabda: 'Sahabat kalian telah berbuat ghulul (mencuri ghanimah sebelum dibagikan) di jalan Allah.' Zaid berkata; 'Carilah padanya dan ternyata ia telah mencuri manik-manik milik orang Yahudi yang harganya mencapai dua dirham.'"},"2804":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَكَانَ عَلَى ثَقَلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ يُقَالُ لَهُ كِرْكِرَةُ فَمَاتَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ فِي النَّارِ فَذَهَبُوا يَنْظُرُونَ فَوَجَدُوا عَلَيْهِ كِسَاءً أَوْ عَبَاءَةً قَدْ غَلَّهَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Amru bin Dinar] dari [Salim bin Abul Ja'd] dari [Abdullah bin Amru] berkata; \"Ada seseorang yang senantiasa memberatkan Nabi. la bernama Karkarah. Kemudian ia meninggal dunia. Nabi shallallahu 'alaihi wasallam bersabda: 'Ia berada di neraka.' Mereka pun melihat dan ternyata ia membawa selendang yang ia curi.\""},"2805":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ أَبِي سِنَانٍ عِيسَى بْنِ سِنَانٍ عَنْ يَعْلَى بْنِ شَدَّادٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ إِلَى جَنْبِ بَعِيرٍ مِنْ الْمَقَاسِمِ ثُمَّ تَنَاوَلَ شَيْئًا مِنْ الْبَعِيرِ فَأَخَذَ مِنْهُ قَرَدَةً يَعْنِي وَبَرَةً فَجَعَلَ بَيْنَ إِصْبَعَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّ هَذَا مِنْ غَنَائِمِكُمْ أَدُّوا الْخَيْطَ وَالْمِخْيَطَ فَمَا فَوْقَ ذَلِكَ فَمَا دُونَ ذَلِكَ فَإِنَّ الْغُلُولَ عَارٌ عَلَى أَهْلِهِ يَوْمَ الْقِيَامَةِ وَشَنَارٌ وَنَارٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Usamah] dari [Abu Sinan Isa bin Sinan] dari [Ya'la bin Syadad] dari [Ubadah bin Ash Shamit], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat bersama kami pada saat peristiwa perang Hunain, beliau berada di samping unta hasil pembagian harta rampasan perang, kemudian beliau mengambil sesuatu dari unta tersebut dan meletakkannya di antara dua jari beliau, lalu bersabda: 'Wahai manusia! Sesungguhnya ini adalah bagian dari harta rampasan perang kalian, janganlah kalian berlaku curang dalam pembagian harta rampasan perang sekalipun hanya berupa kain, atau yang kurang dari itu, karena sesungguhnya pengkhianatan akan menjadi cela bagi pelakunya pada hari Kiamat kelak, (juga akan menjadi) aib dan api neraka.'"},"2806":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ يَزِيدَ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ مَكْحُولٍ عَنْ زِيَادِ بْنِ جَارِيَةَ عَنْ حَبِيبِ بْنِ مَسْلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَّلَ الثُّلُثَ بَعْدَ الْخُمُسِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Yazid bin Yazid bin Jabir] dari [Makhul] dari [Ziyad bin Jariyah] dari [Habib bin Maslamah], ia berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam memberikan sepertiga (harta rampasan perang) setelah sebelumnya seperlima.\""},"2807":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ الزُّرَقِيِّ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ مَكْحُولٍ عَنْ أَبِي سَلَّامٍ الْأَعْرَجِ عَنْ أَبِي أُمَامَةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَّلَ فِي الْبَدْأَةِ الرُّبُعَ وَفِي الرَّجْعَةِ الثُّلُثَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdurrahman bin Harits Az Zuraqqi] dari [Sulaiman bin Musa] dari [Makhul] dari [Abu Sallam Al A'raj] dari [Abu Umamah] dari [Ubadah bin Ash Shamit] bahwa Nabi shallallahu 'alaihi wasallam menambah bekal (dari ghanimah) ketika berangkat seperempat dan ketika pulang sepertiga.\""},"2808":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو الْحُسَيْنِ أَنْبَأَنَا رَجَاءُ بْنُ أَبِي سَلَمَةَ حَدَّثَنَا عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَلَا نَفَلَ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرُدُّ الْمُسْلِمُونَ قَوِيُّهُمْ عَلَى ضَعِيفِهِمْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Al Husain]; telah memberitakan kepada kami [Raja` bin Abu Salamah]; telah menceritakan kepada kami ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] berkata; \"Tidak ada nafal (tambahan harta rampasan perang) setelah Rasulullah shallallahu 'alaihi wasallam, orang-orang muslim yang kuat mengembalikannya kepada yang lemah.\""},"2809":{"ar":"قَالَ رَجَاءٌ فَسَمِعْتُ سُلَيْمَانَ بْنَ مُوسَى يَقُولُ لَهُ حَدَّثَنِي مَكْحُولٌ عَنْ حَبِيبِ بْنِ مَسْلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَّلَ فِي الْبَدْأَةِ الرُّبُعَ وَحِينَ قَفَلَ الثُّلُثَفَقَالَ عَمْرٌو أُحَدِّثُكَ عَنْ أَبِي عَنْ جَدِّي وَتُحَدِّثُنِي عَنْ مَكْحُولٍ","id":"(Masih dari jalur yang sama dengan periwayatan hadits sebelumnya; dari [Ali] dari [Zaid]), [Raja'] berkata; aku mendengar dari [Sulaiman bin Musa], ia mengatakan kepadanya; telah menceritakan kepadaku [Makhul] dari [Habib bin Maslamah] bahwa Nabi shallallahu 'alaihi wasallam menambah bekal seperempat ketika berangkat dan ketika pulang sepertiga. Amru berkata; Aku menceritakannya kepadamu dari Ayahku dari Kakekku dan engkau menceritakannya kepadaku dari Makhul."},"2810":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْهَمَ يَوْمَ خَيْبَرَ لِلْفَارِسِ ثَلَاثَةَ أَسْهُمٍ لِلْفَرَسِ سَهْمَانِ وَلِلرَّجُلِ سَهْمٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam membagi tiga bagian untuk penunggang kuda di hari Khaibar dan dua bagian untuk pejalan kudanya sedang untuk pejalan kaki satu bagian.\""},"2811":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ زَيْدِ بْنِ مُهَاجِرِ بْنِ قُنْفُذٍ قَالَ سَمِعْتُ عُمَيْرًا مَوْلَى آبِي اللَّحْمِ قَالَ وَكِيعٌ كَانَ لَا يَأْكُلُ اللَّحْمَ قَالَغَزَوْتُ مَعَ مَوْلَايَ يَوْمَ خَيْبَرَ وَأَنَا مَمْلُوكٌ فَلَمْ يَقْسِمْ لِي مِنْ الْغَنِيمَةِ وَأُعْطِيتُ مِنْ خُرْثِيِّ الْمَتَاعِ سَيْفًا وَكُنْتُ أَجُرُّهُ إِذَا تَقَلَّدْتُهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Hisyam bin Sa'ad] dari [Muhammad bin Zaid bin Muhajir bin Qunfudz], ia berkata; Aku mendengar [Umair] -mantan budak- Abu Al Lahm, berkata [Waki']; \"Ia tidak memakan daging.\" Ia berkata; 'Aku berperang bersama tuanku di perang Khaibar sedang aku adalah seorang budak, hingga aku tidak mendapat bagian ghanimah, lalu diberikan kepadaku perhiasan pedang dan aku bawa bila mengikutinya.'"},"2812":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ هِشَامٍ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ الْأَنْصَارِيَّةِ قَالَتْغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ أَخْلُفُهُمْ فِي رِحَالِهِمْ وَأَصْنَعُ لَهُمْ الطَّعَامَ وَأُدَاوِي الْجَرْحَى وَأَقُومُ عَلَى الْمَرْضَى","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Hisyam] dari [Hafshah binti Sirin] dari [Ummu 'Athiyah Al Anshariyah] ia berkata; \"Aku berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh kali, aku berada di belakang, membuatkan makanan, mengobati luka dan merawat yang sakit.\""},"2813":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي عَطِيَّةُ بْنُ الْحَارِثِ أَبُو رُوقٍ الْهَمْدَانِيُّ حَدَّثَنِي أَبُو الْغَرِيفِ عُبَيْدُ اللَّهِ بْنُ خَلِيفَةَ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَقَالَ سِيرُوا بِاسْمِ اللَّهِ وَفِي سَبِيلِ اللَّهِ قَاتِلُوا مَنْ كَفَرَ بِاللَّهِ وَلَا تَمْثُلُوا وَلَا تَغْدِرُوا وَلَا تَغُلُّوا وَلَا تَقْتُلُوا وَلِيدًا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal]; telah menceritakan kepada kami [Abu Usamah]; telah menceritakan kepadaku ['Athiyah bin Al Harits Abu Ruq Al Hamdani]; telah menceritakan kepadaku [Abul Gharif Ubaidullah bin Khalifah] dari [Shafwan bin 'Assal], ia berkata Rasulullah shallallahu 'alaihi wasallam mengutus kami di satu peperangan, beliau bersabda: \"Berjalanlah dengan asma Allah di jalan Allah, perangilah siapa saja yang kafir kepada Allah, jangan mencincang, jangan khianat, jangan mencuri dan jangan membunuh orang jompo.\""},"2814":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ الْفِرْيَابِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَّرَ رَجُلًا عَلَى سَرِيَّةٍ أَوْصَاهُ فِي خَاصَّةِ نَفْسِهِ بِتَقْوَى اللَّهِ وَمَنْ مَعَهُ مِنْ الْمُسْلِمِينَ خَيْرًا فَقَالَ اغْزُوا بِاسْمِ اللَّهِ وَفِي سَبِيلِ اللَّهِ قَاتِلُوا مَنْ كَفَرَ بِاللَّهِ اغْزُوا وَلَا تَغْدِرُوا وَلَا تَغُلُّوا وَلَا تَمْثُلُوا وَلَا تَقْتُلُوا وَلِيدًا وَإِذَا أَنْتَ لَقِيتَ عَدُوَّكَ مِنْ الْمُشْرِكِينَ فَادْعُهُمْ إِلَى إِحْدَى ثَلَاثِ خِلَالٍ أَوْ خِصَالٍ فَأَيَّتُهُنَّ أَجَابُوكَ إِلَيْهَا فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ ادْعُهُمْ إِلَى الْإِسْلَامِ فَإِنْ أَجَابُوكَ فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ ثُمَّ ادْعُهُمْ إِلَى التَّحَوُّلِ مِنْ دَارِهِمْ إِلَى دَارِ الْمُهَاجِرِينَ وَأَخْبِرْهُمْ إِنْ فَعَلُوا ذَلِكَ أَنَّ لَهُمْ مَا لِلْمُهَاجِرِينَ وَأَنَّ عَلَيْهِمْ مَا عَلَى الْمُهَاجِرِينَ وَإِنْ أَبَوْا فَأَخْبِرْهُمْ أَنَّهُمْ يَكُونُونَ كَأَعْرَابِ الْمُسْلِمِينَ يَجْرِي عَلَيْهِمْ حُكْمُ اللَّهِ الَّذِي يَجْرِي عَلَى الْمُؤْمِنِينَ وَلَا يَكُونُ لَهُمْ فِي الْفَيْءِ وَالْغَنِيمَةِ شَيْءٌ إِلَّا أَنْ يُجَاهِدُوا مَعَ الْمُسْلِمِينَ فَإِنْ هُمْ أَبَوْا أَنْ يَدْخُلُوا فِي الْإِسْلَامِ فَسَلْهُمْ إِعْطَاءَ الْجِزْيَةِ فَإِنْ فَعَلُوا فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ فَإِنْ هُمْ أَبَوْا فَاسْتَعِنْ بِاللَّهِ عَلَيْهِمْ وَقَاتِلْهُمْ وَإِنْ حَاصَرْتَ حِصْنًا فَأَرَادُوكَ أَنْ تَجْعَلَ لَهُمْ ذِمَّةَ اللَّهِ وَذِمَّةَ نَبِيِّكَ فَلَا تَجْعَلْ لَهُمْ ذِمَّةَ اللَّهِ وَلَا ذِمَّةَ نَبِيِّكَ وَلَكِنْ اجْعَلْ لَهُمْ ذِمَّتَكَ وَذِمَّةَ أَبِيكَ وَذِمَّةَ أَصْحَابِكَ فَإِنَّكُمْ إِنْ تُخْفِرُوا ذِمَّتَكُمْ وَذِمَّةَ آبَائِكُمْ أَهْوَنُ عَلَيْكُمْ مِنْ أَنْ تُخْفِرُوا ذِمَّةَ اللَّهِ وَذِمَّةَ رَسُولِهِ وَإِنْ حَاصَرْتَ حِصْنًا فَأَرَادُوكَ أَنْ يَنْزِلُوا عَلَى حُكْمِ اللَّهِ فَلَا تُنْزِلْهُمْ عَلَى حُكْمِ اللَّهِ وَلَكِنْ أَنْزِلْهُمْ عَلَى حُكْمِكَ فَإِنَّكَ لَا تَدْرِي أَتُصِيبُ فِيهِمْ حُكْمَ اللَّهِ أَمْ لَاقَالَ عَلْقَمَةُ فَحَدَّثْتُ بِهِ مُقَاتِلَ بْنَ حَيَّانَ فَقَالَ حَدَّثَنِي مُسْلِمُ بْنُ هَيْضَمٍ عَنْ النُّعْمَانِ بْنِ مُقَرِّنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Muhammad bin Yusuf Al Firyabi]; telah menceritakan kepada kami [Sufyan] dari ['Alqamah bin Martsad] dari [Ibnu Buraidah] dari [Ayahnya] berkata; Apabila Rasulullah shallallahu'alaihiwasallam mengangkat komandan pasukan atau mengutus ekspedisi pasukan, secara khusus beliau berwasiat kepada panglima pasukan untuk bertakwa kepada Allah dan beliau berwasiat kepada kaum muslimin yang bersamanya agar menegakkan kebaikan-kebaikan, lantas beliau bersabda: \"Berperanglah dengan nama Allah di jalan Allah, perangilah orang yang kafir terhadap Allah, berperanglah dan janganlah berkhianat, jangan memutilasi dan jangan membunuh anak kecil, bila kau bertemu musuhmu dari kalangan orang-orang musyrik, serulah mereka pada satu dari tiga hal, mana saja diantaranya yang mereka terima maka terimalah dari mereka; serulah mereka menuju Islam, bila mereka menerimamu maka terimalah dari mereka kemudian ajaklah mereka untuk pindah dari tempat mereka ke tempat kaum muhajirin. Beritahukan kepada mereka bila mereka mengerjakannya, bahwa mereka mendapatkan hak dan kewajiban yang sama seperti kaum muhajirin lainnya, bila mereka enggan dan lebih memilih tempat mereka, beritahukan pada mereka bahwa mereka seperti kaum badui kalangan muslimin, mereka berkewajiban melaksanakan hukum Allah yang berlaku bagi kaum mu`minin dan mereka tidak mendapatkan fai` dan ghanimah sama sekali kecuali bila mereka berjihad bersama kaum muslimin, bila mereka enggan maka serulah mereka untuk membayar jizyah, bila mereka menerima maka terimalah dari mereka dan tahanlah dirimu (untuk menyerang mereka), bila mereka enggan maka memintalah pertolongan pada Allah kemudian perangilah mereka. Bila kau mengepung penghuni benteng lalu mereka berkeinginan agar engkau membuat jaminan Allah dan nabi-Nya untuk mereka, jangan kalian lakukan tapi buatlah saja jaminanmu, jaminan ayahmu dan jaminan teman-temanmu untuk mereka, karena bila kalian melanggar jaminanmu dan jaminan ayah-ayahmu itu lebih ringan dari pada kalian melanggar jaminan Allah dan Rasul-Nya, bila kau mengepung penghuni benteng lalu mereka menginginkanmu agar engkau memutuskan hukum Allah atas mereka, jangan kau turuti, tapi berilah mereka keputusan dengan hukummu, karena kau tidak tahu apakah kau sesuai dengan hukum Allah tentang mereka ataukah tidak.\" Berkata ['Alqamah]; lalu aku menceritakana hal itu kepada [Muqatil bin Hayyan] lalu ia berkata; telah menceritakan kepadaku [Muslim bin Haidlam] dari [An Nu'man bin Muqarrin] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa."},"2815":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَطَاعَنِي فَقَدْ أَطَاعَ اللَّهَ وَمَنْ عَصَانِي فَقَدْ عَصَى اللَّهَ وَمَنْ أَطَاعَ الْإِمَامَ فَقَدْ أَطَاعَنِي وَمَنْ عَصَى الْإِمَامَ فَقَدْ عَصَانِي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mentaatiku berarti ia taat kepada Allah, dan siapa yang membangkang kepadaku maka ia telah membangkang pada Allah. Dan barang siapa yang mentaati pemimpin maka ia telah mentaatiku dan siap yang membangkang kepada pemimpin maka ia telah membangkang kepadaku.\""},"2816":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي أَبُو التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمَعُوا وَأَطِيعُوا وَإِنْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ كَأَنَّ رَأْسَهُ زَبِيبَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Abu Bisyr Bakar bin Khalaf], keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id]; telah menceritakan kepada kami [Syu'bah]; telah menceritakan kepadaku [Abu At Tayyah] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dengar dan taatlah walaupun yang memimpin kalian adalah seorang budak hitam yang berambut keribo.\""},"2817":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ شُعْبَةَ عَنْ يَحْيَى بْنِ الْحُصَيْنِ عَنْ جَدَّتِهِ أُمِّ الْحُصَيْنِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنْ أُمِّرَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ مُجَدَّعٌ فَاسْمَعُوا لَهُ وَأَطِيعُوا مَا قَادَكُمْ بِكِتَابِ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki' bin Al Jarah] dari [Syu'bah] dari [Yahya bin Al Hushain] dari [Neneknya Ummu Al Hushain], ia berkata; \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Apabila kalian diperintah oleh seorang hamba sahaya dari golongan Habasy yang cacat, maka dengarkanlah dan taatlah kepadanya, yaitu selama dia memimpin kalian dengan Al Qur`an.\""},"2818":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّأَنَّهُ انْتَهَى إِلَى الرَّبَذَةِ وَقَدْ أُقِيمَتْ الصَّلَاةُ فَإِذَا عَبْدٌ يَؤُمُّهُمْ فَقِيلَ هَذَا أَبُو ذَرٍّ فَذَهَبَ يَتَأَخَّرُ فَقَالَ أَبُو ذَرٍّ أَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَسْمَعَ وَأُطِيعَ وَإِنْ كَانَ عَبْدًا حَبَشِيًّا مُجَدَّعَ الْأَطْرَافِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Abu 'Imaran Al Jauni] dari ['Abdullah bin Ash Shamit] dari [Abu Dzar], sesungguhnya ia telah sampai di kawasan Rabdah, pada saat itu telah dilaksanakan shalat dan yang menjadi imam mereka adalah seorang hamba sahaya, maka dikatakan kepadanya; ini Abu Dzar datang, \"lalu hamba sahaya itu mundur kebelakang. Namun Abu Dzar berkata; kekasihku shallallahu 'alaihi wasallam telah berwasiat kepadaku agar aku mendengarkan dan taat sekalipun pemimpinku adalah seorang hamba sahaya dari Habsy yang cacat anggota tubuhnya.'"},"2819":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ عُمَرَ بْنِ الْحَكَمِ بْنِ ثَوْبَانَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ عَلْقَمَةَ بْنَ مُجَزِّرٍ عَلَى بَعْثٍ وَأَنَا فِيهِمْ فَلَمَّا انْتَهَى إِلَى رَأْسِ غَزَاتِهِ أَوْ كَانَ بِبَعْضِ الطَّرِيقِ اسْتَأْذَنَتْهُ طَائِفَةٌ مِنْ الْجَيْشِ فَأَذِنَ لَهُمْ وَأَمَّرَ عَلَيْهِمْ عَبْدَ اللَّهِ بْنَ حُذَافَةَ بْنِ قَيْسٍ السَّهْمِيَّ فَكُنْتُ فِيمَنْ غَزَا مَعَهُ فَلَمَّا كَانَ بِبَعْضِ الطَّرِيقِ أَوْقَدَ الْقَوْمُ نَارًا لِيَصْطَلُوا أَوْ لِيَصْنَعُوا عَلَيْهَا صَنِيعًا فَقَالَ عَبْدُ اللَّهِ وَكَانَتْ فِيهِ دُعَابَةٌ أَلَيْسَ لِي عَلَيْكُمْ السَّمْعُ وَالطَّاعَةُ قَالُوا بَلَى قَالَ فَمَا أَنَا بِآمِرِكُمْ بِشَيْءٍ إِلَّا صَنَعْتُمُوهُ قَالُوا نَعَمْ قَالَ فَإِنِّي أَعْزِمُ عَلَيْكُمْ إِلَّا تَوَاثَبْتُمْ فِي هَذِهِ النَّارِ فَقَامَ نَاسٌ فَتَحَجَّزُوا فَلَمَّا ظَنَّ أَنَّهُمْ وَاثِبُونَ قَالَ أَمْسِكُوا عَلَى أَنْفُسِكُمْ فَإِنَّمَا كُنْتُ أَمْزَحُ مَعَكُمْ فَلَمَّا قَدِمْنَا ذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَمَرَكُمْ مِنْهُمْ بِمَعْصِيَةِ اللَّهِ فَلَا تُطِيعُوهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Yazid bin Harun]; telah menceritakan kepada kami [Muhammad bin 'Amru] dari ['Umar bin Al Hakam bin Tsauban] dari [Abu Said Al Khudri], sesungguhnya Rasulullah shallallahu 'alaihi wasallam mengutus Alqamah bin Mujazir dalam satu rombongan dan aku di dalamnya. Ketika telah sampai di penghujung perang atau di pertengahan jalan, sekelompok bala tentara meminta izin. Rasulullah memberikan izin kepada mereka, lalu pasukan dipimpin oleh Abdullah Hudzafah bin Qais As-Sahmi. Aku termasuk orang yang ikut berperang bersama dengannya. Setelah sampai di pertengahan jalan, sekelompok kaum menyalakan api untuk menghangatkan tubuh atau untuk membuat sesuatu. Abdullah berkata; -untuk sekedar bercanda-; bukankah kalian harus mendengarkan dan taat kepadaku?\" Mereka berkata; 'Tentu.' la berkata; 'Tidakkah yang aku perintahkan tentang sesuatu kepada kalian, pasti kalian lakukan? ' Mereka menjawab; 'Tentu.' Abdullah berkata; 'Aku ingin kalian meloncati api ini.' Sekelompok orang berdiri dan saling bersiap-siap. Ketika ia mengira bahwa mereka akan melompat, ia berkata; 'Berhentilah kalian, karena sesungguhnya aku hanya bergurau kepada kalian.' Ketika kami tiba dan mengemukakannya kepada Nabi shallallahu 'alaihi wasallam. Beliau shallallahu 'alaihi wasallam bersabda: 'Barangsiapa yang memerintahkan kalian untuk bermaksiat kepada Allah, maka janganlah kalian taat kepadanya.'"},"2820":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَى الْمَرْءِ الْمُسْلِمِ الطَّاعَةُ فِيمَا أَحَبَّ أَوْ كَرِهَ إِلَّا أَنْ يُؤْمَرَ بِمَعْصِيَةٍ فَإِذَا أُمِرَ بِمَعْصِيَةٍ فَلَا سَمْعَ وَلَا طَاعَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Al Laits bin Sa'ad] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar]; demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Muhammad bin Ash Shabbah] dan [Suwaid bin Sa'id], keduanya berkata; telah menceritakan kepada kami [Abdullah bin Raja` Al Makki] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah seorang muslim senantiasa taat, baik yang ia sukai atau ia benci, kecuali apabila diperintahkan untuk berbuat maksiat, maka tidak ada kata mendengar dan taat lagi.\""},"2821":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيَلِي أُمُورَكُمْ بَعْدِي رِجَالٌ يُطْفِئُونَ السُّنَّةَ وَيَعْمَلُونَ بِالْبِدْعَةِ وَيُؤَخِّرُونَ الصَّلَاةَ عَنْ مَوَاقِيتِهَا فَقُلْتُ يَا رَسُولَ اللَّهِ إِنْ أَدْرَكْتُهُمْ كَيْفَ أَفْعَلُ قَالَ تَسْأَلُنِي يَا ابْنَ أُمِّ عَبْدٍ كَيْفَ تَفْعَلُ لَا طَاعَةَ لِمَنْ عَصَى اللَّهَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id]; telah menceritakan kepada kami [Yahya bin Sulaim]; demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Isma'il bin 'Ayyasy], keduanya berkata; telah menceritakan kepada kami ['Abdullah bin 'Utsman bin Khutsaim] dari [Al Qasim bin 'Abdurrahman bin 'Abdullah bin Mas'ud] dari [Ayahnya] dari [Kakeknya], sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Ada sekelompok orang yang memimpin urusan kalian setelahku, yaitu orang-orang yang memadamkan Sunnah Nabi dan melakukan bid'ah serta senantiasa mengakhirkan shalat dari waktunya.\" Aku katakan; 'Wahai Rasulullah! Apabila aku bertemu mereka, apa yang harus aku lakukan? ' Rasulullah bersabda: 'Engkau bertanya kepadaku, apa yang harus engkau lakukan wahai Ibnu Umi Abdu? Tidak ada ketaatan bagi orang yang bermaksiat kepada Allah.'"},"2822":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ وَيَحْيَى بْنُ سَعِيدٍ وَعُبَيْدُ اللَّهِ بْنُ عُمَرَ وَابْنُ عَجْلَانَ عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ أَبِيهِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي الْعُسْرِ وَالْيُسْرِ وَالْمَنْشَطِ وَالْمَكْرَهِ وَالْأَثَرَةِ عَلَيْنَا وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ وَأَنْ نَقُولَ الْحَقَّ حَيْثُمَا كُنَّا لَا نَخَافُ فِي اللَّهِ لَوْمَةَ لَائِمٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abdullah bin Idris] dari [Muhammad bin Ishaq] dan [Yahya bin Sa'id], [Ubaidullah bin Umar] dan [Ibnu 'Ajlan] dari ['Ubadah bin Al Walid bin 'Ubadah bin Ash Shamit] dari [Bapaknya] dari ['Ubadah bin Ash Shamit], ia berkata; \"Kami telah membaiatkan diri kepada Rasulullah untuk mendengar dan patuh pada saat yang sulit dan mudah, di saat semangat atau di saat dibenci serta di saat ada kepentingan kita. Selain itu agar kami tidak menolak perintah dari orang yang layak memerintah dan agar kami mengemukakan kebenaran di mana saja berada. Kami tidak takut kepada cacian para pencaci demi hak-hak Allah.\""},"2823":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ التَّنُوخِيُّ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي مُسْلِمٍ قَالَ حَدَّثَنِي الْحَبِيبُ الْأَمِينُ أَمَّا هُوَ إِلَيَّ فَحَبِيبٌ وَأَمَّا هُوَ عِنْدِي فَأَمِينٌ عَوْفُ بْنُ مَالِكٍ الْأَشْجَعِيُّ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَةً أَوْ ثَمَانِيَةً أَوْ تِسْعَةً فَقَالَ أَلَا تُبَايِعُونَ رَسُولَ اللَّهِ فَبَسَطْنَا أَيْدِيَنَا فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ إِنَّا قَدْ بَايَعْنَاكَ فَعَلَامَ نُبَايِعُكَ فَقَالَ أَنْ تَعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَتُقِيمُوا الصَّلَوَاتِ الْخَمْسَ وَتَسْمَعُوا وَتُطِيعُوا وَأَسَرَّ كَلِمَةً خُفْيَةً وَلَا تَسْأَلُوا النَّاسَ شَيْئًا قَالَ فَلَقَدْ رَأَيْتُ بَعْضَ أُولَئِكَ النَّفَرِ يَسْقُطُ سَوْطُهُ فَلَا يَسْأَلُ أَحَدًا يُنَاوِلُهُ إِيَّاهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Al Walid bin Muslim]; telah menceritakan kepada kami [Sa'id bin Abdul Aziz At Tanukhi] dari [Rabi'ah bin Yazid] dari [Abu Idris Al Khaulani] dari [Abu Muslim] berkata; telah menceritakan kepadaku Al Habib Al Amin dan aku memanggilnya Habib tapi dia jugalah yang terpercaya, yaitu [Auf bin Malik Al Asyja'i], ia berkata; \"Kami berada di sisi Nabi shallallahu 'alaihi wasallam tujuh, delapan atau sembilan orang. la berkata; 'Bukankah kalian ingin berbai'at pada Rasulullah?! ' Kami membentangkan tangan kami. Seseorang berkata; 'Wahai Rasulullah! Sesungguhnya kami telah membaiat dirimu, maka bagaimana cara berbaiat atas dirimu? ' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Hendaklah kalian beribadah kepada Allah dan janganlah mempersekutukan-Nya. Dirikanlah shalat lima waktu dan dengarkan serta taati perintah pemimpinmu -beliau mengemukakannya dengan ucapan yang samar- dan janganlah meminta-minta kepada orang lain.' 'Auf berkata; 'Aku sungguh telah melihat sebagian mereka yang cambuknya terjatuh, maka mereka tidak meminta kepada orang lain untuk mengambilkannya.'"},"2824":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ عَتَّابٍ مَوْلَى هُرْمُزَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فَقَالَ فِيمَا اسْتَطَعْتُمْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Syu'bah] dari ['Attab] mantan budak Hurmuz, ia berkata; Aku mendengar [Anas bin Malik], berkata; \"Kami telah berbai'at terhadap Rasulullah shallallahu 'alaihi wasallam, untuk mendengar dan taat kepadanya. Rasulullah shallallahu 'alaihi wasallam bersabda: 'Pada sesuatu yang kalian mampu.'"},"2825":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَجَاءَ عَبْدٌ فَبَايَعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْهِجْرَةِ وَلَمْ يَشْعُرْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ عَبْدٌ فَجَاءَ سَيِّدُهُ يُرِيزُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعْنِيهِ فَاشْتَرَاهُ بِعَبْدَيْنِ أَسْوَدَيْنِ ثُمَّ لَمْ يُبَايِعْ أَحَدًا بَعْدَ ذَلِكَ حَتَّى يَسْأَلَهُ أَعَبْدٌ هُوَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Al Laits bin Sa'ad] dari [Abu Zubair] dari [Jabir], ia berkata; \"Seorang hamba sahaya datang menemui Nabi shallallahu 'alaihi wasallam dan membaiat dirinya di saat hijrah. Rasulullah tidak merasa bahwa orang tersebut adalah seorang hamba sahaya lalu majikannya tiba dan meminta hamba sahaya tersebut. Rasulullah shallallahu 'alaihi wasallam bersabda: 'Juallah hamba sahaya tersebut kepadaku.' Lalu Rasulullah shallallahu 'alaihi wasallam membelinya dengan dua orang hamba sahaya lainnya yang berkulit hitam. Rasulullah tidak pernah melakukannya lagi kepada siapapun setelah itu, sehingga beliau menanyakan kepadanya apakah dirinya seorang hamba sahaya atau bukan? '"},"2826":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَأَحْمَدُ بْنُ سِنَانٍ قَالُوا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ وَلَا يَنْظُرُ إِلَيْهِمْ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ عَلَى فَضْلِ مَاءٍ بِالْفَلَاةِ يَمْنَعُهُ مِنْ ابْنِ السَّبِيلِ وَرَجُلٌ بَايَعَ رَجُلًا بِسِلْعَةٍ بَعْدَ الْعَصْرِ فَحَلَفَ بِاللَّهِ لَأَخَذَهَا بِكَذَا وَكَذَا فَصَدَّقَهُ وَهُوَ عَلَى غَيْرِ ذَلِكَ وَرَجُلٌ بَايَعَ إِمَامًا لَا يُبَايِعُهُ إِلَّا لِدُنْيَا فَإِنْ أَعْطَاهُ مِنْهَا وَفَى لَهُ وَإِنْ لَمْ يُعْطِهِ مِنْهَا لَمْ يَفِ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] serta [Ahmad bin Sinan], semuanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga orang dimana Allah tidak mau berbicara kepada mereka dan tidak mau melihat mereka di hari kiamat. Mereka tidak dibersihkan dosa-dosanya oleh Allah dan bagi mereka siksa yang amat pedih. Seseorang yang memiliki kelebihan air di padang pasir, tetapi ia tidak mau memberikan kepada Ibnu Sabil, seseorang yang menjual suatu barang setelah Ashar dan ia bersumpah untuk mengambilnya, kemudian ia mempercayainya, padahal kenyataannya tidak demikian. Seseorang yang telah membaiatkan diri kepada seorang pemimpin, tetapi ia tidak membaiatnya, kecuali karena urusan duniawi. Apabila orang tersebut memberikannya, maka ia mematuhinya. Dan apabila ia tidak memberikannya, maka ia tidak mematuhinya.\""},"2827":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ حَسَنِ بْنِ فُرَاتٍ عَنْ أَبِيهِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ كَانَتْ تَسُوسُهُمْ أَنْبِيَاؤُهُمْ كُلَّمَا ذَهَبَ نَبِيٌّ خَلَفَهُ نَبِيٌّ وَأَنَّهُ لَيْسَ كَائِنٌ بَعْدِي نَبِيٌّ فِيكُمْ قَالُوا فَمَا يَكُونُ يَا رَسُولَ اللَّهِ قَالَ تَكُونُ خُلَفَاءُ فَيَكْثُرُوا قَالُوا فَكَيْفَ نَصْنَعُ قَالَ أَوْفُوا بِبَيْعَةِ الْأَوَّلِ فَالْأَوَّلِ أَدُّوا الَّذِي عَلَيْكُمْ فَسَيَسْأَلُهُمْ اللَّهُ عَزَّ وَجَلَّ عَنْ الَّذِي عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abdullah bin Idris] dari [Hasan bin Furat] dari [Ayahnya] dari [Abu Hazim] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang-orang Bani Israil telah dipimpin oleh Nabi-Nabi mereka. Setiap seorang Nabi meninggal dunia, maka pasti ada seorang Nabi yang menggantikannya dan sesungguhnya tidak ada Nabi bagi kalian setelah diriku.\" Mereka bertanya; 'Apa yang akan terjadi wahai Rasulullah? ' Rasulullah menjawab: 'Akan ada banyak pemimpin.' Mereka bertanya lagi; 'Maka, apa yang harus kami perbuat? ' Rasulullah shallallahu 'alaihi wasallam berkata; 'Laksanakan bai'at yang ada, satu persatu, laksanakan sesuatu yang menjadikan kewajiban kalian. Dan Allah akan mempertanyakan sesuatu yang menjadi kewajiban mereka.'"},"2828":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْصَبُ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ فَيُقَالُ هَذِهِ غَدْرَةُ فُلَانٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Abu Al Walid]; telah menceritakan kepada kami [Syu'bah]; demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Al A'masy] dari [Abu Wa`il] dari ['Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ditancapkan pada setiap orang yang melarikan diri dari peperangan berupa bendera di hari kiamat. Dikatakan: ini adalah pengkhianatan si fulan.\""},"2829":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ أَنْبَأَنَا عَلِيُّ بْنُ زَيْدِ بْنِ جُدْعَانَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا إِنَّهُ يُنْصَبُ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ بِقَدْرِ غَدْرَتِهِ","id":"Telah menceritakan kepada kami [Imran bin Musa Al Laitsi]; telah menceritakan kepada kami [Hammad bin Zaid]; telah memberitakan kepada kami ['Ali bin Zaid bin Jud'an] dari [Abu Nadlrah] dari [Abu Said Al Khudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ingatlah, akan ditancapkan bendera di hari kiamat bagi orang yang melarikan diri dari peperangan sesuai dengan pengkhianatannya.\""},"2830":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ أَنَّهُ سَمِعَ مُحَمَّدَ بْنَ الْمُنْكَدِرِ قَالَ سَمِعْتُ أُمَيْمَةَ بِنْتَ رُقَيْقَةَ تَقُولُجِئْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ نُبَايِعُهُ فَقَالَ لَنَا فِيمَا اسْتَطَعْتُنَّ وَأَطَقْتُنَّ إِنِّي لَا أُصَافِحُ النِّسَاءَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] bahwa ia mendengar [Muhammad bin Al Munkadir] berkata; Aku mendengar [Umaimah binti Ruqaiqah], ia berkata; \"Aku bersama beberapa wanita lain menemui Nabi untuk berbai'at.\" Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: 'Apa yang kalian mampu untuk melaksanakannya. Sesungguhnya aku tidak berjabat tangan dengan kaum wanita.'"},"2831":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَتْ الْمُؤْمِنَاتُ إِذَا هَاجَرْنَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُمْتَحَنَّ بِقَوْلِ اللَّهِ{ يَا أَيُّهَا النَّبِيُّ إِذَا جَاءَكَ الْمُؤْمِنَاتُ يُبَايِعْنَكَ }إِلَى آخِرِ الْآيَةِ قَالَتْ عَائِشَةُ فَمَنْ أَقَرَّ بِهَا مِنْ الْمُؤْمِنَاتِ فَقَدْ أَقَرَّ بِالْمِحْنَةِ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقْرَرْنَ بِذَلِكَ مِنْ قَوْلِهِنَّ قَالَ لَهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلِقْنَ فَقَدْ بَايَعْتُكُنَّ لَا وَاللَّهِ مَا مَسَّتْ يَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ امْرَأَةٍ قَطُّ غَيْرَ أَنَّهُ يُبَايِعُهُنَّ بِالْكَلَامِ قَالَتْ عَائِشَةُ وَاللَّهِ مَا أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النِّسَاءِ إِلَّا مَا أَمَرَهُ اللَّهُ وَلَا مَسَّتْ كَفُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَفَّ امْرَأَةٍ قَطُّ وَكَانَ يَقُولُ لَهُنَّ إِذَا أَخَذَ عَلَيْهِنَّ قَدْ بَايَعْتُكُنَّ كَلَامًا","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh Al Mishri]; telah menceritakan kepada kami [Abdullah bin Wahab], ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab]; telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah], isteri Nabi Shallallahu 'Aalihi Wa Sallam, ia berkata; \"Wanita-wanita mukmin apabila mereka melakukan hijrah kepada Rasulullah, maka mereka diuji dengan firman Allah Subhanahu Wa Ta'ala: 'Wahai Nabi apabila wanita-wanita mukmin datang kepadamu melakukan bai'at.'\" Aisyah berkata; 'Barangsiapa yang telah berikrar dari wanita-wanita mukmin tersebut, maka ia telah berikrar dengan ujian tersebut. Apabila Rasulullah shallallahu 'alaihi wasallam telah mendengar mereka berikrar dengan ucapan mereka, maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Bergegaslah pergi aku telah membai'at kalian.' Tidak, demi Allah! Tangan Rasulullah tidak pernah menyentuh tangan wanita manapun sama sekali, sesungguhnya Rasulullah shallallahu 'alaihi wasallam membai'at mereka dengan ucapan.' Aisyah berkata; 'Demi Allah! Rasulullah shallallahu 'alaihi wasallam tidak pernah melakukan apa-apa terhadap kaum wanita kecuali apa yang telah diperintahkan oleh Allah Subhanahu Wa Ta'ala. Telapak tangan Rasulullah shallallahu 'alaihi wasallam tidak pernah menyentuh telapak tangan seorang wanita sama sekali. Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka apabila beliau telah membaiat mereka: 'Aku telah membai'at kalian dengan ucapan.'"},"2832":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْخَلَ فَرَسًا بَيْنَ فَرَسَيْنِ وَهُوَ لَا يَأْمَنُ أَنْ يَسْبِقَ فَلَيْسَ بِقِمَارٍ وَمَنْ أَدْخَلَ فَرَسًا بَيْنَ فَرَسَيْنِ وَهُوَ يَأْمَنُ أَنْ يَسْبِقَ فَهُوَ قِمَارٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Yahya], keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun]; telah memberitakan kepada kami [Sufyan bin Husain] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memasukkan kudanya pada dua kuda lainnya (yang sedang berlomba) sedang dirinya tidak merasa yakin bahwa kudanya akan mendahului maka tidaklah mengapa. Dan barangsiapa memasukkan kudanya pada dua kuda lainnya sedang dirinya merasa yakin bahwa kudanya akan menang maka itu adalah judi.\""},"2833":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَضَمَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلَ فَكَانَ يُرْسِلُ الَّتِي ضُمِّرَتْ مِنْ الْحَفْيَاءِ إِلَى ثَنِيَّةِ الْوَدَاعِ وَالَّتِي لَمْ تُضَمَّرْ مِنْ ثَنِيَّةِ الْوَدَاعِ إِلَى مَسْجِدِ بَنِي زُرَيْقٍ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad]; telah menceritakan kepada kami ['Abdullah bin Numair] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mempersiapkan kuda-kuda (untuk berperang), beliau mengirim kuda yang telah siap dari kawasan Al Hafya (suatu kawasan yang jaraknya beberapa mil dari kota Madinah) menuju bukit Tsaniyatil Wada' dan (untuk kuda) yang belum siap, diberangkatkan dari bukit Tsaniyatil Wada menuju masjid Bani Zuraiq."},"2834":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي الْحَكَمِ مَوْلَى بَنِي لَيْثٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا سَبْقَ إِلَّا فِي خُفٍّ أَوْ حَافِرٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Muhammad bin 'Amru] dari [Abu Al Hakam] -mantan budak Bani Laits dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada perlombaan kecuali perlombaan dengan unta dan kuda.\""},"2835":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ وَأَبُو عُمَرَ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُسَافَرَ بِالْقُرْآنِ إِلَى أَرْضِ الْعَدُوِّ مَخَافَةَ أَنْ يَنَالَهُ الْعَدُوُّ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] dan [Abu 'Umar], keduanya berkata; telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Malik bin Anas] dari [Nafi'] dari [Ibnu 'Umar], ia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang seseorang bepergian membawa Al Qur'an ke kawasan musuh karena khawatir akan diambil oleh musuh.\""},"2836":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَنْهَى أَنْ يُسَافَرَ بِالْقُرْآنِ إِلَى أَرْضِ الْعَدُوِّ مَخَافَةَ أَنْ يَنَالَهُ الْعَدُوُّ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Al Laits bin Sa'ad] dari [Nafi'] dari [Ibnu 'Umar], dari Rasulullah shallallahu 'alaihi wasallam, ia bersabda: \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang seseorang bepergian membawa Al Qur'an menuju kawasan musuh karena khawatir akan diambil oleh musuh.\""},"2837":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا أَيُّوبُ بْنُ سُوَيْدٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ جُبَيْرَ بْنَ مُطْعِمٍ أَخْبَرَهُأَنَّهُ جَاءَ هُوَ وَعُثْمَانُ بْنُ عَفَّانَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَلِّمَانِهِ فِيمَا قَسَمَ مِنْ خُمُسِ خَيْبَرَ لِبَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِ فَقَالَا قَسَمْتَ لِإِخْوَانِنَا بَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِ وَقَرَابَتُنَا وَاحِدَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا أَرَى بَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِ شَيْئًا وَاحِدًا","id":"Telah menceritakan kepada kami [Yunus bin Abdul `A'la]; telah menceritakan kepada kami [Ayyub bin Suwaid] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] bahwa [Jubair bin Muth'im] mengabarinya, sesungguhnya ia dan 'Utsman bin Affan datang menemui Rasulullah shallallahu 'alaihi wasallam di mana keduanya berbicara tentang pembagian seperlima dari harta rampasan perang Khaibar kepada Bani Hasyim dan Bani Al Muththalib, keduanya berkata; \"Engkau telah memberi bagian kepada saudara-saudara kami dari Bani Hasyim dan Bani Muththalib sedangkan kami masih satu kerabat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya aku melihat Bani Hasyim dan Bani Muththalib sebagai satu kesatuan.'"},"2838":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَأَبُو مُصْعَبٍ الزُّهْرِيُّ وَسُوَيْدُ بْنُ سَعِيدٍ قَالُوا حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّفَرُ قِطْعَةٌ مِنْ الْعَذَابِ يَمْنَعُ أَحَدَكُمْ نَوْمَهُ وَطَعَامَهُ وَشَرَابَهُ فَإِذَا قَضَى أَحَدُكُمْ نَهْمَتَهُ مِنْ سَفَرِهِ فَلْيُعَجِّلْ الرُّجُوعَ إِلَى أَهْلِهِحَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], [Abu Mush'ab Az Zuhri] dan [Suwaid bin Sa'id], semuanya berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Sumay] maula Abu Bakar bin Abdurrahman dari [Abu Shalih As Samman] dari [Abu Hurairah] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Berpergian jauh (safar) itu bagian dari adzab yang dapat menghalangi seseorang dari kalian dari tidur, makan dan minum. Maka, jika salah seorang kalian telah menyelesaikan tujuan perjalanannya, hendaklah ia lekas kembali kepada keluarganya.\" Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib]; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa."},"2839":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ أَبُو إِسْرَائِيلَ عَنْ فُضَيْلِ بْنِ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ الْفَضْلِ أَوْ أَحَدِهِمَا عَنْ الْآخَرِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَرَادَ الْحَجَّ فَلْيَتَعَجَّلْ فَإِنَّهُ قَدْ يَمْرَضُ الْمَرِيضُ وَتَضِلُّ الضَّالَّةُ وَتَعْرِضُ الْحَاجَةُ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad] dan ['Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Isma'il Abu Isra'il] dari [Fudlail bin 'Amru] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu, dari [Al Fadl] (atau salah seorang dari keduanya) meriwayatkan dari yang lainnya, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barang siapa yang ingin melaksanakan haji, hendaknya ia segera mengerjakannya. Karena mungkin akan terserang penyakit, tersesat atau terkukung kebutuhan.\""},"2840":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا مَنْصُورُ بْنُ وَرْدَانَ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ الْأَعْلَى عَنْ أَبِيهِ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ عَلِيٍّ قَالَلَمَّا نَزَلَتْ{ وَلِلَّهِ عَلَى النَّاسِ حِجُّ الْبَيْتِ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا }قَالُوا يَا رَسُولَ اللَّهِ الْحَجُّ فِي كُلِّ عَامٍ فَسَكَتَ ثُمَّ قَالُوا أَفِي كُلِّ عَامٍ فَقَالَ لَا وَلَوْ قُلْتُ نَعَمْ لَوَجَبَتْ فَنَزَلَتْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] dan ['Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Manshur bin Wardan]; telah menceritakan kepada kami ['Ali bin Abdul A'la] dari [Ayahnya] dari [Abu Al Bakhtari] dari ['Ali] berkata; \"Tatkala turun ayat: mengerjakan haji adalah kewajiban manusia terhadap Allah, yaitu (bagi) orang yang sanggup mengadakan perjalanan ke Baitullah para sahabat bertanya; 'Wahai Rasulullah, haji di setiap tahun? '\" Beliau diam saja. Kemudian mereka bertanya kembali; 'Apakah di setiap tahun? ' Beliau menjawab: 'Tidak, jika aku katakan: ya, pasti akan menjadi wajib setiap tahun.' Maka turunlah ayat Hai orang-orang yang beriman, janganlah kamu menanyakan (kepada Nabimu) hal-hal yang jika diterangkan kepadamu, niscaya menyusahkan kamu.\""},"2841":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُبَيْدَةَ عَنْ أَبِيهِ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالُوا يَا رَسُولَ اللَّهِ الْحَجُّ فِي كُلِّ عَامٍ قَالَ لَوْ قُلْتُ نَعَمْ لَوَجَبَتْ وَلَوْ وَجَبَتْ لَمْ تَقُومُوا بِهَا وَلَوْ لَمْ تَقُومُوا بِهَا عُذِّبْتُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Muhammad bin Abu 'Ubaidah] dari [Ayahnya] dari [Al A'masy] dari [Abu Sufyan] dari [Anas bin Malik] radliallahu 'anhu, ia berkata; \"Para sahabat bertanya; 'Wahai Rasulullah, apakah haji wajib dilaksanakan setiap tahun? ' Beliau menjawab: 'Andai aku jawab: 'Ya' niscaya (akan dianggap) wajib (untuk dilaksanakan) setiap tahun, dan andai memang wajib untuk dikerjakan setiap tahun, tentu kalian tidak akan sanggup melaksanakannya. (Dan jika kalian tidak melaksanakannya) maka kalian tentu akan diadzab'.\""},"2842":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سِنَانٍ عَنْ ابْنِ عَبَّاسٍأَنَّ الْأَقْرَعَ بْنَ حَابِسٍ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ الْحَجُّ فِي كُلِّ سَنَةٍ أَوْ مَرَّةً وَاحِدَةً قَالَ بَلْ مَرَّةً وَاحِدَةً فَمَنْ اسْتَطَاعَ فَتَطَوَّعَ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi]; telah menceritakan kepada kami [Yazid bin Harun]; telah memberitakan kepada kami [Sufyan bin Husain] dari [Az Zuhri] dari [Abu Sinan] dari [Ibnu Abbas] radliallahu 'anhu. Bahwa Al Aqra' bin Habis bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Wahai Rasulullah, (apakah) haji itu wajib dilaksanakan setiap tahun atau sekali saja seumur hidup?\" Rasulullah menjawab: 'Haji itu wajib hanya sekali. Maka barang siapa mampu, maka hendaknya melaksanakan haji yang sunnah.'"},"2843":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرٍ عَنْ أَبِيهِ عَنْ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَابِعُوا بَيْنَ الْحَجِّ وَالْعُمْرَةِ فَإِنَّ الْمُتَابَعَةَ بَيْنَهُمَا تَنْفِي الْفَقْرَ وَالذُّنُوبَ كَمَا يَنْفِي الْكِيرُ خَبَثَ الْحَدِيدِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ashim bin 'Ubaidillah] dari ['Abdullah bin 'Amir] dari [Ayahnya] dari [Umar] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sertakanlah haji dan umrah, karena menyertakan keduanya dapat menghilangkan kefakiran dan dosa, sebagaimana kir (elasan) menghilangkan karat besi.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Muhammad bin Bisyr]; telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari ['Ashim bin 'Ubaidillah] dari ['Abdullah bin 'Amir bin Rabi'ah] dari [Ayahnya] dari ['Umar bin Al Khaththab] dari Nabi shallallahu 'alaihi wasallam seperti itu."},"2844":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَةُ إِلَى الْعُمْرَةِ كَفَّارَةُ مَا بَيْنَهُمَا وَالْحَجُّ الْمَبْرُورُ لَيْسَ لَهُ جَزَاءٌ إِلَّا الْجَنَّةُ","id":"Telah menceritakan kepada kami [Abu Mush'ab]; telah menceritakan kepada kami [Malik bin Anas] dari [Sumay] -mantan budak- Abu Bakar bin Abdurrahmandari [Abu Shalih As Samman] dari [Abu Hurairah] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Antara sebuah umrah hingga umrah berikutnya dapat menjadi kafarat (penghapus dosa) diantara keduanya. Dan Haji yang mabrur tidaklah dibalas kecuali dengan surga.\""},"2845":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ وَسُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَجَّ هَذَا الْبَيْتَ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَمَا وَلَدَتْهُ أُمُّهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki'] dari [Mis'ar] dan [Sufyan] dari [Manshur] dari [Abu Hazim] dari [Abu Hurairah] radliallahu 'anhu berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa mengerjakan haji ke Baitullah, dan (dalam melaksanakannya) ia tidak berbuat rafast (jima, dan berkata kotor) serta kefasikan, jika ia kembali maka seperti baru dilahirkan oleh ibunya.\""},"2846":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الرَّبِيعِ بْنِ صَبِيحٍ عَنْ يَزِيدَ بْنِ أَبَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَحَجَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَحْلٍ رَثٍّ وَقَطِيفَةٍ تُسَاوِي أَرْبَعَةَ دَرَاهِمَ أَوْ لَا تُسَاوِي ثُمَّ قَالَ اللَّهُمَّ حَجَّةٌ لَا رِيَاءَ فِيهَا وَلَا سُمْعَةَ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad]; telah menceritakan kepada kami [Waki'] dari [Ar Rabi' bin Shabih] dari [Yazid bin Aban] dari [Anas bin Malik] radliallahu 'anhu, ia berkata; \"Nabi shallallahu 'alaihi wasallam menunaikan haji dengan mengendarai unta dan mengenakan beludru seharga empat dirham atau dibawah nilai tersebut, lalu beliau bersabda: 'Ya Allah, (jadikanlah haji ini) haji yang suci, tanpa riya dan mencari kemasyhuran.'\""},"2847":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَمَرَرْنَا بِوَادٍ فَقَالَ أَيُّ وَادٍ هَذَا قَالُوا وَادِي الْأَزْرَقِ قَالَ كَأَنِّي أَنْظُرُ إِلَى مُوسَى صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِنْ طُولِ شَعَرِهِ شَيْئًا لَا يَحْفَظُهُ دَاوُدُ وَاضِعًا إِصْبَعَيْهِ فِي أُذُنَيْهِ لَهُ جُؤَارٌ إِلَى اللَّهِ بِالتَّلْبِيَةِ مَارًّا بِهَذَا الْوَادِي قَالَ ثُمَّ سِرْنَا حَتَّى أَتَيْنَا عَلَى ثَنِيَّةٍ فَقَالَ أَيُّ ثَنِيَّةٍ هَذِهِ قَالُوا ثَنِيَّةُ هَرْشَى أَوْ لَفْتٍ قَالَ كَأَنِّي أَنْظُرُ إِلَى يُونُسَ عَلَى نَاقَةٍ حَمْرَاءَ عَلَيْهِ جُبَّةُ صُوفٍ وَخِطَامُ نَاقَتِهِ خُلْبَةٌ مَارًّا بِهَذَا الْوَادِي مُلَبِّيًا","id":"Telah menceritakan kepada kami [Abu Bisyr Bakar bin Khalaf]; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Dawud bin Abu Hindin] dari [Abu Al 'Aliyah] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam saat berada di antara Makkah dan Madinah. Lalu kami melintasi sebuah lembah, dan beliau bertanya: 'Lembah apakah ini? ' Para sahabat menjawab; 'Lembah Al Azraq.' Lalu beliau bersabda: 'Seakan-akan aku melihat Nabi Musa 'Alaihis Salam (beliau lalu menyebutkan tentang panjangnya rambut Nabi Musa 'Alaihis Salam, namun Daud tidak menghapalnya) yang sedang meletakan dua jari ditelinganya dan mengeraskan suaranya meminta pertolongan kepada Allah dengan talbiyah sambil melintasi lembah itu'.\" Ibnu Abbas radliallahu 'anhu berkata; 'Kemudian kami meneruskan perjalanan hingga kami tiba di sebuah bukit, lalu beliau bertanya: 'Bukit apakah ini? ' Para sahabat menjawab; 'Bukit Harsya atau Bukit Laft.' Lantas beliau bersabda: 'Seakan-akan aku melihat Nabi Yunus 'Alaihis Salam sedang mengendarai unta merah, mengenakan jubah wol (domba), dengan tali kekang untanya terbuat dari serat, ia tengah melintasi lembah ini sambil bertalbiyah.'"},"2848":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ بْنِ صَالِحٍ مَوْلَى بَنِي عَامِرٍ حَدَّثَنِي يَعْقُوبُ بْنُ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْحُجَّاجُ وَالْعُمَّارُ وَفْدُ اللَّهِ إِنْ دَعَوْهُ أَجَابَهُمْ وَإِنْ اسْتَغْفَرُوهُ غَفَرَ لَهُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami]; telah menceritakan kepada kami [Shalih bin 'Abdullah bin Shalih] mantan budak Bani 'Amir; telah menceritakan kepadaku [Ya'qub bin Yahya bin 'Abbad bin 'Abdulllah bin Az Zubair] dari [Abu Shalih As Samman] dari [Abu Hurairah], dari Rasulullah shallallahu 'alaihi wasallam, sesungguhnya beliau bersabda: \"Orang-orang yang haji dan orang-orang yang pergi 'Umrah adalah utusan Allah, jika mereka berdo'a kepada-Nya, niscaya Ia akan mengabulkan mereka, dan jika mereka meminta ampun, niscaya Ia akan mengampuni mereka.\""},"2849":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ حَدَّثَنَا عِمْرَانُ بْنُ عُيَيْنَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْغَازِي فِي سَبِيلِ اللَّهِ وَالْحَاجُّ وَالْمُعْتَمِرُ وَفْدُ اللَّهِ دَعَاهُمْ فَأَجَابُوهُ وَسَأَلُوهُ فَأَعْطَاهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Tharif]; telah menceritakan kepada kami ['Imran bin 'Uyainah] dari ['Atha` bin As Sa'ib] dari [Mujahid] dari [Ibnu 'Umar] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang berperang di jalan Allah, orang yang mengerjakan ibadah haji dan umrah adalah para delegasi Allah. Allah memanggil mereka dan mereka menjawab panggilan-Nya. Mereka meminta kepada Allah, maka Dia memberikan permintaan mereka.\""},"2850":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَأَنَّهُ اسْتَأْذَنَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْعُمْرَةِ فَأَذِنَ لَهُ وَقَالَ لَهُ يَا أُخَيَّ أَشْرِكْنَا فِي شَيْءٍ مِنْ دُعَائِكَ وَلَا تَنْسَنَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari ['Ashim bin 'Ubaidillah] dari [Salim] dari [Ibnu 'Umar] dari ['Umar] bahwa ia bermohon izin kepada Nabi shallallahu 'alaihi wasallam untuk umrah, lalu beliau mengizinkannya dan bersabda: \"Wahai saudaraku, sertakan kami dalam do'amu dan janganlah melupakan kami! \""},"2851":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ قَالَوَكَانَتْ تَحْتَهُ ابْنَةُ أَبِي الدَّرْدَاءِ فَأَتَاهَا فَوَجَدَ أُمَّ الدَّرْدَاءِ وَلَمْ يَجِدْ أَبَا الدَّرْدَاءِ فَقَالَتْ لَهُ تُرِيدُ الْحَجَّ الْعَامَ قَالَ نَعَمْ قَالَتْ فَادْعُ اللَّهَ لَنَا بِخَيْرٍ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ دَعْوَةُ الْمَرْءِ مُسْتَجَابَةٌ لِأَخِيهِ بِظَهْرِ الْغَيْبِ عِنْدَ رَأْسِهِ مَلَكٌ يُؤَمِّنُ عَلَى دُعَائِهِ كُلَّمَا دَعَا لَهُ بِخَيْرٍ قَالَ آمِينَ وَلَكَ بِمِثْلِهِ قَالَ ثُمَّ خَرَجْتُ إِلَى السُّوقِ فَلَقِيتُ أَبَا الدَّرْدَاءِ فَحَدَّثَنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Yazid bin Harun] dari [Abdul Malik bin Abu Sulaiman] dari [Abu Az Zubair] dari [Shafwan bin Abdullah bin Shafwan] -suami dari putri Abu Darda-, ia berkata; \"Suatu ketika ia mendatanginya, namun ia hanya mendapati [Ummu Darda'] dan tidak mendapati Abu Darda'. Ummu Darda pun berkata; 'Apakah kamu mau berangkat haji tahun ini? ' Shafwan menjawab; 'Ya' lalu Ummu Darda berkata; 'Doakan kebaikan untuk kami, karena Nabi shallallahu 'alaihi wasallam bersabda: 'Doa seseorang untuk saudaranya yang sedang tidak bersamanya adalah mustajab (terkabul). Karena di atas kepalanya terdapat malaikat yang akan mengamini doanya setiap kali ia berdoa untuk kebaikan saudaranya. Malaikat itu akan berucap: 'Amin, dan untukmu kebaikan yang serupa'. Shafwan berkata; 'Kemudian aku pergi ke pasar, dan di sana aku bertemu dengan [Abu Darda], ia lantas membacakan hadits Nabi shallallahu 'alaihi wasallam yang sama kepadaku'."},"2852":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يَزِيدَ الْمَكِّيُّ عَنْ مُحَمَّدِ بْنِ عَبَّادِ بْنِ جَعْفَرٍ الْمَخْزُومِيِّ عَنْ ابْنِ عُمَرَ قَالَقَامَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا يُوجِبُ الْحَجَّ قَالَ الزَّادُ وَالرَّاحِلَةُ قَالَ يَا رَسُولَ اللَّهِ فَمَا الْحَاجُّ قَالَ الشَّعِثُ التَّفِلُ وَقَامَ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْحَجُّ قَالَ الْعَجُّ وَالثَّجُّقَالَ وَكِيعٌ يَعْنِي بِالْعَجِّ الْعَجِيجَ بِالتَّلْبِيَةِ وَالثَّجُّ نَحْرُ الْبُدْنِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Marwan bin Mu'awiyah]; Demikian juga telah menceritakan dari jalur yang lainnya, dan telah menceritakan kepada kami ['Ali bin Muhammad] dan ['Amru bin 'Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Ibrahim bin Yazid Al Makki] dari [Muhammad bin 'Abbad bin Ja'far Al Makhzumi] dari [Ibnu 'Umar], ia berkata; \"Seseorang berdiri di hadapan Nabi shallallahu 'alaihi wasallam dan berkata; 'Wahai Rasulullah, apa yang mewajibkan haji? ' Beliau menjawab: 'Bekal dan kendaraan.' Dia berkata; 'Wahai Rasulullah, bagaimana orang yang haji itu? ' Beliau menjawab: 'Orang yang rambutnya kusut dan berbau apek.' Yang lain bangun dan bertanya; 'Wahai Rasulullah, apakah haji itu? ' Beliau menjawab: 'Berteriak dan mengalirkan.' Waki' berkata; 'Yang dimaksud dengan berteriak adalah berteriak dengan talbiyah dan mengalirkan adalah berkurban unta.'"},"2853":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا هِشَامُ بْنُ سُلَيْمَانَ الْقُرَشِيُّ عَنْ ابْنِ جُرَيْجٍ قَالَ وَأَخْبَرَنِيهِ أَيْضًا عَنْ ابْنِ عَطَاءٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الزَّادُ وَالرَّاحِلَةُ يَعْنِي قَوْلَهُ{ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا }","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id]; telah menceritakan kepada kami [Hisyam bin Sulaiman Al Qurasyi] dari [Ibnu Juraij] berkata; keduanya mengabariku juga dari [Atha`] dari ['Ikrimah] dari [Ibnu 'Abbas]; sesungguhnya Rasulullah bersabda: \"Bekal dan kendaraan adalah maksud dari firman-Nya yaitu bagi orang yang sanggup mengadakan perjalanan ke Baitullah.\""},"2854":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُسَافِرُ الْمَرْأَةُ سَفَرًا ثَلَاثَةَ أَيَّامٍ فَصَاعِدًا إِلَّا مَعَ أَبِيهَا أَوْ أَخِيهَا أَوْ ابْنِهَا أَوْ زَوْجِهَا أَوْ ذِي مَحْرَمٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah wanita berpergian dalam perjalanan tiga hari atau lebih kecuali bersama bapaknya, atau saudaranya, atau anak laki-lakinya, atau suaminya atau mahramnya.\""},"2855":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُسَافِرَ مَسِيرَةَ يَوْمٍ وَاحِدٍ لَيْسَ لَهَا ذُو حُرْمَةٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Syababah] dari [Ibnu Abi Dzi`b] dari [Sa'id Al Maqburi] dari [Abu Hurairah] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak dibolehkan bagi seorang wanita yang beriman kepada Allah dan hari Akhirat untuk berpergian dalam perjalanan sehari tanpa disertai mahramnya.\""},"2856":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي عَمْرُو بْنُ دِينَارٍ أَنَّهُ سَمِعَ أَبَا مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي اكْتُتِبْتُ فِي غَزْوَةِ كَذَا وَكَذَا وَامْرَأَتِي حَاجَّةٌ قَالَ فَارْجِعْ مَعَهَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Syu'aib bin Ishaq]; telah menceritakan kepada kami [Ibnu Juraij]; telah menceritakan kepadaku ['Amru bin Dinar] bahwa ia mendengar [Abu Ma'bad] -mantan budak- Ibnu Abbas dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Seorang Arab Badui datang menemui Nabi shallallahu 'alaihi wasallam lantas berkata; 'Aku telah ditugaskan dalam sebuah peperangan ini dan itu, sedangkan (saat itu) istriku tengah punya hajat (yang harus dipenuhi).' Maka beliau shallallahu 'alaihi wasallam bersabda: 'Kembalilah kamu bersamanya'.\""},"2857":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ عَائِشَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ عَلَى النِّسَاءِ جِهَادٌ قَالَ نَعَمْ عَلَيْهِنَّ جِهَادٌ لَا قِتَالَ فِيهِ الْحَجُّ وَالْعُمْرَةُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Habib bin Abi Amrah] dari [Aisyah binti Thalhah] dari [Aisyah] radliallahu 'anha, ia berkata; \"Aku berkata; 'Wahai Rasulullah, apakah jihad juga wajib bagi wanita? ' Beliau menjawab: 'Ya. Bagi kaum wanita mempunyai kewajiban berjihad tanpa berperang, yaitu (jihad) haji dan umrah'.\""},"2858":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ الْقَاسِمِ بْنِ الْفَضْلِ الْحُدَّانِيِّ عَنْ أَبِي جَعْفَرٍ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَجُّ جِهَادُ كُلِّ ضَعِيفٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki'] dari [Al Qasim bin Fadlal Al Huddani] dari [Abu Ja'far] dari [Ummu Salamah] radliallahu 'anha, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Haji adalah jihad bagi setiap orang yang lemah'.\""},"2859":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ رَجُلًا يَقُولُ لَبَّيْكَ عَنْ شُبْرُمَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شُبْرُمَةُ قَالَ قَرِيبٌ لِي قَالَ هَلْ حَجَجْتَ قَطُّ قَالَ لَا قَالَ فَاجْعَلْ هَذِهِ عَنْ نَفْسِكَ ثُمَّ حُجَّ عَنْ شُبْرُمَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Sa'id] dari [Qatadah] dari ['Azrah] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam mendengar seorang lelaki mengucapkan; 'Labbaika 'an Syubrumah' (Aku memenuhi pangilan-Mu Ya Allah untuk Syubrumah). Maka Rasulullah bertanya: 'Siapakah Syubrumah itu? ' Lelaki itu menjawab; 'Ia adalah salah seorang kerabatku.' Lalu beliau Rasulullah shallallahu 'alaihi wasallam bertanya lagi; 'Apakah kamu pernah mengerjakan haji? ' Ia menjawab; 'Belum.' Lantas beliau shallallahu 'alaihi wasallam bersabda: 'Jadikanlah haji ini untuk dirimu, lalu (pada haji berikutnya) berhajilah untuk Syubrumah.'\""},"2860":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ سُلَيْمَانَ الشَّيْبَانِيِّ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحُجُّ عَنْ أَبِي قَالَ نَعَمْ حُجَّ عَنْ أَبِيكَ فَإِنْ لَمْ تَزِدْهُ خَيْرًا لَمْ تَزِدْهُ شَرًّا","id":"Telah menceritakan kepada kami [Muhammad bin Abdul `A'la Ash Shan'ani]; telah menceritakan kepada kami [Abdurrazzak]; telah memberitakan kepada kami [Sufyan Ats Tsauri] dari [Sulaiman Asy Syaibani] dari [Yazid bin Al Asham] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Seorang lelaki mendatangi Nabi shallallahu 'alaihi wasallam seraya bertanya; 'Apakah aku boleh menghajikan bapakku? ' Beliau menjawab: 'Ya, berhajilah untuk bapakmu. Karena jika kamu tidak menambahkannya kebaikan, maka kamu juga tidak menambahkannya dengan keburukan.'\""},"2861":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عُثْمَانُ بْنُ عَطَاءٍ عَنْ أَبِيهِ عَنْ أَبِي الْغَوْثِ بْنِ حُصَيْنٍ رَجُلٌ مِنْ الْفُرْعِأَنَّهُ اسْتَفْتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ حَجَّةٍ كَانَتْ عَلَى أَبِيهِ مَاتَ وَلَمْ يَحُجَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُجَّ عَنْ أَبِيكَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَلِكَ الصِّيَامُ فِي النَّذْرِ يُقْضَى عَنْهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Al Walid bin Muslim]; telah menceritakan kepada kami ['Utsman bin Atha`] dari [Ayahnya] dari [Abu Al Ghauts bin Hushain], seorang lelaki dari Fura', sesungguhnya ia meminta fatwa kepada Nabi shallallahu 'alaihi wasallam tentang haji atas bapaknya yang mati sebelum melaksanakan haji. Nabi bersabda: \"Hajilah menggantikan bapakmu.\" Dan beliau bersabda pula: 'Begitu pula puasa nadzar. Dibayarkan untuknya.'"},"2862":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ النُّعْمَانِ بْنِ سَالِمٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ أَبِي رَزِينٍ الْعُقَيْلِيِّأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أَبِي شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ الْحَجَّ وَلَا الْعُمْرَةَ وَلَا الظَّعْنَ قَالَ حُجَّ عَنْ أَبِيكَ وَاعْتَمِرْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [An Nu'man bin Salim] dari [Amru bin Aus] dari [Abu Razin Al 'Uqaili], bahwa ia pernah mendatangi Rasulullah shallallahu 'alaihi wasallam lalu berkata; \"Wahai Rasulullah, sesungguhnya bapakku sudah tua renta, ia sudah tidak mampu melaksanakan haji, umrah maupun berpergian.\" Beliau shallallahu 'alaihi wasallam bersabda: 'Kerjakan haji untuk bapakmu, dan berumrahlah kamu.'"},"2863":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ الدَّرَاوَرْدِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ عَيَّاشِ بْنِ أَبِي رَبِيعَةَ الْمَخْزُومِيِّ عَنْ حَكِيمِ بْنِ حَكِيمِ بْنِ عَبَّادِ بْنِ حُنَيْفٍ الْأَنْصَارِيِّ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ امْرَأَةً مِنْ خَثْعَمٍ جَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبِي شَيْخٌ كَبِيرٌ قَدْ أَفْنَدَ وَأَدْرَكَتْهُ فَرِيضَةُ اللَّهِ عَلَى عِبَادِهِ فِي الْحَجِّ وَلَا يَسْتَطِيعُ أَدَاءَهَا فَهَلْ يُجْزِئُ عَنْهُ أَنْ أُؤَدِّيَهَا عَنْهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin 'Utsman Al 'Utsmani]; telah menceritakan kepada kami ['Abdul Aziz Ad Darawardi] dari [Abdurrahman bin Harits bin 'Ayyasy bin Abu Rabi'ah Al Makhzumi] dari [Hakim bin Hakim bin Abbad bin Hunaif Al Anshari] dari [Nafi' bin Jubair] dari [Abdullah bin Abbas] radliallahu 'anhu, bahwa seorang wanita dari kalangan kaum Khats'am datang menemui Nabi seraya berkata; \"Wahai Rasulullah, sesungguhnya bapakku seorang tua renta yang sudah pikun dan sudah terkena kewajiban Allah atas hamba-hamba-Nya untuk melaksanakan haji, tapi ia tidak mampu melaksanakannya. Apakah aku boleh mengerjakan kewajibannya itu?\" Rasulullah shallallahu 'alaihi wasallam menjawab: 'Ya (boleh).'"},"2864":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ حَدَّثَنَا مُحَمَّدُ بْنُ كُرَيْبٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ أَخْبَرَنِي حُصَيْنُ بْنُ عَوْفٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبِي أَدْرَكَهُ الْحَجُّ وَلَا يَسْتَطِيعُ أَنْ يَحُجَّ إِلَّا مُعْتَرِضًا فَصَمَتَ سَاعَةً ثُمَّ قَالَ حُجَّ عَنْ أَبِيكَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair]; telah menceritakan kepada kami [Abu Khalid Al Ahmar]; telah menceritakan kepada kami [Muhammad bin Kuraib] dari [Ayahnya] dari [Ibnu 'Abbas], ia berkata; telah mengabarkan kepadaku [Husain bin 'Auf], ia berkata; aku berkata; \"Wahai Rasulullah, sesungguhnya ayahku menemui kewajiban haji. Ia tidak bisa haji kecuali dalam keadaan terbaring.\" Beliau diam sejenak, kemudian bersabda: 'Hajikanlah untuk ayahmu.'"},"2865":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أَخِيهِ الْفَضْلِأَنَّهُ كَانَ رِدْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَاةَ النَّحْرِ فَأَتَتْهُ امْرَأَةٌ مِنْ خَثْعَمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ فِي الْحَجِّ عَلَى عِبَادِهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَرْكَبَ أَفَأَحُجُّ عَنْهُ قَالَ نَعَمْ فَإِنَّهُ لَوْ كَانَ عَلَى أَبِيكِ دَيْنٌ قَضَيْتِهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi]; telah menceritakan kepada kami [Walid bin Muslim]; telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Sulaiman bin Yasar] dari [Ibnu Abbas] dari saudaranya [Al Fadl], bahwa ia pernah berada di belakang Rasulullah shallallahu 'alaihi wasallam saat pagi hari 'Ied Adha. Maka datanglah seseorang wanita dari kalangan kaum Khats'am seraya berkata; \"Wahai Rasulullah, sesungguhnya kewajiban Allah atas hamba-hamba-Nya dalam melaksanakan haji telah mengenai bapakku yang sudah tua renta dan ia tidak mampu menaiki kendaraan. Apakah aku boleh menggantikannya untuk mengerjakan haji?\" Beliau menjawab: 'Ya, karena jika bapakmu memiliki utang, maka kamu berkewajiban melunasinya.'"},"2866":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ طَرِيفٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنِي مُحَمَّدُ بْنُ سُوقَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَرَفَعَتْ امْرَأَةٌ صَبِيًّا لَهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّتِهِ فَقَالَتْ يَا رَسُولَ اللَّهِ أَلِهَذَا حَجٌّ قَالَ نَعَمْ وَلَكِ أَجْرٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Tharif]; keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah]; telah menceritakan kepadaku [Muhammad bin Suqah] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] radliallahu 'anhu, ia berkata; \"Seorang wanita memperlihatkan anaknya kepada Nabi shallallahu 'alaihi wasallam saat beliau mengerjakan sebuah ibadah haji, wanita itu bertanya; 'Wahai Rasulullah apakah anak ini boleh mengerjakan haji? ' Beliau menjawab: 'Ya (boleh). Dan kamu akan mendapatkan ganjaran pahalanya.'"},"2867":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْنُفِسَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ بِالشَّجَرَةِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ أَنْ يَأْمُرَهَا أَنْ تَغْتَسِلَ وَتُهِلَّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah]; telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Ubaidullah] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \" Asma binti Umais mengalami nifas (melahirkan anak) di bawah sebuah pohon, maka Rasulullah shallallahu 'alaihi wasallam memerintahkan Abu Bakar agar menyuruhnya mandi dan bertalbiyah (berniat haji dan umrah).\""},"2868":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّهُ سَمِعَ الْقَاسِمَ بْنَ مُحَمَّدٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ أَبِي بَكْرٍأَنَّهُ خَرَجَ حَاجًّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ أَسْمَاءُ بِنْتُ عُمَيْسٍ فَوَلَدَتْ بِالشَّجَرَةِ مُحَمَّدَ بْنَ أَبِي بَكْرٍ فَأَتَى أَبُو بَكْرٍ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْمُرَهَا أَنْ تَغْتَسِلَ ثُمَّ تُهِلَّ بِالْحَجِّ وَتَصْنَعَ مَا يَصْنَعُ النَّاسُ إِلَّا أَنَّهَا لَا تَطُوفُ بِالْبَيْتِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Khalid bin Makhlad] dari [Sulaiman bin Bilal]; telah menceritakan kepada kami [Yahya bin Sa'id] bahwa ia mendengar [Al Qasim bin Muhammad] menceritakan dari [Ayahnya] dari [Abu Bakar], bahwa ia pernah berangkat haji bersama Rasulullah shallallahu 'alaihi wasallam ditemani oleh isterinya (Asma binti Umais) yang kemudian melahirkan Muhammad bin Abu Bakar di bawah sebuah pohon. Abu Bakar mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengabari beliau. Maka beliau memerintahkan Abu Bakar agar menyuruh isterinya mandi, kemudian memulai niat haji, dan boleh mengerjakan segala apa yang dikerjakan orang-orang (dalam haji) kecuali thawaf di Baitullah.\""},"2869":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ قَالَنُفِسَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ بِمُحَمَّدِ بْنِ أَبِي بَكْرٍ فَأَرْسَلَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهَا أَنْ تَغْتَسِلَ وَتَسْتَثْفِرَ بِثَوْبٍ ثُمَّ تُهِلَّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Yahya bin Adam] dari [Sufyan] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] radliallahu 'anhu, ia berkata; \"Asma binti Umais melahirkan Muhammad bin Abu Bakar, lalu kabarnya disampaikan kepada Nabi shallallahu 'alaihi wasallam, maka beliau memerintahkannya untuk mandi dan mengikat farajnya dengan kain (pembalut), lalu berniat untuk mengerjakan haji.\""},"2870":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُهِلُّ أَهْلُ الْمَدِينَةِ مِنْ ذِي الْحُلَيْفَةِ وَأَهْلُ الشَّامِ مِنْ الْجُحْفَةِ وَأَهْلُ نَجْدٍ مِنْ قَرْنٍ فَقَالَ عَبْدُ اللَّهِ أَمَّا هَذِهِ الثَّلَاثَةُ فَقَدْ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَلَغَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيُهِلُّ أَهْلُ الْيَمَنِ مِنْ يَلَمْلَمَ","id":"Telah menceritakan kepada kami [Abu Mush'ab]; telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penduduk Madinah memulai (haji dan umrahnya) dari Dzul Hulaifah, dan penduduk Syam dari Juhfah, serta penduduk Najd, dari Qarn.\" Abdullah berkata; 'Adapun tiga tempat ini aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, dan telah sampai kabar kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sedangkan untuk ahli Yaman adalah dari Yalamlam.'"},"2871":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يَزِيدَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُهَلُّ أَهْلِ الْمَدِينَةِ مِنْ ذِي الْحُلَيْفَةِ وَمُهَلُّ أَهْلِ الشَّامِ مِنْ الْجُحْفَةِ وَمُهَلُّ أَهْلِ الْيَمَنِ مِنْ يَلَمْلَمَ وَمُهَلُّ أَهْلِ نَجْدٍ مِنْ قَرْنٍ وَمُهَلُّ أَهْلِ الْمَشْرِقِ مِنْ ذَاتِ عِرْقٍ ثُمَّ أَقْبَلَ بِوَجْهِهِ لِلْأُفُقِ ثُمَّ قَالَ اللَّهُمَّ أَقْبِلْ بِقُلُوبِهِمْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Ibrahim bin Yazid] dari [Abu Az Zubair] dari [Jabir] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami, seraya bersabda: 'Tempat berniat (haji dan umrah) penduduk Madinah dari Dzul Hulaifah. Tempat berniat (haji dan umrah) penduduk Syam dari Juhfah. Tempat berniat (haji dan umrah) penduduk Yaman dari Yalamlam. Dan tempat berniat (haji dan umrah) penduduk Masyriq dari Dzatu Irq.\" Kemudian beliau menengadahkan wajahnya ke ufuk seraya berkata: 'Ya Allah, terimalah kedekatan hati mereka.'"},"2872":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَدْخَلَ رِجْلَهُ فِي الْغَرْزِ وَاسْتَوَتْ بِهِ رَاحِلَتُهُ أَهَلَّ مِنْ عِنْدِ مَسْجِدِ ذِي الْحُلَيْفَةِ","id":"Telah menceritakan kepada kami [Muhriz bin Salamah Al 'Adani]; telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi]; telah menceritakan kepadaku [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, bahwa jika Rasulullah shallallahu 'alaihi wasallam memasukan kakinya ke tali pelananya dan kendaraannya telah berdiri tegap, maka beliau mulai berniat (haji atau Umrah) dari sisi masjid Dzul Hulaifah."},"2873":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ وَعُمَرُ بْنُ عَبْدِ الْوَاحِدِ قَالَا حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَإِنِّي عِنْدَ ثَفِنَاتِ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ الشَّجَرَةِ فَلَمَّا اسْتَوَتْ بِهِ قَائِمَةً قَالَ لَبَّيْكَ بِعُمْرَةٍ وَحِجَّةٍ مَعًا وَذَلِكَ فِي حَجَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi]; telah menceritakan kepada kami [Al Walid bin Muslim] dan [Umar bin Abdul Wahid], keduanya berkata; telah menceritakan kepada kami [Al `Auza'i] dari [Ayyub bin musa] dari [Abdullah bin Ubaidillah bin Umair] dari [Tsabit Al Bunani] dari [Anas bin Malik] radliallahu 'anhu, ia berkata; \"Ketika aku berada di samping unta Nabi shallallahu 'alaihi wasallam yang terletak di bawah pohon, dan ketika unta itu telah berdiri sempurna membawa Nabi shallallahu 'alaihi wasallam di atasnya, beliau pun lantas mengucapkan: 'Aku menjawab panggilanmu dengan melaksanakan haji dan umrah sekaligus.' Dan itu terjadi saat beliau mengerjakan haji Wada.\""},"2874":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَأَبُو أُسَامَةَ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَتَلَقَّفْتُ التَّلْبِيَةَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَقَالَ وَكَانَ ابْنُ عُمَرَ يَزِيدُ فِيهَا لَبَّيْكَ لَبَّيْكَ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ لَبَّيْكَ وَالرَّغْبَاءُ إِلَيْكَ وَالْعَمَلُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Mu'awiyah] dan [Abu Usamah] serta [Abdullah bin Numair] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, ia berkata; \"Aku mengambil ucapan talbiyah dari Rasulullah shallallahu 'alaihi wasallam, yaitu beliau mengucapkan: 'Ya Allah aku penuhi panggilan-Mu. Aku penuhi panggilan-Mu. Aku penuhi panggilan-Mu. Tiada sekutu bagi-Mu. Aku penuhi panggilan-Mu. Sesungguhnya pujian, kenikmatan dan kerajaan hanya milik-Mu.Tiada sekutu bagi-Mu.'\" (Perawi berkata): Ibnu Umar menambahkan ungkapan talbiyah dengan ucapan; 'Aku penuhi panggilan-Mu. Aku penuhi panggilan-Mu. Aku penuhi panggilan-Mu. Kebahagiaan dan Kebaikan hanya ada di tangan-Nya. Aku penuhi panggilan-Mu. Permohonan hanya kepada-Mu dan beramal untuk-Mu.'"},"2875":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ حَدَّثَنَا مُؤَمَّلُ بْنُ إِسْمَعِيلَ حَدَّثَنَا سُفْيَانُ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ قَالَكَانَتْ تَلْبِيَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَ","id":"Telah menceritakan kepada kami [Zaid bin Akhzam]; telah menceritakan kepada kami [Mu`ammal bin Isma'il]; telah menceritakan kepada kami [Sufyan] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] radliallahu 'anhu, ia berkata; \"Talbiyah Rasulullah shallallahu 'alaihi wasallam adalah: 'Aku penuhi panggilan-Mu. Ya Allah aku penuhi panggilan-Mu. Aku penuhi panggilan-Mu. Tiada sekutu bagi-Mu, aku penuhi panggilan-Mu. Sesungguhnya pujian, kenikmatan dan kerajaan hanya milik-Mu. Tiada sekutu bagi-Mu.'\""},"2876":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي تَلْبِيَتِهِ لَبَّيْكَ إِلَهَ الْحَقِّ لَبَّيْكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Abdul Aziz bin Abdullah bin Abu Salamah] dari [Abdullah bin Fadll] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda dalam talbiahnya: \"Aku penuhi panggilan-Mu, wahai Tuhan yang Hak (sebenar-benarnya). Aku penuhi panggilan-Mu.\""},"2877":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا عُمَارَةُ بْنُ غَزِيَّةَ الْأَنْصَارِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُلَبٍّ يُلَبِّي إِلَّا لَبَّى مَا عَنْ يَمِينِهِ وَشِمَالِهِ مِنْ حَجَرٍ أَوْ شَجَرٍ أَوْ مَدَرٍ حَتَّى تَنْقَطِعَ الْأَرْضُ مِنْ هَاهُنَا وَهَاهُنَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Isma'il bin 'Ayyasy]; telah menceritakan kepada kami ['Umarah bin Ghaziyyah Al Anshari] dari [Abu Hazim] dari [Sahl bin Sa'ad As Sa'idi] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seseorang yang mengucapkan talbiyah kecuali akan dijawab oleh apa saja yang ada di sebelah kanan dan sebelah kirinya. (Baik) oleh batu atau pohon atau tanah yang keras, sehingga terbelahlah bumi dari sebelah sini dan sebelah sini.\""},"2878":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ حَدَّثَهُ عَنْ خَلَّادِ بْنِ السَّائِبِ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي جِبْرِيلُ فَأَمَرَنِي أَنْ آمُرَ أَصْحَابِي أَنْ يَرْفَعُوا أَصْوَاتَهُمْ بِالْإِهْلَالِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdullah bin Abu Bakar] dari [Abdul Malik bin Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam]; ia menceritakannya dari [Khallad bin As-Sa'ib] dari [Ayahnya]; bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jibril telah mendatangiku, lalu memerintahkanku untuk menyuruh para sahabatku mengeraskan suara saat bertalbiyah.\""},"2879":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي لَبِيدٍ عَنْ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ عَنْ خَلَّادِ بْنِ السَّائِبِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَنِي جِبْرِيلُ فَقَالَ يَا مُحَمَّدُ مُرْ أَصْحَابَكَ فَلْيَرْفَعُوا أَصْوَاتَهُمْ بِالتَّلْبِيَةِ فَإِنَّهَا مِنْ شِعَارِ الْحَجِّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Abu Labid] dari [Al Muthallib bin Abdullah bin Hanthab] dari [Khalad bin As Sa'ib] dari [Zaid bin Khalid Al Juhanni]; ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Jibril telah mendatangiku, seraya berkata; 'Wahai Muhammad. Perintahkan para sahabatmu untuk mengeraskan suara mereka dengan talbiyah. Karena itu termasuk syi'ar haji'.\""},"2880":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَرْبُوعٍ عَنْ أَبِي بَكْرٍ الصِّدِّيقِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ الْعَجُّ وَالثَّجُّ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] dan [Ya'qub bin Humaid bin Kasib], keduanya berkata; telah menceritakan kepada kami [Ibnu Abi Fudaik] dari [Adl Dlahhak bin 'Utsman] dari [Muhammad bin Al Munkadir] dari [Abdurrahman bin Yarbu'] dari [Abu Bakar Ash Shiddiq] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam ditanya; \"Amal perbuatan apakah yang paling utama di musim haji?\" Beliau menjawab: 'Mengeraskan suara dengan talbiyah dan menyembelih hewan kurban.'"},"2881":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ وَعَبْدُ اللَّهِ بْنُ وَهْبٍ وَمُحَمَّدُ بْنُ فُلَيْحٍ قَالُوا حَدَّثَنَا عَاصِمُ بْنُ عُمَرَ بْنِ حَفْصٍ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُحْرِمٍ يَضْحَى لِلَّهِ يَوْمَهُ يُلَبِّي حَتَّى تَغِيبَ الشَّمْسُ إِلَّا غَابَتْ بِذُنُوبِهِ فَعَادَ كَمَا وَلَدَتْهُ أُمُّهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami]; telah menceritakan kepada kami [Abdullah bin Nafi'] dan [Abdullah bin Wahab] serta [Muhammad bin Fulaih], semuanya berkata; telah menceritakan kepada kami ['Ashim bin 'Umar bin Hafsh] dari ['Ashim bin 'Ubaidillah] dari [Abdullah bin Amir bin Rabi'ah] dari [Jabir bin Abdillah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang yang berihram berkurban untuk Allah, pada harinya ia bertalbiyah sehingga matahari terbenam kecuali hilang dosa-dosanya, dan dia kembali seperti waktu ibunya melahirkannya.\""},"2882":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ جَمِيعًا عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْطَيَّبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِإِحْرَامِهِ قَبْلَ أَنْ يُحْرِمَ وَلِحِلِّهِ قَبْلَ أَنْ يُفِيضَ قَالَ سُفْيَانُ بِيَدَيَّ هَاتَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan bin Uyainah]; Demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Al Laits bin Sa'ad] semuanya dari ['Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Aisyah] radliallahu 'anha bahwa ia berkata; Aku telah memakaikan wewangian untuk Rasulullah shallallahu 'alaihi wasallam sebelum beliau berihram dan saat beliau bertahalul sebelum beliau mengerjakan thawaf ifadah. Sufyan berkata; Aisyah berkata; \"Aku melakukannya dengan kedua tanganku ini.\""},"2883":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَأَنِّي أَنْظُرُ إِلَى وَبِيصِ الطِّيبِ فِي مَفَارِقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُلَبِّي","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Aisyah] radliallahu 'anha, ia berkata; \"Seakan-akan aku melihat kilauan minyak wangi pada belahan rambut Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang bertalbiyah.\""},"2884":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَأَنِّي أَرَى وَبِيصَ الطِّيبِ فِي مَفْرِقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ثَلَاثَةٍ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Isma'il bin Musa]; telah menceritakan kepada kami [Syariik] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] radliallahu 'anhu, ia berkata; \"Seakan aku dapat memandang kilauan wangi pada belahan rambut Rasulullah shallallahu 'alaihi wasallam setelah tiga hari, sedangkan beliau mengerjakan ihram.\""},"2885":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَلْبَسُ الْمُحْرِمُ مِنْ الثِّيَابِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَلْبَسُ الْقُمُصَ وَلَا الْعَمَائِمَ وَلَا السَّرَاوِيلَاتِ وَلَا الْبَرَانِسَ وَلَا الْخِفَافَ إِلَّا أَنْ لَا يَجِدَ نَعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِ وَلْيَقْطَعْهُمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ وَلَا تَلْبَسُوا مِنْ الثِّيَابِ شَيْئًا مَسَّهُ الزَّعْفَرَانُ أَوْ الْوَرْسُ","id":"Telah menceritakan kepada kami [Abu Mush'ab]; telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Abdullah bin 'Umar] radliallahu 'anhu bahwa seorang lelaki bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Pakaian apakah yang boleh dikenakan oleh orang-orang yang berihram?\" Rasulullah shallallahu 'alaihi wasallam menjawab: 'Tidak boleh memakai baju, penutup kepala, celana, mantel yang bertudung kepala dan sepatu tinggi, kecuali jika ia tidak mendapatkan sepasang sandal, maka ia boleh memakai khuf, tetapi hendaknya ia memotong keduanya lebih rendah dari mata kaki dan janganlah melumuri pakaian dengan za'faran atau wars (tumbuhan berwarna kuning dan beraroma wangi).\""},"2886":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَلْبَسَ الْمُحْرِمُ ثَوْبًا مَصْبُوغًا بِوَرْسٍ أَوْ زَعْفَرَانٍ","id":"Telah menceritakan kepada kami [Abu Mush'ab]; telah menceritakan kepada kami [Malik bin Anas] dari [Abdullah bin Dinar] dari [Abdullah bin 'Umar] berkata; Rasulullah shallallahu 'alaihi wasallam melarang orang yang ihram memakai baju yang bercelup wars (warna kuning dan wangi) atau za'faran."},"2887":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ أَبِي الشَّعْثَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَالَ هِشَامٌ عَلَى الْمِنْبَرِ فَقَالَ مَنْ لَمْ يَجِدْ إِزَارًا فَلْيَلْبَسْ سَرَاوِيلَ وَمَنْ لَمْ يَجِدْ نَعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِو قَالَ هِشَامٌ فِي حَدِيثِهِ فَلْيَلْبَسْ سَرَاوِيلَ إِلَّا أَنْ يَفْقِدَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Amru bin Dinar] dari [Jabir bin Zaid Abu Asy Sya'tsa`] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam berkhutbah di atas mimbar seraya bersabda: \"Barang siapa yang tidak mendapatkan kain, maka ia dapat memakai celana dan siapa saja yang tidak mendapatkan sepasang sandal, maka ia dapat mengenakan sepatu.\" Hisyam berkata di dalam Haditsnya; 'Maka ia dapat memakai celana jika ia tidak mendapatkan kain.'"},"2888":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ وَعَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَجِدْ نَعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِ وَلْيَقْطَعْهُمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Abu Mush'ab]; telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dan dari ['Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang tidak mendapatkan sepasang sandal, maka dia dapat mengenakan sepatu (khuf), hendaknya dia memotong bawah keduanya lebih rendah dari dua mata kaki.\""},"2889":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كُنَّا بِالْعَرْجِ نَزَلْنَا فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَائِشَةُ إِلَى جَنْبِهِ وَأَنَا إِلَى جَنْبِ أَبِي بَكْرٍ فَكَانَتْ زِمَالَتُنَا وَزِمَالَةُ أَبِي بَكْرٍ وَاحِدَةً مَعَ غُلَامِ أَبِي بَكْرٍ قَالَ فَطَلَعَ الْغُلَامُ وَلَيْسَ مَعَهُ بَعِيرُهُ فَقَالَ لَهُ أَيْنَ بَعِيرُكَ قَالَ أَضْلَلْتُهُ الْبَارِحَةَ قَالَ مَعَكَ بَعِيرٌ وَاحِدٌ تُضِلُّهُ قَالَ فَطَفِقَ يَضْرِبُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ انْظُرُوا إِلَى هَذَا الْمُحْرِمِ مَا يَصْنَعُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abdullah bin Idris] dari [Muhammad bin Ishaq] dari [Yahya bin Abbad bin Abdullah bin Az Zubair] dari [Ayahnya] dari [Asma binti Abu Bakar] radliallahu 'anha, ia berkata; \"Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam, dan ketika tiba di daerah 'Ara', kamipun singgah. Lalu Rasulullah shallallahu 'alaihi wasallam duduk (beristirahat) dan Aisyah duduk di sisi beliau, sedangkan aku duduk di samping Abu Bakar. Kendaraan kami dan kendaraan Abu Bakar satu, yang dibawa oleh budak Abu Bakar.\" (Perawi) berkata; 'Budak itupun muncul tanpa ditemani untanya (kendaraan). Lantas Abu Bakar bertanya; 'Mana untamu? ' Budak itu menjawab; 'Aku kehilangan semalam.' Abu Bakar berujar; 'Kamu hanya memiliki seekor unta lalu kamu hilangkan? ' (Perawi) berkata; 'Maka Abu Bakar pun memukulnya, dan Rasulullah shallallahu 'alaihi wasallam bersabda: 'Perhatikanlah orang yang tengah berihram ini? Apa yang ia perbuat! '"},"2890":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِأَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ اخْتَلَفَا بِالْأَبْوَاءِ فَقَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ يَغْسِلُ الْمُحْرِمُ رَأْسَهُ وَقَالَ الْمِسْوَرُ لَا يَغْسِلُ الْمُحْرِمُ رَأْسَهُ فَأَرْسَلَنِي ابْنُ عَبَّاسٍ إِلَى أَبِي أَيُّوبَ الْأَنْصَارِيِّ أَسْأَلُهُ عَنْ ذَلِكَ فَوَجَدْتُهُ يَغْتَسِلُ بَيْنَ الْقَرْنَيْنِ وَهُوَ يَسْتَتِرُ بِثَوْبٍ فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَنْ هَذَا قُلْتُ أَنَا عَبْدُ اللَّهِ بْنُ حُنَيْنٍ أَرْسَلَنِي إِلَيْكَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ أَسْأَلُكَ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْسِلُ رَأْسَهُ وَهُوَ مُحْرِمٌ قَالَ فَوَضَعَ أَبُو أَيُّوبَ يَدَهُ عَلَى الثَّوْبِ فَطَأْطَأَهُ حَتَّى بَدَا لِي رَأْسُهُ ثُمَّ قَالَ لِإِنْسَانٍ يَصُبُّ عَلَيْهِ اصْبُبْ فَصَبَّ عَلَى رَأْسِهِ ثُمَّ حَرَّكَ رَأْسَهُ بِيَدِهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ ثُمَّ قَالَ هَكَذَا رَأَيْتُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah menceritakan kepada kami [Abu Mush'ab]; telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari [Ibrahim bin Abdullah bin Hunain] dari [Ayahnya] bahwa Abdullah bin Abbas dan Al Miswar bin Makramah berselisih pendapat di daerah Abwa'. Abdullah bin Abbas berkata; \"Orang berihram boleh mencuci kepalanya. Sedangkan Al Miswar mengatakan; 'Orang yang berihram tidak boleh mencuci kepalanya.' Maka Ibnu Abbas radliallahu 'anhu mengutusku untuk menemui [Abu Ayub Al Anshari] guna menanyakan tentang hal tersebut, dan aku mendapatkannya (Abu Ayyub) sedang mandi diantara dua tanduk dan ia menutupinya dengan pakaian. Lalu kuucapkan salam kepadanya, dan ia pun bertanya; 'Siapakah itu? ' Aku menjawab; 'Aku Abdullah bin Hunain. Abdullah bin Abbas telah mengutusku kepadamu untuk menanyakan tentang bagaimana Rasulullah shallallahu 'alaihi wasallam membasuh kepalanya saat berihram.' Abdullah bin Hunain berkata; Abu Ayyub lalu meletakan tangannya di atas pakaian, lalu mengangguk-anggukkan kepalanya, sehingga nampak olehku kepalanya, kemudian dia berkata kepada seseorang yang tengah menyirami kepalanya; 'Siramilah'. Maka iapun menyirami kepalanya, lalu menggerakan kepalanya dengan kedua tangannya ke depan dan ke belakang. Kemudian Abu Ayyub berkata; 'Begitulah aku melihat Nabi shallallahu 'alaihi wasallam melakukannya.'"},"2891":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ قَالَتْكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ مُحْرِمُونَ فَإِذَا لَقِيَنَا الرَّاكِبُ أَسْدَلْنَا ثِيَابَنَا مِنْ فَوْقِ رُءُوسِنَا فَإِذَا جَاوَزَنَا رَفَعْنَاهَاحَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari ['Aisyah] berkata; \"Kami bersama Nabi shallallahu 'alaihi wasallam dalam ihram, apabila lewat para pengendara kami tutup wajah kami dan apabila ia telah pergi maka kami buka kembali.\" Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami ['Abdullah bin Idris] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam seperti itu."},"2892":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ جَدَّتِهِ قَالَ لَا أَدْرِي أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَوْ سُعْدَى بِنْتِ عَوْفٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى ضُبَاعَةَ بِنْتِ عَبْدِ الْمُطَّلِبِ فَقَالَ مَا يَمْنَعُكِ يَا عَمَّتَاهُ مِنْ الْحَجِّ فَقَالَتْ أَنَا امْرَأَةٌ سَقِيمَةٌ وَأَنَا أَخَافُ الْحَبْسَ قَالَ فَأَحْرِمِي وَاشْتَرِطِي أَنَّ مَحِلَّكِ حَيْثُ حُبِسْتِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair]; telah menceritakan kepada kami [Ayahku]; Demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami ['Abdullah bin Numair]; telah menceritakan kepada kami ['Utsman bin Hakim] dari [Abu Bakar bin Abdullah bin Az Zubair], dari kakeknya, ia berkata; \"Aku tidak mengetahui [Asma binti Abu Bakar] atau [Su'da bin Auf], bahwa Rasulullah shallallahu 'alaihi wasallam menemui Dluba'ah binti Abdul Muththalib seraya bersabda: 'Wahai bibiku apa yang mencegahmu untuk melaksanakan haji? ' Dluba'ah menjawab; 'Aku wanita yang sedang sakit, dan aku takut tertahan (tidak bisa melanjutkan ibadahku).' Maka beliau bersabda: 'Berihramlah. Dan syaratkan tempat tahalul-mu di manapun kamu tertahan.'"},"2893":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ وَوَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ ضُبَاعَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا شَاكِيَةٌ فَقَالَ أَمَا تُرِيدِينَ الْحَجَّ الْعَامَ قُلْتُ إِنِّي لَعَلِيلَةٌ يَا رَس��ولَ اللَّهِ قَالَ حُجِّي وَقُولِي مَحِلِّي حَيْثُ تَحْبِسُنِي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Muhammad bin Fudlail] dan [Waki'] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Dluba'ah], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menemuiku dan aku sedang sakit, maka beliau bertanya: 'Bukankah kamu ingin melaksanakan haji tahun ini? ' Aku menjawab; 'Aku sedang sakit wahai Rasulullah! ' Beliau pun bersabda: 'Laksanakanlah haji, dan ucapkan: 'Tempat tahallul-ku di manapun (penyakit itu) menahanku (untuk meneruskan haji).'"},"2894":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ طَاوُسًا وَعِكْرِمَةَ يُحَدِّثَانِ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَتْ ضُبَاعَةُ بِنْتُ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي امْرَأَةٌ ثَقِيلَةٌ وَإِنِّي أُرِيدُ الْحَجَّ فَكَيْفَ أُهِلُّ قَالَ أَهِلِّي وَاشْتَرِطِي أَنَّ مَحِلِّي حَيْثُ حَبَسْتَنِي","id":"Telah menceritakan kepada kami [Abu Bisyr bin Khalaf]; telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij]; telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar [Thawus] dan ['Ikrimah], keduanya menceritakan dari [Ibnu 'Abbas] radliallahu 'anhu, ia berkata; \"Dluba'ah binti Zubair bin Abdul Muththalib datang menemui Rasulullah shallallahu 'alaihi wasallam, lalu berkata: 'Aku adalah wanita yang sedang sakit berat, tapi aku ingin sekali melaksanakan haji. Bagaimana aku dapat berniat haji? ' Beliau menjawab: 'Berniatlah dan syaratkan: 'Bahwa tempat tahallulku dimanapun aku tertahan.'"},"2895":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ صَبِيحٍ حَدَّثَنَا مُبَارَكُ بْنُ حَسَّانَ أَبُو عَبْدِ اللَّهِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَكَانَتْ الْأَنْبِيَاءُ تَدْخُلُ الْحَرَمَ مُشَاةً حُفَاةً وَيَطُوفُونَ بِالْبَيْتِ وَيَقْضُونَ الْمَنَاسِكَ حُفَاةً مُشَاةً","id":"Telah menceritakan kepada kami [Abu Kuraib]; telah menceritakan kepada kami [Isma'il bin Shabih]; telah menceritakan kepada kami [Mubarak bin Hassan Abu Abdullah] dari ['Atha` bin Abu Rabah] dari [Abdullah bin 'Abbas], ia berkata; \"Para Nabi, mereka memasuki Baitul Haram dalam keadaan berjalan kaki dan tidak memakai sandal, dan mereka berthawaf mengelilingi Ka'bah dan melaksanakan manasik dalam keadaan telanjang kaki dan berjalan kaki.\""},"2896":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْخُلُ مَكَّةَ مِنْ الثَّنِيَّةِ الْعُلْيَا وَإِذَا خَرَجَ خَرَجَ مِنْ الثَّنِيَّةِ السُّفْلَى","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Mu'awiyah]; telah menceritakan kepada kami [Ubaidillah bin Umar] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam memasuki Makkah dari bukit tertinggi. Dan jika keluar, maka beliau akan keluar dari bukit terendah."},"2897":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْعُمَرِيُّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ نَهَارًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Al 'Umari] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam memasuki Makkah pada siang hari."},"2898":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيْنَ تَنْزِلُ غَدًا وَذَلِكَ فِي حَجَّتِهِ قَالَ وَهَلْ تَرَكَ لَنَا عَقِيلٌ مَنْزِلًا ثُمَّ قَالَ نَحْنُ نَازِلُونَ غَدًا بِخَيْفِ بَنِي كِنَانَةَ يَعْنِي الْمُحَصَّبَ حَيْثُ قَاسَمَتْ قُرَيْشٌ عَلَى الْكُفْرِ وَذَلِكَ أَنَّ بَنِي كِنَانَةَ حَالَفَتْ قُرَيْشًا عَلَى بَنِي هَاشِمٍ أَنْ لَا يُنَاكِحُوهُمْ وَلَا يُبَايِعُوهُمْقَالَ مَعْمَرٌ قَالَ الزُّهْرِيُّ وَالْخَيْفُ الْوَادِي","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazak]; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ali bin Al Husain] dari [Amru bin Utsman] dari [Usamah bin Sa'id], ia berkata; \"Aku bertanya; 'Wahai Rasulullah, di mana engkau akan singgah esok? ' Kejadian itu pada saat beliau mengerjakan haji. Lalu beliau menjawab: 'Apakah 'Aqil menyiapkan rumah untuk kita? ' Beliau kemudian bersabda: 'Besok kita singgah di lembah Bani Kinanah.' Yang beliau maksud adalah Al Muhashshab, sebuah lokasi melempar jumrah yang pernah menjadi lokasi kaum Quraisy berikrar untuk tidak kufur. Ini terjadi saat Bani Kinanah bersekutu dengan Quraisy melawan Bani Hasyim dengan menolak mengawinkan keturunan Bani Hasyim dan menolak berdagang dengan mereka.\" Ma'mar berkata; 'Zuhri berkata; 'Al Khaif adalah sebuah lembah'.'"},"2899":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَرَأَيْتُ الْأُصَيْلِعَ عُمَرَ بْنَ الْخَطَّابِ يُقَبِّلُ الْحَجَرَ وَيَقُولُ إِنِّي لَأُقَبِّلُكَ وَإِنِّي لَأَعْلَمُ أَنَّكَ حَجَرٌ لَا تَضُرُّ وَلَا تَنْفَعُ وَلَوْلَا أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُكَ مَا قَبَّلْتُكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah]; telah menceritakan kepada kami ['Ashim bin Al Ahwal] dari [Abdullah bin Sarjis], ia berkata; \"Aku melihat seorang yang gundul ([Umar bin Khaththab radliallahu 'anhu]) mencium Hajar Aswad sambil mengucapkan; 'Aku sungguh menciummu, walau ku tahu bahwa engkau adalah batu yang tidak memberi mudlarat dan juga tidak memberi manfaat. Seandainya tidak karena kulihat Rasulullah shallallahu 'alaihi wasallam menciummu, tentu aku tidak akan menciummu.\""},"2900":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ الرَّازِيُّ عَنْ ابْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَأْتِيَنَّ هَذَا الْحَجَرُ يَوْمَ الْقِيَامَةِ وَلَهُ عَيْنَانِ يُبْصِرُ بِهِمَا وَلِسَانٌ يَنْطِقُ بِهِ يَشْهَدُ عَلَى مَنْ يَسْتَلِمُهُ بِحَقٍّ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id]; telah menceritakan kepada kami [Abdurrahim Ar Razi] dari [Ibnu Khutsaim] dari [Sa'id bin Jubair] berkata; Aku mendengar [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Batu ini (Hajar Aswad) sungguh akan datang pada hari kiamat, ia mempunyai dua mata untuk melihat dan lidah untuk berbicara serta bersaksi atas orang yang mengusap (atau menciumnya) dengan benar.'\""},"2901":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا خَالِي يَعْلَى عَنْ مُحَمَّدِ بْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَاسْتَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَجَرَ ثُمَّ وَضَعَ شَفَتَيْهِ عَلَيْهِ يَبْكِي طَوِيلًا ثُمَّ الْتَفَتَ فَإِذَا هُوَ بِعُمَرَ بْنِ الْخَطَّابِ يَبْكِي فَقَالَ يَا عُمَرُ هَاهُنَا تُسْكَبُ الْعَبَرَاتُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Pamanku, Ya'la] dari [Muhammad bin 'Aun] dari [Nafi'] dari [Ibnu 'Umar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menghadap Hajar Aswad kemudian meletakkan kedua bibirnya kepadanya, dan beliau menangis lama sekali, kemudian dia berpaling, dan ternyata dia menemukan 'Umar dalam keadaan menangis pula, beliau bersabda: 'Wahai Umar, di sinilah ditumpahkan air mata.'\""},"2902":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَلِمُ مِنْ أَرْكَانِ الْبَيْتِ إِلَّا الرُّكْنَ الْأَسْوَدَ وَالَّذِي يَلِيهِ مِنْ نَحْوِ دُورِ الْجُمَحِيِّينَ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh Al Mishri]; Telah menceritakan kepada kami [Abdullah bin Wahab]; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [Ayahnya], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam belum pernah mengusap rukun-rukun (pojok) Ka'bah kecuali rukun Hajar Aswad dan rukun setelahnya (rukun Yamani) di sekitar tempat tinggal kaum Jumah.\""},"2903":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ قَالَتْلَمَّا اطْمَأَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ طَافَ عَلَى بَعِيرٍ يَسْتَلِمُ الرُّكْنَ بِمِحْجَنٍ بِيَدِهِ ثُمَّ دَخَلَ الْكَعْبَةَ فَوَجَدَ فِيهَا حَمَامَةَ عَيْدَانٍ فَكَسَرَهَا ثُمَّ قَامَ عَلَى بَابِ الْكَعْبَةِ فَرَمَى بِهَا وَأَنَا أَنْظُرُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Yunus bin Bukair]; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ja'far bin Az Zubair] dari [Ubaidullah bin Abdullah bin Abu Tsaur] dari [Shafiyyah binti Syaibah], ia berkata; \"Ketika Rasulullah merasa tenang saat hari penaklukan kota Makkah, beliau lantas thawaf di atas untanya dan mengusap rukun (Hajar Aswad) dengan tongkat yang ada di tangannya. Kemudian beliau masuk ke dalam Ka'bah dan di dalamnya mendapati patung merpati panjang yang terbuat dari pohon kurma. Lalu beliau menghancurkannya dan berdiri di depan pintu Ka'bah seraya melemparkannya. Saat itu aku melihatnya.\""},"2904":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ فِي حَجَّةِ الْوَدَاعِ عَلَى بَعِيرٍ يَسْتَلِمُ الرُّكْنَ بِمِحْجَنٍ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh]; telah memberitakan kepada kami [Abdullah bin Wahab] dari [Yunus] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam berthawaf di atas untanya saat mengerjakan haji Wada'. Beliau mengusap Hajar Aswad dengan tongkat.\""},"2905":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا هَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى قَالَا حَدَّثَنَا مَعْرُوفُ بْنُ خَرَّبُوذَ الْمَكِّيُّ قَالَ سَمِعْتُ أَبَا الطُّفَيْلِ عَامِرَ بْنَ وَاثِلَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَطُوفُ بِالْبَيْتِ عَلَى رَاحِلَتِهِ يَسْتَلِمُ الرُّكْنَ بِمِحْجَنِهِ وَيُقَبِّلُ الْمِحْجَنَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; Demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Hadiyyah bin Abdul Wahhab]; telah menceritakan kepada kami [Fadlal bin Musa], keduanya berkata; telah menceritakan kepada kami [Ma'ruf bin Kharrabudz Al Maki], ia berkata; aku mendengar [Abu Ath Thufail 'Amir bin Watshilah], berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam di atas kendaraannya berthawaf di Baitullah. Beliau mengusap rukun Hajar Aswad dengan tongkatnya, lalu mencium tongkat tersebut.\""},"2906":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَحْمَدُ بْنُ بَشِيرٍ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا طَافَ بِالْبَيْتِ الطَّوَافَ الْأَوَّلَ رَمَلَ ثَلَاثَةً وَمَشَى أَرْبَعَةً مِنْ الْحِجْرِ إِلَى الْحِجْرِ وَكَانَ ابْنُ عُمَرَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Ahmad bin Basyir]; Demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Muhammad bin Ubaid], keduanya berkata; telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam jika melakukan thawaf pertama, maka beliau akan berlari kecil tiga kali dan berjalan empat kali dari Hijr Isma'il sampai kembali ke Hijr Isma'il (satu putaran). Dan Ibnu Umar juga mengerjakannya."},"2907":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو الْحُسَيْنِ الْعُكْلِيُّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَلَ مِنْ الْحِجْرِ إِلَى الْحِجْرِ ثَلَاثًا وَمَشَى أَرْبَعًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Husain Al 'Ukli] dari [Malik bin Anas] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam berlari-lari kecil tiga kali dari Hijr Isma'il sampai ke Hijr Ismai'il (satu putaran) dan berjalan empat kali."},"2908":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُمَرَ يَقُولُفِيمَ الرَّمَلَانُ الْآنَ وَقَدْ أَطَّأَ اللَّهُ الْإِسْلَامَ وَنَفَى الْكُفْرَ وَأَهْلَهُ وَايْمُ اللَّهِ مَا نَدَعُ شَيْئًا كُنَّا نَفْعَلُهُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Hisyam bin Sa'ad] dari [Zaid bin Aslam] dari [Ayahnya] berkata; Aku mendengar [Umar] radliallahu 'anhu, ia berkata; \"Untuk apa lari kecil saat itu? Padahal sungguh Allah telah menetapkan Islam dan meniadakan kekafiran dan pemeluknya. Demi Allah! Kami tidak meninggalkan apapun yang dulu kami kerjakan pada masa Rasulullah shallallahu 'alaihi wasallam.\""},"2909":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ خُثَيْمٍ عَنْ أَبِي الطُّفَيْلِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ حِينَ أَرَادُوا دُخُولَ مَكَّةَ فِي عُمْرَتِهِ بَعْدَ الْحُدَيْبِيَةِ إِنَّ قَوْمَكُمْ غَدًا سَيَرَوْنَكُمْ فَلَيَرَوُنَّكُمْ جُلْدًا فَلَمَّا دَخَلُوا الْمَسْجِدَ اسْتَلَمُوا الرُّكْنَ وَرَمَلُوا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُمْ حَتَّى إِذَا بَلَغُوا الرُّكْنَ الْيَمَانِيَ مَشَوْا إِلَى الرُّكْنِ الْأَسْوَدِ ثُمَّ رَمَلُوا حَتَّى بَلَغُوا الرُّكْنَ الْيَمَانِيَ ثُمَّ مَشَوْا إِلَى الرُّكْنِ الْأَسْوَدِ فَفَعَلَ ذَلِكَ ثَلَاثَ مَرَّاتٍ ثُمَّ مَشَى الْأَرْبَعَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazak]; telah memberitakan kepada kami [Ma'mar] dari [Ibnu Khutsaim] dari [Abu Ath Thufail] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Nabi shallallahu 'alaihi wasallam bersabda kepada para sahabatnya ketika hendak memasuki kota Makkah guna mengerjakan umrah setelah dilakukannya perjanjian Hudaibiyah, 'Sesungguhnya kaum kalian besok akan melihat kalian. Maka perlihatkanlah kekuatan kalian pada mereka.' Ketika mereka memasuki Masjidil Haram, mereka lantas mengusap rukun (Hajar Aswad) dan berlari-lari kecil disertai Nabi shallallahu 'alaihi wasallam yang bersama mereka. Dan ketika sampai pada rukun Yamani, mereka berjalan sampai rukun Hajar Aswad, kemudian berlari-lari kecil lagi hingga mencapai rukun Yamani. Kemudian mereka berjalan lagi Hingga Hajar Aswad. Dan itu dilakukan tiga kali. Kemudian mereka berjalan di empat putaran yang tersisa.\""},"2910":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ وَقَبِيصَةُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْحَمِيدِ عَنْ ابْنِ يَعْلَى بْنِ أُمَيَّةَ عَنْ أَبِيهِ يَعْلَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ مُضْطَبِعًا قَالَ قَبِيصَةُ وَعَلَيْهِ بُرْدٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Muhammad bin Yusuf] dan [Qabishah], keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Abdul hamid] dari [Ibnu Ya'la bin Umayyah] dari [Ya'la] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam melakukan thawaf dengan idlthiba' (melipat kain dari bawah ketiak sebelah kanan ke pundak sebelah kiri). [Qabishah] berkata; dan diatasnya memakai selendang yang bergaris.\""},"2911":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَائِشَةَ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحِجْرِ فَقَالَ هُوَ مِنْ الْبَيْتِ قُلْتُ مَا مَنَعَهُمْ أَنْ يُدْخِلُوهُ فِيهِ فَقَالَ عَجَزَتْ بِهِمْ النَّفَقَةُ قُلْتُ فَمَا شَأْنُ بَابِهِ مُرْتَفِعًا لَا يُصْعَدُ إِلَيْهِ إِلَّا بِسُلَّمٍ قَالَ ذَلِكَ فِعْلُ قَوْمِكِ لِيُدْخِلُوهُ مَنْ شَاءُوا وَيَمْنَعُوهُ مَنْ شَاءُوا وَلَوْلَا أَنَّ قَوْمَكِ حَدِيثُ عَهْدٍ بِكُفْرٍ مَخَافَةَ أَنْ تَنْفِرَ قُلُوبُهُمْ لَنَظَرْتُ هَلْ أُغَيِّرُهُ فَأُدْخِلَ فِيهِ مَا انْتَقَصَ مِنْهُ وَجَعَلْتُ بَابَهُ بِالْأَرْضِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Ubaidullah bin Musa]; telah menceritakan kepada kami [Syaiban] dari [Asy'ats bin Abi Asy Sya'tsa`] dari [Aswad bin Yazid] dari [Aisyah] radliallahu 'anha, ia berkata; \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang Hijr Isma'il, maka beliau menjawab: \"Ia adalah bagian dari Ka'bah\". Aku bertanya lagi; 'Apa yang mencegah (orang-orang dulu) memasukannya ke dalam bagian Ka'bah? ' Beliau menjawab: 'Mereka kekurangan biaya.' Lalu aku bertanya lagi; 'Kenapa pintunya tinggi, hingga tidak dapat dinaiki kecuali dengan tangga? ' Beliau menjawab: 'Itu adalah perbuatan kaummu, agar dapat (mengatur) masuknya siapa yang dikehendaki dan melarang orang yang dikehendaki ke dalamnya. Seandainya kaummu tidak dekat dari kekufuran dan khawatir hati mereka (keimanan) akan pudar, tentu aku akan pertimbangkan kembali apakah mungkin aku merubahnya dan kumasukan sesuatu yang kurang ke dalamnya, serta kujadikan pintunya dekat dengan tanah (pendek).'"},"2912":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ عَنْ الْعَلَاءِ بْنِ الْمُسَيَّبِ عَنْ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ طَافَ بِالْبَيْتِ وَصَلَّى رَكْعَتَيْنِ كَانَ كَعِتْقِ رَقَبَةٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Al 'Ala bin Al Musayyab] dari ['Atha`] dari ['Abdullah bin Umar] radliallahu 'anhu, ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa berthawaf di Baitullah dan mengerjakan shalat dua rakaat, maka pahalanya seperti membebaskan seorang budak.'\""},"2913":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا حُمَيْدُ بْنُ أَبِي سَوِيَّةَ قَالَ سَمِعْتُ ابْنَ هِشَامٍ يَسْأَلُ عَطَاءَ بْنَ أَبِي رَبَاحٍ عَنْ الرُّكْنِ الْيَمَانِي وَهُوَ يَطُوفُ بِالْبَيْتِ فَقَالَ عَطَاءٌ حَدَّثَنِي أَبُو هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وُكِلَ بِهِ سَبْعُونَ مَلَكًا فَمَنْ قَالَ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ قَالُوا آمِينَ فَلَمَّا بَلَغَ الرُّكْنِ الْأَسْوَدِ قَالَ يَا أَبَا مُحَمَّدٍ مَا بَلَغَكَ فِي هَذَا الرُّكْنِ الْأَسْوَدِ فَقَالَ عَطَاءٌ حَدَّثَنِي أَبُو هُرَيْرَةَ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ فَاوَضَهُ فَإِنَّمَا يُفَاوِضُ يَدَ الرَّحْمَنِ قَالَ لَهُ ابْنُ هِشَامٍ يَا أَبَا مُحَمَّدٍ فَالطَّوَافُ قَالَ عَطَاءٌ حَدَّثَنِي أَبُو هُرَيْرَةَ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ طَافَ بِالْبَيْتِ سَبْعًا وَلَا يَتَكَلَّمُ إِلَّا بِسُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ مُحِيَتْ عَنْهُ عَشْرُ سَيِّئَاتٍ وَكُتِبَتْ لَهُ عَشْرُ حَسَنَاتٍ وَرُفِعَ لَهُ بِهَا عَشْرَةُ دَرَجَاتٍ وَمَنْ طَافَ فَتَكَلَّمَ وَهُوَ فِي تِلْكَ الْحَالِ خَاضَ فِي الرَّحْمَةِ بِرِجْلَيْهِ كَخَائِضِ الْمَاءِ بِرِجْلَيْهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Isma'il bin Ayyasy]; telah menceritakan kepada kami [Humaid bin Abu Sawiyyah] berkata; Aku mendengar Ibnu Hisyam bertanya pada 'Atha` bin Abu Rabah tentang rukun Yamani sedang ia berthawaf di Ka'bah, ['Atha`] berkata; telah menceritakan kepadaku [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Padanya ada tujuh puluh malaikat yang menjaganya, siapa saja yang berdoa; ALLAHUMMA INNI AS`ALUKA AFWA WAL AFIYAH FIDUNYA WAL AKHIRAH RABBANA ATINA FIDUNYA HASANAH WAFIL AKHIRATI HASANAH WAQINA ADZABAN NAAR (Ya Allah aku berharap kemaafan dan kesehatan dari di dunia dan akhirat wahai Rabb kami, berilah kami kebaikan di dunia dan akhirat dan jauhkan kami dari api neraka).\" Niscaya mereka berkata; 'Amien (kabulkanlah!) '. Ketika ia sampai dirukun Hajar Aswad, ia berkata; 'Wahai Abu Muhammad, apa yang engkau ketahui jika sampai di sini?.' Atha` berkata; telah menceritakan kepadaku Abu Hurairah bahwa ia mendengar Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Siapa yang berusaha sesungguhnya ia berusaha menggapai tangan Ar Rahman.' Ibnu Hisyam berkata kepadanya; 'Wahai Abu Muhammad, bagaiamana dengan thawaf? ' 'Atha` menjawab; telah menceritakan kepadaku [Abu Hurairah] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barang siapa yang berthawaf sebanyak tujuh kali dan ia tidak mengucapkan kecuali \"Subhanallah\" (Maha Suci Allah), \"Alhamdulillah\" (Segala puji bagi Allah), \"Laa ilaaha Illallah (Tiada Tuhan kecuali Allah) dan \"Allahu Akbar\" (Allah Maha Besar), 'Laa haula wa laa quwwata illaa billaah (Tiada daya dan upaya kecuali dari Allah), maka dihapuskan padanya sepuluh kesalahan, dituliskan sepuluh kebaikan dan diangkat derajatnya sepuluh tingkat. Dan siapa yang berthawaf dengan berkata-kata (tidak berdzikir) maka seakan-akan ia berenang pada rahmat Allah dengan kedua kakinya saja (tanpa jasadnya) semisal ia berenang di air dengan kedua kakinya.'"},"2914":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ كَثِيرِ بْنِ كَثِيرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ السَّهْمِيِّ عَنْ أَبِيهِ عَنْ الْمُطَّلِبِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَرَغَ مِنْ سَبْعِهِ جَاءَ حَتَّى يُحَاذِيَ بِالرُّكْنِ فَصَلَّى رَكْعَتَيْنِ فِي حَاشِيَةِ الْمَطَافِ وَلَيْسَ بَيْنَهُ وَبَيْنَ الطُّوَّافِ أَحَدٌقَالَ ابْن مَاجَةَ هَذَا بِمَكَّةَ خَاصَّةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah]; telah menceritakan kepada kami [Abu Usamah] dari [Ibnu Juraij] dari [Katsir bin Katsir bin Muththalib bin Abu Wada'ah As Sahmi] dari [Ayahnya] dari [Al Muththalib] berkata; Aku melihat Rasulullah shallallahu 'alaihi wasallam bila selesai melakukan thawaf yang ke tujuh, beliau datang dan shalat di belakang rukun di ujung tempat thawaf dan tidak ada seseorang pun yang menghalanginya diantara beliau dan orang yang sedang thawaf.\" Ibnu Majah berkata; \"Ini khusus di Mekah.\""},"2915":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ مُحَمَّدِ بْنِ ثَابِتٍ الْعَبْدِيِّ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِمَ فَطَافَ بِالْبَيْتِ سَبْعًا ثُمَّ صَلَّى رَكْعَتَيْنِ قَالَ وَكِيعٌ يَعْنِي عِنْدَ الْمَقَامِ ثُمَّ خَرَجَ إِلَى الصَّفَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Muhammad bin Tsabit Al 'Abdi] dari [Amru bin Dinar] dari [Ibnu Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam datang ke Makkah, lantas mengerjakan Thawaf di Baitullah tujuh putaran, kemudian mengerjakan shalat dua rakaat. Waki' berkata; \"Shalat ini dilakukan di maqam Ibrahim.\" Kemudian beliau keluar menuju Shafa (untuk bersa'i).\""},"2916":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّهُ لَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ طَوَافِ الْبَيْتِ أَتَى مَقَامَ إِبْرَاهِيمَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ هَذَا مَقَامُ أَبِينَا إِبْرَاهِيمَ الَّذِي قَالَ اللَّهُ سُبْحَانَهُ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ الْوَلِيدُ فَقُلْتُ لِمَالِكٍ هَكَذَا قَرَأَهَا{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Al 'Abbas bin 'Utsman Ad Dimasyqi]; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Malik bin Anas] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] radliallahu 'anhu, ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam selesai melaksanakan Thawaf di Baitullah, maka beliau mendatangi Maqam Ibrahim. Kemudian 'Umar radliallahu 'anhu bertanya; 'Wahai Rasulullah, apakah ini maqam bapak kita (Ibrahim 'Alaihis Salam) yang Allah Subhanahu Wa Ta'ala telah sebutkan dalam firman-Nya: 'Dan jadikanlah sebagian dari Maqam Ibrahim sebagai tempat shalat.' (Qs. Al Baqarah 2:125)\" Al Walid berkata; 'Aku bertanya kepada Malik; 'Beginikah Umar membacanya; 'Dan jadikanlah sebagian dari Maqam Ibrahim sebagai tempat Shalat? ' Malik menjawab; 'Ya.'"},"2917":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَأَحْمَدُ بْنُ سِنَانٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ ابْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ عَنْ زَيْنَبَ عَنْ أُمِّ سَلَمَةَأَنَّهَا مَرِضَتْ فَأَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَطُوفَ مِنْ وَرَاءِ النَّاسِ وَهِيَ رَاكِبَةٌ قَالَتْ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَى الْبَيْتِ وَهُوَ يَقْرَأُ وَالطُّورِ وَكِتَابٍ مَسْطُورٍقَالَ ابْن مَاجَةَ هَذَا حَدِيثُ أَبِي بَكْرٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Mu'alla bin Manshur]; Demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah menceritakan kepada kami [Ishaq bin Manshur] dan [Ahmad bin Sinan], keduanya berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi], ia berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Muhammad bin Abdurrahman bin Naufal] dari ['Urwah] dari [Zainab] dari [Ummu Salamah] radliallahu 'anha, bahwa ia ditimpa sakit, maka Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk berthawaf di belakang jama'ah sambil berkendara. Ummu Salamah berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam Shalat menghadap ke Baitullah seraya membaca: WA THUUR WA KITAABI MASTHUUR.' QS.Ath Tuur 52: 1-2).\" Ibnu Majah berkata; Ini hadits dari Abu Bakar.\""},"2918":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ سَمِعْتُ الْمُثَنَّى بْنَ الصَّبَّاحِ يَقُولُ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَطُفْتُ مَعَ عَبْدِ اللَّهِ بْنِ عَمْرٍو فَلَمَّا فَرَغْنَا مِنْ السَّبْعِ رَكَعْنَا فِي دُبُرِ الْكَعْبَةِ فَقُلْتُ أَلَا نَتَعَوَّذُ بِاللَّهِ مِنْ النَّارِ قَالَ أَعُوذُ بِاللَّهِ مِنْ النَّارِ قَالَ ثُمَّ مَضَى فَاسْتَلَمَ الرُّكْنَ ثُمَّ قَامَ بَيْنَ الْحَجَرِ وَالْبَابِ فَأَلْصَقَ صَدْرَهُ وَيَدَيْهِ وَخَدَّهُ إِلَيْهِ ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazaq], ia berkata; Aku mendengar [Al Mutsanna bin Ash Shabah] berkata; telah menceritakan kepadaku [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya], ia berkata; \"Aku pernah melakukan thawaf bersama Abdullah bin 'Amru dan setelah kami selesai dari putaran ke tujuh, kami shalat di belakang Ka'bah. Aku kemudian berkata; 'Tidakkah kita seharusnya memohon perlindungan kepada Allah dari neraka? ' Maka ia berkata; 'Aku berlindung kepada Allah dari neraka.' Kemudian ia berlalu, lantas mengusap rukun Hajar Aswad, kemudian berdiri di antara Hajar Aswad dan pintu Ka'bah lalu menempelkan dada, kedua tangan dan pipinya di sana seraya berkata; 'Beginilah aku melihat Rasulullah shallallahu 'alaihi wasallam melakukannya'.\""},"2919":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَرَى إِلَّا الْحَجَّ فَلَمَّا كُنَّا بِسَرِفَ أَوْ قَرِيبًا مِنْ سَرِفَ حِضْتُ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبْكِي فَقَالَ مَا لَكِ أَنَفِسْتِ قُلْتُ نَعَمْ قَالَ إِنَّ هَذَا أَمْرٌ كَتَبَهُ اللَّهُ عَلَى بَنَاتِ آدَمَ فَاقْضِي الْمَنَاسِكَ كُلَّهَا غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ قَالَتْ وَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نِسَائِهِ بِالْبَقَرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \"Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam (sepertinya) tidak ada tujuan lain kecuali untuk mengerjakan haji. Dan ketika kami berada di daerah Sarif atau dekat dengan Sarif, Aku pun mengalami haid. Maka Rasulullah shallallahu 'alaihi wasallam menemuiku dan mendapatiku tengah menangis. Beliau bersabda: 'Kenapa kamu? Apakah kamu sedang mengalami nifas (haid)? ' Aku menjawab; 'Ya.' Lalu beliau bersabda: 'Sesungguhnya ini adalah perkara yang telah ditetapkan Allah Subhanahu Wa Ta'ala terhadap anak-anak perempuan keturunan Adam 'Alaihis Salam. Maka lakukanlah seluruh manasik haji selain thawaf di Baitullah.' Aisyah berkata; 'Rasulullah shallallahu 'alaihi wasallam lantas memotong kurban seekor sapi untuk para istrinya.'"},"2920":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَأَبُو مُصْعَبٍ قَالَا حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْرَدَ الْحَجَّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Amar] dan [Abu Mush'ab]; keduanya berkata; telah menceritakan kepada kami [Malik bin Anas]; telah menceritakan kepadaku [Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Aisyah] radliallahu 'anha Ummul Mukminin, bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan haji Ifrad."},"2921":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي الْأَسْوَدِ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ وَكَانَ يَتِيمًا فِي حِجْرِ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْرَدَ الْحَجَّ","id":"Telah menceritakan kepada kami [Abu Mush'ab]; telah menceritakan kepada kami [Malik bin Anas] dari [Abu Al Aswad Muhammad bin Abdurrahman bin Naufal], dia adalah seorang yatim di rumah ['Urwah bin Zubair], dari [Aisyah] radliallahu 'anha Ummul Mukminin, bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan haji Ifrad."},"2922":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ الدَّرَاوَرْدِيُّ وَحَاتِمُ بْنُ إِسْمَعِيلَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْرَدَ الْحَجَّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami ['Abdul Aziz Ad Darawardi] dan [Hatim bin Isma'il] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] Radlialahu 'Anhu, bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan haji Ifrad."},"2923":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْقَاسِمُ بْنُ عَبْدِ اللَّهِ الْعُمَرِيُّ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ وَعُثْمَانَ أَفْرَدُوا الْحَجَّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Al Qasim bin Abdullah Al 'Umari] dari [Muhammad bin Al Munkadir] dari [Jabir] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman mengerjakan haji Ifrad."},"2924":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا يَحْيَى بْنُ أَبِي إِسْحَقَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَكَّةَ فَسَمِعْتُهُ يَقُولُ لَبَّيْكَ عُمْرَةً وَحِجَّةً","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami]; telah menceritakan kepada kami [Abdul `A'la bin 'Abdul A'la]; telah menceritakan kepada kami [Yahya bin Abu Ishaq] dari [Anas bin Malik] radliallahu 'anhu, ia berkata; \"Kami keluar bersama Rasulullah Shallallahu 'Alahi Wa Sallam menuju Makkah, kudengar beliau bersabda: \"Aku penuhi panggilan-Mu. Dengan melaksanakan umrah dan haji.\""},"2925":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَبَّيْكَ بِعُمْرَةٍ وَحِجَّةٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali]; telah menceritakan kepada kami ['Abdul Wahab]; telah menceritakan kepada kami [Humaid] dari [Anas] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Aku penuhi panggilan-Mu. Dengan melaksanakan haji dan Umrah (bersamaan).\""},"2926":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ قَالَ سَمِعْتُ أَبَا وَائِلٍ شَقِيقَ بْنَ سَلَمَةَ يَقُولُ سَمِعْتُ الصُّبَيَّ بْنَ مَعْبَدٍ يَقُولُكُنْتُ رَجُلًا نَصْرَانِيًّا فَأَسْلَمْتُ فَأَهْلَلْتُ بِالْحَجِّ وَالْعُمْرَةِ فَسَمِعَنِي سَلْمَانُ بْنُ رَبِيعَةَ وَزَيْدُ بْنُ صُوحَانَ وَأَنَا أُهِلُّ بِهِمَا جَمِيعًا بِالْقَادِسِيَّةِ فَقَالَا لَهَذَا أَضَلُّ مِنْ بَعِيرِهِ فَكَأَنَّمَا حَمَلَا عَلَيَّ جَبَلًا بِكَلِمَتِهِمَا فَقَدِمْتُ عَلَى عُمَرَ بْنِ الْخَطَّابِ فَذَكَرْتُ ذَلِكَ لَهُ فَأَقْبَلَ عَلَيْهِمَا فَلَامَهُمَا ثُمَّ أَقْبَلَ عَلَيَّ فَقَالَ هُدِيتَ لِسُنَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُدِيتَ لِسُنَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هِشَامٌ فِي حَدِيثِهِ قَالَ شَقِيقٌ فَكَثِيرًا مَا ذَهَبْتُ أَنَا وَمَسْرُوقٌ نَسْأَلُهُ عَنْهُحَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ وَخَالِي يَعْلَى قَالُوا حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ الصُّبَيِّ بْنِ مَعْبَدٍ قَالَ كُنْتُ حَدِيثَ عَهْدٍ بِنَصْرَانِيَّةٍ فَأَسْلَمْتُ فَلَمْ آلُ أَنْ أَجْتَهِدَ فَأَهْلَلْتُ بِالْحَجِّ وَالْعُمْرَةِ فَذَكَرَ نَحْ��َهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Hisyam bin 'Ammar], keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdah bin Abu Lubabah] berkata; Aku mendengar [Abu Wa`il Syaqiq bin Salamah] berkata; Aku telah mendengar [Ash Shubay bin Ma'bad] berkata; \"Dulu aku seorang Nasrani, lalu masuk Islam. (Ketika berangkat haji) aku mengeraskan niat bacaan haji dan umrah. Salman bin Rabi'ah dan Zaid bin Shuhan pun mendengar niatku itu saat bersama mereka di Qadisiyah. Maka mereka berkata; 'Sungguh orang ini lebih sesat daripada untanya.' Seakan-akan mereka berdua telah membebaniku dengan gunung lewat ucapan mereka itu. Maka aku mendatangi [Umar bin Khaththab] radliallahu 'anhu, lalu kuceritakan kejadiannya. Lalu Umar menjumpai Salman dan Zaid lantas mencela mereka berdua. Kemudian Umar menjumpaiku dan berkata; 'Kamu telah diberi petunjuk kepada sunnah Nabi shallallahu 'alaihi wasallam, sungguh kamu telah diberi petunjuk kepada sunah Nabi shallallahu 'alaihi wasallam. [Hisyam] berkata dalam haditsnya; Syaqiq berkata; dan kebanyakan kepergianku dan Masruq untyuk bertanya tentang masalah tersebut. Telah menceritakan kepada kami [Ali bin Muhammad] Telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] dan pamanku [Ya'la] mereka berkata; Telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Ash Shubay bin Ma'bad] ia berkata; 'Belum lama aku memeluk agama Nashrani, akupun masuk kedalam Islam dan aku tidak biasa berijtihad, maka kukeraskan bacaan niat haji dan umrahku.\" -Lalu Shubai menyebutkan kisah seperti itu.-"},"2927":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا حَجَّاجٌ عَنْ الْحَسَنِ بْنِ سَعْدٍ عَنْ ابْنِ عَبَّاسٍ أَخْبَرَنِي أَبُو طَلْحَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَنَ الْحَجَّ وَالْعُمْرَةَ","id":"Telah menceritakan kepada kami [Ali bin Muhammd]; telah menceritakan kepada kami [Abu Mu'awiyah]; telah menceritakan kepada kami [Hajjaj] dari [Al Hasan bin Sa'd] dari [Ibnu 'Abbas]; telah mengabarkan kepadaku [Abu Thalhah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam pernah memadukan Haji dan Umrah.\""},"2928":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى بْنِ حَارِثٍ الْمُحَارِبِيُّ حَدَّثَنَا أَبِي عَنْ غَيْلَانَ بْنِ جَامِعٍ عَنْ لَيْثٍ عَنْ عَطَاءٍ وَطَاوُسٍ وَمُجَاهِدٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَابْنِ عُمَرَ وَابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَطُفْ هُوَ وَأَصْحَابُهُ لِعُمْرَتِهِمْ وَحَجَّتِهِمْ حِينَ قَدِمُوا إِلَّا طَوَافًا وَاحِدًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Yahya bin Ya'la bin Harits Al Muharibi]; telah menceritakan kepada kami [Ayahku] dari [Ghailan bin Jami'] dari [Laits] dari ['Atha`] dan [Thawus] dan [Mujahid] dari [Jabir bin Abdullah] radliallahu 'anhu, [Ibnu Umar] radliallahu 'anhu dan [Ibnu Abbas] radliallahu 'anhu bahwa Rasulullah dan para sahabatnya belum pernah melakukan thawaf untuk haji dan umrah mereka saat mereka tiba kecuali hanya sekali."},"2929":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْثَرُ بْنُ الْقَاسِمِ عَنْ أَشْعَثَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ لِلْحَجِّ وَالْعُمْرَةِ طَوَافًا وَاحِدًا","id":"Telah menceritakan kepada kami [Hannad bin As Sari]; telah menceritakan kepada kami ['Abtsar bin Al Qasim] dari [Asy'ats] dari [Abu Az Zubair] dari [Jabir] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam melakukan thawaf untuk haji dan umrah hanya dengan satu thawaf."},"2930":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُسْلِمُ بْنُ خَالِدٍ الزَّنْجِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ قَدِمَ قَارِنًا فَطَافَ بِالْبَيْتِ سَبْعًا وَسَعَى بَيْنَ الصَّفَا وَالْمَرْوَةِ ثُمَّ قَالَ هَكَذَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Muslim bin Khalid Az Zanji]; telah menceritakan kepada kami [Ubaidullah bin 'Umar] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu bahwa ia datang dengan niat haji qiran, lalu mengerjakan thawaf tujuh putaran di Baitullah dan mengerjakan Sa'i dari Shafa ke Marwa, kemudian ia mengatakan; \"Inilah yang dikerjakan Rasulullah shallallahu 'alaihi wasallam.\""},"2931":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحْرَمَ بِالْحَجِّ وَالْعُمْرَةِ كَفَى لَهُمَا طَوَافٌ وَاحِدٌ وَلَمْ يَحِلَّ حَتَّى يَقْضِيَ حَجَّهُ وَيَحِلَّ مِنْهُمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Muhriz bin Salamah]; telah menceritakan kepada kami ['Abdul Aziz bin Muhammad] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa berniat ihram melaksanakan haji dan umrah (secara bersamaan), maka cukup baginya mengerjakan sekali thawaf, dan tidaklah ia bertahallul sampai ia menyelesaikan hajinya, (barulah kemudian) bertahallul untuk keduanya (haji dan umrah) sekaligus.\""},"2932":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ ح و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ يَعْنِي دُحَيْمًا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَا حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي عِكْرِمَةُ حَدَّثَنَا ابْنُ عَبَّاسٍ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَهُوَ بِالْعَقِيقِ أَتَانِي آتٍ مِنْ رَبِّي فَقَالَ صَلِّ فِي هَذَا الْوَادِي الْمُبَارَكِ وَقُلْ عُمْرَةٌ فِي حَجَّةٍوَاللَّفْظُ لِدُحَيْمٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Muhammad bin Mush'ab]; telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] yaitu Duhaima; telah menceritakan kepada kami [Al Walid bin Muslim], keduanya berkata; telah menceritakan kepada kami [Al Auza'i]; telah menceritakan kepadaku [Yahya bin Abu Katsir]; telah menceritakan kepadaku ['Ikrimah]; telah menceritakan kepada kami [Ibnu 'Abbas]; telah menceritakan kepadaku [Umar bin Khaththab] radliallahu 'anhu, ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda ketika berada di 'Aqiq: 'Utusan dari Tuhanku mendatangiku, seraya berkata. 'Shalatlah kamu di lembah yang diberkahi ini, dan katakan: 'Umrah dan Haji'.\" Lafadz ini dari Duhaim."},"2933":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ طَاوُسٍ عَنْ سُرَاقَةَ بْنِ جُعْشُمٍ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا فِي هَذَا الْوَادِي فَقَالَ أَلَا إِنَّ الْعُمْرَةَ قَدْ دَخَلَتْ فِي الْحَجِّ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Mis'ar] dari [Abdul Malik bin Maisarah] dari [Thawus] dari [Suraqah bin Ju'tsam], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bangkit untuk berkhutbah di lembah yang diberkahi ini, seraya bersabda: \"Ingatlah bahwa haji Tamattu' (telah disyari'atkan) hingga hari kiamat.\""},"2934":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ يَزِيدَ بْنِ الشِّخِّيرِ عَنْ أَخِيهِ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ قَالَ قَالَ لِي عِمْرَانُ بْنُ الْحُصَيْنِإِنِّي أُحَدِّثُكَ حَدِيثًا لَعَلَّ اللَّهَ أَنْ يَنْفَعَكَ بِهِ بَعْدَ الْيَوْمِ اعْلَمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ اعْتَمَرَ طَائِفَةٌ مِنْ أَهْلِهِ فِي الْعَشْرِ مِنْ ذِي الْحِجَّةِ فَلَمْ يَنْهَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَنْزِلْ نَسْخُهُ قَالَ فِي ذَلِكَ بَعْدُ رَجُلٌ بِرَأْيِهِ مَا شَاءَ أَنْ يَقُولَ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad]; telah menceritakan kepada kami [Abu Usamah] dari [Al Jurairi] dari [Abul Ala` Yazid bin Asy Syikhkhir] dari saudaranya [Mutharrif bin Abdullah bin Asy Syikhkhir], ia berkata; [Imran bin Al Hushain] berkata kepadaku; \"Akan kusampaikan sebuah hadist kepadamu, semoga akan memberi manfaat pada hari ini. Ketahuilah bahwa sekelompok keluarga Rasulullah telah melakukan umrah pada bulan Dzulhijjah, sedangkan beliau tidak melarangnya dan tidak pula turun (nash) yang me-nasakh-nya. Dan nanti seseorang (biasanya) akan berpendapat sesuka hatinya dalam masalah ini.\""},"2935":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنِي أَبِي قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ إِبْرَاهِيمَ بْنِ أَبِي مُوسَى عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّهُ كَانَ يُفْتِي بِالْمُتْعَةِ فَقَالَ لَهُ رَجُلٌ رُوَيْدَكَ بَعْضَ فُتْيَاكَ فَإِنَّكَ لَا تَدْرِي مَا أَحْدَثَ أَمِيرُ الْمُؤْمِنِينَ فِي النُّسُكِ بَعْدَكَ حَتَّى لَقِيتُهُ بَعْدُ فَسَأَلْتُهُ فَقَالَ عُمَرُ قَدْ عَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَهُ وَأَصْحَابُهُ وَلَكِنِّي كَرِهْتُ أَنْ يَظَلُّوا بِهِنَّ مُعْرِسِينَ تَحْتَ الْأَرَاكِ ثُمَّ يَرُوحُونَ بِالْحَجِّ تَقْطُرُ رُءُوسُهُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Basysyar], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdlami]; telah menceritakan kepada kami [Ayahku], keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari ['Umarah bin 'Umair] dari [Ibrahim bin Abu Musa] dari [Abu Musa Al Asy'ari] radliallahu 'anhu, bahwa ia pernah menfatwakan untuk melaksanakan haji Tamattu', lantas seorang laki-laki berkata kepadanya; \"Tahan dulu fatwamu itu, karena kamu tidak tahu apa yang diperbaharui oleh Amirul Mukminin setelahmu masalah pelaksanaan haji.\" Abu Musa berkata; Sampai suatu ketika aku menjumpai Amirul Mukminin, maka kukatakan kepadanya. Lalu [Umar] berkata; 'Aku tahu bahwa Rasulullah shallallahu 'alaihi wasallam dan para sahabat beliau telah mengerjakannya. Namun aku tidak suka (jika) orang-orang nanti bernaung di bawahnya beristirahat di bawah pohon ark (Siwak), kemudian berangkat melaksanakan haji dan kepala mereka terbentur dengan keras.'"},"2936":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأَهْلَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَجِّ خَالِصًا لَا نَخْلِطُهُ بِعُمْرَةٍ فَقَدِمْنَا مَكَّةَ لِأَرْبَعِ لَيَالٍ خَلَوْنَ مِنْ ذِي الْحِجَّةِ فَلَمَّا طُفْنَا بِالْبَيْتِ وَسَعَيْنَا بَيْنَ الصَّفَا وَالْمَرْوَةِ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَجْعَلَهَا عُمْرَةً وَأَنْ نَحِلَّ إِلَى النِّسَاءِ فَقُلْنَا مَا بَيْنَنَا لَيْسَ بَيْنَنَا وَبَيْنَ عَرَفَةَ إِلَّا خَمْسٌ فَنَخْرُجُ إِلَيْهَا وَمَذَاكِيرُنَا تَقْطُرُ مَنِيًّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَبَرُّكُمْ وَأَصْدَقُكُمْ وَلَوْلَا الْهَدْيُ لَأَحْلَلْتُ فَقَالَ سُرَاقَةُ بْنُ مَالِكٍ أَمُتْعَتُنَا هَذِهِ لِعَامِنَا هَذَا أَمْ لِأَبَدٍ فَقَالَ لَا بَلْ لِأَبَدِ الْأَبَدِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi]; telah menceritakan kepada kami [Al Walid bin Muslim]; telah menceritakan kepada kami [Al Auza'i] dari ['Atha`] dari [Jabir bin Abdullah], ia berkata; \"Kami mengeraskan suara bacaan niat untuk mengerjakan haji saja bersama Rasulullah shallallahu 'alaihi wasallam tanpa mencampurnya dengan niat umrah. Dan kami tiba di Makkah pada malam keempat bulan Dzulhijjah. Maka ketika kami thawaf di Baitullah, dan Sa'i antara Shafa dan Marwa, Rasulullah shallallahu 'alaihi wasallam lantas memerintahkan kami untuk menjadikannya sebagai umrah dan segera berkumpul dengan para istri kami. Maka kami saling berkata; 'Antara kita kini dari hari Arafah hanya tersisa lima hari. Apakah kita harus pergi ke sana (Arafah) sedangkan kemaluan kita mengucurkan mani (kita tengah berhadast)? ' Maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya aku adalah orang yang paling baik dan jujur di antara kalian, seandainya tidak ada (al hadyu), niscaya akan kubolehkan (untuk melakukannya).' Suraqah bin Malik bertanya; 'Apakah haji Tamattu' kami hanya diwajibkan untuk tahun ini saja atau untuk selamanya? ' Beliau menjawab: 'Tidak tetapi untuk selamanya'."},"2937":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِخَمْسٍ بَقِينَ مِنْ ذِي الْقَعْدَةِ لَا نُرَى إِلَّا الْحَجَّ حَتَّى إِذَا قَدِمْنَا وَدَنَوْنَا أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ أَنْ يَحِلَّ فَحَلَّ النَّاسُ كُلُّهُمْ إِلَّا مَنْ كَانَ مَعَهُ هَدْيٌ فَلَمَّا كَانَ يَوْمُ النَّحْرِ دُخِلَ عَلَيْنَا بِلَحْمِ بَقَرٍ فَقِيلَ ذَبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَزْوَاجِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Yazid bin Harun] dari [Yahya bin Sa'id] dari [Amrah] dari [Aisyah] radliallahu 'anha, ia berkata; \"Kami berangkat bersama Rasulullah pada lima hari tersisa di bulan Dzulqa'dah dan kami tidak diperlihatkan kecuali haji. Ketika waktunya tiba dan mendekat, Rasulullah memerintahkan orang yang tidak membawa hewan sesembelihan (al hadyu) untuk bertahalul, sehingga semua orang bertahalul. Kecuali orang yang membawa hewan sesembelihan. Dan ketika datang hari 'Ied Adha, dibawakanlah kepada kami daging sapi, maka dikatakan bahwa Rasulullah shallallahu 'alaihi wasallam menyembelih kurban untuk para istrinya.\""},"2938":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ فَأَحْرَمْنَا بِالْحَجِّ فَلَمَّا قَدِمْنَا مَكَّةَ قَالَ اجْعَلُوا حِجَّتَكُمْ عُمْرَةً فَقَالَ النَّاسُ يَا رَسُولَ اللَّهِ قَدْ أَحْرَمْنَا بِالْحَجِّ فَكَيْفَ نَجْعَلُهَا عُمْرَةً قَالَ انْظُرُوا مَا آمُرُكُمْ بِهِ فَافْعَلُوا فَرَدُّوا عَلَيْهِ الْقَوْلَ فَغَضِبَ فَانْطَلَقَ ثُمَّ دَخَلَ عَلَى عَائِشَةَ غَضْبَانَ فَرَأَتْ الْغَضَبَ فِي وَجْهِهِ فَقَالَتْ مَنْ أَغْضَبَكَ أَغْضَبَهُ اللَّهُ قَالَ وَمَا لِي لَا أَغْضَبُ وَأَنَا آمُرُ أَمْرًا فَلَا أُتْبَعُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah]; telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Abu Ishaq] dari [Al Bara` bin 'Azib], ia berkata; Rasulullah bersama dengan para sahabat menemui kami, maka kami melakukan ihram untuk haji. Tatkala kami sampai di Makkah, beliau bersabda: \"Ubahlah haji kalian menjadi 'umrah.\" Maka para sahabat bertanya; 'Wahai Rasulullah, kita telah berihram untuk haji, bagaimana kami mengubahnya menjadi 'umrah? ' Beliau bersabda: 'Perhatikan apa yang aku perintahkan kepada kalian dan kerjakanlah.' Tetapi mereka menolak sabdanya sehingga Rasulullah shallallahu 'alaihi wasallam marah dan pergi kemudian masuk menemui 'Aisyah dalam keadaan marah, maka 'Aisyah melihat kemarahan di wajahnya dan berkata; 'Siapa yang membuat kamu marah maka telah membuat marah Allah.' Beliau bersabda: 'Bagaimana aku tidak marah, sedang aku memerintahkan suatu perintah tapi tidak diikuti.'"},"2939":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا أَبُو عَاصِمٍ أَنْبَأَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مَنْصُورُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ صَفِيَّةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْرِمِينَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ مَعَهُ هَدْيٌ فَلْيُقِمْ عَلَى إِحْرَامِهِ وَمَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ فَلْيَحْلِلْ قَالَتْ فَلَمْ يَكُنْ مَعِي هَدْيٌ فَأَحْلَلْتُ وَكَانَ مَعَ الزُّبَيْرِ هَدْيٌ فَلَمْ يَحِلَّ فَلَبِسْتُ ثِيَابِي وَجِئْتُ إِلَى الزُّبَيْرِ فَقَالَ قُومِي عَنِّي فَقُلْتُ أَتَخْشَى أَنْ أَثِبَ عَلَيْكَ","id":"Telah menceritakan kepada kami [Bakar bin Khalaf Abu Bisyr]; telah menceritakan kepada kami [Abu 'Ashim]; telah memberitakan kepada kami [Ibnu Juraij]; telah mengabarkan kepadaku [Manshur bin Abdurrahman] dari ibunya [Shafiyyah] dari [Asma` binti Abu Bakar] ia berkata; \"Kami pergi (berangkat haji) bersama Rasulullah shallallahu 'alaihi wasallam dalam keadaan berihram. Maka Nabi shallallahu 'alaihi wasallam bersabda: 'Barang siapa membawa hewan sesembelihan, maka tetaplah memakai ihram. Dan barang siapa tidak membawa hewan sesembelihan, maka ia hendaknya bertahalul'.\" Asma berkata; 'Saat itu aku tidak membawa hewan sembelihan, maka akupun bertahalul. Dan Zubair membawa hewan sembelihan maka ia tidak bertahalul. Lantas kupakai pakaianku dan aku datang menemui Zubair, lalu Zubair berkata; 'Pergilah dariku! ' Akupun berkata; 'Apakah kamu takut aku akan menerkammu?."},"2940":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ الْحَارِثِ بْنِ بِلَالِ بْنِ الْحَارِثِ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ فَسْخَ الْحَجِّ فِي الْعُمْرَةِ لَنَا خَاصَّةً أَمْ لِلنَّاسِ عَامَّةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلْ لَنَا خَاصَّةً","id":"Telah menceritakan kepada kami [Abu Mush'ab]; telah menceritakan kepada kami ['Abdul Aziz bin Muhammad Ad Darawardi] dari [Rabi'ah bin Abu 'Abdurrahman] dari [Al Harits bin Bilal bin Al Harits] dari [Ayahnya] berkata; Aku bertanya pada Rasulullah shallallahu 'alaihi wasallam: \"Apakah mengganti haji dengan umrah itu khusus untuk kami atau untuk manusia secara umum?\" Beliau shallallahu 'alaihi wasallam menjawab: 'Bahkan khusus untuk kami.'"},"2941":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَكَانَتْ الْمُتْعَةُ فِي الْحَجِّ لِأَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاصَّةً","id":"Telah menceritakan kepada kami ['Ali bin Muhammad]; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Ayahnya] dari [Abu Dzar] radliallahu 'anhu, ia berkata; \"Haji tamattu hanya untuk para sahabat Muhammad shallallahu 'alaihi wasallam.\""},"2942":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ أَخْبَرَنِي أَبِي قَالَقُلْتُ لِعَائِشَةَ مَا أَرَى عَلَيَّ جُنَاحًا أَنْ لَا أَطَّوَّفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ قَالَتْ إِنَّ اللَّهَ يَقُولُ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }وَلَوْ كَانَ كَمَا تَقُولُ لَكَانَ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَ هَذَا فِي نَاسٍ مِنْ الْأَنْصَارِ كَانُوا إِذَا أَهَلُّوا أَهَلُّوا لِمَنَاةَ فَلَا يَحِلُّ لَهُمْ أَنْ يَطَّوَّفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا قَدِمُوا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَجِّ ذَكَرُوا ذَلِكَ لَهُ فَأَنْزَلَهَا اللَّهُ فَلَعَمْرِي مَا أَتَمَّ اللَّهُ عَزَّ وَجَلَّ حَجَّ مَنْ لَمْ يَطُفْ بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah]; telah mengabarkan kepadaku [Ayahku] ia berkata; \"Aku berkata kepada Aisyah; \"Kurasa tidak ada dosa bagiku, (jika aku tidak bersa'i antar Shafa dan Marwa\". [Aisyah] menjawab; \"Allah Subhanahu Wa Ta'ala berfirman: Sesungguhnya Shafa dan Marwa adalah sebagian dari syiar Allah. Maka barang siapa beribadah haji ke Baitullah atau berumrah, maka tidak ada dosa baginya untuk mengerjakan sa'i antara keduanya.\" Seandainya maknanya seperti yang kamu katakan, tentu bunyi firman-Nya (akan menjadi); Maka tidak ada dosa baginya tidak mengerjakan Sa'i di antara keduanya. Ayat ini turun kepada orang-orang Anshar yang biasa mengeraskan suara, mereka melakukannya untuk Manat, maka tidak boleh bagi mereka untuk bersa'i antara Shafa dan Marwa. Dan ketika mereka tiba bersama Nabi shallallahu 'alaihi wasallam pada sebuah musim haji, merekapun menceritakannya kepada beliau, maka Allah Subhanahu Wa Ta'ala menurunkan ayat ini. Aku bersumpah; Allah Subhanahu Wa Ta'ala tidak akan menyempurnakan haji orang yang tidak melakukan sa'i antara Shafa dan Marwa.\""},"2943":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أُمِّ وَلَدٍ لِشَيْبَةَ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْعَى بَيْنَ الصَّفَا وَالْمَرْوَةِ وَهُوَ يَقُولُ لَا يُقْطَعُ الْأَبْطَحُ إِلَّا شَدًّا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Hisyam Ad Dastuwa`i] dari [Budail bin Maisarah] dari [Shafiyyah binti Syaibah] dari [Ummu Waladnya Syaibah], ia berkata; \"Aku melihat Rasulullah melakukan sa'i antara Shafa dan Marwa, dan beliau bersabda: 'Jarak (dalam sa'i) tidak terpotong kecuali dengan berlari.'"},"2944":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبِي عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ كَثِيرِ بْنِ جُمْهَانَ عَنْ ابْنِ عُمَرَ قَالَإِنْ أَسْعَ بَيْنَ الصَّفَا وَالْمَرْوَةِ فَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْعَى وَإِنْ أَمْشِ فَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي وَأَنَا شَيْخٌ كَبِيرٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Ayahku] dari ['Atha` bin As Sa`ib] dari [Katsir bin Jumhan] dari [Ibnu Umar] radliallahu 'anhu, ia berkata; \"Jika aku bersa'i antara Shafa dan Marwa, maka terlihat olehku Rasulullah shallallahu 'alaihi wasallam bersa'i dan jika aku berjalan, maka aku telah melihat Rasulullah shallallahu 'alaihi wasallam berjalan, sedangkan aku adalah orang yang sudah tua.\""},"2945":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْحَسَنُ بْنُ يَحْيَى الْخُشَنِيُّ حَدَّثَنَا عُمَرُ بْنُ قَيْسٍ أَخْبَرَنِي طَلْحَةُ بْنُ يَحْيَى عَنْ عَمِّهِ إِسْحَقَ بْنِ طَلْحَةَ عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحَجُّ جِهَادٌ وَالْعُمْرَةُ تَطَوُّعٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar]; telah menceritakan kepada kami [Al Hasan bin Yahya Al Khusyani]; telah menceritakan kepada kami ['Umar bin Qais]; telah mengabarkan kepadaku [Thalhah bin Yahya] dari Pamannya [Ishaq bin Thalhah] dari [Thalhah bin 'Ubaidillah] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Haji adalah jihad, sedang 'umrah adalah tathawwu (tidak wajib).\""},"2946":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يَقُولُكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ اعْتَمَرَ فَطَافَ وَطُفْنَا مَعَهُ وَصَلَّى وَصَلَّيْنَا مَعَهُ وَكُنَّا نَسْتُرُهُ مِنْ أَهْلِ مَكَّةَ لَا يُصِيبُهُ أَحَدٌ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Ya'la]; telah menceritakan kepada kami [Isma'il]; Aku mendengar dari [Abdullah bin Abu 'Aufa] berkata; \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam ketika beliau tengah mengerjakan sebuah umrah. Beliau melakukan thawaf, kamipun melakukannya bersama beliau. Beliau mengerjakan shalat, kami pun mengerjakannya bersama beliau. Kami melindungi beliau dari pandangan penduduk kota Makkah, agar tidak ada seorangpun (dari mereka) dapat melukai beliau.\""},"2947":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ بَيَانٍ وَجَابِرٌ عَنْ الشَّعْبِيِّ عَنْ وَهْبِ بْنِ خَنْبَشٍ قَالَقَالَ رَسُول اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمْرَةٌ فِي رَمَضَانَ تَعْدِلُ حَجَّةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan] dari [Bayan] dan [Jabir] dari [Asy Sya'bi] dari [Wahb bin Khanbasy], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Umrah di bulan Ramadhan menyamai (pahala) haji'.\""},"2948":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ جَمِيعًا عَنْ دَاوُدَ بْنِ يَزِيدَ الزَّعَافِرِيِّ عَنْ الشَّعْبِيِّ عَنْ هَرِمِ بْنِ خَنْبَشٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمْرَةٌ فِي رَمَضَانَ تَعْدِلُ حَجَّةً","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah]; telah menceritakan kepada kami [Sufyan]; Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami ['Ali bin Muhammad] dan ['Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki'] semuanya dari [Dawud bin Yazid Az Za'afiri] dari [Asy Sya'bi] dari [Harim bin Khanbasy]. Ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Umrah di bulan Ramadhan menyamai (pahala) haji'.\""},"2949":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُثْمَانَ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ أَبِي مَعْقِلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُمْرَةٌ فِي رَمَضَانَ تَعْدِلُ حَجَّةً","id":"Telah menceritakan kepada kami [Jubarah bin Mughallis]; telah menceritakan kepada kami [Ibrahim bin 'Utsman] dari [Abu Ishaq] dari [Al Aswad bin Yazid] dari [Abu Maqil], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Umrah di bulan Ramadhan menyamai (pahala) haji.\""},"2950":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمْرَةٌ فِي رَمَضَانَ تَعْدِلُ حَجَّةً","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hajjaj] dari ['Atha`] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Umrah di bulan Ramadhan menyamai (pahala) ibadah haji'.\""},"2951":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ بْنِ وَاقِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ الْكَرِيمِ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُمْرَةٌ فِي رَمَضَانَ تَعْدِلُ حَجَّةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Ahmad bin Abdul Malik bin Waqid]; telah menceritakan kepada kami [Ubaidullah bin 'Amru] dari [Abdul Karim] dari ['Atha`] dari [Jabir] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Umrah di bulan Ramadhan menyamai (pahala) mengerjakan haji.\""},"2952":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمْ يَعْتَمِرْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا فِي ذِي الْقَعْدَةِ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah]; telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Zaidah] dari [Ibnu Abu Laila] dari ['Atha`] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam belum pernah umrah kecuali di bulan Dzulqa'dah.\""},"2953":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ حَبِيبٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْلَمْ يَعْتَمِرْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمْرَةً إِلَّا فِي ذِي الْقَعْدَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abdullah bin Numair] dari [Al A'masy] dari [Mujahid] dari [Habib] dari ['Urwah] dari [Aisyah] radliallahu 'anha, ia bekata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah melakukan umrah kecuali di bulan Dzulqa'dah.\""},"2954":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ حَبِيبٍ يَعْنِي ابْنَ أَبِي ثَابِتٍ عَنْ عُرْوَةَ قَالَسُئِلَ ابْنُ عُمَرَ فِي أَيِّ شَهْرٍ اعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي رَجَبٍ فَقَالَتْ عَائِشَةُ مَا اعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَجَبٍ قَطُّ وَمَا اعْتَمَرَ إِلَّا وَهُوَ مَعَهُ تَعْنِي ابْنَ عُمَرَ","id":"Telah menceritakan kepada kami [Abu Kuraib]; telah menceritakan kepada kami [Yahya bin Adam] dari [Abu Bakar bin 'Ayyasy] dari [Al A'masy] dari [Habib yaitu Ibnu Abu Tsabit] dari ['Urwah], ia berkata; \" [Ibnu Umar] radliallahu 'anhu ditanya; 'Pada bulan apakah Rasulullah shallallahu 'alaihi wasallam melaksanakan Umrah? ' Ia menjawab; 'Pada bulan Rajab.' Maka [Aisyah] radliallahu 'anha berkata; 'Rasulullah tidak pernah sekalipun melakukan umrah pada bulan Rajab, dan tidak pernah melakukannya kecuali ia Ibnu Umar bersama beliau'.\""},"2955":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو إِسْحَقَ الشَّافِعِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ الْعَبَّاسِ بْنِ عُثْمَانَ بْنِ شَافِعٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ أَخْبَرَنِي عَمْرُو بْنُ أَوْسٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يُرْدِفَ عَائِشَةَ فَيُعْمِرَهَا مِنْ التَّنْعِيمِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Ishaq Asy Syafi'i Ibrahim bin Muhammad bin Al 'Abbas bin 'Utsman bin Syafi'], keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru bin Dinar]; telah mengabarkan kepadaku ['Amru bin Aus]; telah menceritakan kepadaku [Abdurrahman bin Abu Bakr] bahwa Nabi shallallahu 'alaihi wasallam memerintahkannya untuk mengiringi Aisyah, lalu membawanya umrah dari Tan'im."},"2956":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ نُوَافِي هِلَالَ ذِي الْحِجَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَرَادَ مِنْكُمْ أَنْ يُهِلَّ بِعُمْرَةٍ فَلْيُهْلِلْ فَلَوْلَا أَنِّي أَهْدَيْتُ لَأَهْلَلْتُ بِعُمْرَةٍ قَالَتْ فَكَانَ مِنْ الْقَوْمِ مَنْ أَهَلَّ بِعُمْرَةٍ وَمِنْهُمْ مَنْ أَهَلَّ بِحَجٍّ فَكُنْتُ أَنَا مِمَّنْ أَهَلَّ بِعُمْرَةٍ قَالَتْ فَخَرَجْنَا حَتَّى قَدِمْنَا مَكَّةَ فَأَدْرَكَنِي يَوْمُ عَرَفَةَ وَأَنَا حَائِضٌ لَمْ أَحِلَّ مِنْ عُمْرَتِي فَشَكَوْتُ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعِي عُمْرَتَكِ وَانْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَهِلِّي بِالْحَجِّ قَالَتْ فَفَعَلْتُ فَلَمَّا كَانَتْ لَيْلَةُ الْحَصْبَةِ وَقَدْ قَضَى اللَّهُ حَجَّنَا أَرْسَلَ مَعِي عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ فَأَرْدَفَنِي وَخَرَجَ إِلَى التَّنْعِيمِ فَأَحْلَلْتُ بِعُمْرَةٍ فَقَضَى اللَّهُ حَجَّنَا وَعُمْرَتَنَا وَلَمْ يَكُنْ فِي ذَلِكَ هَدْيٌ وَلَا صَدَقَةٌ وَلَا صَوْمٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \"Kami berangkat bersama Rasulullah shallallahu 'alaihi wasallam dalam haji Wada'. Kami menyempurnakan awal bulan Dzulhijjah, maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barang siapa diantara kalian ingin berniat umrah, maka segera lakukanlah. Seandainya aku tidak membawa Al Hadyu (hewan kurban) niscaya akupun berniat untuk umrah'.\" Aisyah berkata; 'Maka diantara para sahabat ada pula yang berniat umrah, dan diantara mereka ada yang berniat haji. Aku termasuk dikalangan orang yang berniat umrah.' Aisyah berkata lagi; 'Lalu kami berangkat hingga sampai di Makkah. Saat datang hari Arafah, ternyata aku haid, sedangkan belum tiba waktuku untuk bertahallul dari umrahku. Maka kuadukan hal itu kepada Nabi shallallahu 'alaihi wasallam. Lantas beliau bersabda: 'Tinggalkanlah umrahmu. Lerailah (ikatan) rambutmu, dan sisirlah, lalu berniatlah haji'. Aisyah berkata; 'Maka aku melaksanakan perintah beliau. Dan ketika datang malam melempar Jumrah, dan Allah telah menyempurnakan ibadah haji kami, Beliau shallallahu 'alaihi wasallam mengutus Abdurrahman bin Abu Bakar kepadaku, lalu mengiringiku keluar menuju Tan'im, kemudian aku bertahalul untuk umrah. Maka Allah telah menyempurnakan haji dan umrah kami. Dalam pelaksanaan haji tersebut, tidak ada hadyu, sedekah ataupun puasa.'"},"2957":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي سُلَيْمَانُ بْنُ سُحَيْمٍ عَنْ أُمِّ حَكِيمٍ بِنْتِ أُمَيَّةَ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَهَلَّ بِعُمْرَةٍ مِنْ بَيْتِ الْمَقْدِسِ غُفِرَ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] dari [Muhammad bin Ishaq]; telah menceritakan kepadaku [Sulaiman bin Suhaim] dari [Ummu Hakim binti Umayyah] dari [Ummu Salamah]; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berniat 'umrah dari Baitul Maqdis, akan diampuni dosanya.\""},"2958":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَحْيَى بْنِ أَبِي سُفْيَانَ عَنْ أُمِّهِ أُمِّ حَكِيمٍ بِنْتِ أُمَيَّةَ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَهَلَّ بِعُمْرَةٍ مِنْ بَيْتِ الْمَقْدِسِ كَانَتْ لَهُ كَفَّارَةً لِمَا قَبْلَهَا مِنْ الذُّنُوبِ قَالَتْ فَخَرَجْتُ أَيْ مِنْ بَيْتِ الْمَقْدِسِ بِعُمْرَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi]; telah menceritakan kepada kami [Ahmad bin Khalid]; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yahya bin Abu Sufyan] dari ibunya [Ummu Hakim binti Umayyah] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berniat dari Baitul Maqdis, maka akan dihapuskan baginya dosa-dosa yang telah lalu. Ummu Salamah berkata; 'Maka aku keluar dari Baitul Maqdis untuk berumrah.'"},"2959":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الشَّافِعِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدٍ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَاعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَ عُمَرٍ عُمْرَةَ الْحُدَيْبِيَةِ وَعُمْرَةَ الْقَضَاءِ مِنْ قَابِلٍ وَالثَّالِثَةَ مِنْ الْجِعْرَانَةِ وَالرَّابِعَةَ الَّتِي مَعَ حَجَّتِهِ","id":"Telah menceritakan kepada kami [Abu Ishaq Asy Syafi'i Ibrahim bin Muhammad]; telah menceritakan kepada kami [Dawud bin Abdurrahman] dari [Amru bin Dinar] dari ['Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melakukan umrah empat kali, (yaitu) umrah selepas perjanjian Hudaibiyah, umrah sebagai Qadha yaitu di tahun berikutnya, umrah yang ketiga adalah yang dikerjakan dari Ji'ranah, dan umrah yang keempat yang dilakukan bersama haji beliau."},"2960":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ إِسْمَعِيلَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِمِنًى يَوْمَ التَّرْوِيَةِ الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ وَالْفَجْرَ ثُمَّ غَدَا إِلَى عَرَفَةَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Isma'il] dari ['Atha`] dari [Ibnu Abbas] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam berada di Mina pada hari Tarwiyah dan shalat Zhuhur, Ashar, Maghrib, Isya', dan Shubuh di sana. Kemudian (selepas itu) beliau pergi ke Arafah."},"2961":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ يُصَلِّي الصَّلَوَاتِ الْخَمْسَ بِمِنًى ثُمَّ يُخْبِرُهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami ['Abdurrazak]; telah memberitakan kepada kami [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa ia mengerjakan Shalat lima waktu di Mina, kemudian memberitahukan orang-orang bahwa Rasulullah shallallahu 'alaihi wasallam melakukan demikian."},"2962":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ أَلَا نَبْنِي لَكَ بِمِنًى بَيْتًا قَالَ لَا مِنًى مُنَاخُ مَنْ سَبَقَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Ibrahim bin Muhajir] dari [Yusuf bin Mahak] dari [Ibunya] dari [Aisyah] berkata; Aku bertanya pada Rasulullah shallallahu 'alaihi wasallam; \"Wahai Rasulullah, apakah perlu kami buatkan engkau rumah di Mina?\" Beliau menjawab: 'Tidak, 'Mina adalah tempat peristirahatan orang-orang dahulu.'"},"2963":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ أُمِّهِ مُسَيْكَةَ عَنْ عَائِشَةَ قَالَتْقُلْنَا يَا رَسُولَ اللَّهِ أَلَا نَبْنِي لَكَ بِمِنًى بَيْتًا يُظِلُّكَ قَالَ لَا مِنًى مُنَاخُ مَنْ سَبَقَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Ibrahim bin Muhajir] dari [Yusuf bin Mahak] dari [Ummu Musaikah] dari [Aisyah] berkata; Kami bertanya; \"Wahai Rasulullah, bagaimana jika kami membuatkan rumah untukmu di Mina agar engkau bisa berteduh?\" Beliau menjawab: 'Tidak, Mina adalah tempat istirahatnya orang-orang dahulu.'"},"2964":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عُقْبَةَ عَنْ مُحَمَّدِ بْنِ أَبِي بَكْرٍ عَنْ أَنَسٍ قَالَغَدَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْيَوْمِ مِنْ مِنًى إِلَى عَرَفَةَ فَمِنَّا مَنْ يُكَبِّرُ وَمِنَّا مَنْ يُهِلُّ فَلَمْ يَعِبْ هَذَا عَلَى هَذَا وَلَا هَذَا عَلَى هَذَا وَرُبَّمَا قَالَ هَؤُلَاءِ عَلَى هَؤُلَاءِ وَلَا هَؤُلَاءِ عَلَى هَؤُلَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin Uqbah] dari [Muhammad bin Abu Bakar] dari [Anas] radliallahu 'anhu, ia berkata; \"Kami berangkat pagi-pagi bersama Rasulullah dihari ini dari Mina menuju Arafah. (Dalam perjalanan) diantara kami ada yang bertakbir, ada pula yang membaca Talbiyah, dan tidak terjadi kelompok yang bertakbir mencela kelompok yang bertalbiyah, demikian juga kelompok yang bertalbiyah tidak mencela kelompok yang bertakbir.\" Atau Perawi berkata; 'Mereka (kelompok) ini (tidak mencela) kelompok ini, dan kelompok ini (tidak mencela) kelompok ini.'"},"2965":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ أَنْبَأَنَا نَافِعُ بْنُ عُمَرَ الْجُمَحِيُّ عَنْ سَعِيدِ بْنِ حَسَّانَ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْزِلُ بِعَرَفَةَ فِي وَادِي نَمِرَةَ قَالَ فَلَمَّا قَتَلَ الْحَجَّاجُ ابْنَ الزُّبَيْرِ أَرْسَلَ إِلَى ابْنِ عُمَرَ أَيَّ سَاعَةٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرُوحُ فِي هَذَا الْيَوْمِ قَالَ إِذَا كَانَ ذَلِكَ رُحْنَا فَأَرْسَلَ الْحَجَّاجُ رَجُلًا يَنْظُرُ أَيَّ سَاعَةٍ يَرْتَحِلُ فَلَمَّا أَرَادَ ابْنُ عُمَرَ أَنْ يَرْتَحِلَ قَالَ أَزَاغَتْ الشَّمْسُ قَالُوا لَمْ تَزِغْ بَعْدُ فَجَلَسَ ثُمَّ قَالَ أَزَاغَتْ الشَّمْسُ قَالُوا لَمْ تَزِغْ بَعْدُ فَجَلَسَ ثُمَّ قَالَ أَزَاغَتْ الشَّمْسُ قَالُوا لَمْ تَزِغْ بَعْدُ فَجَلَسَ ثُمَّ قَالَ أَزَاغَتْ الشَّمْسُ قَالُوا نَعَمْ فَلَمَّا قَالُوا قَدْ زَاغَتْ ارْتَحَلَقَالَ وَكِيعٌ يَعْنِي رَاحَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki']; telah memberitakan kepada kami [Nafi' bin Umar Al Jumahi] dari [Sa'id bin Hassan] dari [Ibnu Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam singgah di Arafah di lembah Namirah. Ia Perawi berkata; \"Ketika Al Hajjaj membunuh 'Abdullah bin Zubair, ia pernah mengutus seorang (utusan) untuk menemui Ibnu Umar radliallahu 'anhu (untuk melihat) kapankah dulu Rasulullah shallallahu 'alaihi wasallam berangkat ke Arafah pada hari ini? Ia berkata; 'Jika (sudah diketahui waktunya) maka kami akan berangkat.' Maka Al Hajjaj mengutus seseorang untuk melihat kapan Ibnu Umar bergegas berangkat. Ketika Ibnu Umar hendak berangkat, Ibnu Umar radliallahu 'anhu bertanya; 'Apakah matahari sudah tergelincir? ' Mereka menjawab; 'Belum'. Maka ia duduk. (Beberapa saat) kemudian ia bertanya lagi; 'Apakah matahari sudah tergelincir? ' Mereka menjawab; 'Belum'. Maka ia pun duduk kembali. (Beberapa saat) kemudian ia bertanya lagi; 'Apakah matahari sudah tergelincir? ' Mereka menjawab; 'Belum'. Maka ia pun duduk kembali. (Beberapa saat kemudian) ia bertanya lagi; 'Apakah matahari sudah tergelincir? ' Mereka menjawab; 'Ya'. Ketika mereka mengatakan bahwa matahari sudah tergelincir, maka Ibnu Umar segera bergegas berangkat. Waki' berkata; 'Yang dimaksud berangkat adalah berangkat di sore hari.'"},"2966":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَيَّاشٍ عَنْ زَيْدِ بْنِ عَلِيٍّ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيٍّ قَالَوَقَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَقَالَ هَذَا الْمَوْقِفُ وَعَرَفَةُ كُلُّهَا مَوْقِفٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Yahya bin Adam] dari [Sufyan] dari [Abdurrahman bin Ayyasy] dari [Zaid bin Ali] dari [Ayahnya] dari [Ubaidullah bin Abu Rafi'] dari [Ali] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam wukuf di Arafah, lalu bersabda: \"Di sinilah tempat Wukuf, dan seluruh Arafah adalah tempat wukuf.\""},"2967":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ عَنْ يَزِيدَ بْنِ شَيْبَانَ قَالَكُنَّا وُقُوفًا فِي مَكَانٍ تُبَاعِدُهُ مِنْ الْمَوْقِفِ فَأَتَانَا ابْنُ مِرْبَعٍ فَقَالَ إِنِّي رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْكُمْ يَقُولُ كُونُوا عَلَى مَشَاعِرِكُمْ فَإِنَّكُمْ الْيَوْمَ عَلَى إِرْثٍ مِنْ إِرْثِ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan bin Uyainah] dari ['Amru bin Dinar] dari [Amru bin Abdullah bin Shafwan] dari [Yazid bin Syaiban] bekata; \"Kami melakukan wukuf di suatu tempat yang berjauhan dari tempat wukuf (yang seharusnya). Lalu Ibnu Mirba' mendatangi kami seraya berkata; 'Sesungguhnya aku adalah utusan dari Rasulullah shallallahu 'alaihi wasallam kepadamu untuk mengatakan: 'Tetaplah kalian untuk berada di tempat syi'ar (masya'ir) kalian. Karena kalian pada hari ini tengah berada pada sebuah warisan Nabi Ibrahim Alaihis Salam.'\""},"2968":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْقَاسِمُ بْنُ عَبْدِ اللَّهِ الْعُمَرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ عَرَفَةَ مَوْقِفٌ وَارْتَفِعُوا عَنْ بَطْنِ عَرَفَةَ وَكُلُّ الْمُزْدَلِفَةِ مَوْقِفٌ وَارْتَفِعُوا عَنْ بَطْنِ مُحَسِّرٍ وَكُلُّ مِنًى مَنْحَرٌ إِلَّا مَا وَرَاءَ الْعَقَبَةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Qasim bin Abdullah Al 'Umari]; telah menceritakan kepada kami [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Semua lokasi di Arafah adalah tempat wukuf, penuhilah perut lembah Arafah. Dan semua lokasi di Muzdalifah adalah tempat wukuf, penuhilah perut lembah Muhassar. Dan semua lokasi di Mina adalah tempat menyembelih hewan kurban, kecuali lokasi di belakang Aqabah.\""},"2969":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الْهَاشِمِيُّ حَدَّثَنَا عَبْدُ الْقَاهِرِ بْنُ السَّرِيِّ السُّلَمِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ كِنَانَةَ بْنِ عَبَّاسِ بْنِ مِرْدَاسٍ السُّلَمِيُّ أَنَّ أَبَاهُ أَخْبَرَهُ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا لِأُمَّتِهِ عَشِيَّةَ عَرَفَةَ بِالْمَغْفِرَةِ فَأُجِيبَ إِنِّي قَدْ غَفَرْتُ لَهُمْ مَا خَلَا الظَّالِمَ فَإِنِّي آخُذُ لِلْمَظْلُومِ مِنْهُ قَالَ أَيْ رَبِّ إِنْ شِئْتَ أَعْطَيْتَ الْمَظْلُومَ مِنْ الْجَنَّةِ وَغَفَرْتَ لِلظَّالِمِ فَلَمْ يُجَبْ عَشِيَّتَهُ فَلَمَّا أَصْبَحَ بِالْمُزْدَلِفَةِ أَعَادَ الدُّعَاءَ فَأُجِيبَ إِلَى مَا سَأَلَ قَالَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ تَبَسَّمَ فَقَالَ لَهُ أَبُو بَكْرٍ وَعُمَرُ بِأَبِي أَنْتَ وَأُمِّي إِنَّ هَذِهِ لَسَاعَةٌ مَا كُنْتَ تَضْحَكُ فِيهَا فَمَا الَّذِي أَضْحَكَكَ أَضْحَكَ اللَّهُ سِنَّكَ قَالَ إِنَّ عَدُوَّ اللَّهِ إِبْلِيسَ لَمَّا عَلِمَ أَنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ اسْتَجَابَ دُعَائِي وَغَفَرَ لِأُمَّتِي أَخَذَ التُّرَابَ فَجَعَلَ يَحْثُوهُ عَلَى رَأْسِهِ وَيَدْعُو بِالْوَيْلِ وَالثُّبُورِ فَأَضْحَكَنِي مَا رَأَيْتُ مِنْ جَزَعِهِ","id":"Telah menceritakan kepada kami [Ayyub bin Muhammad Al Hasyimi]; telah menceritakan kepada kami [Abdul Qahir bin Sari As Sulami]; telah menceritakan kepada kami [Abdullah bin Kinanah bin Abbas bin Mirdas As Sulami] bahwa [Ayahnya]; telah mengabarkan kepadanya dari [ayahnya], bahwa Nabi shallallahu 'alaihi wasallam berdoa untuk kebahagiaan dan ampunan, maka Allah menjawab: \"Aku mengampuni mereka kecuali orang yang berbuat kezhaliman maka aku memberikannya kepada yang dizhalimi.\" Beliau bertanya: 'Kenapa wahai Rabbku, bukankah Engkau dapat memasukan yang terzhalimi ke dalam surga dan mengampuni yang berbuat kezhaliman? ' Maka Allah tidak menjawabnya, hingga ketika Nabi berada di Muzdalifah beliau kembali mengulangi doanya, maka dijawab apa yang beliau minta, Maka Rasulullah shallallahu 'alaihi wasallam tertawa atau tersenyum, Abu Bakar dan Umar pun berkata; 'Demi bapak ibuku, sungguh pada saat ini, apa yang membuat engkau tertawa, siapa lagi yang bukan menjadikan tertawa kecuali Allah menjadikanmu tertawa dengan gigi-gigimu.' Beliau menjawab: 'Sesungguhnya musuh Allah, Iblis, ketika mengetahui Allah mengabulkan doaku, dan mengampuni umatku maka ia mengambil tanah dan di letakkan di kepalanya seraya mendoakan dengan kecelakaan dan kebinasaan, maka itu menjadikanku tertawa dari sikapnya itu.'"},"2970":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْمِصْرِيُّ أَبُو جَعْفَرٍ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي مَخْرَمَةُ بْنُ بُكَيْرٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ يُونُسَ بْنَ يُوسُفَ يَقُولُ عَنْ ابْنِ الْمُسَيَّبِ قَالَ قَالَتْ عَائِشَةُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ يَوْمٍ أَكْثَرَ مِنْ أَنْ يُعْتِقَ اللَّهُ عَزَّ وَجَلَّ فِيهِ عَبْدًا مِنْ النَّارِ مِنْ يَوْمِ عَرَفَةَ وَإِنَّهُ لَيَدْنُو عَزَّ وَجَلَّ ثُمَّ يُبَاهِي بِهِمْ الْمَلَائِكَةَ فَيَقُولُ مَا أَرَادَ هَؤُلَاءِ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Mishri Abu Ja'far]; telah memberitakan kepada kami [Abdullah bin Wahab]; telah mengkabarkan kepadaku [Makhramah bin Bukair] dari [Ayahnya] berkata; Aku mendengar [Yunus bin Yusuf] berkata; dari [Ibnu Al Musayyab] berkata; dari [Aisyah] radliallahu 'anha, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hari yang lebih banyak Allah bebaskan hamba dari api neraka dari pada hari Arafah. (Pada hari itu) Allah Subhanahu Wa Ta'ala akan mendekat, kemudian berbangga dengan para hamba-Nya kepada para Malaikat, seraya berfirman: 'Apa gerangan yang mereka inginkan? '\""},"2971":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ بُكَيْرِ بْنِ عَطَاءٍ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَعْمَرَ الدِّيلِيَّ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَاقِفٌ بِعَرَفَةَ وَأَتَاهُ نَاسٌ مِنْ أَهْلِ نَجْدٍ فَقَالُوا يَا رَسُولَ اللَّهِ كَيْفَ الْحَجُّ قَالَ الْحَجُّ عَرَفَةُ فَمَنْ جَاءَ قَبْلَ صَلَاةِ الْفَجْرِ لَيْلَةَ جَمْعٍ فَقَدْ تَمَّ حَجُّهُ أَيَّامُ مِنًى ثَلَاثَةٌ فَمَنْ تَعَجَّلَ فِي يَوْمَيْنِ فَلَا إِثْمَ عَلَيْهِ وَمَنْ تَأَخَّرَ فَلَا إِثْمَ عَلَيْهِ ثُمَّ أَرْدَفَ رَجُلًا خَلْفَهُ فَجَعَلَ يُنَادِي بِهِنَّحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ بُكَيْرِ بْنِ عَطَاءٍ اللَّيْثِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَعْمَرَ الدِّيلِيِّ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَجَاءَهُ نَفَرٌ مِنْ أَهْلِ نَجْدٍ فَذَكَرَ نَحْوَهُ قَالَ مُحَمَّدُ بْنُ يَحْيَى مَا أُرَ لِلثَّوْرِيِّ حَدِيثًا أَشْرَفَ مِنْهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhamad], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan] dari [Bukair bin Atha`]; Aku mendengar [Abdurahman bin Ya'mar Ad-Dili], ia berkata; \"Aku menyaksikan Rasulullah shallallahu 'alaihi wasallam ketika sedang wukuf di Arafah, dan sekelompok orang dari kalangan penduduk Najd mendatangi beliau, mereka bertanya; 'Wahai Rasulullah, bagaimana (cara melaksanakan) haji? ' Beliau menjawab: ' Haji itu adalah Arafah. Maka barang siapa datang ke Arafah sebelum fajar malam berkumpulnya manusia, maka telah sempurnalah ibadah haji. Hari-hari Mina itu tiga hari, barangsiapa ingin cepat berangkat (dari Mina) sesudah dua hari, maka tidak ada dosa baginya, dan barang siapa ingin menangguhkan (keberangkatannya dari dua hari), maka tidak ada dosa pula baginya.' Kemudian seorang laki-laki di belakang beliau mengiringi ucapannya dan turut menyerukan ucapan tersebut.' Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazak]; telah memberitakan kepada kami [Ats Tsauri] dari [Bukair bin Atha` Al Laitsi] dari [Abdurrahman bin Ya'mar Ad Dili] berkata; Aku mendatangi Rasulullah shallallahu 'alaihi wasallam di Arafah, lalu datanglah seseorang dari penduduk Najed, lalu ia sebutkan hadits tersebut. [Muhammad bin Yahya] berkata; Aku tidak diperlihatkan dari Ats Tsauri sebuah hadits yang lebih baik dari ini.\""},"2972":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ عَامِرٍ يَعْنِي الشَّعْبِيَّ عَنْ عُرْوَةَ بْنِ مُضَرِّسٍ الطَّائِيِّأَنَّهُ حَجَّ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُدْرِكْ النَّاسَ إِلَّا وَهُمْ بِجَمْعٍ قَالَ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَنْضَيْتُ رَاحِلَتِي وَأَتْعَبْتُ نَفْسِي وَاللَّهِ إِنْ تَرَكْتُ مِنْ حَبْلٍ إِلَّا وَقَفْتُ عَلَيْهِ فَهَلْ لِي مِنْ حَجٍّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَهِدَ مَعَنَا الصَّلَاةَ وَأَفَاضَ مِنْ عَرَفَاتٍ لَيْلًا أَوْ نَهَارًا فَقَدْ قَضَى تَفَثَهُ وَتَمَّ حَجُّهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Amir Asy Sya'bi] dari [Urwah bin Mudharris At-Tha'i], ia pernah berangkat haji pada zaman Nabi shallallahu 'alaihi wasallam, dan tidak dapat mengejar orang-orang kecuali mereka sudah berada di Muzdalifah. Lalu ia berkata; Aku menemui Nabi shallallahu 'alaihi wasallam, maka kukatakan kepada beliau: 'Wahai Rasulullah aku telah membuat kurus untaku, dan melelahkan diriku (karena tergesa-gesa mengejar waktu Arafah). Demi Allah jika aku terlepas dari perjalanan panjang itu, tentu aku dapat turut berwukuf. Lalu apakah aku mendapatkan haji? ' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa menyaksikan shalat bersama kami, dan menemui wukuf di Arafah baik malam maupun siang, maka ia telah melaksanakan tahalullul dan sempurnalah hajinya.'"},"2973":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أُسَامَةَ بْنِ زَيْدٍأَنَّهُ سُئِلَ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِيرُ حِينَ دَفَعَ مِنْ عَرَفَةَ قَالَ كَانَ يَسِيرُ الْعَنَقَ فَإِذَا وَجَدَ فَجْوَةً نَصَّقَالَ وَكِيعٌ وَالنَّصُّ يَعْنِي فَوْقَ الْعَنَقِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Usamah bin Zaid], bahwa ia pernah ditanya: 'Bagaimana Rasulullah shallallahu 'alaihi wasallam berjalan ketika berangkat dari Arafah? ' Usamah menjawab; 'Beliau berjalan dengan kecepatan sedang. Dan jika beliau menemukan kekosongan (di jalan), maka beliau akan mempercepat jalannya.' Waki' berkata; 'Yang dimaksud adalah kecepatan yang melebihi kecepatan biasa (rata-rata).'"},"2974":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَتْ قُرَيْشٌ نَحْنُ قَوَاطِنُ الْبَيْتِ لَا نُجَاوِزُ الْحَرَمَ فَقَالَ اللَّهُ عَزَّ وَجَلَّ{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazaq]; telah menceritakan kepada kami [Ats Tsauri] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \"Seseorang dari kalangan kaum Quraisy berkata; 'Kami adalah penduduk di sekitar Baitullah, dan (tinggal) tidak jauh dari daerah Haram. Allah Subhanahu Wa Ta'ala telah berfirman: 'Kemudian bertolaklah kamu dari tempat bertolaknya orang-orang banyak (Arafah) …'(Qs. Al Baqarah 2: 199) "},"2975":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ عُقْبَةَ عَنْ كُرَيْبٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَأَفَضْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا بَلَغَ الشِّعْبَ الَّذِي يَنْزِلُ عِنْدَهُ الْأُمَرَاءُ نَزَلَ فَبَالَ فَتَوَضَّأَ قُلْتُ الصَّلَاةَ قَالَ الصَّلَاةُ أَمَامُكَ فَلَمَّا انْتَهَى إِلَى جَمْعٍ أَذَّنَ وَأَقَامَ ثُمَّ صَلَّى الْمَغْرِبَ ثُمَّ لَمْ يَحِلَّ أَحَدٌ مِنْ النَّاسِ حَتَّى قَامَ فَصَلَّى الْعِشَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Abdurrahman bin Mahdi]; telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Uqbah] dari [Kuraib] dari [Usamah bin Zaid] radliallahu 'anhu, ia berkata; \"Aku bertolak bersama Rasulullah shallallahu 'alaihi wasallam, ketika sampai di lembah tempat para penguasa biasa singgah, beliau turun lalu membuang air kecil dan berwudlu. Aku berkata; 'Waktu shalat sudah masuk? ' Beliau bersabda: 'Sebentar lagi kita akan melaksanakan shalat.' Ketika beliau tiba di Muzdalifah, maka dikumandangkanlah adzan dan Iqamat, lalu beliau mengerjakan shalat Maghrib. Dan tidak seorangpun beranjak sampai beliau berdiri dan mengerjakan shalat Isya'.\""},"2976":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ الْأَنْصَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَطْمِيِّ أَنَّهُ سَمِعَ أَبَا أَيُّوبَ الْأَنْصَارِيَّ يَقُولُصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَغْرِبَ وَالْعِشَاءَ فِي حَجَّةِ الْوَدَاعِ بِالْمُزْدَلِفَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yahya bin Sa'id] dari ['Addi bin Tsabit Al Anshari] dari [Abdullah bin Yazid Al Khathmi] bahwa ia mendengar [Abu Ayyub Al Anshari] radliallahu 'anhu, ia berkata; \"Aku mengerjakan shalat Maghrib dan Isya saat melakukan haji Wada' (perpisahan) di Muzdalifah bersama Rasulullah.\""},"2977":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْمَغْرِبَ بِالْمُزْدَلِفَةِ فَلَمَّا أَنَخْنَا قَالَ الصَّلَاةُ بِإِقَامَةٍ","id":"Telah menceritakan kepada kami [Muhriz bin Salamah Al 'Adani]; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Ubaidullah] dari [Salim] dari [Ayahnya], bahwa Nabi shallallahu 'alaihi wasallam mengerjakan Shalat Maghrib di Muzdalifah. Dan ketika kami beristirahat, beliau bersabda: \"Shalatlah dengan iqamat.\""},"2978":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَجَّاجٍ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَحَجَجْنَا مَعَ عُمَرَ بْنِ الْخَطَّابِ فَلَمَّا أَرَدْنَا أَنْ نُفِيضَ مِنْ الْمُزْدَلِفَةِ قَالَ إِنَّ الْمُشْرِكِينَ كَانُوا يَقُولُونَ أَشْرِقْ ثَبِيرُ كَيْمَا نُغِيرُ وَكَانُوا لَا يُفِيضُونَ حَتَّى تَطْلُعَ الشَّمْسُ فَخَالَفَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَفَاضَ قَبْلَ طُلُوعِ الشَّمْسِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Hajjaj] dari [Abu Ishaq] dari [Amru bin Maimun] berkata; \"Kami berangkat haji bersama [Umar bin Khaththab], maka ketika kami ingin bertolak dari Muzdalifah, ia berkata; 'Sesungguhnya orang-orang musyrik dahulu berkata; 'Serbulah ketika matahari telah terbit! sebagaimana kita menyerang.' Merekapun tidak bertolak sehingga terbit matahari, maka Rasulullah shallallahu 'alaihi wasallam melakukan hal yang bertentangan dengan mereka, beliau bertolak justru sebelum matahari terbit.'"},"2979":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ الثَّوْرِيِّ قَالَ قَالَ أَبُو الزُّبَيْرِ قَالَ جَابِرٌأَفَاضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ وَعَلَيْهِ السَّكِينَةُ وَأَمَرَهُمْ بِالسَّكِينَةِ وَأَمَرَهُمْ أَنْ يَرْمُوا بِمِثْلِ حَصَى الْخَذْفِ وَأَوْضَعَ فِي وَادِي مُحَسِّرٍ وَقَالَ لِتَأْخُذْ أُمَّتِي نُسُكَهَا فَإِنِّي لَا أَدْرِي لَعَلِّي لَا أَلْقَاهُمْ بَعْدَ عَامِي هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah]; telah menceritakan kepada kami [Abdullah bin Raja` Al Makki] dari [Ats Tsauri] dia berkata; [Abu Az Zubair] dia berkata; dari [Jabir] radliallahu 'anhu, ia berkata; \"Nabi shallallahu 'alaihi wasallam bertolak saat melaksanakan haji Wada' dalam keadaan tenang. Beliau pun memerintahkan orang-orang (yang bersama beliau) untuk tenang, memerintahkan mereka untuk melontar dengan kerikil sebesar kerikil ketapel, serta mempercepat jalan ke lembah Muhassir. Lalu beliau bersabda: 'Hendaklah umatku mengambil tata cara ibadah haji tersebut. Karena aku tidak tahu, mungkin saja aku tidak akan bertemu lagi dengan mereka setelah tahun ini.'"},"2980":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي رَوَّادٍ عَنْ أَبِي سَلَمَةَ الْحِمْصِيِّ عَنْ بِلَالِ بْنِ رَبَاحٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ غَدَاةَ جَمْعٍ يَا بِلَالُ أَسْكِتْ النَّاسَ أَوْ أَنْصِتْ النَّاسَ ثُمَّ قَالَ إِنَّ اللَّهَ تَطَوَّلَ عَلَيْكُمْ فِي جَمْعِكُمْ هَذَا فَوَهَبَ مُسِيئَكُمْ لِمُحْسِنِكُمْ وَأَعْطَى مُحْسِنَكُمْ مَا سَأَلَ ادْفَعُوا بِاسْمِ اللَّهِ","id":"Telah menceritakan kepada kami ['Ali bin Muhammad] dan [Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Ibnu Abu Rawwad] dari [Abu Salamah Al Himsha] dari [Bilal bin Rabah] sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Wahai Bilal. (Perintahkan) orang-orang untuk diam! \" (Atau beliau bersabda: '(Perintahkan) orang untuk mendengarkan), Kemudian bersabda: 'Sesungguhnya Allah menganugerahi kalian di Muzdalifah kalian ini, Dia menganugerahi orang yang berbuat jahat dari kalian untuk yang berbuat baik, dan memberi yang berbuat baik diantara kalian apa yang dia minta. Berangkatlah dengan menyebut nama Allah.\""},"2981":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ وَسُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ الْحَسَنِ الْعُرَنِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُغَيْلِمَةَ بَنِي عَبْدِ الْمُطَّلِبِ عَلَى حُمُرَاتٍ لَنَا مِنْ جَمْعٍ فَجَعَلَ يَلْطَحُ أَفْخَاذَنَا وَيَقُولُ أُبَيْنِيَّ لَا تَرْمُوا الْجَمْرَةَ حَتَّى تَطْلُعَ الشَّمْسُ زَادَ سُفْيَانُ فِيهِ وَلَا إِخَالُ أَحَدًا يَرْمِيهَا حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan ['Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Mis'ar] dan [Sufyan] dari [Salamah bin Kuhail] dari [Hasan Al Urani] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; Kami mendahulukan anak-anak dari bani Abdul Muththalib yang berada di atas keledai-keledai kami dari pada Rasulullah shallallahu 'alaihi wasallam (ketika berangkat) dari Muzdalifah. Beliau lantas menepuk-nepuk paha kami sambil bersabda: \"Wahai anak-anakku, janganlah kalian melontar jumrah (kecuali) sampai matahari terbit.\""},"2982":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَكُنْتُ فِيمَنْ قَدِمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ضَعَفَةِ أَهْلِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan]; telah menceritakan kepada kami [Amru] dari [Atha`] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Aku termasuk orang yang mendahului Rasulullah shallallahu 'alaihi wasallam dalam kelompok orang-orang lemah dari kalangan keluarganya.\""},"2983":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ سَوْدَةَ بِنْتَ زَمْعَةَ كَانَتْ امْرَأَةً ثَبْطَةً فَاسْتَأْذَنَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَدْفَعَ مِنْ جَمْعٍ قَبْلَ دَفْعَةِ النَّاسِ فَأَذِنَ لَهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin Qasim] dari [Ayahnya] dari [Aisyah] radliallahu 'anhu, bahwa Saudah binti Zam'ah adalah wanita yang berat dan lambat (jalannya), maka ia meminta izin kepada Rasulullah shallallahu 'alaihi wasallam untuk bertolak ke Muzdalifah mendahului orang-orang, dan beliaupun mengizinkannya."},"2984":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ قَالَتْرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ عِنْدَ جَمْرَةِ الْعَقَبَةِ وَهُوَ رَاكِبٌ عَلَى بَغْلَةٍ فَقَالَ يَا أَيُّهَا النَّاسُ إِذَا رَمَيْتُمْ الْجَمْرَةَ فَارْمُوا بِمِثْلِ حَصَى الْخَذْفِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Mushir], dari [Yazid bin Abu Ziyad] dari [Sulaiman bin Amru bin Al Ahwash], dari [Ibunya], ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam pada hari 'Idul Adha ketika melontar jumrah Aqabah dengan mengendarai bahgalnya. Beliau bersabda: 'Wahai manusia sekalian, jika kalian melontar jumrah, maka lontarlah dengan kerikil kecil seperti kerikil ketapel'.\""},"2985":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَوْفٍ عَنْ زِيَادِ بْنِ الْحُصَيْنِ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَاةَ الْعَقَبَةِ وَهُوَ عَلَى نَاقَتِهِ الْقُطْ لِي حَصًى فَلَقَطْتُ لَهُ سَبْعَ حَصَيَاتٍ هُنَّ حَصَى الْخَذْفِ فَجَعَلَ يَنْفُضُهُنَّ فِي كَفِّهِ وَيَقُولُ أَمْثَالَ هَؤُلَاءِ فَارْمُوا ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِيَّاكُمْ وَالْغُلُوَّ فِي الدِّينِ فَإِنَّهُ أَهْلَكَ مَنْ كَانَ قَبْلَكُمْ الْغُلُوُّ فِي الدِّينِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abu Usamah] dari [Auf] dari [Ziyad bin Hushain] dari [Abu Aliyah] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda di pagi hari jumrah Aqabah saat beliau berada di atas untanya: 'Tolong ambilkan aku kerikil.' Maka aku ambilkan untuk beliau tujuh kerikil, semuanya sebesar kerikil ketapel. Beliau mengebutkan (membersihkan debunya) di telapak tangan, seraya besabda: 'Dengan kerikil-kerikil seperti inilah hendaknya kalian melempar.' Kemudian beliau bersabda: 'Wahai manusia jauhkanlah kalian berlebih-lebihan dalam agama. Karena orang-orang sebelum kalian telah binasa sebab mereka berlebih-lebihan dalam agama.'"},"2986":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْمَسْعُودِيِّ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَلَمَّا أَتَى عَبْدُ اللَّهِ بْنُ مَسْعُودٍ جَمْرَةَ الْعَقَبَةِ اسْتَبْطَنَ الْوَادِيَ وَاسْتَقْبَلَ الْكَعْبَةَ وَجَعَلَ الْجَمْرَةَ عَلَى حَاجِبِهِ الْأَيْمَنِ ثُمَّ رَمَى بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ ثُمَّ قَالَ مِنْ هَاهُنَا وَالَّذِي لَا إِلَهَ غَيْرُهُ رَمَى الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki'] dari [Al Mas'udi] dari [Jami' bin Syaddad] dari [Abdurrahman bin Yazid], ia berkata; \"Ketika [Abdullah bin Mas'ud] datang (hendak melontar) jumrah Aqabah, ia masuk ke tengah lembah, menghadap kiblat dan memposisikan tempat jumrah di sebelah kanan. Kemudian ia melontar tujuh kerikil, bertakbir pada tiap lontaran, kemudian ia berkata; 'Demi Dzat yang tidak ada tuhan selain Dia, yang di turunkan kepadanya surat Al Baqarah (Rasulullah shallallahu 'alaihi wasallam), 'dari sebelah sinilah (melontar jumrah Aqabah) beliau melakukannya'.\""},"2987":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ قَالَتْرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ عِنْدَ جَمْرَةِ الْعَقَبَةِ اسْتَبْطَنَ الْوَادِيَ فَرَمَى الْجَمْرَةَ بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ ثُمَّ انْصَرَفَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّ جُنْدَبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Mushir] dari [Yazid bin Abu Ziyad] dari [Sulaiman bi Amru bin Al Ahwash], dari [ibunya], ia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam pada hari 'Iedul Adha berada di sisi jumrah Aqabah, beliau masuk ke tengah lembah, lalu melontar jumrah dengan tujuh kerikil. Beliau bertakbir setiap kali melempar lontaran lalu pergi.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Yazid bin Abu Ziyad] dari [Sulaiman bin Amru bin Al Ahwash] dari [Ummu Jundab] dari Nabi shallallahu 'alaihi wasallam seperti itu."},"2988":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ رَمَى جَمْرَةَ الْعَقَبَةِ وَلَمْ يَقِفْ عِنْدَهَا وَذَكَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah]; telah menceritakan kepada kami [Thalhah bin Yahya] dari [Yunus bin Yazid] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] radliallahu 'anhu, bahwa ia melontar jumrah Aqabah tanpa berhenti di tempat jumrah itu. Dan dia menyebutkan bahwa Nabi shallallahu 'alaihi wasallam mengerjakan seperti demikian.\""},"2989":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْحَجَّاجِ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَمَى جَمَرَ الْعَقَبَةِ مَضَى وَلَمْ يَقِفْ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id]; telah menceritakan kepada kami [Ali bin Mushir] dari [Al Hajjaj] dari [Al Hakam bin Utaibah] dari [Miqsam] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam jika melontar jumrah Aqabah, beliau terus berjalan dan tidak berhenti.\""},"2990":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَجَّاجٍ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَى الْجَمْرَةَ عَلَى رَاحِلَتِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Hajjaj] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam melontar jumrah dari atas kendaraannya."},"2991":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أَيْمَنَ بْنِ نَابِلٍ عَنْ قُدَامَةَ بْنِ عَبْدِ اللَّهِ الْعَامِرِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَى الْجَمْرَةَ يَوْمَ النَّحْرِ عَلَى نَاقَةٍ لَهُ صَهْبَاءَ لَا ضَرْبَ وَلَا طَرْدَ وَلَا إِلَيْكَ إِلَيْكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Waki'] dari [Aiman bin Nabil] dari [Qudamah bin Abdullah Al Amiri], ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam melontar jumrah pada hari 'Ied Adha dari atas unta coklat muda beliau, tidak ada pukulan dan tidak pula usiran, serta tidak ada ucapan: 'Kepadamu, kepadamu.\""},"2992":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرٍ عَنْ أَبِي الْبَدَّاحِ بْنِ عَاصِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لِلرِّعَاءِ أَنْ يَرْمُوا يَوْمًا وَيَدَعُوا يَوْمًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdullah bin Abu Bakar] dari [Abdul Malik bin Abu Bakar] dari [Abdul Badah bin Ashim] dari [Bapaknya], bahwa Nabi shallallahu 'alaihi wasallam memberikan keringanan kepada para penggembala untuk melontar jumrah dalam sehari, kemudian tidak melontar sehari (berikutnya)."},"2993":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَالِكُ بْنُ أَنَسٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ أَبِي الْبَدَّاحِ بْنِ عَاصِمٍ عَنْ أَبِيهِ قَالَرَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرِعَاءِ الْإِبِلِ فِي الْبَيْتُوتَةِ أَنْ يَرْمُوا يَوْمَ النَّحْرِ ثُمَّ يَجْمَعُوا رَمْيَ يَوْمَيْنِ بَعْدَ النَّحْرِ فَيَرْمُونَهُ فِي أَحَدِهِمَا قَالَ مَالِكٌ ظَنَنْتُ أَنَّهُ قَالَ فِي الْأَوَّلِ مِنْهُمَا ثُمَّ يَرْمُونَ يَوْمَ النَّفْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazak]; telah memberitakan kepada kami [Malik bin Anas]; Demikian juga diriwayatkan dari jalur lainnya, telah menceritakan kepada kami [Ahmad bin Sinan]; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Malik bin Anas]; telah menceritakan kepadaku [Abdullah bin Abu Bakar] dari [Ayahnya] dari [Abul Badah bin Ashim], dari [Ayahnya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memberikan keringanan pada penggembala unta (yang sibuk mengurus makan gembala) saat mabit di Mina untuk melontar jumrah pada hari 'Ied Adha. Mereka dapat mengumpulkan lontarannya pada dua hari setelah hari 'Ied Adha, mereka (dibolehkan) untuk melontar pada salah satu dari dua hari tersebut. Malik berkata; 'Aku mengira bahwa beliau bersabda: 'Pada hari pertama dari dua hari tersebut'. Kemudian mereka pun melontar pada hari Nafar.\""},"2994":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ أَشْعَثَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَحَجَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَنَا النِّسَاءُ وَالصِّبْيَانُ فَلَبَّيْنَا عَنْ الصِّبْيَانِ وَرَمَيْنَا عَنْهُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abdullah bin Numair] dari [Asy'ats] dari [Abu Zubair] dari [Jabir] berkata; \"Kami melaksanakan haji bersama Rasulullah shallallahu 'alaihi wasallam sedang bersama kami ada wanita dan anak-anak, kami bertalbiyah diikuti anak-anak dan kami melempar bersama mereka.\""},"2995":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا حَمْزَةُ بْنُ الْحَارِثِ بْنِ عُمَيْرٍ عَنْ أَبِيهِ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبَّى حَتَّى رَمَى جَمْرَةَ الْعَقَبَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Khalaf Abu Bisyr]; telah menceritakan kepada kami [Hamzah bin Al Harits bin Umair] dari [Ayahnya] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam bertalbiyah hingga beliau melontar jumrah Aqabah."},"2996":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ خُصَيْفٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ الْفَضْلُ بْنُ عَبَّاسٍكُنْتُ رِدْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا زِلْتُ أَسْمَعُهُ يُلَبِّي حَتَّى رَمَى جَمْرَةَ الْعَقَبَةِ فَلَمَّا رَمَاهَا قَطَعَ التَّلْبِيَةَ","id":"Telah menceritakan kepada kami [Hannad bin As Sari]; telah menceritakan kepada kami [Abul Ahwash] dari [Khushaif] dari [Mujahid] dari [Ibnu Abbas] berkata; Al Fahdl bin Abbas radliallahu 'anhu, ia berkata; \"Aku berada di belakang Nabi shallallahu 'alaihi wasallam, dan aku masih mendengar beliau bertalbiyah sampai beliau melontar jumrah Aqabah. Selepas melontarnya, beliaupun berhenti bertalbiyah.\""},"2997":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَوَكِيعٌ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ الْحَسَنِ الْعُرَنِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَإِذَا رَمَيْتُمْ الْجَمْرَةَ فَقَدْ حَلَّ لَكُمْ كُلُّ شَيْءٍ إِلَّا النِّسَاءَ فَقَالَ لَهُ رَجُلٌ يَا ابْنَ عَبَّاسٍ وَالطِّيبُ فَقَالَ أَمَّا أَنَا فَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُضَمِّخُ رَأْسَهُ بِالْمِسْكِ أَفَطِيبٌ ذَلِكَ أَمْ لَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki']; Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Abu Bakar bin Khalad Al Bahili]; telah menceritakan kepada kami [Yahya bin Sa'id] dan [Waki'] serta [Abdurrahman bin Mahdi], semuanya mengatakan; telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Al Hasan Al 'Urani] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Jika kalian telah melontar jumrah (Aqabah), maka telah dihalalkan bagi kalian segala sesuatu (dari larangan Ihram) kecuali menggauli istri.\" Seorang lelaki bertanya kepadanya; 'Wahai Ibnu Abbas radliallahu 'anhu, bagaimana dengan wewangian? ' Ia menjawab; 'Aku telah melihat Rasulullah shallallahu 'alaihi wasallam melumuri kepalanya dengan Kesturi, bukankah (kesturi) itu wangi-wangian atau bukan? '"},"2998":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا خَالِي مُحَمَّدٌ وَأَبُو مُعَاوِيَةَ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْطَيَّبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِإِحْرَامِهِ حِينَ أَحْرَمَ وَلِإِحْلَالِهِ حِينَ أَحَلَّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Pamanku Muhammad] dan [Abu Mu'awiyah] serta [Abu Usamah] dari [Ubaidullah] dari [Al Qasim bin Muhammad] dari [Aisyah] radliallahu 'anha, ia berkata; \"Aku memakaikan wewangian kepada Rasulullah shallallahu 'alaihi wasallam ketika beliau berihram dan ketika beliau bertahalul.\""},"2999":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اغْفِرْ لِلْمُحَلِّقِينَ قَالُوا يَا رَسُولَ اللَّهِ وَالْمُقَصِّرِينَ قَالَ اللَّهُمَّ اغْفِرْ لِلْمُحَلِّقِينَ ثَلَاثًا قَالُوا يَا رَسُولَ اللَّهِ وَالْمُقَصِّرِينَ قَالَ وَالْمُقَصِّرِينَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Fudhail]; telah menceritakan kepada kami [Umarah bin Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berdoa: 'Ya Allah ampunilah orang-orang yang bercukur.'\" Para sahabat berkata; 'Wahai Rasulullah, (bagaimana dengan) orang-orang yang memendekan rambutnya? ' Beliau bersabda: 'Ya Allah ampunilah orang-orang yang bercukur.' Beliau menyebutnya tiga kali. Mereka berkata; 'Wahai Rasulullah, (bagaimana dengan) orang-orang yang memendekkan rambutnya? ' Beliau bersabda: 'Dan orang-orang yang memendekkan rambutnya.'"},"3000":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَأَحْمَدُ بْنُ أَبِي الْحَوَارِيِّ الدِّمَشْقِيُّ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَحِمَ اللَّهُ الْمُحَلِّقِينَ قَالُوا وَالْمُقَصِّرِينَ يَا رَسُولَ اللَّهِ قَالَ رَحِمَ اللَّهُ الْمُحَلِّقِينَ قَالُوا وَالْمُقَصِّرِينَ يَا رَسُولَ اللَّهِ قَالَ رَحِمَ اللَّهُ الْمُحَلِّقِينَ قَالُوا وَالْمُقَصِّرِينَ يَا رَسُولَ اللَّهِ قَالَ وَالْمُقَصِّرِينَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Ahmad bin Abu Hawari Ad Dimasyqi], keduanya berkata; telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah merahmati orang-orang yang bercukur.\" Para sahabat bertanya; 'Dan apakah juga orang-orang yang memendekkan rambut, wahai Rasulullah? ' Beliau bersabda: 'Semoga Allah merahmati orang-orang yang bercukur.' Mereka berkata lagi; 'Dan apakah juga orang-orang yang memendekkan rambut, wahai Rasulullah? ' Beliau bersabda: 'Semoga Allah merahmati orang-orang yang bercukur.' Mereka berkata lagi; 'Dan apakah juga orang-orang yang memendekkan rambut, wahai Rasulullah? ' Beliau pun bersabda: 'Dan orang-orang yang memendekkan rambut.'"}};
